def is_trade_candidate_name(name: str) -> bool:
    """мӢӨм „ м§„мһ…(нҸ¬м°©/м§„мһ…к°җмӢң) лҢҖмғҒмқём§Җ нҢҗлӢЁ"""
    if not name:
        return True
    for kw in EXCLUDE_TRADE_KEYWORDS:
        if kw and kw in name:
            return False
    return True



