# в‘Ө мӨ‘м•ҷ м—җлҹ¬ лЎңкұ° (мӨ‘мҡ” кё°лҠҘ мҳӨлҘҳ мЎ°мҡ©нһҲ л¬»нһҲм§Җ м•ҠкІҢ)
_error_counts: dict = {}

def _log_error(func_name: str, e: Exception, critical: bool = False):
    _error_counts[func_name] = _error_counts.get(func_name, 0) + 1
    cnt = _error_counts[func_name]
    # v38.3-D2: мқјмқј м—җлҹ¬ м§‘кі„
    _error_daily_counts[func_name] = _error_daily_counts.get(func_name, 0) + 1
    _error_daily_samples[func_name] = f"{type(e).__name__}: {str(e)[:80]}"
    print(f"вҡ пёҸ [{func_name}] {type(e).__name__}: {e} (лҲ„м Ғ {cnt}нҡҢ)", flush=True)
    if critical or cnt in (5, 20, 100):
        try:
            send(f"рҹ”ө <b>л°ҳліө мҳӨлҘҳ к°җм§Җ</b>\n"
                 f"н•ЁмҲҳ: <code>{func_name}</code>  лҲ„м Ғ {cnt}нҡҢ\n"
                 f"мҳӨлҘҳ: {type(e).__name__}: {str(e)[:100]}")
        except Exception: pass

