# v41.77 #2: NXT м„ н–үмғҒмҠ№ вҶ’ м •к·ңмһҘ м¶”м Ғ м „нҷҳ
# ============================================================
def _register_nxt_surge_to_krx_watch(watch: dict, nxt_price: int):
    """
    NXTм—җм„ң м„ н–ү кёүл“ұн•ң мў…лӘ©мқ„ м°ЁлӢЁн•ҳлҠ” лҢҖмӢ  KRX м •к·ңмһҘ к°ңмӢң нӣ„ м¶”м Ғ лҢҖмғҒмңјлЎң л“ұлЎқ.
    кё°мЎҙ entry_watch к°җмӢңлҠ” мң м§Җн•ҳлҗҳ, nxt_surge_tracked н”Ңлһҳк·ёлҘј м¶”к°Җн•ҙ
    KRX м •к·ңмһҘ к°ңмӢң(09:00) нӣ„ check_entry_watchм—җм„ң мҡ°м„  мІҙнҒ¬.
    """
    try:
        if watch.get("nxt_surge_tracked"):
            return
        watch["nxt_surge_tracked"] = True
        watch["nxt_surge_price"]   = int(nxt_price or 0)
        watch["nxt_surge_time"]    = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        code = watch.get("code", "")
        name = watch.get("name", "")
        watch.setdefault("entry_price_at_detect", safe_int(watch.get("entry_price", 0), 0))
        watch.setdefault("pattern_grade_at_detect", str(watch.get("pattern_grade", watch.get("grade", "B")) or "B"))
        watch.setdefault("execution_grade_at_detect", str(watch.get("execution_grade", watch.get("grade", "B")) or "B"))
        watch.setdefault("grade_at_detect", str(watch.get("execution_grade_at_detect", watch.get("grade", "B")) or "B"))
        # м§„мһ…к°ҖлҘј NXT кёүл“ұк°Җ кё°мӨҖмңјлЎң мҶҢнҸӯ мһ¬мЎ°м • (кё°мЎҙ м§„мһ…к°ҖліҙлӢӨ лӮ®мңјл©ҙ мң м§Җ)
        orig_entry = watch.get("entry_price", 0)
        if orig_entry and nxt_price:
            # NXT к°ҖкІ©мқҙ м§„мһ…к°ҖліҙлӢӨ мқҙлҜё мҳ¬лқјк°”мңјл©ҙ м§„мһ…к°Җ н•ҳн–Ҙ мЎ°м • (5% лҲҢлҰј кё°лҢҖ)
            if nxt_price > orig_entry * 1.03:
                new_entry = int(nxt_price * 0.97)
                watch["entry_price_orig"] = orig_entry
                watch["entry_price"]      = new_entry
                print(f"  рҹ”„ NXTм„ н–үвҶ’KRXм¶”м Ғ: {name} м§„мһ…к°Җ {orig_entry:,}вҶ’{new_entry:,}мӣҗ (NXT {nxt_price:,})")
            else:
                print(f"  рҹ”„ NXTм„ н–үвҶ’KRXм¶”м Ғ: {name} м§„мһ…к°Җ мң м§Җ {orig_entry:,}мӣҗ (NXT {nxt_price:,})")

        # [v41.90] NXT м „нҷҳ мӢң pattern/execution grade мһ¬кі„мӮ°
        prev_pattern = str(watch.get("pattern_grade", watch.get("grade", "B"))).upper()
        prev_exec = str(watch.get("execution_grade", watch.get("grade", "B"))).upper()
        try:
            _reeval = analyze_mid_pullback(code, name)
            if not _reeval:
                _reeval = check_intraday_pullback_breakout(code, name)
            if _reeval:
                _sector = calc_sector_momentum(code, name)
                _reeval["sector_info"] = _sector
                _reeval["score"] += int((_sector.get("bonus", 0) or 0) * _dynamic.get("feat_w_sector", 1.0))
                _reeval = _finalize_mid_pullback_signal(_reeval)
                new_pattern = str(_reeval.get("pattern_grade", prev_pattern)).upper()
                new_exec = str(_reeval.get("grade", prev_exec)).upper()
                new_score = int(_reeval.get("score", watch.get("score", 0)) or 0)
                watch["pattern_grade"] = new_pattern
                watch["execution_grade"] = new_exec
                watch["grade"] = new_exec
                watch["score"] = new_score
                watch["mid_pullback_bucket"] = _reeval.get("mid_pullback_bucket", watch.get("mid_pullback_bucket", ""))
                watch["mid_pullback_bucket_label"] = _reeval.get("mid_pullback_bucket_label", watch.get("mid_pullback_bucket_label", ""))
                if new_exec != prev_exec or new_pattern != prev_pattern:
                    print(f"  рҹ“Ҡ NXTм „нҷҳ л“ұкёү мһ¬нҸүк°Җ: {name} нҢЁн„ҙ {prev_pattern}вҶ’{new_pattern} / мӢӨн–ү {prev_exec}вҶ’{new_exec} ({new_score}м җ)")
                if _grade_rank(new_pattern) > _grade_rank(prev_pattern):
                    _mid_pullback_alert_history.pop(code, None)
                    print(f"  рҹ”„ мҝЁлӢӨмҡҙ лҰ¬м…Ӣ: {name} (нҢЁн„ҙ мғҒн–Ҙ {prev_pattern}вҶ’{new_pattern})")
        except Exception as _re:
            print(f"  вҡ пёҸ NXTм „нҷҳ л“ұкёү мһ¬нҸүк°Җ мӢӨнҢЁ: {_re}")

        print(f"  рҹ“Ў NXTм„ н–үвҶ’KRXм¶”м Ғ л“ұлЎқ: {name} (м§„мһ…к°Җ {int(watch.get('entry_price', 0) or 0):,}мӣҗ / мӢӨн–үл“ұкёү {str(watch.get('execution_grade', watch.get('grade', 'B'))).upper()})")
    except Exception as e:
        print(f"вҡ пёҸ _register_nxt_surge_to_krx_watch: {e}")


# ============================================================
# v41.77 #4: м•јк°„ мқҙлІӨнҠё вҶ’ мһҘм „ мӣҢм№ҳлҰ¬мҠӨнҠё мһҗлҸҷ мғқм„ұ
# ============================================================
def _extract_overnight_event_keywords(headlines: list) -> dict:
    """
    м•јк°„ лүҙмҠӨ н—Өл“ңлқјмқём—җм„ң мқҙлІӨнҠё нӮӨмӣҢл“ң мһҗлҸҷ м¶”м¶ң.
    л°ҳнҷҳ: {event_name: [matched_keywords]}
    """
    result = {}
    all_text = " ".join(headlines).lower()
    for event_name, keywords in OVERNIGHT_EVENT_KEYWORDS.items():
        matched = [kw for kw in keywords if kw.lower() in all_text]
        if matched:
            result[event_name] = matched
    return result


def _build_overnight_watchlist(detected_events: dict):
    """
    к°җм§Җлҗң м•јк°„ мқҙлІӨнҠё вҶ’ мҲҳнҳң көӯлӮҙ мў…лӘ© мӣҢм№ҳлҰ¬мҠӨнҠё мғқм„ұ вҶ’ overnight_watchlist.json м ҖмһҘ.
    detected_events: {event_name: [matched_keywords]}
    """
    global _overnight_watchlist
    try:
        watchlist = {}
        for event_name, kws in detected_events.items():
            sectors = OVERNIGHT_EVENT_SECTOR_MAP.get(event_name, [])
            for sec in sectors:
                # THEME_MAPм—җм„ң н•ҙлӢ№ м„№н„° мў…лӘ© м¶”м¶ң
                for tk, ti in THEME_MAP.items():
                    if sec in ti.get("sectors", []) or sec.lower() in ti.get("desc", "").lower():
                        for c, n in ti.get("stocks", []):
                            if c not in watchlist:
                                watchlist[c] = {
                                    "name":     n,
                                    "event":    event_name,
                                    "keywords": kws,
                                    "sectors":  sectors,
                                    "ts":       time.time(),
                                }
                # лҸҷм Ғ н…Ңл§Ҳм—җм„ңлҸ„ м¶”к°Җ
                for tk, ti in _dynamic_theme_map.items():
                    if sec.lower() in ti.get("desc", "").lower():
                        for c, n in ti.get("stocks", []):
                            if c not in watchlist:
                                watchlist[c] = {
                                    "name":     n,
                                    "event":    event_name,
                                    "keywords": kws,
                                    "sectors":  sectors,
                                    "ts":       time.time(),
                                    "source":   "dynamic_theme",
                                }

        if watchlist:
            _overnight_watchlist = watchlist
            try:
                _write_json_atomic(OVERNIGHT_WATCHLIST_FILE, watchlist, indent=2)
                print(f"  рҹҢҷ м•јк°„ мӣҢм№ҳлҰ¬мҠӨнҠё м ҖмһҘ: {len(watchlist)}мў…лӘ© ({list(detected_events.keys())})")
            except Exception: pass
    except Exception as e:
        print(f"вҡ пёҸ _build_overnight_watchlist: {e}")


def _format_overnight_watchlist_block() -> str:
    """мһҘм „ лёҢлҰ¬н•‘мҡ© м•јк°„ мӣҢм№ҳлҰ¬мҠӨнҠё лё”лЎқ мғқм„ұ"""
    if not _overnight_watchlist:
        return ""
    try:
        lines = ["рҹҢҷ <b>м•јк°„ мқҙлІӨнҠё мҲҳнҳң мҳҲмғҒ мў…лӘ©</b>"]
        by_event: dict = {}
        for c, v in _overnight_watchlist.items():
            ev = v.get("event", "кё°нғҖ")
            by_event.setdefault(ev, []).append((c, v))
        for ev, items in by_event.items():
            kws = items[0][1].get("keywords", [])[:3]
            lines.append(f"  рҹ“Ң <b>{ev}</b>  ({', '.join(kws)})")
            for c, v in items[:4]:
                lines.append(f"    вҖў {v['name']} <code>{c}</code>")
        return "\n".join(lines)
    except Exception:
        return ""


# ============================================================
# рҹҸ—пёҸ мӢӨм§Ҳ м„№н„° л¶„лҘҳ (4л Ҳмқҙм–ҙ к°ҖмӨ‘ мҠӨмҪ”м–ҙ)
# ============================================================
_dart_related_cache: dict = {}   # code вҶ’ {related: [...], ts}
_real_sector_cache:  dict = {}   # code вҶ’ {sector_id, score, peers, ts}

def get_dart_related_stocks(code: str) -> list:
    """
    DART м§Җл¶„кіөмӢңм—җм„ң лӘЁмһҗ/кҙҖкі„нҡҢмӮ¬ мў…лӘ© мЎ°нҡҢ.
    л°ҳнҷҳ: [(code, name, reason)] 
    мҳҲ: [("005930", "мӮјм„ұм „мһҗ", "мөңлҢҖмЈјмЈј")]
    мәҗмӢң 24мӢңк°„ (м§Җл¶„кҙҖкі„лҠ” мһҗмЈј м•Ҳ л°”лҖң)
    """
    if not DART_API_KEY:
        return []
    cached = _dart_related_cache.get(code)
    if cached and time.time() - cached["ts"] < 86400:
        return cached["related"]
    try:
        # DART кё°м—…к°ңнҷ©м—җм„ң corp_code мЎ°нҡҢ
        url = "https://opendart.fss.or.kr/api/company.json"
        resp = _session.get(url, params={"crtfc_key": DART_API_KEY, "stock_code": code}, timeout=10)
        if resp.status_code != 200:
            _dart_related_cache[code] = {"related": [], "ts": time.time()}
            return []
        corp_code = resp.json().get("corp_code", "")
        if not corp_code:
            _dart_related_cache[code] = {"related": [], "ts": time.time()}
            return []

        # мөңлҢҖмЈјмЈј нҳ„нҷ© мЎ°нҡҢ (лҢҖн‘ңм Ғ м§Җл¶„ кіөмӢң)
        url2  = "https://opendart.fss.or.kr/api/hyslrSttus.json"
        year  = datetime.now().strftime("%Y")
        resp2 = _session.get(url2, params={
            "crtfc_key": DART_API_KEY, "corp_code": corp_code,
            "bsns_year": year, "reprt_code": "11011"  # мӮ¬м—…ліҙкі м„ң
        }, timeout=10)
        items = resp2.json().get("list", []) if resp2.status_code == 200 else []

        related = []
        for item in items:
            relate_stock = item.get("stock_code", "").strip()
            relate_name  = item.get("nm", "").strip()
            relate_type  = item.get("relate", "").strip()
            if relate_stock and relate_stock != code:
                related.append((relate_stock, relate_name, relate_type or "кҙҖкі„нҡҢмӮ¬"))
        _dart_related_cache[code] = {"related": related[:10], "ts": time.time()}
        return related[:10]
    except Exception:
        _dart_related_cache[code] = {"related": [], "ts": time.time()}
        return []

def calc_real_sector_score(code_a: str, code_b: str,
                            name_a: str = "", name_b: str = "") -> dict:
    """
    л‘җ мў…лӘ© к°„ мӢӨм§Ҳ м„№н„° м—°кҙҖм„ұ мҠӨмҪ”м–ҙ (0~100).
    4к°Җм§Җ л Ҳмқҙм–ҙ к°ҖмӨ‘ н•©мӮ°:
      в‘  мЈјк°Җ мғҒкҙҖкі„мҲҳ 0.7вҶ‘  вҶ’ 40м җ
      в‘Ў лӢ№мқј лҸҷл°ҳ мғҒмҠ№ мӨ‘   вҶ’ 30м җ
      в‘ў DART м§Җл¶„ м—°кІ°      вҶ’ 20м җ
      в‘Ј лүҙмҠӨ лҸҷмӢң м–ёкёү      вҶ’ 10м җ
    л°ҳнҷҳ: {"score": int, "layers": dict, "label": str}
    """
    score   = 0
    layers  = {}

    # в‘  мЈјк°Җ мғҒкҙҖкі„мҲҳ (60мқј)
    try:
        corr = calc_price_correlation(code_a, code_b)
        if corr >= 0.7:
            pts = int(40 * min((corr - 0.7) / 0.3 + 0.5, 1.0))  # 0.7вҶ’20м җ, 1.0вҶ’40м җ
            score += pts
            layers["мғҒкҙҖкі„мҲҳ"] = f"{corr:.2f} (+{pts}м җ)"
        elif corr >= 0.5:
            score += 10
            layers["мғҒкҙҖкі„мҲҳ"] = f"{corr:.2f} (+10м җ)"
    except Exception: pass

    # в‘Ў лӢ№мқј лҸҷл°ҳ мғҒмҠ№ (мӢӨмӢңк°„)
    try:
        pa = get_stock_price(code_a)
        pb = get_stock_price(code_b)
        cr_a = pa.get("change_rate", 0)
        cr_b = pb.get("change_rate", 0)
        if cr_a >= 2.0 and cr_b >= 2.0:
            score += 30
            layers["лҸҷл°ҳмғҒмҠ№"] = f"+{cr_a:.1f}%/+{cr_b:.1f}% (+30м җ)"
        elif cr_a >= 1.0 and cr_b >= 1.0:
            score += 15
            layers["лҸҷл°ҳмғҒмҠ№"] = f"+{cr_a:.1f}%/+{cr_b:.1f}% (+15м җ)"
    except Exception: pass

    # в‘ў DART м§Җл¶„ кҙҖкі„
    try:
        related = get_dart_related_stocks(code_a)
        dart_hit = next((r for r in related if r[0] == code_b), None)
        if dart_hit:
            score += 20
            layers["DARTм§Җл¶„"] = f"{dart_hit[2]} (+20м җ)"
    except Exception: pass

    # в‘Ј лүҙмҠӨ лҸҷмӢң м–ёкёү
    try:
        cooccur_a = _news_cooccur.get(code_a, {}).get("peers", {})
        if code_b in cooccur_a and cooccur_a[code_b] >= 2:
            score += 10
            layers["лүҙмҠӨлҸҷмӢңм–ёкёү"] = f"{cooccur_a[code_b]}нҡҢ (+10м җ)"
    except Exception: pass

    if score >= 60:   label = "рҹ”ө к°•н•ң м—°кҙҖ"
    elif score >= 40: label = "рҹҹЎ ліҙнҶө м—°кҙҖ"
    elif score >= 20: label = "рҹҹЎ м•Ҫн•ң м—°кҙҖ"
    else:             label = "м—°кҙҖ м—ҶмқҢ"

    return {"score": score, "layers": layers, "label": label}

def get_theme_sector_stocks(code: str) -> tuple:
    """
    мў…лӘ© мҪ”л“ң вҶ’ (н…Ңл§ҲлӘ…, [(peer_code, peer_name)]) л°ҳнҷҳ
    мҡ°м„ мҲңмң„:
      1. н•ҳл“ңмҪ”л”© THEME_MAP
      2. лҸҷм Ғ н…Ңл§Ҳл§ө (к°ҖкІ©мғҒкҙҖкҙҖкі„ + лүҙмҠӨ кіөлҸҷм–ёкёүмңјлЎң мһҗлҸҷ мғқм„ұ)
      3. KIS м—…мў…мҪ”л“ң л§Өм№ӯ
    к°Ғ мҶҢмҠӨлҘј лі‘н•©н•ҙм„ң к°ҖмһҘ н’Қл¶Җн•ң м •ліҙ м ңкіө
    """
    peers_all = {}   # code вҶ’ (name, source, reason)

    # 1. THEME_MAP
    theme_name = "кё°нғҖм—…мў…"
    for tk, ti in THEME_MAP.items():
        if code in [c for c,_ in ti["stocks"]]:
            theme_name = tk
            for c, n in ti["stocks"]:
                if c != code:
                    peers_all[c] = (n, "н…Ңл§Ҳ", tk)
            break

    # 2. лҸҷм Ғ н…Ңл§Ҳл§ө
    dyn_reason = ""
    for tk, ti in _dynamic_theme_map.items():
        if code in [c for c,_ in ti["stocks"]]:
            if theme_name == "кё°нғҖм—…мў…":
                theme_name = ti["desc"]
            dyn_reason = ti.get("reason", "")
            for c, n in ti["stocks"]:
                if c != code and c not in peers_all:
                    peers_all[c] = (n, "лҸҷм Ғн…Ңл§Ҳ", ti["desc"])
            break

    # 3. KIS м—…мў…мҪ”л“ң л§Өм№ӯ (лӮҳлЁём§Җ мұ„мҡ°кё°мҡ©)
    kis_peers = get_sector_stocks_from_kis(code)
    for c, n in kis_peers:
        if c not in peers_all:
            peers_all[c] = (n, "м—…мў…мҪ”л“ң", "")

    peers = [(c, n) for c, (n, src, rsn) in peers_all.items()]
    return theme_name, peers, peers_all   # peers_allмқҖ мҶҢмҠӨ м •ліҙ нҸ¬н•Ё


# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# рҹҢҚ J: н•ҙмҷё м„ л¬јвҶ’м„№н„° м—°лҸҷ (v39.0)
# в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
# мӣҗмһҗмһ¬/кёҲлҰ¬ ліҖлҸҷмқҙ м§Ғм ‘ мҳҒн–Ҙмқ„ мЈјлҠ” н•ңкөӯ м„№н„° л§Өн•‘
COMMODITY_SECTOR_MAP = {
    # (м§Җн‘ңнӮӨ, мһ„кі„к°’, л°©н–Ҙ) вҶ’ [(м„№н„°лӘ…, ліҙм •м җмҲҳ)]
    # мң к°Җ кёүл“ұ вҶ’ м—җл„Ҳм§Җ/м„қмң нҷ”н•ҷ нҳёмһ¬, н•ӯкіө/н•ҙмҡҙ м•…мһ¬
    "oil_up":    {"threshold": 3.0, "sectors": {"м„қмң нҷ”н•ҷ": +5, "м—җл„Ҳм§Җ": +5, "м •мң ": +5,
                                                 "н•ӯкіө": -4, "н•ҙмҡҙ": -3, "мҡҙмҲҳ": -3}},
    "oil_down":  {"threshold": -3.0, "sectors": {"м„қмң нҷ”н•ҷ": -4, "м—җл„Ҳм§Җ": -4,
                                                   "н•ӯкіө": +3, "н•ҙмҡҙ": +2}},
    # кёҲ кёүл“ұ вҶ’ м•Ҳм „мһҗмӮ° м„ нҳё = л°©мӮ°/к·ҖкёҲмҶҚ нҳёмһ¬, м„ұмһҘмЈј м•Ҫм„ё
    "gold_up":   {"threshold": 1.5, "sectors": {"л°©мӮ°": +4, "кёҲ": +3, "к·ҖкёҲмҶҚ": +3}},
    "gold_down": {"threshold": -1.5, "sectors": {"л°©мӮ°": -2}},
    # көӯмұ„ мҲҳмқөлҘ  мғҒмҠ№ вҶ’ кёҲмңө нҳёмһ¬, кұҙм„Ө/м„ұмһҘмЈј м•…мһ¬
    "tnx_high":  {"threshold": 4.5, "sectors": {"мқҖн–ү": +3, "ліҙн—ҳ": +3, "кёҲмңө": +3,
                                                  "кұҙм„Ө": -3, "л°”мқҙмҳӨ": -3}},
    "tnx_low":   {"threshold": 3.5, "sectors": {"кұҙм„Ө": +2, "л°”мқҙмҳӨ": +2,
                                                  "мқҖн–ү": -2}},
}

def _get_commodity_sector_adj(theme_name: str) -> int:
    """v39.0-J: н•ҙмҷё м„ л¬ј лҚ°мқҙн„° кё°л°ҳ м„№н„°лі„ м җмҲҳ ліҙм •."""
    if not theme_name:
        return 0
    try:
        us = _us_cache  # get_us_market_signals()мқҳ мәҗмӢң
        if not us or time.time() - us.get("ts", 0) > 7200:
            return 0
        oil_chg  = float(us.get("oil_chg", 0) or 0)
        gold_chg = float(us.get("gold_chg", 0) or 0)
        tnx      = float(us.get("tnx", 0) or 0)

        adj = 0
        theme_lower = theme_name.lower()

        # мң к°Җ
        if oil_chg >= COMMODITY_SECTOR_MAP["oil_up"]["threshold"]:
            for sec, val in COMMODITY_SECTOR_MAP["oil_up"]["sectors"].items():
                if sec in theme_name or sec in theme_lower:
                    adj += val; break
        elif oil_chg <= COMMODITY_SECTOR_MAP["oil_down"]["threshold"]:
            for sec, val in COMMODITY_SECTOR_MAP["oil_down"]["sectors"].items():
                if sec in theme_name or sec in theme_lower:
                    adj += val; break
        # кёҲ
        if gold_chg >= COMMODITY_SECTOR_MAP["gold_up"]["threshold"]:
            for sec, val in COMMODITY_SECTOR_MAP["gold_up"]["sectors"].items():
                if sec in theme_name or sec in theme_lower:
                    adj += val; break
        elif gold_chg <= COMMODITY_SECTOR_MAP["gold_down"]["threshold"]:
            for sec, val in COMMODITY_SECTOR_MAP["gold_down"]["sectors"].items():
                if sec in theme_name or sec in theme_lower:
                    adj += val; break
        # көӯмұ„
        if tnx >= COMMODITY_SECTOR_MAP["tnx_high"]["threshold"]:
            for sec, val in COMMODITY_SECTOR_MAP["tnx_high"]["sectors"].items():
                if sec in theme_name or sec in theme_lower:
                    adj += val; break
        elif tnx > 0 and tnx <= COMMODITY_SECTOR_MAP["tnx_low"]["threshold"]:
            for sec, val in COMMODITY_SECTOR_MAP["tnx_low"]["sectors"].items():
                if sec in theme_name or sec in theme_lower:
                    adj += val; break
        return adj
    except Exception:
        return 0


def calc_sector_momentum(code: str, name: str) -> dict:
    theme_name, peers, peers_all = get_theme_sector_stocks(code)
    # [v37.10-all5] м§Җм •н•ҷ/лүҙмҠӨ м„№н„° л°”мқҙм–ҙмҠӨ(м җмҲҳ ліҙм •)
    geo_bias = 0
    try:
        geo_bias = int(globals().get('GEO_SECTOR_BIAS', {}).get(theme_name, 0) or 0)
    except Exception:
        geo_bias = 0
    if not peers:
        return {"bonus":0,"theme":theme_name,"summary":"","rising":[],"flat":[],"detail":[],"sources":{},"leader":None}
    results = []
    total_trade_amount = 0  # v38.6-B: м„№н„° м „мІҙ кұ°лһҳлҢҖкёҲ
    for peer_code, peer_name in peers[:8]:
        try:
            cur = get_stock_price(peer_code)
            if not cur: continue
            safe_peer_name = _resolve_stock_name(peer_code, peer_name, cur)
            cr, vr = cur.get("change_rate",0), cur.get("volume_ratio",0)
            price = cur.get("price", 0)
            today_vol = cur.get("today_vol", 0)
            trade_amt = price * today_vol if price and today_vol else 0  # кұ°лһҳлҢҖкёҲ м¶”м •
            total_trade_amount += trade_amt
            src, rsn = peers_all.get(peer_code, (safe_peer_name, "м—…мў…мҪ”л“ң", ""))[1:]
            results.append({"code":peer_code,"name":safe_peer_name,"price":price,
                             "change_rate":cr,"volume_ratio":vr,"trade_amount":trade_amt,
                             "strong":cr>=2.0 and vr>=2.0,"weak":cr>=2.0,
                             "source":src, "reason":rsn})
            time.sleep(0.15)
        except Exception: continue
    if not results:
        return {"bonus":0,"theme":theme_name,"summary":"","rising":[],"flat":[],"detail":[],"sources":{},"leader":None}

    # в”Җв”Җ v38.6-B: м„№н„° мһҗкёҲ м§‘мӨ‘лҸ„ (Sector Score) в”Җв”Җ
    total, react_cnt = len(results), sum(1 for r in results if r["weak"])
    strong_cnt = sum(1 for r in results if r["strong"])
    react_ratio = react_cnt / total
    avg_vr = sum(r["volume_ratio"] for r in results) / total if total else 1.0
    avg_cr = sum(r["change_rate"] for r in results) / total if total else 0.0
    # Sector Score = 0.5*кұ°лһҳлҹүмҰқк°ҖмңЁ + 0.3*мғҒмҠ№мў…лӘ©л№„мңЁ + 0.2*нҸүк· мғҒмҠ№лҘ 
    sector_score = round(0.5 * min(avg_vr / 3.0, 1.0) + 0.3 * react_ratio + 0.2 * min(avg_cr / 5.0, 1.0), 2)

    bonus = (15 if react_ratio>=1.0 else 10 if react_ratio>=0.5 else 5 if react_cnt>=1 else 0)
    if strong_cnt >= 2: bonus += 5
    # B: м„№н„° мһҗкёҲ м§‘мӨ‘лҸ„ ліҙл„ҲмҠӨ
    if sector_score >= 0.7: bonus += 8
    elif sector_score >= 0.5: bonus += 4

    # в”Җв”Җ v38.6-C: лҢҖмһҘмЈј Leader Score в”Җв”Җ
    leader = None
    if results:
        cr_sorted = sorted(range(len(results)), key=lambda i: -results[i]["change_rate"])
        vr_sorted = sorted(range(len(results)), key=lambda i: -results[i]["volume_ratio"])
        amt_sorted = sorted(range(len(results)), key=lambda i: -results[i]["trade_amount"])
        n = len(results)
        for i, r in enumerate(results):
            cr_rank = cr_sorted.index(i) / max(n-1, 1)   # 0=1л“ұ
            vr_rank = vr_sorted.index(i) / max(n-1, 1)
            amt_rank = amt_sorted.index(i) / max(n-1, 1)
            r["leader_score"] = round(
                0.35 * (1 - cr_rank) +    # л“ұлқҪлҘ  мҲңмң„
                0.30 * (1 - vr_rank) +    # кұ°лһҳлҹү мҲңмң„
                0.25 * (1 - amt_rank) +   # кұ°лһҳлҢҖкёҲ мҲңмң„
                0.10 * (1.0 if r["change_rate"] > 0 and r["price"] > 0 else 0),  # м–‘лҙү м—¬л¶Җ
            2)
        leader_r = max(results, key=lambda r: r.get("leader_score", 0))
        if leader_r.get("leader_score", 0) >= 0.5:
            leader = {"code": leader_r["code"], "name": leader_r["name"],
                      "score": leader_r["leader_score"], "cr": leader_r["change_rate"],
                      "vr": leader_r["volume_ratio"]}

    rising = [r for r in results if r["weak"]]
    flat   = [r for r in results if not r["weak"]]
    if bonus == 0:            summary = f"рҹ“ү м„№н„° л°ҳмқ‘ м—ҶмқҢ ({theme_name}: {react_cnt}/{total})"
    elif react_ratio >= 1.0:  summary = f"рҹ”Ҙ м„№н„° м „мІҙ лҸҷл°ҳ мғҒмҠ№! ({theme_name}: {react_cnt}/{total})"
    elif react_ratio >= 0.5:  summary = f"вң… м„№н„° м Ҳл°ҳ мқҙмғҒ л°ҳмқ‘ ({theme_name}: {react_cnt}/{total})"
    else:                     summary = f"рҹҹЎ м„№н„° мқјл¶Җ л°ҳмқ‘ ({theme_name}: {react_cnt}/{total})"
    # B: м„№н„° м җмҲҳ н‘ңмӢң
    if sector_score >= 0.5:
        summary += f"  рҹ’° мһҗкёҲм§‘мӨ‘лҸ„ {sector_score:.0%}"
    # C: лҢҖмһҘмЈј н‘ңмӢң
    if leader:
        summary += f"  рҹ‘‘ лҢҖмһҘ {leader['name']}({leader['cr']:+.1f}%)"

    # в”Җв”Җ NXT м„№н„° лҸҷн–Ҙ ліҙм • в”Җв”Җ
    # м„№н„° лӮҙ мў…лӘ©л“Өмқҳ NXT мҷёмқё лҸҷн–Ҙмқҙ мқјм№ҳн• мҲҳлЎқ мӢ лў°лҸ„ вҶ‘
    if is_nxt_open() and results:
        nxt_bullish_cnt = 0
        nxt_bearish_cnt = 0
        for r in results[:4]:   # API л¶Җн•ҳ м ңн•ң: мөңлҢҖ 4мў…лӘ©
            try:
                nxt = get_nxt_info(r["code"])
                if nxt.get("inv_bullish"): nxt_bullish_cnt += 1
                elif nxt.get("inv_bearish"): nxt_bearish_cnt += 1
                time.sleep(0.1)
            except Exception: continue
        if nxt_bullish_cnt >= 2:
            bonus = min(bonus + 10, 30)
            summary += f"  рҹ”ҙ NXT {nxt_bullish_cnt}мў…лӘ© мҷёмқё+кё°кҙҖ л§ӨмҲҳ"
        elif nxt_bearish_cnt >= 2:
            bonus = max(bonus - 10, 0)
            summary += f"  рҹ”ө NXT {nxt_bearish_cnt}мў…лӘ© мҷёмқё+кё°кҙҖ л§ӨлҸ„"

    # мҶҢмҠӨлі„ л¶„лҘҳ (м•ҢлҰјм—җ 'мҷң л¬¶мҳҖлҠ”м§Җ' н‘ңмӢңмҡ©)
    sources = {}
    for r in results:
        src = r.get("source","м—…мў…мҪ”л“ң")
        sources.setdefault(src, []).append(r["name"])

    bonus = int(bonus + geo_bias)
    # v39.0-J: н•ҙмҷё м„ л¬јвҶ’м„№н„° ліҙм •
    commodity_bias = _get_commodity_sector_adj(theme_name)
    bonus = int(bonus + commodity_bias)
    if commodity_bias != 0:
        summary += f"  рҹҢҗ мӣҗмһҗмһ¬м—°лҸҷ {commodity_bias:+d}м җ"
    return {"bonus":bonus,"theme":theme_name,"summary":summary,
            "rising":rising,"flat":flat,"detail":results,"sources":sources,
            "leader":leader,"sector_score":sector_score}

# ============================================================
# рҹ’ҫ м ҖмһҘВ·ліөмӣҗ
# ============================================================
# ============================================================
# рҹ“Ӣ мӢ нҳё лЎңк·ё м ҖмһҘ (лӘЁл“  мӢ нҳё мң нҳ• кіөнҶө)
# ============================================================
SIGNAL_LOG_FILE = os.path.join(DATA_DIR, "signal_log.json")   # лӘЁл“  мӢ нҳё м¶”м Ғ (мӢ к·ң)

# ============================================================
# рҹҺҜ мөңм ҒмЎ°кұҙ л§Ңл“Өкё°мҡ© лҚ°мқҙн„°/нҠңлӢқ м„Өм •
#   - signal_logлҠ” мөңлҢҖ Nкұҙл§Ң мң м§Җ (л„Ҳл¬ҙ м»Өм§Җл©ҙ нҠңлӢқ н’Ҳм§Ҳ/мҶҚлҸ„ м Җн•ҳ)
#   - params_snapshot(мӢ нҳё лӢ№мӢң нҢҢлқјлҜён„°) + feature_snapshot(мғҒнҷ©/м§Җн‘ң) м ҖмһҘ
#   - params_snapshot м„ұкіј л№„көҗлЎң м җм§„м Ғ(auto) нҠңлӢқ
# ============================================================
SIGNAL_LOG_MAX_RECORDS = int(os.getenv("SIGNAL_LOG_MAX_RECORDS", "5000") or "5000")  # v38.3: 50000вҶ’5000
SIGNAL_LOG_ARCHIVE_DAYS = int(os.getenv("SIGNAL_LOG_ARCHIVE_DAYS", "90") or "90")
STRICT_ENTRY_CLEANUP_MARKER = os.path.join(DATA_DIR, "strict_entry_cleanup_v37_25.done")

def _strict_cleanup_legacy_entry_hits() -> None:
    """м—„кІ© м§„мһ…к°Җ лҸ„лӢ¬ мІҙкі„ м „нҷҳмҡ© 1нҡҢм„ұ л§Ҳмқҙк·ёл Ҳмқҙм…ҳ.
    кіјкұ° н—Ҳмҡ©мҳӨм°Ё кё°л°ҳмңјлЎң кё°лЎқлҗҗмқ„ мҲҳ мһҲлҠ” л№„мӢӨм§„мһ… entry_hitлҘј мҙҲкё°нҷ”н•ңлӢӨ.
    мғҲ strict hitк°Җ мһ¬мӢңмһ‘ л•Ң м§ҖмӣҢм§Җм§Җ м•ҠлҸ„лЎқ marker нҢҢмқјлЎң 1нҡҢл§Ң мҲҳн–үн•ңлӢӨ.
    """
    try:
        if os.path.exists(STRICT_ENTRY_CLEANUP_MARKER):
            return
        if not os.path.exists(SIGNAL_LOG_FILE):
            with open(STRICT_ENTRY_CLEANUP_MARKER, "w", encoding="utf-8") as f:
                f.write(datetime.now().strftime("%Y-%m-%d %H:%M:%S"))
            return

        data = _read_json_locked(SIGNAL_LOG_FILE)
        if not isinstance(data, dict):
            return

        changed = 0
        now_s = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        backup_path = os.path.join(DATA_DIR, f"signal_log.before_strict_cleanup_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json")

        for _k, rec in data.items():
            if not isinstance(rec, dict):
                continue
            if rec.get("actual_entry") is True:
                continue
            if rec.get("entry_hit") is True:
                rec["legacy_entry_hit"] = True
                rec["legacy_entry_hit_time"] = rec.get("entry_hit_time")
                rec["legacy_entry_hit_price"] = rec.get("entry_hit_price")
                rec["legacy_entry_hit_date"] = rec.get("entry_hit_date")
                rec["legacy_entry_hit_clock"] = rec.get("entry_hit_clock")
                rec["legacy_entry_hit_reset_at"] = now_s
                rec["legacy_entry_hit_reset_reason"] = "strict_cleanup_non_actual_entry"
                rec["entry_hit"] = False
                rec["entry_hit_time"] = None
                changed += 1

        if changed > 0:
            original = _read_json_locked(SIGNAL_LOG_FILE)
            _write_json_atomic(backup_path, original, indent=2)
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
            print(f"рҹ§№ strict cleanup: кіјкұ° л№„мӢӨм§„мһ… entry_hit {changed}кұҙ мҙҲкё°нҷ”, л°ұм—…={os.path.basename(backup_path)}")
        else:
            print("рҹ§№ strict cleanup: мҙҲкё°нҷ”н•  кіјкұ° л№„мӢӨм§„мһ… entry_hit м—ҶмқҢ")

        with open(STRICT_ENTRY_CLEANUP_MARKER, "w", encoding="utf-8") as f:
            f.write(now_s)
    except Exception as e:
        print(f"вҡ пёҸ strict cleanup мҳӨлҘҳ: {e}")

TUNE_LOOKBACK_DAYS = int(os.getenv("TUNE_LOOKBACK_DAYS", "30") or "30")
TUNE_MIN_SAMPLES   = int(os.getenv("TUNE_MIN_SAMPLES", "30") or "30")
TUNE_ALPHA         = float(os.getenv("TUNE_ALPHA", "0.35") or "0.35")  # 0~1, нҒҙмҲҳлЎқ л№ лҘҙкІҢ л°ҳмҳҒ

ROUND_TRIP_COST_PCT = float(os.getenv("ROUND_TRIP_COST_PCT", "0.30") or "0.30")  # мҷ•ліө мҲҳмҲҳлЈҢ+мҠ¬лҰ¬н”јм§Җ кіөнҶө н•©мӮ°(%)

def _safe_float(x, default=0.0):
    try:
        if x is None:
            return default
        return float(x)
    except Exception:
        return default

def safe_float(x, default=0.0):
    """н•ҳмң„ нҳёнҷҳмҡ© float ліҖнҷҳ helper."""
    return _safe_float(x, default)

def _is_manual_pnl_record(rec: dict) -> bool:
    try:
        if not isinstance(rec, dict):
            return False
        if rec.get("signal_type") == "MANUAL":
            return True
        if rec.get("exit_reason") == "мҲҳлҸҷмһ…л Ҙ":
            return True
        return False
    except Exception:
        return False

def _calc_net_pnl_pct(gross_pnl_pct, round_trip_cost_pct=None, *, is_manual: bool = False) -> float:
    gross = _safe_float(gross_pnl_pct, 0.0)
    if is_manual:
        return round(gross, 2)
    cost = _safe_float(ROUND_TRIP_COST_PCT if round_trip_cost_pct is None else round_trip_cost_pct, ROUND_TRIP_COST_PCT)
    return round(gross - cost, 2)

def _effective_pnl_pct(rec: dict, default: float = 0.0) -> float:
    try:
        if not isinstance(rec, dict):
            return default
        is_manual = _is_manual_pnl_record(rec)
        net = rec.get("net_pnl_pct")
        if net is not None:
            return round(_safe_float(net, default), 2)
        gross = rec.get("gross_pnl_pct")
        if gross is not None:
            return _calc_net_pnl_pct(gross, rec.get("round_trip_cost_pct"), is_manual=is_manual)
        pnl = rec.get("pnl_pct")
        if pnl is not None:
            return _calc_net_pnl_pct(pnl, rec.get("round_trip_cost_pct"), is_manual=is_manual)
        return default
    except Exception:
        return default

def _sync_record_pnl_fields(rec: dict) -> bool:
    try:
        if not isinstance(rec, dict):
            return False
        changed = False
        is_manual = _is_manual_pnl_record(rec)
        completed = rec.get("status") in ("мҲҳмқө", "мҶҗмӢӨ", "ліём „") or bool(rec.get("exit_reason"))

        desired_cost = 0.0 if is_manual else ROUND_TRIP_COST_PCT
        cur_cost = rec.get("round_trip_cost_pct")
        if cur_cost is None or abs(_safe_float(cur_cost, desired_cost) - desired_cost) > 1e-9:
            rec["round_trip_cost_pct"] = round(desired_cost, 4)
            changed = True

        if completed:
            gross_val = rec.get("gross_pnl_pct")
            if gross_val is None:
                src = rec.get("pnl_pct")
                if src is None:
                    src = rec.get("net_pnl_pct", 0.0)
                gross_val = _safe_float(src, 0.0)
                rec["gross_pnl_pct"] = round(gross_val, 2)
                changed = True
            else:
                gross_val = _safe_float(gross_val, 0.0)

            desired_net = _calc_net_pnl_pct(gross_val, rec.get("round_trip_cost_pct"), is_manual=is_manual)
            cur_net = rec.get("net_pnl_pct")
            if cur_net is None or abs(_safe_float(cur_net, desired_net) - desired_net) > 1e-9:
                rec["net_pnl_pct"] = desired_net
                changed = True

            cur_pnl = rec.get("pnl_pct")
            if cur_pnl is None or abs(_safe_float(cur_pnl, desired_net) - desired_net) > 1e-9:
                rec["pnl_pct"] = desired_net
                changed = True
        else:
            if rec.get("gross_pnl_pct") is None:
                rec["gross_pnl_pct"] = 0.0
                changed = True
            if rec.get("net_pnl_pct") is None:
                rec["net_pnl_pct"] = 0.0
                changed = True
            if rec.get("pnl_pct") is None:
                rec["pnl_pct"] = 0.0
                changed = True
        return changed
    except Exception:
        return False

def _normalize_signal_log_pnl_fields(data: dict) -> int:
    if not isinstance(data, dict):
        return 0
    changed = 0
    for rec in data.values():
        if _sync_record_pnl_fields(rec):
            changed += 1
    return changed

def migrate_signal_log_pnl_fields() -> None:
    """кё°мЎҙ signal_logм—җ gross/net/cost н•„л“ңлҘј 1нҡҢ ліҙк°•н•ҙ net кё°мӨҖ нҶөкі„лҘј мң м§Җн•ңлӢӨ."""
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
        if not isinstance(data, dict) or not data:
            return
        changed = _normalize_signal_log_pnl_fields(data)
        if changed <= 0:
            return
        data = _prune_signal_log(data)
        _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        try:
            _history_cache["data"] = data
            _history_cache["ts"] = time.time()
        except Exception:
            pass
        print(f"рҹ’ё signal_log pnl м •к·ңнҷ” мҷ„лЈҢ: {changed}кұҙ (мҷ•ліөл№„мҡ© {ROUND_TRIP_COST_PCT:.2f}%)")
    except Exception as e:
        print(f"вҡ пёҸ signal_log pnl м •к·ңнҷ” мҳӨлҘҳ: {e}")

def _prune_signal_log(data: dict) -> dict:
    """v38.3-P1-7: signal_log нҒ¬кё° кҙҖлҰ¬ вҖ” 90мқј м•„м№ҙмқҙлёҢ + кұҙмҲҳ м ңн•ң."""
    try:
        if not isinstance(data, dict):
            return data
        # 1лӢЁкі„: 90мқј мҙҲкіј мҷ„лЈҢкұҙ м•„м№ҙмқҙлёҢ
        cutoff = (datetime.now() - timedelta(days=SIGNAL_LOG_ARCHIVE_DAYS)).strftime("%Y%m%d")
        archive, keep = {}, {}
        for k, v in data.items():
            if not isinstance(v, dict):
                keep[k] = v; continue
            if v.get("status") in ("мҲҳмқө","мҶҗмӢӨ","ліём „") and str(v.get("detect_date","")) < cutoff:
                archive[k] = v
            else:
                keep[k] = v
        if archive:
            try:
                arch_path = os.path.join(DATA_DIR, "signal_log_archive.json")
                existing = _read_json_locked(arch_path)
                if not isinstance(existing, dict): existing = {}
                existing.update(archive)
                _write_json_atomic(arch_path, existing, indent=1)
                print(f"рҹ“Ұ signal_log м•„м№ҙмқҙлёҢ: {len(archive)}кұҙ")
            except Exception:
                keep.update(archive)  # мӢӨнҢЁ мӢң мӣҗліё мң м§Җ
        data = keep
        # 2лӢЁкі„: кұҙмҲҳ м ңн•ң
        if len(data) <= SIGNAL_LOG_MAX_RECORDS:
            return data
        def _k(item):
            k, v = item
            d = str(v.get("detect_date","")) if isinstance(v,dict) else ""
            t = str(v.get("detect_time","")) if isinstance(v,dict) else ""
            return (d + t.replace(":","")[:6]) if len(d)==8 and len(t)>=5 else k
        items = sorted(data.items(), key=_k)
        return dict(items[-SIGNAL_LOG_MAX_RECORDS:])
    except Exception:
        return data

def _get_params_snapshot() -> dict:
    """мӢ нҳё лӢ№мӢң 'мЎ°кұҙ'мқ„ мөңмҶҢ н•өмӢ¬л§Ң мҠӨлғ…мғ·(мөңм Ғнҷ”мҡ©)."""
    try:
        # л„Ҳл¬ҙ л§ҺмқҖ нӮӨлҘј м ҖмһҘн•ҳл©ҙ нҠңлӢқ лҚ°мқҙн„°к°Җ м§Җм Җл¶„н•ҙм§җ вҶ’ н•өмӢ¬л§Ң
        keys = [
            "min_score_normal", "min_score_strict",
            "atr_stop_mult", "atr_target_mult",
            "early_price_min", "early_volume_min",
            "mid_surge_min_pct", "mid_pullback_min", "mid_pullback_max",
            "mid_pullback_bucket_a_confirm_min", "mid_pullback_bucket_b_confirm_min",
            "mid_pullback_close_window_min_krx", "mid_pullback_close_window_min_nxt",
            "mid_pullback_close_gate_level",
            "themed_score_bonus",
            # к°ҖмӨ‘м№ҳ(кё°м—¬лҸ„ нҠңлӢқмҡ©)
            "feat_w_rsi", "feat_w_ma", "feat_w_bb", "feat_w_sector", "feat_w_nxt", "feat_w_geo",
        ]
        snap = {k: _dynamic.get(k) for k in keys if k in _dynamic}
        snap["_v"] = BOT_VERSION
        return snap
    except Exception:
        return {"_v": BOT_VERSION}

def _tune_score(records: list) -> float:
    """
    нҢҢлқјлҜён„° нӣ„ліҙмқҳ м„ұлҠҘ м җмҲҳ.
    - нҸүк·  мҲҳмқөлҘ (+)мқ„ мӨ‘мӢ¬мңјлЎң, мҶҗмӢӨ/л“ңлЎңмҡ°лӢӨмҡҙ(MAE)мқ„ нҺҳл„җнӢ°лЎң л°ҳмҳҒ.
    """
    if not records:
        return -1e9
    pnls = [_effective_pnl_pct(r, 0.0) for r in records]
    maes = [_safe_float(r.get("mae_pct"), 0.0) for r in records]  # мқҢмҲҳ(мҶҗмӢӨнҸӯ)
    # MAEлҠ” ліҙнҶө мқҢмҲҳмқҙлҜҖлЎң absлЎң нҺҳл„җнӢ°
    avg = sum(pnls) / len(pnls)
    win = sum(1 for p in pnls if p > 0)
    wr  = win / len(pnls)
    avg_abs_mae = (sum(abs(x) for x in maes) / len(maes)) if maes else 0.0
    # м җмҲҳ: нҸүк· мҲҳмқө + (мҠ№лҘ -0.5)*2 ліҙл„ҲмҠӨ - MAE нҺҳл„җнӢ°
    return avg + (wr - 0.5) * 2.0 - avg_abs_mae * 0.35

def _select_best_params(completed: list) -> dict:
    """мөңк·ј lookback кө¬к°„м—җм„ң params_snapshotлі„ м„ұлҠҘ л№„көҗ вҶ’ best snapshot л°ҳнҷҳ."""
    if not completed:
        return {}
    # lookback filter
    try:
        cutoff = datetime.now() - timedelta(days=TUNE_LOOKBACK_DAYS)
        filtered = []
        for r in completed:
            d = r.get("exit_date") or r.get("detect_date")
            t = r.get("exit_time") or r.get("detect_time") or "00:00:00"
            if d and len(str(d)) == 8:
                try:
                    dt = datetime.strptime(str(d) + str(t)[:8], "%Y%m%d%H:%M:%S")
                except Exception:
                    try:
                        dt = datetime.strptime(str(d), "%Y%m%d")
                    except Exception:
                        dt = None
                if dt and dt >= cutoff:
                    filtered.append(r)
            else:
                filtered.append(r)
    except Exception:
        filtered = completed

    groups = {}
    for r in filtered:
        snap = r.get("params_snapshot")
        if not isinstance(snap, dict):
            continue
        # signature (н•өмӢ¬ к°’л§Ң)
        sig = (
            snap.get("min_score_normal"),
            snap.get("min_score_strict"),
            snap.get("atr_stop_mult"),
            snap.get("atr_target_mult"),
        )
        groups.setdefault(sig, []).append(r)

    # м¶©л¶„н•ң мғҳн”Ңл§Ң
    scored = []
    for sig, recs in groups.items():
        if len(recs) < TUNE_MIN_SAMPLES:
            continue
        scored.append((_tune_score(recs), sig, recs))

    if not scored:
        return {}
    scored.sort(key=lambda x: x[0], reverse=True)
    best_score, best_sig, best_recs = scored[0]
    # best snapshotмқҖ лҢҖн‘ң 1к°ңлҘј мӮ¬мҡ©
    best_snap = dict(best_recs[0].get("params_snapshot", {}))
    best_snap["_score"] = round(best_score, 4)
    best_snap["_n"] = len(best_recs)
    return best_snap

def _apply_result_labels(rec: dict):
    """м¶”м Ғ кІ°кіјлҘј мөңм Ғнҷ”/нҠңлӢқм—җ м“°кё° мўӢкІҢ лқјлІЁл§Ғ(MFE/MAE/ліҙмң кё°к°„ л“ұ)."""
    try:
        entry = _safe_float(rec.get("entry_price"), 0.0)
        if entry <= 0:
            return
        max_p = _safe_float(rec.get("max_price"), entry)
        min_p = _safe_float(rec.get("min_price"), entry)
        rec["mfe_pct"] = round((max_p - entry) / entry * 100, 2)
        rec["mae_pct"] = round((min_p - entry) / entry * 100, 2)  # ліҙнҶө мқҢмҲҳ
        # ліҙмң  кё°к°„(л¶„) вҖ” detect_date/time лҳҗлҠ” log_key кё°л°ҳ
        try:
            d = str(rec.get("detect_date", ""))
            t = str(rec.get("detect_time", "00:00:00"))
            dt0 = datetime.strptime(d + t[:8], "%Y%m%d%H:%M:%S")
            d2 = str(rec.get("exit_date", ""))
            t2 = str(rec.get("exit_time", "00:00:00"))
            dt1 = datetime.strptime(d2 + t2[:8], "%Y%m%d%H:%M:%S")
            rec["hold_minutes"] = int((dt1 - dt0).total_seconds() // 60)
        except Exception:
            pass
        _sync_record_pnl_fields(rec)
        pnl = _effective_pnl_pct(rec, 0.0)
        if pnl > 0:
            rec["outcome"] = "win"
        elif pnl < 0:
            rec["outcome"] = "loss"
        else:
            rec["outcome"] = "flat"
    except Exception:
        pass


TRACK_ACTIVE_STATUSES = {"м¶”м ҒмӨ‘", "м§„мһ…мӨҖл№„"}
TRACK_EPISODE_CANDIDATE_KEEP = int(os.getenv("TRACK_EPISODE_CANDIDATE_KEEP", "12") or "12")
TRACK_ENTRY_UPDATE_HISTORY_KEEP = int(os.getenv("TRACK_ENTRY_UPDATE_HISTORY_KEEP", "8") or "8")


# [v41.85] кі м•„ м¶”м Ғ нҢҗлі„ л°Ҹ м •лҰ¬
def _is_orphan_tracking(rec: dict) -> bool:
    """entry/stop/targetмқҙ лӘЁл‘җ 0мқё 'м¶”м ҒмӨ‘' л ҲмҪ”л“ңмқём§Җ нҢҗлі„."""
    if rec.get("status") != "м¶”м ҒмӨ‘":
        return False
    return _is_empty_tracking_price_triplet(
        rec.get("entry_price", 0),
        rec.get("stop_price", 0),
        rec.get("target_price", 0),
    )


def _get_valid_tracking(data: dict) -> list:
    """signal_logм—җм„ң кі м•„/л§ҢлЈҢ мҳҲм • л ҲмҪ”л“ңлҘј м ңмҷён•ң мң нҡЁ м¶”м ҒмӨ‘ л ҲмҪ”л“ңл§Ң л°ҳнҷҳ."""
    today = datetime.now().strftime("%Y%m%d")
    out = []
    for rec in _iter_signal_log_records(data):
        if rec.get("status") != "м¶”м ҒмӨ‘":
            continue
        if _is_orphan_tracking(rec):
            continue
        if _is_tracking_display_expired(rec, today):
            continue
        out.append(rec)
    return out


def _drop_tracking_runtime_artifacts(codes: set[str]) -> None:
    normalized = set()
    for code in codes or set():
        norm = normalize_stock_code(code)
        if norm:
            normalized.add(norm)
    codes = normalized
    if not codes:
        return

    detected_changed = False
    entry_changed = False
    execution_changed = False
    try:
        with _state_lock:
            for code in list(codes):
                if _detected_stocks.pop(code, None) is not None:
                    detected_changed = True

            for key in list(_entry_watch.keys()):
                watch = _entry_watch.get(key)
                if not isinstance(watch, dict):
                    continue
                if normalize_stock_code(watch.get("code")) in codes:
                    _entry_watch.pop(key, None)
                    entry_changed = True

            for key in list(_execution_setup_watch.keys()):
                watch = _execution_setup_watch.get(key)
                if not isinstance(watch, dict):
                    continue
                if normalize_stock_code(watch.get("code")) in codes:
                    _execution_setup_watch.pop(key, None)
                    execution_changed = True
    except Exception:
        pass

    if detected_changed:
        save_carry_stocks()
    if entry_changed:
        _save_entry_watch_active()
    if execution_changed:
        _save_execution_setup_watch(force=True)

    try:
        build_next_open_watchlist(max_codes=30)
    except Exception:
        pass


def purge_orphan_tracking(notify: bool = False) -> int:
    """signal_log м „мІҙм—җм„ң кі м•„ м¶”м Ғ мў…лӘ©мқ„ мқјкҙ„ л§ҢлЈҢ мІҳлҰ¬. лҙҮ мӢңмһ‘ мӢң нҳём¶ң."""
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
    except Exception:
        return 0
    today = datetime.now().strftime("%Y%m%d")
    purged = 0
    purged_codes: set[str] = set()
    for log_key, rec in data.items():
        if not isinstance(rec, dict):
            continue
        if not _is_orphan_tracking(rec):
            continue
        elapsed = _get_tracking_elapsed_days(rec, today)
        if elapsed >= TRACK_MAX_DAYS:
            rec["status"] = TRACK_TIMEOUT_RESULT
            rec["exit_date"] = today
            rec["exit_reason"] = "кі м•„м¶”м Ғ_мһҗлҸҷл§ҢлЈҢ"
            rec["pnl_pct"] = 0.0
            purged += 1
            code = normalize_stock_code(rec.get("code"))
            if code:
                purged_codes.add(code)
            print(f"  рҹ—‘ кі м•„ м¶”м Ғ л§ҢлЈҢ: {rec.get('name', rec.get('code', log_key))} ({elapsed}мқј кІҪкіј)")
    if purged:
        try:
            _write_json_atomic(SIGNAL_LOG_FILE, data)
        except Exception:
            pass
        _drop_tracking_runtime_artifacts(purged_codes)
        if notify:
            print(f"  рҹ—‘ кі м•„ м¶”м Ғ мҙқ {purged}кұҙ мһҗлҸҷ л§ҢлЈҢ")
    return purged

def _extract_signal_detect_datetime(stock: dict | None) -> datetime:
    stock = stock or {}
    detected_at = stock.get("detected_at")
    if isinstance(detected_at, datetime):
        return detected_at
    return datetime.now()


def _build_tracking_episode_candidate(stock: dict | None, reason: str = "мӢ нҳёнҸ¬м°©") -> dict:
    stock = stock or {}
    detected_at = _extract_signal_detect_datetime(stock)
    return {
        "recorded_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "reason": str(reason or "мӢ нҳёнҸ¬м°©"),
        "detect_date": detected_at.strftime("%Y%m%d"),
        "detect_time": detected_at.strftime("%H:%M:%S"),
        "signal_type": str(stock.get("signal_type", "") or ""),
        "entry_price": safe_int(stock.get("entry_price", stock.get("price", 0)), 0),
        "stop_price": safe_int(stock.get("stop_loss", 0), 0),
        "target_price": safe_int(stock.get("target_price", 0), 0),
        "detect_price": safe_int(stock.get("price", 0), 0),
        "change_rate": safe_float(stock.get("change_rate", 0.0), 0.0),
        "volume_ratio": safe_float(stock.get("volume_ratio", 0.0), 0.0),
        "score": safe_int(stock.get("score", 0), 0),
        "grade": str(stock.get("grade", "") or ""),
    }


def _append_tracking_episode_candidate(rec: dict | None, candidate: dict | None) -> None:
    if not isinstance(rec, dict) or not isinstance(candidate, dict):
        return
    items = list(rec.get("episode_candidates") or [])
    items.append(candidate)
    keep = max(2, TRACK_EPISODE_CANDIDATE_KEEP)
    rec["episode_candidates"] = items[-keep:]
    rec["episode_candidate_count"] = len(rec["episode_candidates"])
    rec["episode_last_signal_time"] = f"{candidate.get('detect_date', '')} {candidate.get('detect_time', '')}".strip()


def _append_tracking_entry_update(rec: dict | None, old_entry: int, new_entry: int, reason: str = "мһ¬нҸ¬м°©лҢҖн‘ңм§„мһ…к°ұмӢ ") -> None:
    if not isinstance(rec, dict):
        return
    old_entry = safe_int(old_entry, 0)
    new_entry = safe_int(new_entry, 0)
    if old_entry <= 0 or new_entry <= 0 or old_entry == new_entry:
        return
    hist = list(rec.get("entry_update_history") or [])
    hist.append({
        "updated_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "reason": str(reason or "мһ¬нҸ¬м°©лҢҖн‘ңм§„мһ…к°ұмӢ "),
        "old_entry": old_entry,
        "new_entry": new_entry,
    })
    keep = max(2, TRACK_ENTRY_UPDATE_HISTORY_KEEP)
    rec["entry_update_history"] = hist[-keep:]
    rec["entry_update_count"] = len(rec["entry_update_history"])
    rec["last_entry_update_time"] = rec["entry_update_history"][-1].get("updated_at", "")


def _calc_pullback_reclaim_ratio(peak_price: int, pullback_low: int, price: int) -> float:
    peak_price = safe_int(peak_price, 0)
    pullback_low = safe_int(pullback_low, 0)
    price = safe_int(price, 0)
    if peak_price <= 0 or pullback_low <= 0 or peak_price <= pullback_low or price <= 0:
        return 0.0
    return round(max(0.0, min(1.0, (price - pullback_low) / (peak_price - pullback_low))), 3)


def _calc_resurge_entry_price(current_price: int, pullback_low: int, reclaim_ratio: float = 0.0) -> int:
    current_price = safe_int(current_price, 0)
    pullback_low = safe_int(pullback_low, 0)
    reclaim_ratio = max(0.0, min(1.0, float(reclaim_ratio or 0.0)))
    if current_price <= 0:
        return 0
    discount_pct = MID_RESURGE_ENTRY_DISCOUNT_PCT + (0.5 if reclaim_ratio >= 0.7 else 0.0)
    base_entry = _round_price_down(current_price * (1 - discount_pct / 100.0))
    if pullback_low > 0:
        floor_entry = _round_price_down(pullback_low * (1 + 0.025 + min(reclaim_ratio, 0.8) * 0.03))
        if floor_entry > 0:
            base_entry = max(base_entry, floor_entry) if base_entry > 0 else floor_entry
    if base_entry <= 0 or base_entry >= current_price:
        base_entry = _round_price_down(current_price * 0.99)
    if base_entry <= 0 or base_entry >= current_price:
        base_entry = _round_price_down(current_price)
    return int(base_entry)


def _select_representative_entry_price(prev_entry: int, next_entry: int, signal_type: str = "",
                                       detect_date: str = "", miss_count: int = 0) -> tuple[int, str]:
    prev_entry = safe_int(prev_entry, 0)
    next_entry = safe_int(next_entry, 0)
    sig_type = str(signal_type or "")
    if prev_entry <= 0:
        return next_entry, "мӢ к·ңл“ұлЎқ"
    if next_entry <= 0:
        return prev_entry, "кё°мЎҙмң м§Җ"
    if next_entry < prev_entry:
        return next_entry, "н•ҳн–Ҙк°ұмӢ "
    if next_entry > prev_entry and sig_type in NO_CHASE_ENTRY_SIGNAL_TYPES:
        if sig_type in _get_dynamic_relaxable_no_chase_signal_types():
            try:
                if detect_date:
                    elapsed = (datetime.strptime(datetime.now().strftime("%Y%m%d"), "%Y%m%d") -
                               datetime.strptime(detect_date, "%Y%m%d")).days
                else:
                    elapsed = 0
            except Exception:
                elapsed = 0
            gap_pct = (next_entry - prev_entry) / prev_entry * 100 if prev_entry else 0.0
            if elapsed >= 2 or safe_int(miss_count, 0) >= 3 or gap_pct >= 15.0:
                reason = f"кІҪкіјмҷ„нҷ”({elapsed}мқј/{safe_int(miss_count, 0)}нҡҢ/кҙҙлҰ¬{gap_pct:.0f}%)"
                return next_entry, reason
        return prev_entry, "кі м җм¶”кІ©л°©м§Җмң м§Җ"
    return next_entry, "мғҒн–Ҙк°ұмӢ " if next_entry > prev_entry else "кё°мЎҙмң м§Җ"


def _apply_entry_price_guard(stock: dict | None, prev_entry: int = 0, detect_date: str = "", miss_count: int = 0) -> tuple[int, str]:
    stock = stock if isinstance(stock, dict) else {}
    current_entry = safe_int(stock.get("entry_price", stock.get("price", 0)), 0)
    _det_date = detect_date or str(stock.get("first_detect_date", stock.get("detect_date", "")) or "")
    _miss_cnt = miss_count or safe_int(stock.get("miss_count", 0), 0)
    chosen_entry, mode = _select_representative_entry_price(
        prev_entry, current_entry, stock.get("signal_type", ""),
        detect_date=_det_date, miss_count=_miss_cnt
    )
    if chosen_entry > 0:
        stock["entry_price"] = chosen_entry
        planned_prev = safe_int(stock.get("planned_entry_price", current_entry or chosen_entry), 0)
        if planned_prev <= 0 or mode == "кі м җм¶”кІ©л°©м§Җмң м§Җ":
            stock["planned_entry_price"] = chosen_entry
        else:
            stock["planned_entry_price"] = min(planned_prev, chosen_entry)
        try:
            stop_price, target_price, stop_pct, target_pct, atr_used = calc_stop_target(stock.get("code"), chosen_entry, signal_type=stock.get("signal_type"))
            if stop_price > 0 and target_price > chosen_entry:
                stock["stop_loss"] = int(stop_price)
                stock["target_price"] = int(target_price)
                stock["stop_pct"] = float(stop_pct)
                stock["target_pct"] = float(target_pct)
                stock["atr_used"] = bool(atr_used)
        except Exception:
            pass
    stock["entry_guard_mode"] = mode
    return chosen_entry, mode


def _should_soft_allow_no_ask_liquidity(cur: dict, signal: dict | None = None) -> bool:
    signal = signal if isinstance(signal, dict) else {}
    sig_type = str(signal.get("signal_type") or "")
    if sig_type != "MID_PULLBACK":
        return False
    ask_qty = safe_int(cur.get("ask_qty", 0), 0)
    bid_qty = safe_int(cur.get("bid_qty", 0), 0)
    if ask_qty > 0:
        return False
    if bid_qty > 0 and float(cur.get("change_rate", 0.0) or 0.0) >= 29.0:
        return False
    if signal.get("entry_soft_block_allowed"):
        return True
    if signal.get("resurge_mode"):
        return True
    if signal.get("direct_news_theme"):
        return True
    return int(signal.get("score", 0) or 0) >= MID_SOFT_ALLOW_MIN_SCORE


def _enrich_mid_pullback_direct_news(signal: dict | None) -> dict:
    signal = signal if isinstance(signal, dict) else {}
    if str(signal.get("signal_type") or "") != "MID_PULLBACK":
        return signal
    if signal.get("direct_news_hit") or signal.get("direct_news_theme"):
        return signal
    code = normalize_stock_code(signal.get("code"))
    if not code:
        return signal
    name = _resolve_stock_name(code, signal.get("name", code))
    direct = _infer_direct_news_theme(code, name)
    theme = str(direct.get("theme", "") or "").strip()
    if not theme:
        return signal
    signal["direct_news_hit"] = True
    signal["direct_news_theme"] = theme
    signal["direct_news_bonus"] = int(direct.get("bonus", 0) or 0)
    sector_info = signal.get("sector_info") if isinstance(signal.get("sector_info"), dict) else {}
    if not sector_info:
        sector_info = {}
        signal["sector_info"] = sector_info
    if str(sector_info.get("theme", "") or "") in ("", "кё°нғҖм—…мў…", "unknown", "лҜёл¶„лҘҳ"):
        sector_info["theme"] = theme
        sector_info["theme_key"] = theme
        signal["sector_theme"] = theme
    matched = ", ".join((direct.get("matched") or [])[:3])
    signal.setdefault("reasons", []).append(
        f"рҹ“° м§Ғм ‘лүҙмҠӨ мҳҲмҷё н—Ҳмҡ© [{theme}] вҖ” {direct.get('reason', '')}"
        + (f" ({matched})" if matched else "")
    )
    return signal


def _should_suppress_mid_pullback_c_alert(signal: dict | None) -> bool:
    signal = signal if isinstance(signal, dict) else {}
    if str(signal.get("signal_type") or "") != "MID_PULLBACK":
        return False
    if str(signal.get("grade") or "").upper() != "C":
        return False
    if signal.get("resurge_mode"):
        return False
    if signal.get("direct_news_hit") or signal.get("direct_news_theme"):
        return False
    return True


def _tracking_active_items(data: dict | None, code: str = "") -> list[tuple[str, dict]]:
    data = data or {}
    code = normalize_stock_code(code)
    items = []
    for _k, _rec in data.items():
        if not isinstance(_rec, dict):
            continue
        if _rec.get("status") not in TRACK_ACTIVE_STATUSES:
            continue
        if code and normalize_stock_code(_rec.get("code")) != code:
            continue
        items.append((_k, _rec))
    return items


def _find_representative_tracking_log_key(data: dict | None, code: str, preferred_key: str = "") -> str:
    code = normalize_stock_code(code)
    if not code:
        return ""
    data = data or {}
    if preferred_key:
        pref = data.get(preferred_key)
        if isinstance(pref, dict) and pref.get("status") in TRACK_ACTIVE_STATUSES and normalize_stock_code(pref.get("code")) == code:
            return preferred_key
    items = _tracking_active_items(data, code)
    if not items:
        return ""
    best_key, _ = max(items, key=lambda kv: _tracking_record_sort_key(kv[1]))
    return best_key


def _merge_tracking_episode_records(data: dict | None, code: str, representative_key: str, reason: str = "лҢҖн‘ңл ҲмҪ”л“ңнҶөн•©") -> bool:
    data = data or {}
    code = normalize_stock_code(code)
    if not code or not representative_key or representative_key not in data:
        return False
    changed = False
    for _k, _rec in data.items():
        if _k == representative_key or not isinstance(_rec, dict):
            continue
        if _rec.get("status") not in TRACK_ACTIVE_STATUSES:
            continue
        if normalize_stock_code(_rec.get("code")) != code:
            continue
        _rec["status"] = "лҢҖн‘ңм§„мһ…мҠ№кі„"
        _rec["exit_reason"] = str(reason or "лҢҖн‘ңл ҲмҪ”л“ңнҶөн•©")
        _rec["pnl_pct"] = 0.0
        _rec["merged_into_log_key"] = representative_key
        _rec["episode_representative"] = False
        changed = True
    rep = data.get(representative_key)
    if isinstance(rep, dict):
        rep["episode_representative"] = True
    return changed


