# ============================================================
_overnight_state: dict = {
    "last_us_regime": "neutral",  # м§Ғм „ лҜёкөӯ көӯл©ҙ
    "last_vix":        20.0,      # м§Ғм „ VIX
    "alerted_regime":  "",        # мқҙлҜё м•ҢлҰј ліҙлӮё көӯл©ҙ
    "summary_lines":   [],        # мҳӨлІ„лӮҳмқҙнҠё мҡ”м•Ҫ (лёҢлҰ¬н•‘мҡ©)
}
try:
    _ov_boot = _load_overnight_active_state()
    _overnight_state.update({
        "last_us_regime": _ov_boot.get("last_us_regime", "neutral"),
        "last_vix": float(_ov_boot.get("last_vix", 20.0) or 20.0),
        "alerted_regime": _ov_boot.get("alerted_regime", ""),
        "summary_lines": list(_ov_boot.get("summary_lines") or [])[-10:],
    })
except Exception:
    pass

def run_overnight_monitor():
    """
    мҳӨлІ„лӮҳмқҙнҠё(20:10~07:30) мЈјкё°м Ғ мӢӨн–ү.
    лҜёкөӯ мӢңмһҘ көӯл©ҙ ліҖнҷ” к°җм§Җ вҶ’ мҰүмӢң м•ҢлҰј.
    ліҖнҷ” м—Ҷмңјл©ҙ мЎ°мҡ©нһҲ л„ҳм–ҙк°җ (мҠӨнҢё л°©м§Җ).
    """
    try:
        now_dt = _now_kst()
        # v41.60: м•јк°„ мӢңк°„ нҢҗм •мқ„ KST кё°мӨҖ мӢңк°Ғ л№„көҗлЎң көҗм •.
        # кё°мЎҙ `(now_h >= 20 and now_m >= 10)`лҠ” 21:00~23:59лҘј лҲ„лқҪмӢңмј°лӢӨ.
        in_overnight = (now_dt.time() >= dtime(20, 10)) or (now_dt.time() < dtime(7, 30))
        if not in_overnight:
            return

        persisted = _load_overnight_active_state()
        _overnight_state["last_us_regime"] = str(persisted.get("last_us_regime") or _overnight_state.get("last_us_regime", "neutral"))
        _overnight_state["last_vix"] = float(persisted.get("last_vix", _overnight_state.get("last_vix", 20.0)) or 20.0)
        _overnight_state["alerted_regime"] = str(persisted.get("alerted_regime") or _overnight_state.get("alerted_regime", ""))
        _overnight_state["summary_lines"] = list(persisted.get("summary_lines") or _overnight_state.get("summary_lines") or [])[-10:]

        us = get_us_market_signals()
        cur_regime  = us.get("us_regime", "neutral")
        cur_vix     = us.get("vix", 20.0)
        nasdaq_chg  = us.get("nasdaq_chg", 0.0)
        gap_signal  = us.get("gap_signal", "flat")
        prev_regime = _overnight_state["last_us_regime"]
        prev_vix    = _overnight_state["last_vix"]

        alerts = []

        # в”Җв”Җ көӯл©ҙ ліҖнҷ” к°җм§Җ в”Җв”Җ
        regime_rank = {"risk_on": 0, "neutral": 1, "risk_off": 2, "panic": 3}
        cur_rank    = regime_rank.get(cur_regime, 1)
        prev_rank   = regime_rank.get(prev_regime, 1)

        if cur_rank > prev_rank and cur_regime != _overnight_state["alerted_regime"]:
            _overnight_state["alerted_regime"] = cur_regime
            regime_label = {"risk_off": "рҹ”ө м•Ҫм„ёмһҘ", "panic": "рҹ”ө кёүлқҪмһҘ"}
            alerts.append(
                f"вҡ пёҸ лҜёкөӯ мӢңмһҘ көӯл©ҙ м•…нҷ”: {regime_label.get(cur_regime, cur_regime)}\n"
                f"  лӮҳмҠӨлӢҘ {nasdaq_chg:+.1f}%  VIX {cur_vix:.0f}"
            )
        elif cur_rank < prev_rank and cur_regime != _overnight_state["alerted_regime"]:
            _overnight_state["alerted_regime"] = cur_regime
            alerts.append(
                f"вң… лҜёкөӯ мӢңмһҘ көӯл©ҙ к°ңм„ : рҹ”ҙ к°•м„ёмһҘ м „нҷҳ\n"
                f"  лӮҳмҠӨлӢҘ {nasdaq_chg:+.1f}%  VIX {cur_vix:.0f}"
            )

        # в”Җв”Җ VIX кёүл“ұ лӢЁлҸ… к°җм§Җ (көӯл©ҙ ліҖнҷ” м—Ҷм–ҙлҸ„) в”Җв”Җ
        if cur_vix >= 30 and prev_vix < 30:
            alerts.append(f"рҹ”ө VIX кіөнҸ¬ кө¬к°„ м§„мһ…: {cur_vix:.0f} (мқҙм „ {prev_vix:.0f})")
        elif cur_vix >= 25 and prev_vix < 25:
            alerts.append(f"рҹҹЎ VIX л¶Ҳм•Ҳ кө¬к°„ м§„мһ…: {cur_vix:.0f}")

        # в”Җв”Җ лӮҳмҠӨлӢҘ кёүлқҪ лӢЁлҸ… к°җм§Җ в”Җв”Җ
        if nasdaq_chg <= -3.0 and prev_rank < 3:
            alerts.append(f"рҹ”ө лӮҳмҠӨлӢҘ кёүлқҪ {nasdaq_chg:+.1f}% вҖ” лӮҙмқј к°ӯн•ҳлқҪ мЈјмқҳ")
        elif nasdaq_chg >= 2.0 and prev_rank > 0:
            alerts.append(f"рҹ”ҙ лӮҳмҠӨлӢҘ к°•м„ё {nasdaq_chg:+.1f}% вҖ” лӮҙмқј к°ӯмғҒмҠ№ кё°лҢҖ")

        # в”Җв”Җ мғҒнғң м—…лҚ°мқҙнҠё в”Җв”Җ
        _overnight_state["last_us_regime"] = cur_regime
        _overnight_state["last_vix"]       = cur_vix

        # в”Җв”Җ мҡ”м•Ҫ лҲ„м Ғ (лёҢлҰ¬н•‘мҡ©) в”Җв”Җ
        ts_str = now_dt.strftime("%H:%M")
        for a in alerts:
            line = f"[{ts_str}] {a}"
            _overnight_state["summary_lines"].append(line)
            # мөңк·ј 10к°ңл§Ң мң м§Җ
            _overnight_state["summary_lines"] = _overnight_state["summary_lines"][-10:]

        _save_overnight_active_state({
            "last_us_regime": _overnight_state.get("last_us_regime", "neutral"),
            "last_vix": _overnight_state.get("last_vix", 20.0),
            "alerted_regime": _overnight_state.get("alerted_regime", ""),
            "summary_lines": list(_overnight_state.get("summary_lines") or [])[-10:],
        })

        # в”Җв”Җ м§Җм •н•ҷ мқҙлІӨнҠё мҳӨлІ„лӮҳмқҙнҠё мІҙнҒ¬ в”Җв”Җ
        try:
            headlines_by_src = _fetch_multi_source_headlines()
            if headlines_by_src:
                geo = analyze_geopolitical_event(headlines_by_src)
                if geo.get("detected") and geo.get("uncertainty") in ("high", "mid"):
                    alerts.append(
                        f"рҹҢҚ м§Җм •н•ҷ мқҙлІӨнҠё: {geo.get('summary','')}\n"
                        f"  кҙҖл Ё м„№н„°: {', '.join(geo.get('sectors',[]))}"
                    )
                # v41.78 #2: м•јк°„ лүҙмҠӨ вҶ’ мқҙлІӨнҠё нӮӨмӣҢл“ң м¶”м¶ң вҶ’ мӣҢм№ҳлҰ¬мҠӨнҠё мғқм„ұ
                all_headlines = [h for hl in headlines_by_src.values() for h in hl]
                if all_headlines:
                    detected_events = _extract_overnight_event_keywords(all_headlines)
                    if detected_events:
                        _build_overnight_watchlist(detected_events)
                        print(f"  рҹҢҷ overnightвҶ’м•јк°„ мқҙлІӨнҠё {len(detected_events)}кұҙ вҶ’ мӣҢм№ҳлҰ¬мҠӨнҠё к°ұмӢ ")
        except Exception: pass

        # в”Җв”Җ м•ҢлҰј л°ңмҶЎ в”Җв”Җ
        # v38.4: кіөнңҙмқј/мЈјл§җм—җлҠ” лӮҙл¶Җ мҡ”м•Ҫл§Ң лҲ„м Ғ, мӮ¬мҡ©мһҗ м•ҢлҰј м°ЁлӢЁ (кё°ліёмҲҳм№ҷ #16)
        if alerts and not is_holiday():
            gap_emoji = {"gap_up": "в¬ҶпёҸ к°ӯмғҒмҠ№", "flat": "вһЎпёҸ к°ӯ м—ҶмқҢ", "gap_down": "в¬ҮпёҸ к°ӯн•ҳлқҪ"}
            msg = (f"рҹҢҷ <b>мҳӨлІ„лӮҳмқҙнҠё м•ҢлҰј</b>  {ts_str}\n"
                   f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                   + "\n".join(alerts) +
                   f"\n\nлӮҙмқј к°ӯ мҳҲмёЎ: {gap_emoji.get(gap_signal, 'вһЎпёҸ')}")
            # v38.6-K: м¶”к°Җ м§Җн‘ң н‘ңмӢң
            _gold = us.get("gold_chg", 0)
            _oil = us.get("oil_chg", 0)
            _tnx = us.get("tnx", 0)
            _sp = us.get("sp500_chg", 0)
            extra = []
            if _gold: extra.append(f"кёҲ{_gold:+.1f}%")
            if _oil: extra.append(f"мң к°Җ{_oil:+.1f}%")
            if _tnx: extra.append(f"10Y{_tnx:.2f}%")
            if _sp: extra.append(f"S&P{_sp:+.1f}%")
            if extra:
                msg += f"\nрҹ“Ҡ {' '.join(extra)}"
            print("рҹҢҷ мҳӨлІ„лӮҳмқҙнҠё м•ҢлҰј к°җм§Җ вҖ” н…”л Ҳк·ёлһЁ л°ңмҶЎ л№„нҷңм„ұнҷ”")
        elif alerts:
            print(f"  рҹҢҷ мҳӨлІ„лӮҳмқҙнҠё(лҢҖкё°лӘЁл“ң): {len(alerts)}кұҙ вҖ” лӮҙл¶Җ м ҖмһҘл§Ң")

    except Exception as e:
        _log_error("run_overnight_monitor", e)

def _send_pending_result_reminder():
    """
    мһҘ л§Ҳк°җ мӢң м¶”м Ғ мӨ‘мқё мў…лӘ© мӨ‘ мҳӨлҠҳ мӢ нҳёмқҙл©ҙм„ң м•„м§Ғ кІ°кіј лҜёмһ…л Ҙмқё кІғл“Өмқ„
    н…”л Ҳк·ёлһЁмңјлЎң м•Ңл ӨмӨҢ.

    вҖ» мһ…л Ҙн•ҳм§Җ м•Ҡмңјл©ҙ?
      - лӘ©н‘ңк°Җ/мҶҗм Ҳк°Җ лҸ„лӢ¬ мӢң мһҗлҸҷ нҷ•м • (кі„мҶҚ к°җмӢң)
      - TRACK_MAX_DAYS(5мқј) кІҪкіј мӢң к·ёлӮ  мў…к°Җ кё°мӨҖмңјлЎң мһҗлҸҷ кё°лЎқ
      - NXT мғҒмһҘ мў…лӘ©мқҖ 20:00к№Ңм§Җ мһҗлҸҷ к°җмӢң нӣ„ кё°лЎқ
    """
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception: return

        today   = datetime.now().strftime("%Y%m%d")
        pending = [
            v for v in data.values()
            if v.get("status") == "м¶”м ҒмӨ‘"
            and not _is_orphan_tracking(v)
            and v.get("detect_date") == today
        ]
        if not pending:
            return

        # NXT мҡҙмҳҒ мӨ‘мқҙл©ҙ NXT л§Ҳк°җ нӣ„ л°ңмҶЎ (20:05), KRXл§Ңмқҙл©ҙ 15:30 нӣ„ л°ңмҶЎ
        # мқҙ н•ЁмҲҳлҠ” л‘җ мӢңм җ лӘЁл‘җм—җм„ң нҳём¶ңлҗҳлҜҖлЎң мӨ‘ліө л°©м§Җ н”Ңлһҳк·ё мӮ¬мҡ©
        reminder_key = f"reminder_{today}"
        if reminder_key in _tracking_notified:
            return
        _tracking_notified.add(reminder_key)

        nxt_running = is_nxt_open()
        timing_note = ("рҹ“Ў NXT л§Ҳк°җ(20:00) нӣ„м—җлҸ„ NXT мғҒмһҘ мў…лӘ©мқҖ мһҗлҸҷ к°җмӢңлҗ©лӢҲлӢӨ."
                       if nxt_running else
                       "рҹ’Ў лӮҙмқјлҸ„ мһҗлҸҷ м¶”м Ғлҗ©лӢҲлӢӨ. (мөңлҢҖ 5мқј)")

        msg = (f"вңҚпёҸ <b>мҳӨлҠҳ кІ°кіј лҜёмһ…л Ҙ мў…лӘ©</b>  ({len(pending)}кұҙ)\n"
               f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
               f"мӢӨм ң л§ӨлҸ„н•ҳм…ЁлӢӨл©ҙ /result лЎң мһ…л Ҙн•ҙмЈјм„ёмҡ”.\n"
               f"мһ…л Ҙ м•Ҳ н•ҳм…”лҸ„ лҙҮмқҙ мһҗлҸҷ м¶”м Ғн•©лӢҲлӢӨ.\n\n")

        sig_labels = {
            "UPPER_LIMIT":"мғҒн•ңк°Җ","NEAR_UPPER":"мғҒн•ңк°Җк·јм ‘","SURGE":"кёүл“ұ",
            "EARLY_DETECT":"мЎ°кё°нҸ¬м°©","MID_PULLBACK":"лҲҢлҰјлӘ©",
            "ENTRY_POINT":"лҲҢлҰјлӘ©","STRONG_BUY":"к°•л Ҙл§ӨмҲҳ",
        }
        for v in pending:
            entry = v.get("entry_price", 0)
            code  = v.get("code", "")
            # NXT лЁјм Җ, м—Ҷмңјл©ҙ KRX нҳ„мһ¬к°Җ
            try:
                if is_nxt_open() and is_nxt_listed(code):
                    cur_p = get_nxt_stock_price(code).get("price", 0) or get_stock_price(code).get("price", 0)
                else:
                    cur_p = get_stock_price(code).get("price", 0)
                cur_pnl = round((cur_p - entry) / entry * 100, 1) if entry and cur_p else 0
                pnl_emoji = "рҹ”ҙ" if cur_pnl >= 0 else "рҹ”ө"
                cur_str = f"  нҳ„мһ¬ {cur_p:,}мӣҗ  {pnl_emoji}{cur_pnl:+.1f}%"
            except Exception:
                cur_str = ""
            sig = sig_labels.get(v.get("signal_type",""), "")
            msg += (f"вҖў <b>{v['name']}</b>  {sig}\n"
                    f"  м§„мһ… {entry:,}мӣҗ  мҶҗм Ҳ {v.get('stop_price',0):,}  лӘ©н‘ң {v.get('target_price',0):,}\n"
                    f"{cur_str}\n"
                    f"  вҶ’ <code>/result {v['name']} +мҲҳмқөлҘ </code>\n\n")

        msg += f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n{timing_note}"
        send(msg)

    except Exception as e:
        print(f"вҡ пёҸ кІ°кіј мһ…л Ҙ м•ҢлҰј мҳӨлҘҳ: {e}")

def track_signal_results():
    """
    м¶”м Ғ мӨ‘мқё лӘЁл“  мӢ нҳёмқҳ нҳ„мһ¬к°ҖлҘј мЎ°нҡҢн•ҙм„ң
    в‘  лӘ©н‘ңк°Җ лҸ„лӢ¬ вҶ’ мҲҳмқө нҷ•м •
    в‘Ў мҶҗм Ҳк°Җ лҸ„лӢ¬ вҶ’ мҶҗмӢӨ нҷ•м •
    в‘ў Nмқј кІҪкіј   вҶ’ нҳ„мһ¬к°Җ кё°мӨҖ кІ°кіј кё°лЎқ
    кІ°кіј нҷ•м • мӢң н…”л Ҳк·ёлһЁ м•ҢлҰј л°ңмҶЎ
    """
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception:
            return

        updated = False
        today = datetime.now().strftime("%Y%m%d")

        active_codes = []
        for _k, _rec in data.items():
            if not isinstance(_rec, dict):
                continue
            if _rec.get("status") not in TRACK_ACTIVE_STATUSES:
                continue
            _code = normalize_stock_code(_rec.get("code"))
            if _code and _code not in active_codes:
                active_codes.append(_code)
        for _code in active_codes:
            rep_key = _find_representative_tracking_log_key(data, _code)
            if rep_key and _merge_tracking_episode_records(data, _code, rep_key, reason="м¶”м ҒмӨ‘_лҢҖн‘ңл ҲмҪ”л“ңнҶөн•©"):
                updated = True

        for log_key, rec in data.items():
            if rec.get("status") != "м¶”м ҒмӨ‘":
                continue
            if log_key in _tracking_notified:
                continue
            rec["episode_representative"] = True

            code         = rec["code"]
            entry        = rec.get("entry_price", 0)
            stop         = rec.get("stop_price",  0)
            target       = rec.get("target_price", 0)
            detect_date  = rec.get("detect_date", today)

            # [v41.85] кі м•„ м¶”м Ғ мў…лӘ© мһҗлҸҷ л§ҢлЈҢ: entry/stop/targetмқҙ м—Ҷмңјл©ҙ нҢҗм • л¶Ҳк°Җ
            # вҶ’ TRACK_MAX_DAYS кІҪкіј мӢң "мӢңк°„мҙҲкіј"лЎң к°•м ң мў…лЈҢ, лҜёкІҪкіј мӢң skip
            if not entry or not stop or not target:
                try:
                    elapsed_orphan = (datetime.strptime(today, "%Y%m%d") -
                                     datetime.strptime(detect_date, "%Y%m%d")).days
                except Exception:
                    elapsed_orphan = 0
                if elapsed_orphan >= TRACK_MAX_DAYS:
                    rec["status"] = TRACK_TIMEOUT_RESULT
                    rec["exit_date"] = today
                    rec["exit_reason"] = "кі м•„м¶”м Ғ_мһҗлҸҷл§ҢлЈҢ"
                    rec["pnl_pct"] = 0.0
                    _tracking_notified.add(log_key)
                    updated = True
                    print(f"  рҹ—‘ кі м•„ м¶”м Ғ мһҗлҸҷ л§ҢлЈҢ: {rec.get('name', code)} (entry/stop/target лҜём„Өм •, {elapsed_orphan}мқј кІҪкіј)")
                continue

            # кІҪкіј мқјмҲҳ кі„мӮ°
            try:
                elapsed_days = (datetime.strptime(today, "%Y%m%d") -
                                datetime.strptime(detect_date, "%Y%m%d")).days
            except Exception:
                elapsed_days = 0

            # нҳ„мһ¬к°Җ мЎ°нҡҢ вҖ” KRX мһҘмӨ‘мқҙл©ҙ KRX, л§Ҳк°җ нӣ„л©ҙ NXT мӮ¬мҡ©
            try:
                if is_market_open():
                    cur   = get_stock_price(code)
                    price = cur.get("price", 0)
                elif is_nxt_open():
                    # KRX л§Ҳк°җ нӣ„ NXT к°ҖкІ©мңјлЎң м¶”м Ғ (15:30~20:00)
                    nxt_cur = get_nxt_stock_price(code)
                    price   = nxt_cur.get("price", 0)
                    if not price:          # NXT кұ°лһҳ м—Ҷмңјл©ҙ KRX мў…к°Җ
                        cur   = get_stock_price(code)
                        price = cur.get("price", 0)
                else:
                    continue   # лӘЁл“  мӢңмһҘ л§Ҳк°җ
                if not price: continue
            except Exception:
                continue

            # мөңкі к°ҖВ·мөңм Җк°Җ м—…лҚ°мқҙнҠё (MDD кі„мӮ°мҡ©)
            rec["max_price"] = max(rec.get("max_price", price), price)
            rec["min_price"] = min(rec.get("min_price", price), price)
            updated = True

            # в”Җв”Җ вҳ… ліҙмң  мў…лӘ© лүҙмҠӨ/кіөмӢң мӢӨмӢңк°„ м•…мһ¬ к°җмӢң в”Җв”Җ
            _now_ts = time.time()
            _last_check = _carry_news_watch.get(code, 0)
            if _now_ts - _last_check >= 1800:  # 30л¶„л§ҲлӢӨ мІҙнҒ¬
                _carry_news_watch[code] = _now_ts
                _rec_name = rec.get("name", code)
                pnl_now   = round((price - entry) / entry * 100, 2) if entry else 0

                # DART мң„н—ҳ кіөмӢң мІҙнҒ¬
                try:
                    _d = check_dart_risk(code)
                    if _d["is_risk"]:
                        _dk = f"{log_key}_dart_exit"
                        if _dk not in _tracking_notified:
                            _tracking_notified.add(_dk)
                            _msg = (
                                "рҹҡЁ <b>[ліҙмң  мў…лӘ© м•…мһ¬ кіөмӢң к°җм§Җ]</b>\n"
                                "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                                f"рҹ”ө <b>{_rec_name}</b>  <code>{code}</code>\n"
                                "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                                f"рҹ“Ӣ кіөмӢң: {_d['title']}\n"
                                "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                                f"рҹ’° нҳ„мһ¬к°Җ: <b>{price:,}мӣҗ</b>  ({pnl_now:+.1f}%)\n"
                                "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                                "вҡЎ <b>мҰүмӢң л§ӨлҸ„ кІҖнҶ  к¶ҢмһҘ</b>\n"
                                f"рҹ’Ў /result {code} лЎң кІ°кіј кё°лЎқ"
                            )
                            send_with_chart_buttons(_msg, code, _rec_name)
                            print(f"  рҹҡЁ ліҙмң мў…лӘ© кіөмӢңм•…мһ¬: {_rec_name} вҖ” {_d['title']}")
                except Exception as _e:
                    print(f"  вҡ пёҸ ліҙмң мў…лӘ© DARTмІҙнҒ¬мҳӨлҘҳ: {_e}")

                # лүҙмҠӨ мӢ¬мёө к°җм„ұ мІҙнҒ¬ (analyze_news_deep нҷңмҡ©)
                try:
                    _articles = fetch_news_for_stock(code, _rec_name)
                    if _articles:
                        _deep = analyze_news_deep(_articles, _rec_name, code)
                        _nadj = int(_deep.get("score_adj", 0) or 0)
                        _verd = _deep.get("verdict", "мӨ‘лҰҪ")
                        if _nadj <= -40:
                            _nk = f"{log_key}_news_exit"
                            if _nk not in _tracking_notified:
                                _tracking_notified.add(_nk)
                                _rps = "\n".join(
                                    f"  вҡ пёҸ {rp}"
                                    for rp in _deep.get("risk_points", [])[:3]
                                )
                                _msg2 = (
                                    "вҡ пёҸ <b>[ліҙмң  мў…лӘ© л¶Җм • лүҙмҠӨ к°җм§Җ]</b>\n"
                                    "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                                    f"рҹҹЎ <b>{_rec_name}</b>  <code>{code}</code>\n"
                                    "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                                    f"рҹ“° лүҙмҠӨ нҢҗлӢЁ: {_verd}  ({_nadj:+d}м җ)\n"
                                    f"{_rps}\n"
                                    "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                                    f"рҹ’° нҳ„мһ¬к°Җ: <b>{price:,}мӣҗ</b>  ({pnl_now:+.1f}%)\n"
                                    "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                                    "рҹ’Ў мҶҗм Ҳк°Җ мһ¬нҷ•мқё нӣ„ л§ӨлҸ„ нҢҗлӢЁ к¶ҢмһҘ\n"
                                    f"/result {code} лЎң кІ°кіј кё°лЎқ"
                                )
                                send_with_chart_buttons(_msg2, code, _rec_name)
                                print(f"  вҡ пёҸ ліҙмң мў…лӘ© л¶Җм •лүҙмҠӨ: {_rec_name} к°җм„ұм җмҲҳ={_nadj}")
                except Exception as _e:
                    print(f"  вҡ пёҸ ліҙмң мў…лӘ© лүҙмҠӨмІҙнҒ¬мҳӨлҘҳ: {_e}")

            # в”Җв”Җ л¶„н•  мІӯмӮ° к°Җмқҙл“ң (лӘ©н‘ңк°Җ лҸ„лӢ¬ м „ мӨ‘к°„ м•ҢлҰј) в”Җв”Җ
            if entry and target and _should_send_partial_exit_guide(rec):
                pnl_now  = (price - entry) / entry * 100
                half_pct = (target - entry) / entry * 100 / 2   # лӘ©н‘ңмқҳ м Ҳл°ҳ
                partial_key = f"{log_key}_partial"
                _partial_min = calc_partial_exit_min_pct(code, price)
                if (pnl_now >= half_pct
                        and partial_key not in _tracking_notified
                        and half_pct > _partial_min
                        and (time.time() - _partial_exit_last_ts.get(code, 0) >= PARTIAL_EXIT_GUIDE_COOLDOWN_MIN * 60)):
                    _tracking_notified.add(partial_key)
                    _partial_exit_last_ts[code] = time.time()
                    inv_info = ""
                    try:
                        inv   = get_investor_trend(code)
                        f_net = inv.get("foreign_net", 0)
                        i_net = inv.get("institution_net", 0)
                        if f_net > 0 and i_net > 0:
                            inv_info = "\n  вң… мҷёкөӯмқё+кё°кҙҖ мҲңл§ӨмҲҳ вҖ” нҷҖл”© мҡ°нҳём Ғ"
                        elif f_net < 0 or i_net < 0:
                            inv_info = "\n  вҡ пёҸ мҷёкөӯмқё/кё°кҙҖ л§ӨлҸ„ м „нҷҳ вҖ” мқөм Ҳ кі л Ө"
                    except Exception: pass
                    target_pct = ((target - entry) / entry * 100) if entry else 0
                    target_progress_pct = (pnl_now / target_pct * 100) if target_pct else 0
                    display_rec = dict(rec); display_rec['log_key'] = log_key
                    entry_hit_line = _build_entry_hit_line(entry, display_rec, include_hit_price=False, include_hit_time=True)
                    send_with_chart_buttons(
                        f"рҹ’Ў <b>[л¶„н•  мІӯмӮ° нғҖмқҙл°Қ]</b>\n"
                        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                        f"рҹ”ҙ <b>{rec['name']}</b>  <code>{code}</code>\n"
                        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                        f"нҳ„мһ¬ <b>+{pnl_now:.1f}%</b>  (лӘ©н‘ңмқҳ {target_progress_pct:.0f}%)\n"
                        f"рҹ“Ң л¶„н•  кё°мӨҖ: <b>+{half_pct:.1f}% мқҙмғҒ</b> лӢ¬м„ұ мӢң 1м°Ё мқөм Ҳ кІҖнҶ \n"
                        f"вң… нҳ„мһ¬ мғҒнғң: кё°мӨҖ лҢҖл№„ <b>{pnl_now-half_pct:+.1f}%p</b>\n"
                        f"рҹ“Қ нҳ„мһ¬к°Җ: <b>{price:,}мӣҗ</b>\n"
                        f"{entry_hit_line}\n"
                        f"рҹҸҶ лӘ©н‘ңк°Җ: <b>{target:,}мӣҗ</b>  (+{target_pct:.1f}%)\n"
                        f"{inv_info}\n"
                        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                        f"рҹ’Ў м Ҳл°ҳ мқөм Ҳ нӣ„ лӮҳлЁём§Җ нҷҖл”© м „лһө кі л Ө",
                        code, rec["name"]
                    )
                    print(f"  рҹ’Ў л¶„н•  мІӯмӮ° к°Җмқҙл“ң: {rec['name']} +{pnl_now:.1f}%")

            # в”Җв”Җ в‘Ў нҠёл Ҳмқјл§Ғ мҠӨнғ‘ в”Җв”Җ
            # лӘ©н‘ңк°Җ лҸ„лӢ¬ нӣ„ мөңкі к°Җм—җм„ң -3% н•ҳлқҪн•ҳл©ҙ мһҗлҸҷ мІӯмӮ° (лҚ” лЁ№кё°)
            trailing_key = f"{log_key}_trailing"
            if rec.get("trailing_active"):
                trail_stop = rec.get("trailing_stop", target)
                if price > rec.get("max_price", price):
                    # мөңкі к°Җ к°ұмӢ  вҶ’ ATR+көӯл©ҙ кё°л°ҳ нҠёл Ҳмқјл§Ғ мҠӨнғ‘ лҒҢм–ҙмҳ¬лҰ¬кё°
                    new_trail = calc_trailing_stop(code, price)
                    if new_trail > trail_stop:
                        rec["trailing_stop"] = new_trail

                # в”Җв”Җ мҲҳкёү мқҙнғҲ кІҪкі  (м¶”м Ғ мӨ‘) в”Җв”Җ
                try:
                    fp_key = f"force_warn_{code}"
                    if fp_key not in _tracking_notified:
                        fp = detect_force_pattern(code, name)
                        if fp.get("risk_flag"):
                            _tracking_notified.add(fp_key)
                            out_patterns = [p for p in fp.get("patterns", [])
                                            if p.get("score_adj", 0) < 0]
                            out_lines = ""
                            for op in out_patterns[:3]:
                                ce = {"high":"рҹ”ө","mid":"рҹҹЎ","low":""}.get(op.get("confidence","low"),"")
                                ck = {"high":"мӢ лў°лҶ’мқҢ","mid":"м°ёкі мҡ©"}.get(op.get("confidence",""),"м°ёкі мҡ©")
                                out_lines += f"  {ce} {op['label']} [{ck}]\n  в”” {op['detail']}\n"
                            send(
                                f"рҹ”ө <b>[мҲҳкёү мқҙнғҲ кІҪкі ]  {name}</b>\n"
                                f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                                f"{out_lines}"
                                f"нҳ„мһ¬к°Җ: {price:,}мӣҗ  ({pnl_now:+.1f}%)\n"
                                f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                                f"вҡ пёҸ нҶөкі„м Ғ нҢЁн„ҙ к°җм§Җ вҖ” нҷ•мҰқ м•„лӢҳ, мқөм Ҳ/мҶҗм Ҳ м§Ғм ‘ нҢҗлӢЁ н•„мҡ”"
                            )
                except Exception:
                    pass

        # в”Җв”Җ н…Ңл§Ҳ м•Ҫм„ё м „нҷҳ кІҪкі  (м¶”м Ғ мӨ‘) в”Җв”Җ
                try:
                    _rot      = detect_theme_rotation()
                    _si       = rec.get("sector_info") or {}
                    _tkey     = _si.get("theme", "") or _si.get("theme_key", "")
                    _weak_now = [k for k, v in _rot.get("weak", [])]
                    _theme_warn_key = f"theme_warn_{code}"
                    if (_tkey and _tkey in _weak_now
                            and _theme_warn_key not in _tracking_notified
                            and pnl_now > 0):
                        _tracking_notified.add(_theme_warn_key)
                        t_chg = _rot.get("themes", {}).get(_tkey, 0)
                        send_with_chart_buttons(
                            f"рҹ”„ <b>[{name}] н…Ңл§Ҳ м•Ҫм„ё м „нҷҳ кІҪкі </b>\n"
                            f"  [{_tkey}] нҳ„мһ¬ {t_chg:+.1f}% вҖ” н…Ңл§Ҳ мӢқлҠ” мӨ‘\n"
                            f"  нҳ„мһ¬ мҲҳмқө {pnl_now:+.1f}% вҖ” мқөм Ҳ кі л Ө к¶ҢмһҘ",
                            code, name
                        )
                except Exception: pass

                # в”Җв”Җ мӢӨмӢңк°„ мҳӨлІ„лӮҳмқҙнҠё мң„н—ҳлҸ„ кёүл“ұ мӢң мҰүмӢң м•ҢлҰј в”Җв”Җ
                try:
                    _risk_key = f"overnight_risk_{code}"
                    if _risk_key not in _tracking_notified:
                        _risk = calc_overnight_risk(code, name, entry, pnl_now)
                        if _risk["level"] == "high":
                            _tracking_notified.add(_risk_key)
                            send_with_chart_buttons(
                                f"рҹ”ө <b>[{name}] мҳӨлІ„лӮҳмқҙнҠё мң„н—ҳ кёҙкёү м•ҢлҰј</b>\n"
                                f"  {_risk['reason']}\n"
                                f"  нҳ„мһ¬ {pnl_now:+.1f}% вҖ” л§Ҳк°җ м „ л§ӨлҸ„ кі л Ө",
                                code, name
                            )
                except Exception: pass

                if price <= rec["trailing_stop"]:
                    exit_reason = "нҠёл Ҳмқјл§ҒмҠӨнғ‘"
                    exit_price  = price
                    gross_pnl_pct = round((exit_price - entry) / entry * 100, 2) if entry else 0
                    net_pnl_pct   = _calc_net_pnl_pct(gross_pnl_pct, rec.get("round_trip_cost_pct"))
                    pnl_pct       = net_pnl_pct
                    status        = "мҲҳмқө" if net_pnl_pct > 0 else ("мҶҗмӢӨ" if net_pnl_pct < 0 else "ліём „")
                    rec["status"]      = status
                    rec["exit_price"]  = exit_price
                    rec["current_price"] = price  # v39.3-#6
                    rec["exit_date"]   = today
                    rec["exit_time"]   = datetime.now().strftime("%H:%M:%S")
                    rec["gross_pnl_pct"] = gross_pnl_pct
                    rec["net_pnl_pct"] = net_pnl_pct
                    rec["round_trip_cost_pct"] = round(ROUND_TRIP_COST_PCT, 4)
                    rec["pnl_pct"]     = net_pnl_pct
                    rec["exit_reason"] = exit_reason
                    _apply_result_labels(rec)
                    _tracking_notified.add(log_key)
                    updated = True
                    _send_tracking_result(rec, log_key=log_key)
                    print(f"  рҹ“Ҡ нҠёл Ҳмқјл§Ғ мІӯмӮ°: {rec['name']} {pnl_pct:+.1f}%")
                    continue

            # в”Җв”Җ кІ°кіј нҢҗм • в”Җв”Җ
            exit_reason = None
            exit_price  = price

            if price >= target:
                # лӘ©н‘ңк°Җ лҸ„лӢ¬ вҶ’ нҠёл Ҳмқјл§Ғ мҠӨнғ‘ лӘЁл“ң м „нҷҳ (л°”лЎң мІӯмӮ° м•Ҳ н•Ё)
                if not rec.get("trailing_active"):
                    rec["trailing_active"] = True
                    rec["trailing_stop"]   = calc_trailing_stop(code, price)
                    updated = True
                    if trailing_key not in _tracking_notified:
                        display_rec = dict(rec); display_rec['log_key'] = log_key
                        if not _is_representative_tracking_record(data, log_key, display_rec):
                            _tracking_notified.add(f"{trailing_key}_suppressed_non_repr")
                            print(f"  рҹ”Ү нҠёл Ҳмқјл§ҒлӘЁл“ң л©”мӢңм§Җ м–өм ң(лҢҖн‘ңл ҲмҪ”л“ң м•„лӢҳ): {rec.get('name', code)} {log_key}")
                        elif _should_send_trailing_mode_message(display_rec):
                            _tracking_notified.add(trailing_key)
                            entry_hit_line = _build_entry_hit_line(entry, display_rec, include_hit_price=True, include_hit_time=True)
                            send_with_chart_buttons(
                                f"рҹҺҜ <b>[лӘ©н‘ңк°Җ лҸ„лӢ¬ вҶ’ ліҙмң  мң м§ҖВ·нҠёл Ҳмқјл§Ғ]</b>\n"
                                f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                                f"рҹ”ҙ <b>{rec['name']}</b>  <code>{code}</code>\n"
                                f"{entry_hit_line}\n"
                                f"нҳ„мһ¬к°Җ <b>{price:,}мӣҗ</b>  лӘ©н‘ңк°Җ {target:,}мӣҗ\n"
                                f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                                f"вң… м§ҖкёҲмқҖ <b>л§ӨлҸ„ м§ҖмӢңк°Җ м•„лӢҲлқј ліҙмң  мң м§Җ кө¬к°„</b>мһ…лӢҲлӢӨ\n"
                                f"рҹ“Ҳ мһ”лҹүмқҖ м¶”к°Җ мғҒмҠ№мқ„ м¶”м Ғн•©лӢҲлӢӨ\n"
                                f"рҹ“ү кі м җ лҢҖл№„ -3% н•ҳлқҪ мӢң <b>мөңмў… мІӯмӮ°</b>",
                                code, rec["name"]
                            )
                        else:
                            _tracking_notified.add(f"{trailing_key}_suppressed_no_entry_hit")
                            print(f"  рҹ”Ү нҠёл Ҳмқјл§ҒлӘЁл“ң л©”мӢңм§Җ м–өм ң(лҸ„лӢ¬л©”нғҖ м—ҶмқҢ): {rec.get('name', code)} {log_key}")
                continue   # нҠёл Ҳмқјл§Ғ лӘЁл“ңлЎң кі„мҶҚ м¶”м Ғ
            elif price <= stop:
                exit_reason = "мҶҗм Ҳк°Җ"
            elif elapsed_days >= TRACK_MAX_DAYS:
                exit_reason = TRACK_TIMEOUT_RESULT

            if not exit_reason:
                continue   # м•„м§Ғ м¶”м Ғ мӨ‘

            # в”Җв”Җ мқҙлЎ  мҲҳмқөлҘ  кі„мӮ° (лҙҮ н•ҷмҠөмҡ©) в”Җв”Җ
            gross_pnl_pct = round((exit_price - entry) / entry * 100, 2) if entry else 0
            net_pnl_pct   = _calc_net_pnl_pct(gross_pnl_pct, rec.get("round_trip_cost_pct"))
            pnl_pct       = net_pnl_pct
            status        = "мҲҳмқө" if net_pnl_pct > 0 else ("мҶҗмӢӨ" if net_pnl_pct < 0 else "ліём „")

            # мқҙлЎ  кІ°кіј м ҖмһҘ (н•ӯмғҒ)
            rec["status"]      = status
            rec["exit_price"]  = exit_price
            rec["current_price"] = price  # v39.3-#6
            rec["exit_date"]   = today
            rec["exit_time"]   = datetime.now().strftime("%H:%M:%S")
            rec["gross_pnl_pct"] = gross_pnl_pct
            rec["net_pnl_pct"] = net_pnl_pct
            rec["round_trip_cost_pct"] = round(ROUND_TRIP_COST_PCT, 4)
            rec["pnl_pct"]     = net_pnl_pct   # net кё°мӨҖ мқҙлЎ  мҲҳмқөлҘ 
            rec["exit_reason"] = exit_reason

            # мӢӨм ң м§„мһ… м—¬л¶Җк°Җ None(лҜёнҷ•мқё)мқё кІҪмҡ° вҶ’ м§„мһ… нҷ•мқё мҡ”мІӯ м•ҢлҰј
            # v40.5: кё°ліёмқҖ мһҗлҸҷ л°ңмҶЎ OFF. н•„мҡ” мӢң нҷҳкІҪліҖмҲҳлЎңл§Ң нҷңм„ұнҷ”.
            if ACTUAL_ENTRY_CONFIRM_ENABLED and rec.get("actual_entry") is None and exit_reason != TRACK_TIMEOUT_RESULT:
                _request_actual_entry_confirm(rec)

            _tracking_notified.add(log_key)

            # в”Җв”Җ v39.3-#2: ETF/л ҲлІ„лҰ¬м§Җ м¶”м ҒкІ°кіјлҠ” лӮҙл¶Җ кё°лЎқл§Ң, мӮ¬мҡ©мһҗ м•ҢлҰј X в”Җв”Җ
            if not is_trade_candidate_name(rec.get("name", "")):
                print(f"  рҹ“Ҡ м¶”м Ғ мҷ„лЈҢ(лӮҙл¶Җ): {rec['name']} {pnl_pct:+.1f}% ({exit_reason}) [мғҒн’ҲвҶ’м•ҢлҰјмғқлһө]")
            else:
                # в”Җв”Җ v39.3-#3: лҸҷмқј мў…лӘ© мӨ‘ліө л°ңмҶЎ л°©м§Җ (code кё°мӨҖ) в”Җв”Җ
                _dup_key = f"result_{code}_{rec.get('detect_date','')}"
                if _dup_key not in _tracking_notified:
                    _tracking_notified.add(_dup_key)
                    _send_tracking_result(rec, log_key=log_key)
                    print(f"  рҹ“Ҡ м¶”м Ғ мҷ„лЈҢ: {rec['name']} {pnl_pct:+.1f}% ({exit_reason}) [мқҙлЎ ]")
                else:
                    print(f"  рҹ“Ҡ м¶”м Ғ мҷ„лЈҢ(мӨ‘ліөмғқлһө): {rec['name']} {pnl_pct:+.1f}%")

            # м—°мҶҚ мҶҗм Ҳ м№ҙмҡҙн„° м—…лҚ°мқҙнҠё (кёҙкёү нҠңлӢқмҡ©)
            global _consecutive_loss_count, _consecutive_win_count  # v39.3-B1: global м¶”к°Җ
            if pnl_pct <= 0:
                _consecutive_loss_count += 1
                _consecutive_win_count  = 0   # мҶҗмӢӨ мӢң м—°мҶҚ мҲҳмқө м№ҙмҡҙн„° лҰ¬м…Ӣ
                if _consecutive_loss_count >= EMERGENCY_TUNE_THRESHOLD:
                    print(f"  рҹҡЁ м—°мҶҚ мҶҗм Ҳ {_consecutive_loss_count}нҡҢ вҶ’ кёҙкёү нҠңлӢқ нҸүк°Җ")
                    auto_tune(notify=True)
            else:
                if _consecutive_loss_count >= EMERGENCY_TUNE_THRESHOLD:
                    _clear_emergency_tune_state("win_recovered")
                _consecutive_loss_count = 0
                _consecutive_win_count  += 1
                # в‘ў м—°мҶҚ мҲҳмқө кіөкІ© лӘЁл“ң
                if _consecutive_win_count >= WIN_STREAK_THRESHOLD:
                    old_n = _dynamic["min_score_normal"]
                    old_s = _dynamic["min_score_strict"]
                    if old_n > 50:
                        _dynamic["min_score_normal"] = max(old_n - 3, 50)
                        _dynamic["min_score_strict"] = max(old_s - 3, 60)
                        print(f"  рҹ”Ҙ м—°мҶҚ мҲҳмқө {_consecutive_win_count}нҡҢ вҶ’ кіөкІ© лӘЁл“ң: мөңмҶҢм җмҲҳ {old_n}вҶ’{_dynamic['min_score_normal']}")
                        try:
                            send(f"рҹ”Ҙ <b>м—°мҶҚ мҲҳмқө {_consecutive_win_count}нҡҢ!</b>\n"
                                 f"мӢ нҳё кё°мӨҖ мҷ„нҷ”: {old_n}вҶ’{_dynamic['min_score_normal']}м җ\n"
                                 f"лҚ” л§ҺмқҖ мӢ нҳёлҘј нҸ¬м°©н•©лӢҲлӢӨ")
                        except Exception: pass

        if updated:
            data = _prune_signal_log(data)
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
            # tracker н”јл“ңл°ұ мҰүмӢң к°ұмӢ 
            load_tracker_feedback()

    except Exception as e:
        _log_error("track_signal_results", e, critical=True)


def _send_tracking_result(rec: dict, log_key: str | None = None):
    """кІ°кіј нҷ•м • н…”л Ҳк·ёлһЁ м•ҢлҰј + мҶҗм Ҳ мӣҗмқё л¶„м„қ"""
    pnl      = rec["pnl_pct"]
    reason   = rec["exit_reason"]
    sig_type = rec.get("signal_type", "")
    name     = rec["name"]
    code     = rec["code"]
    entry    = rec.get("entry_price", 0)
    exit_p   = rec["exit_price"]
    max_p    = rec.get("max_price", exit_p)
    min_p    = rec.get("min_price", exit_p)
    theme    = rec.get("sector_theme", "")
    bonus    = rec.get("sector_bonus", 0)

    if reason == "лӘ©н‘ңк°Җ":
        emoji = "рҹҺҜвң…"; title = "лӘ©н‘ңк°Җ лӢ¬м„ұ!"
    elif reason == "мҶҗм Ҳк°Җ":
        emoji = "рҹӣЎрҹ”ө"; title = "мҶҗм Ҳк°Җ лҸ„лӢ¬"
    elif reason == TRACK_TIMEOUT_RESULT:
        emoji = "вҸұ"; title = f"{TRACK_MAX_DAYS}мқј кІҪкіј кІ°кіј"
    else:
        emoji = "рҹ“Ҡ"; title = "кІ°кіј нҷ•м •"

    pnl_emoji = "вң…" if pnl > 0 else ("рҹ”ө" if pnl < 0 else "вһ–")
    sig_labels = {
        "UPPER_LIMIT":"мғҒн•ңк°Җ", "NEAR_UPPER":"мғҒн•ңк°Җк·јм ‘",
        "SURGE":"кёүл“ұ", "EARLY_DETECT":"мЎ°кё°нҸ¬м°©",
        "MID_PULLBACK":"лҲҢлҰјлӘ©", "ENTRY_POINT":"лҲҢлҰјлӘ©",
        "STRONG_BUY":"к°•л Ҙл§ӨмҲҳ",
    }
    sig_label = sig_labels.get(sig_type, sig_type)
    theme_tag = f"\nрҹҸӯ н…Ңл§Ҳ: {theme} (+{bonus}м җ)" if bonus > 0 else "\nрҹ”Қ лӢЁлҸ… мғҒмҠ№"
    mdd = round((min_p - entry) / entry * 100, 1) if entry else 0

    # в”Җв”Җ мҶҗм Ҳ мӣҗмқё л¶„м„қ в”Җв”Җ
    cause_block = ""
    if reason == "мҶҗм Ҳк°Җ":
        causes = []
        try:
            cur = get_stock_price(code)
            p   = cur.get("price", 0)
            if p:
                inv = get_investor_trend(code)
                f_net = inv.get("foreign_net", 0)
                i_net = inv.get("institution_net", 0)
                vr    = cur.get("volume_ratio", 0)

                if f_net < -5000:  causes.append(f"рҹ”ө мҷёкөӯмқё лҢҖлҹү л§ӨлҸ„ ({f_net:+,}мЈј)")
                elif f_net < 0:    causes.append(f"рҹ”ө мҷёкөӯмқё мҲңл§ӨлҸ„ ({f_net:+,}мЈј)")
                if i_net < -3000:  causes.append(f"рҹ”ө кё°кҙҖ лҢҖлҹү л§ӨлҸ„ ({i_net:+,}мЈј)")
                elif i_net < 0:    causes.append(f"рҹ”ө кё°кҙҖ мҲңл§ӨлҸ„ ({i_net:+,}мЈј)")
                if vr and vr < 0.5: causes.append(f"рҹ“ү кұ°лһҳлҹү кёүк°җ ({vr:.1f}л°° вҖ” л§ӨмҲҳм„ё мҶҢл©ё)")
                if vr and vr > 5:   causes.append(f"рҹҢҠ кұ°лһҳлҹү кёүмҰқ мҶҚ н•ҳлқҪ (м„ёл Ҙ л§ӨлҸ„ к°ҖлҠҘм„ұ)")
                if not causes:      causes.append("вҡ пёҸ нҠ№мқҙ мӣҗмқё лҜёк°җм§Җ (кё°мҲ м Ғ мҶҗм Ҳ)")
        except Exception: causes = ["мЎ°нҡҢ мӢӨнҢЁ"]
        cause_block = "\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ”Қ <b>мҶҗм Ҳ мӣҗмқё л¶„м„қ</b>\n" + "\n".join(f"  {c}" for c in causes) + "\n"
        # v41.66: мҶҗм Ҳ мӢң ліҙмң л¶„ м •лҰ¬ к°Җмқҙл“ң м¶”к°Җ
        cause_block += (
            "\nрҹҡЁ <b>нҸ¬м§Җм…ҳ м •лҰ¬ мӢ нҳё</b>\n"
            "  вҶ’ мӢ к·ң м§„мһ… нҢҗлӢЁмқҙ м•„лӢҢ ліҙмң л¶„ к°җм¶•/мІӯмӮ° лӢЁкі„\n"
            "  вҶ’ м¶”к°Җл§ӨмҲҳ кёҲм§Җ, мһ”м—¬ ліҙмң л¶„ мҰүмӢң м •лҰ¬ кІҖнҶ \n"
            "  вҶ’ л°ҳл“ұ мӢң мһ¬м§„мһ…мқҖ мғҲлЎңмҡҙ нҸ¬м°© мӢ нҳё кё°мӨҖмңјлЎңл§Ң\n"
        )

    # в”Җв”Җ л¶„н•  мІӯмӮ° к°Җмқҙл“ң (мҲҳмқө мӢң) в”Җв”Җ
    profit_guide = ""
    if pnl > 0 and reason == "лӘ©н‘ңк°Җ" and entry and target:
        target = rec.get("target_price", exit_p)
        r2 = int(entry + (target - entry) * 1.5)
        profit_guide = (
            f"\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
            f"рҹ’Ў <b>м¶”к°Җ ліҙмң  кі л Ө</b>\n"
            f"  нҳ„мһ¬ +{pnl:.1f}% лӢ¬м„ұ\n"
            f"  R2 лӘ©н‘ң: {r2:,}мӣҗ  (+{(r2-entry)/entry*100:.1f}%)\n"
            f"  вҶ’ м Ҳл°ҳ мқөм Ҳ нӣ„ лӮҳлЁём§Җ нҷҖл”© м „лһө\n"
        )

    display_rec = dict(rec or {})
    if log_key:
        display_rec['log_key'] = log_key
    entry_hit_line = _build_entry_hit_line(entry, display_rec, include_hit_price=False, include_hit_time=True)

    send_with_chart_buttons(
        f"{emoji} <b>[мһҗлҸҷ м¶”м Ғ кІ°кіј]</b>  {title}\n"
        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
        f"{pnl_emoji} <b>{name}</b>  <code>{code}</code>\n"
        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
        f"мӢ нҳё: {sig_label}  |  к°җм§Җ: {_format_capture_datetime_label(detect_date=rec.get('detect_date',''), detect_time=rec.get('detect_time',''))}\n"
        f"{theme_tag}\n"
        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
        f"{entry_hit_line}\n"
        f"мІӯмӮ°к°Җ:  <b>{exit_p:,}мӣҗ</b>  ({reason})\n"
        f"нҳ„мһ¬к°Җ:  <b>{rec.get('current_price', exit_p):,}мӣҗ</b>\n"
        f"мөңкі к°Җ:  {max_p:,}мӣҗ  |  мөңм Җк°Җ: {min_p:,}мӣҗ\n"
        f"мөңлҢҖлӮҷнҸӯ: {mdd:+.1f}%\n"
        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
        f"{pnl_emoji} <b>мҲҳмқөлҘ : {pnl:+.1f}%</b>"
        f"{cause_block}"
        f"{profit_guide}",
        code, name
    )

    # в”Җв”Җ мҶҗм Ҳ мӢң мһ¬м§„мһ… к°җмӢң л“ұлЎқ (KRX + NXT лӘЁл‘җ) в”Җв”Җ
    if reason == "мҶҗм Ҳк°Җ" and is_any_market_open():
        try:
            # KRX мһҘмӨ‘мқҙл©ҙ KRX к°ҖкІ©, л§Ҳк°җ нӣ„ NXT мһҲмңјл©ҙ NXT к°ҖкІ©
            if is_market_open():
                cur_price = get_stock_price(code).get("price", 0)
            elif is_nxt_open():
                cur_price = get_nxt_stock_price(code).get("price", 0) or get_stock_price(code).get("price", 0)
            else:
                cur_price = 0
            if cur_price:
                _reentry_watch[code] = {
                    "name":        name,
                    "stop_price":  cur_price,
                    "entry":       rec.get("entry_price", 0),
                    "stop":        rec.get("stop_price", 0),
                    "target":      rec.get("target_price", 0),
                    "signal_type": rec.get("signal_type", ""),
                    "ts":          time.time(),
                    "nxt_listed":  bool(is_nxt_listed(code)),
                    "market_basis": "NXT" if is_nxt_listed(code) else "KRX",
                }
                _save_reentry_watch()
                print(f"  рҹ”„ мһ¬м§„мһ… к°җмӢң л“ұлЎқ: {name} ({code}) мҶҗм Ҳк°Җ {cur_price:,}")
        except Exception: pass

def check_reentry_watch():
    """
    мҶҗм Ҳ мў…лӘ© мһ¬м§„мһ… к°җмӢң вҖ” 20мҙҲл§ҲлӢӨ run_scanм—җм„ң нҳём¶ң
    л§ҢлЈҢ: мһҘ мҷ„м „ л§Ҳк°җ(KRX onlyвҶ’15:30, NXT мғҒмһҘвҶ’20:00) лҳҗлҠ” on_market_close
    мЎ°кұҙ: мҶҗм Ҳк°Җ лҢҖл№„ +3% л°ҳл“ұ + кұ°лһҳлҹү 1.5л°° мқҙмғҒ
    """
    if not _reentry_watch: return
    expired = []
    changed = False
    for code, w in list(_reentry_watch.items()):
        # мў…лӘ©лі„ мӢӨм§Ҳ л§Ҳк°җ нҢҗлӢЁ
        nxt_ok  = is_nxt_open() and is_nxt_listed(code)
        krx_ok  = is_market_open()
        if not krx_ok and not nxt_ok:
            expired.append(code); continue   # лӘЁл“  мӢңмһҘ л§Ҳк°җ вҶ’ л§ҢлЈҢ
        try:
            # KRX мһҘмӨ‘мқҙл©ҙ KRX к°ҖкІ©, л§Ҳк°җ нӣ„л©ҙ NXT к°ҖкІ©
            if krx_ok:
                cur   = get_stock_price(code)
                price = cur.get("price", 0)
                vr    = cur.get("volume_ratio", 0)
            else:
                cur   = get_nxt_stock_price(code)
                price = cur.get("price", 0)
                vr    = cur.get("volume_ratio", 0)
                if not price:   # NXT кұ°лһҳ м—Ҷмңјл©ҙ мҠӨнӮө (л§Ҳк°җ м•„лӢҳ)
                    continue
            if not price: continue

            bounce = (price - w["stop_price"]) / w["stop_price"] * 100
            mkt_tag = " рҹҹЎNXT" if not krx_ok and nxt_ok else ""
            _reentry_min = calc_reentry_bounce(code, price)
            if bounce >= _reentry_min and vr >= REENTRY_VOL_MIN:
                sig_labels = {"UPPER_LIMIT":"мғҒн•ңк°Җ","NEAR_UPPER":"мғҒн•ңк°Җк·јм ‘",
                              "SURGE":"кёүл“ұ","EARLY_DETECT":"мЎ°кё°нҸ¬м°©",
                              "MID_PULLBACK":"лҲҢлҰјлӘ©","ENTRY_POINT":"лҲҢлҰјлӘ©"}
                sig = sig_labels.get(w["signal_type"], w["signal_type"])
                send_with_chart_buttons(
                    f"рҹ”„ <b>[мҶҗм Ҳ нӣ„ мһ¬м§„мһ… нӣ„ліҙ{mkt_tag}]</b>\n"
                    f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                    f"рҹҹЎ <b>{w['name']}</b>  <code>{code}</code>\n"
                    f"мӣҗмӢ нҳё: {sig}\n"
                    f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                    f"рҹ“Қ мҶҗм Ҳк°Җ:  {w['stop_price']:,}мӣҗ\n"
                    f"рҹ“Ҳ нҳ„мһ¬к°Җ:  <b>{price:,}мӣҗ</b>  (+{bounce:.1f}% л°ҳл“ұ)\n"
                    f"рҹ”Ҡ кұ°лһҳлҹү:  {vr:.1f}л°° (нҡҢліө)\n"
                    f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                    f"в„№пёҸ мӢӨм ң мһ¬м§„мһ…к°ҖлҠ” мһ¬м§„мһ… нҷ•м • м•ҢлҰјм—җм„ңл§Ң м ңкіөн•©лӢҲлӢӨ.\n"
                    f"вҡ пёҸ мҶҗм Ҳ нӣ„ мһ¬м§„мһ… вҖ” л¬јнғҖкё° м•„лӢҳ, мғҲ нҸ¬м§Җм…ҳмңјлЎң нҢҗлӢЁ",
                    code, w["name"]
                )
                expired.append(code)
                print(f"  рҹ”„ мһ¬м§„мһ… мӢ нҳё: {w['name']} {price:,} (+{bounce:.1f}%){mkt_tag}")
        except Exception: continue
    for code in expired:
        _reentry_watch.pop(code, None)
        changed = True
    if changed:
        _save_reentry_watch()

def save_carry_stocks():
    with _file_lock:  # v38.3-P0-5
        try:
            payload = {}
            for raw_code, info in _detected_stocks.items():
                if not isinstance(info, dict):
                    continue
                code = normalize_stock_code(raw_code or info.get("code"))
                if not code:
                    continue
                snap = {
                    "code": code,
                    "name": info.get("name", code),
                    "high_price": safe_int(info.get("high_price", 0), 0),
                    "entry_price": safe_int(info.get("entry_price", 0), 0),
                    "stop_loss": safe_int(info.get("stop_loss", 0), 0),
                    "target_price": safe_int(info.get("target_price", 0), 0),
                    "detected_at": info.get("detected_at").strftime("%Y%m%d%H%M%S") if isinstance(info.get("detected_at"), datetime) else str(info.get("detected_at", "") or ""),
                    "carry_day": safe_int(info.get("carry_day", 0), 0),
                }
                if not _is_active_carry_snapshot(snap):
                    continue
                payload[code] = snap
            with open(CARRY_FILE, "w", encoding="utf-8", newline="\n") as f:
                json.dump(payload, f, ensure_ascii=False)
        except Exception as e: print(f"вҡ пёҸ мқҙмӣ” м ҖмһҘ мӢӨнҢЁ: {e}")

def load_carry_stocks():
    """Railway мһ¬мӢңмһ‘ мӢң м¶”м Ғ мғҒнғң м „мІҙ ліөмӣҗ"""
    # [v55] кі м•„ м¶”м Ғ мў…лӘ© мқјкҙ„ м •лҰ¬ (ліөмӣҗ м „м—җ лЁјм Җ 1нҡҢ)
    try:
        _orphan_count = purge_orphan_tracking(notify=True)
        if _orphan_count:
            print(f"рҹ—‘ лҙҮ мӢңмһ‘ мӢң кі м•„ м¶”м Ғ {_orphan_count}кұҙ мһҗлҸҷ л§ҢлЈҢ")
    except Exception as _oe:
        print(f"вҡ пёҸ кі м•„ м¶”м Ғ м •лҰ¬ мҳӨлҘҳ: {_oe}")

    try:
        sig_data = _read_json_locked(SIGNAL_LOG_FILE)
    except Exception:
        sig_data = {}

    # в‘  мқҙмӣ” мў…лӘ© ліөмӣҗ м „ carry нҢҢмқј мһҗмІҙлҘј м •лҰ¬
    try:
        raw_carry = _read_json_locked(CARRY_FILE)
        data, dropped_codes = _sanitize_carry_snapshot_map(raw_carry, siglog_data=sig_data)
        if dropped_codes or not isinstance(raw_carry, dict) or len(data) != len(raw_carry):
            _write_json_atomic(CARRY_FILE, data)
        if dropped_codes:
            print(f"  рҹ§№ stale carry м •лҰ¬: {len(dropped_codes)}к°ң м ңкұ°")

        for code, info in data.items():
            detected_at = _parse_compact_datetime(info.get("detected_at")) or datetime.now()
            _detected_stocks[code] = {
                "name": info.get("name", code),
                "high_price": safe_int(info.get("high_price", 0), 0),
                "entry_price": safe_int(info.get("entry_price", 0), 0),
                "stop_loss": safe_int(info.get("stop_loss", 0), 0),
                "target_price": safe_int(info.get("target_price", 0), 0),
                "detected_at": detected_at,
                "carry_day": safe_int(info.get("carry_day", 0), 0),
            }
        if _detected_stocks:
            print(f"рҹ“Ӯ мқҙмӣ” мў…лӘ© {len(_detected_stocks)}к°ң ліөмӣҗ")
    except Exception:
        pass

    # в‘Ў signal_logм—җм„ң мң нҡЁ м¶”м Ғ мў…лӘ© ліөмӣҗ (мқҙмӣ” нҢҢмқјм—җ м—ҶлҠ” лӢ№мқј м¶”м Ғ мў…лӘ©)
    try:
        today = datetime.now().strftime("%Y%m%d")
        restored = 0
        for rec in _get_valid_tracking(sig_data):
            code = normalize_stock_code(rec.get("code", ""))
            if (rec.get("detect_date") == today
                    and code
                    and code not in _detected_stocks):
                _detected_stocks[code] = {
                    "name":        rec["name"],
                    "high_price":  rec.get("detect_price", 0),
                    "entry_price": rec.get("entry_price", 0),
                    "stop_loss":   rec.get("stop_price", 0),
                    "target_price":rec.get("target_price", 0),
                    "detected_at": datetime.now(),
                    "carry_day":   0,
                }
                restored += 1
        if restored:
            print(f"  рҹ“Ӣ signal_logм—җм„ң м¶”м Ғ мӨ‘ мў…лӘ© {restored}к°ң м¶”к°Җ ліөмӣҗ")
    except Exception:
        pass

    save_carry_stocks()

    # ліөмӣҗ м•ҢлҰј
    if _detected_stocks:
        send(
            f"рҹ”„ <b>лҙҮ мһ¬мӢңмһ‘ вҖ” м¶”м Ғ мғҒнғң ліөмӣҗ</b>\n"
            f"рҹ“Ӯ к°җмӢң мӨ‘ мў…лӘ© {len(_detected_stocks)}к°ң\n"
            + "\n".join([f"вҖў {v['name']} ({k})" for k, v in list(_detected_stocks.items())[:6]])
            + ("\n  ..." if len(_detected_stocks) > 6 else "")
            + "\n\nрҹ“Ў мҠӨмә” мһ¬к°ң"
        )

    # в‘ў м»ҙнҢ©нҠё лӘЁл“ң ліөмӣҗ
    _load_compact_mode()

