def _load_dynamic_params():
    """
    м ҖмһҘлҗң _dynamic к°’мқ„ л¶Ҳлҹ¬мҷҖм„ң нҳ„мһ¬ м„ём…ҳм—җ ліөмӣҗ
    нҢҢмқј м—Ҷмңјл©ҙ кё°ліёк°’ мң м§Җ
    """
    global _dynamic, _early_price_min_dynamic, _early_volume_min_dynamic
    try:
        with open(DYNAMIC_PARAMS_FILE) as f:
            saved = json.load(f)
        # м ҖмһҘлҗң к°’ мӨ‘ мң нҡЁн•ң нӮӨл§Ң лҚ®м–ҙм”Җ (мғҲлЎң м¶”к°Җлҗң нӮӨлҠ” кё°ліёк°’ мң м§Җ)
        # v37.0: нғҖмһ… к°•м ң ліҖнҷҳ (JSON strвҶ’int/float мҳӨлҘҳ л°©м§Җ)
        for k, v in saved.items():
            if k in _dynamic:
                default = _dynamic[k]
                try:
                    if isinstance(default, int) and not isinstance(default, bool):
                        _dynamic[k] = int(v)
                    elif isinstance(default, float):
                        _dynamic[k] = float(v)
                    elif isinstance(default, dict) and isinstance(v, dict):
                        _dynamic[k] = v
                    elif isinstance(default, str):
                        _dynamic[k] = str(v)
                    else:
                        _dynamic[k] = v
                except (ValueError, TypeError):
                    pass  # ліҖнҷҳ мӢӨнҢЁ мӢң кё°ліёк°’ мң м§Җ
        print(f"  рҹ”§ лҸҷм Ғ нҢҢлқјлҜён„° ліөмӣҗ мҷ„лЈҢ (min_score={_dynamic['min_score_normal']}м җ, "
              f"atr_stop={_dynamic['atr_stop_mult']})")
    except FileNotFoundError:
        print("  рҹ”§ dynamic_params.json м—ҶмқҢ вҶ’ кё°ліёк°’ мӮ¬мҡ©")
        # м ҖмһҘ нҢҢмқјмқҙ м—Ҷмңјл©ҙ кё°ліёк°’мқ„ мҰүмӢң м ҖмһҘн•ҙ лӢӨмқҢ мһ¬мӢңмһ‘л¶Җн„° ліөмӣҗлҗҳлҸ„лЎқ н•ңлӢӨ
        try:
            _save_dynamic_params()
            print("  рҹ’ҫ dynamic_params.json кё°ліёк°’ м ҖмһҘ мҷ„лЈҢ")
        except Exception as se:
            print(f"  вҡ пёҸ dynamic_params кё°ліёк°’ м ҖмһҘ мӢӨнҢЁ: {se}")
