def _get_timeslot(detect_time: str) -> str:
    """
    мӢ нҳё л°ңмғқ мӢңк°„(HH:MM:SS лҳҗлҠ” HH:MM)мқ„ 4к°ң кө¬к°„мңјлЎң л¶„лҘҳ
    мһҘмҙҲл°ҳ 09:00~10:00 / мҳӨм „ 10:00~12:00 / мҳӨнӣ„ 12:00~14:00 / мһҘнӣ„л°ҳ 14:00~15:30
    """
    try:
        t = detect_time[:5]   # "HH:MM"
        h, m = int(t[:2]), int(t[3:])
        minutes = h * 60 + m
        if minutes < 10 * 60:              return "мһҘмҙҲл°ҳ"   # ~10:00
        elif minutes < 12 * 60:            return "мҳӨм „"     # 10:00~12:00
        elif minutes < 14 * 60:            return "мҳӨнӣ„"     # 12:00~14:00
        else:                              return "мһҘнӣ„л°ҳ"   # 14:00~
    except Exception:
        return "кё°нғҖ"

def analyze_timeslot_winrate(completed: list) -> dict:
    """
    мҷ„лЈҢ мӢ нҳёлҘј мӢңк°„лҢҖлі„лЎң л¶„лҘҳн•ҙ мҠ№лҘ В·нҸүк·  мҲҳмқөлҘ  л°ҳнҷҳ
    л°ҳнҷҳ: {"мһҘмҙҲл°ҳ": {"win":N,"total":N,"avg":F}, ...}
    """
    slots = {"мһҘмҙҲл°ҳ": [], "мҳӨм „": [], "мҳӨнӣ„": [], "мһҘнӣ„л°ҳ": [], "кё°нғҖ": []}
    for r in completed:
        t = r.get("detect_time", r.get("detected_at", ""))
        slot = _get_timeslot(t)
        slots[slot].append(r["pnl_pct"])
    result = {}
    for slot, pnls in slots.items():
        if not pnls: continue
        result[slot] = {
            "win":   sum(1 for p in pnls if p > 0),
            "total": len(pnls),
            "avg":   round(sum(pnls) / len(pnls), 1),
            "rate":  round(sum(1 for p in pnls if p > 0) / len(pnls) * 100, 0),
        }
    return result

def _feature_change_bucket(change_rate: float) -> str:
    try:
        cr = float(change_rate or 0)
        if cr >= 20:
            return "extreme"
        elif cr >= 8:
            return "strong"
        return "mild"
    except Exception:
        return "mild"


def _feature_volume_bucket(volume_ratio: float) -> str:
    try:
        vr = float(volume_ratio or 0)
        if vr >= 8:
            return "extreme"
        elif vr >= 3:
            return "high"
        return "normal"
    except Exception:
        return "normal"


def _safe_nested_dict(base: dict, key: str, default: dict) -> dict:
    try:
        val = base.get(key, default)
        return val if isinstance(val, dict) else dict(default)
    except Exception:
        return dict(default)


def analyze_loss_pattern(completed: list) -> str:
    """
    мҶҗмӢӨ мў…лӘ©л“Өмқҳ кіөнҶө нҢЁн„ҙ л¶„м„қ вҶ’ н…ҚмҠӨнҠё мҡ”м•Ҫ л°ҳнҷҳ
    л¶„м„қ н•ӯлӘ©: мҶҗм Ҳ мқҙмң  л¶„нҸ¬ / мӢңк°„лҢҖ / мӢ нҳёмң нҳ• / н…Ңл§Ҳм—¬л¶Җ
    """
    losses = [r for r in completed if r.get("pnl_pct", 0) <= 0]
    if len(losses) < 3:
        return ""

    lines = [f"рҹ”ө <b>мҶҗмӢӨ нҢЁн„ҙ л¶„м„қ</b>  ({len(losses)}кұҙ)"]

    # мҶҗм Ҳ мқҙмң  л¶„нҸ¬
    reasons = {}
    for r in losses:
        ex = r.get("exit_reason", "?")
        reasons[ex] = reasons.get(ex, 0) + 1
    reason_str = "  ".join([f"{k}:{v}кұҙ" for k, v in sorted(reasons.items(), key=lambda x: -x[1])])
    lines.append(f"  мІӯмӮ° мқҙмң : {reason_str}")

    # мӢңк°„лҢҖлі„ мҶҗмӢӨ м§‘мӨ‘лҸ„
    slot_counts = {}
    for r in losses:
        t = r.get("detect_time", r.get("detected_at", ""))
        slot = _get_timeslot(t)
        slot_counts[slot] = slot_counts.get(slot, 0) + 1
    worst_slot = max(slot_counts, key=slot_counts.get) if slot_counts else None
    if worst_slot:
        lines.append(f"  мҶҗмӢӨ м§‘мӨ‘ мӢңк°„лҢҖ: {worst_slot} ({slot_counts[worst_slot]}кұҙ)")

    # мӢ нҳё мң нҳ•лі„ мҶҗмӢӨ
    type_counts = {}
    for r in losses:
        t = r.get("signal_type", "кё°нғҖ")
        type_counts[t] = type_counts.get(t, 0) + 1
    worst_type = max(type_counts, key=type_counts.get) if type_counts else None
    if worst_type:
        type_labels = {"UPPER_LIMIT":"мғҒн•ңк°Җ","NEAR_UPPER":"мғҒн•ңк°Җк·јм ‘","SURGE":"кёүл“ұ",
                       "EARLY_DETECT":"мЎ°кё°нҸ¬м°©","MID_PULLBACK":"лҲҢлҰјлӘ©",
                       "ENTRY_POINT":"лҲҢлҰјлӘ©","STRONG_BUY":"к°•л Ҙл§ӨмҲҳ"}
        lines.append(f"  мҶҗмӢӨ л§ҺмқҖ мӢ нҳё: {type_labels.get(worst_type, worst_type)} ({type_counts[worst_type]}кұҙ)")

    # лӢЁлҸ… vs н…Ңл§Ҳ мҶҗмӢӨ л№„мңЁ
    solo_loss   = sum(1 for r in losses if not r.get("sector_bonus", 0))
    themed_loss = sum(1 for r in losses if r.get("sector_bonus", 0))
    if solo_loss + themed_loss > 0:
        lines.append(f"  лӢЁлҸ…:{solo_loss}кұҙ  н…Ңл§ҲлҸҷл°ҳ:{themed_loss}кұҙ")

    return "\n".join(lines)


