# рҹ“Ҡ v41.63: signal_log н”јл“ңл°ұ лЈЁн”„ вҖ” KPI мһҗлҸҷ л¶„м„қ + м „лһө кұҙк°•лҸ„ нҢҗм •
# ============================================================
KPI_MIN_SAMPLES = int(os.getenv("KPI_MIN_SAMPLES", "10") or "10")


def compute_signal_kpi(completed: list | None = None, pnl_field: str = "pnl_pct") -> dict:
    """
    signal_log кё°л°ҳ мҠ№лҘ /мҶҗмқөл№„/кё°лҢҖмҲҳмқө KPI мһҗлҸҷ кі„мӮ°.
    v41.63 #1: мӢ нҳёмң нҳ•лі„В·л Ҳм§җлі„В·мӢңк°„лҢҖлі„ м„ёл¶„нҷ” KPI.
    v41.93/v41.95: лҲҢлҰјлӘ© bucket л°Ҹ мӢӨм§„мһ…(actual_pnl) KPI м§Җмӣҗ.
    л°ҳнҷҳ: {
      "overall": {win_rate, avg_pnl, profit_factor, payoff_ratio, expectancy, n},
      "by_type": {signal_type: {...}},
      "by_regime": {regime: {...}},
      "by_slot": {timeslot: {...}},
      "by_mid_pullback_bucket": {bucket: {...}},
      "consecutive_loss": int,
    }
    """
    if completed is None:
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception:
            data = {}
        completed = [v for v in data.values()
                     if v.get("status") in ["мҲҳмқө", "мҶҗмӢӨ", "ліём „"]]

    def _calc_kpi(recs: list) -> dict:
        if not recs:
            return {"win_rate": 0, "avg_pnl": 0, "profit_factor": 0,
                    "payoff_ratio": 0, "expectancy": 0, "n": 0}
        pnls = []
        for r in recs:
            try:
                pnls.append(float(r.get(pnl_field, 0) or 0))
            except Exception:
                pnls.append(0.0)
        n = len(pnls)
        if not n:
            return {"win_rate": 0, "avg_pnl": 0, "profit_factor": 0,
                    "payoff_ratio": 0, "expectancy": 0, "n": 0}
        wins = [p for p in pnls if p > 0]
        losses = [p for p in pnls if p < 0]
        win_rate = len(wins) / n * 100 if n else 0
        avg_pnl = sum(pnls) / n if n else 0
        avg_win = sum(wins) / len(wins) if wins else 0
        avg_loss = abs(sum(losses) / len(losses)) if losses else 1
        payoff_ratio = round(avg_win / avg_loss, 2) if avg_loss > 0 else 99.0
        profit_factor = round(sum(wins) / abs(sum(losses)), 2) if losses and sum(losses) != 0 else 99.0
        loss_rate = 1 - len(wins) / n if n else 0
        expectancy = round((len(wins) / n * avg_win - loss_rate * avg_loss) if n else 0, 2)
        return {
            "win_rate": round(win_rate, 1),
            "avg_pnl": round(avg_pnl, 2),
            "profit_factor": profit_factor,
            "payoff_ratio": payoff_ratio,
            "expectancy": expectancy,
            "n": n,
        }

    result = {"overall": _calc_kpi(completed)}

    by_type = {}
    for v in completed:
        t = v.get("signal_type", "кё°нғҖ")
        by_type.setdefault(t, []).append(v)
    result["by_type"] = {t: _calc_kpi(recs) for t, recs in by_type.items()}

    by_regime = {}
    for v in completed:
        r = v.get("regime", v.get("market_regime_mode", "normal"))
        by_regime.setdefault(r, []).append(v)
    result["by_regime"] = {r: _calc_kpi(recs) for r, recs in by_regime.items()}

    by_slot = {}
    for v in completed:
        slot = _get_timeslot(v.get("time", "10:00:00"))
        by_slot.setdefault(slot, []).append(v)
    result["by_slot"] = {s: _calc_kpi(recs) for s, recs in by_slot.items()}

    by_bucket = {}
    for v in completed:
        bucket = str(v.get("mid_pullback_bucket", "") or "")
        if not bucket:
            continue
        by_bucket.setdefault(bucket, []).append(v)

    bucket_result = {}
    for bucket, recs in by_bucket.items():
        entry = _calc_kpi(recs)
        grade_dist = {"A": 0, "B": 0, "C": 0}
        for r in recs:
            grade = str(r.get("execution_grade") or r.get("grade") or "").upper()
            if grade in grade_dist:
                grade_dist[grade] += 1
        entry["execution_grade_dist"] = grade_dist
        bucket_result[bucket] = entry
    result["by_mid_pullback_bucket"] = bucket_result

    sorted_recs = sorted(completed, key=lambda x: x.get("exit_date", "") + x.get("exit_time", ""))
    consec = 0
    for r in reversed(sorted_recs):
        try:
            pnl_val = float(r.get(pnl_field, 0) or 0)
        except Exception:
            pnl_val = 0.0
        if pnl_val < 0:
            consec += 1
        else:
            break
    result["consecutive_loss"] = consec

    return result


def _check_strategy_health(kpi: dict, notify: bool = True) -> list:
    """
    v41.63 #2: KPI кё°л°ҳ м „лһө кұҙк°•лҸ„ мһҗлҸҷ нҢҗм •.
    л¬ём ң мһҲлҠ” мӢ нҳёмң нҳ•мқ„ к°җм§Җн•ҳкі  мһҗлҸҷ кё°мӨҖ к°•нҷ” лҳҗлҠ” кІҪкі  л°ңмҶЎ.
    л°ҳнҷҳ: ліҖкІҪмӮ¬н•ӯ лҰ¬мҠӨнҠё (auto_tune changesм—җ н•©лҘҳ)
    """
    changes = []
    try:
        overall = kpi.get("overall", {})
        if overall.get("n", 0) < KPI_MIN_SAMPLES:
            return changes

        # в”Җв”Җ м „мІҙ кұҙк°•лҸ„ мІҙнҒ¬ в”Җв”Җ
        if overall["win_rate"] < 35:
            changes.append(
                f"вҡ пёҸ <b>м „мІҙ мҠ№лҘ  кІҪкі </b>: {overall['win_rate']:.0f}% "
                f"(лӘ©н‘ң 40%вҶ‘)  n={overall['n']}"
            )
        if overall.get("payoff_ratio", 1) < 1.0 and overall["n"] >= 20:
            changes.append(
                f"вҡ пёҸ <b>мҶҗмқөл№„ кІҪкі </b>: {overall['payoff_ratio']:.2f} "
                f"(лӘ©н‘ң 1.0вҶ‘)  вҖ” нҸүк·  мҲҳмқө < нҸүк·  мҶҗмӢӨ"
            )

        # в”Җв”Җ м—°мҶҚ мҶҗм Ҳ кёҙкёү кІҪкі  в”Җв”Җ
        consec = kpi.get("consecutive_loss", 0)
        if consec >= 5:
            changes.append(
                f"рҹҡЁ <b>м—°мҶҚ мҶҗм Ҳ {consec}нҡҢ</b> вҖ” кёҙкёү кё°мӨҖ к°•нҷ” к¶Ңкі "
            )
            if notify:
                send(
                    f"рҹҡЁ <b>м „лһө кёҙкёү кІҪкі </b>\n"
                    f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                    f"м—°мҶҚ мҶҗм Ҳ <b>{consec}нҡҢ</b> л°ңмғқ!\n"
                    f"мҠ№лҘ : {overall['win_rate']:.0f}%  мҶҗмқөл№„: {overall.get('payoff_ratio',0):.2f}\n"
                    f"кё°лҢҖмҲҳмқө: {overall.get('expectancy',0):+.2f}%\n\n"
                    f"рҹ’Ў мһҗлҸҷ нҠңлӢқмқҙ кё°мӨҖмқ„ к°•нҷ”н•©лӢҲлӢӨ.\n"
                    f"/stats лЎң мғҒм„ё нҷ•мқё"
                )

        # в”Җв”Җ мӢ нҳёмң нҳ•лі„ кұҙк°•лҸ„ мІҙнҒ¬ в”Җв”Җ
        for sig_type, sig_kpi in kpi.get("by_type", {}).items():
            if sig_kpi.get("n", 0) < max(KPI_MIN_SAMPLES // 2, 5):
                continue
            if sig_kpi["win_rate"] < 30:
                changes.append(
                    f"рҹ“ү {sig_type} мҠ№лҘ  {sig_kpi['win_rate']:.0f}% "
                    f"(n={sig_kpi['n']}) вҶ’ кё°мӨҖ к°•нҷ” н•„мҡ”"
                )
            elif sig_kpi["win_rate"] > 70 and sig_kpi.get("payoff_ratio", 1) >= 1.5:
                changes.append(
                    f"рҹҢҹ {sig_type} кі м„ұкіј: мҠ№лҘ  {sig_kpi['win_rate']:.0f}% "
                    f"мҶҗмқөл№„ {sig_kpi['payoff_ratio']:.1f} вҶ’ кё°мӨҖ мҷ„нҷ” к°ҖлҠҘ"
                )

        # в”Җв”Җ л Ҳм§җлі„ кұҙк°•лҸ„ мІҙнҒ¬ в”Җв”Җ
        for regime, reg_kpi in kpi.get("by_regime", {}).items():
            if reg_kpi.get("n", 0) < max(KPI_MIN_SAMPLES // 2, 5):
                continue
            if reg_kpi["win_rate"] < 25 and regime in ("bear", "crash"):
                changes.append(
                    f"вҡ пёҸ {regime} л Ҳм§җ мҠ№лҘ  {reg_kpi['win_rate']:.0f}% "
                    f"(n={reg_kpi['n']}) вҖ” н•ҙлӢ№ л Ҳм§җ м§„мһ… м¶•мҶҢ к¶Ңкі "
                )

    except Exception as e:
        _log_error("_check_strategy_health", e)
    return changes


def _auto_tune_mid_pullback_bucket_params(mid_recs: list) -> list:
    changes = []
    if len(mid_recs) < max(MIN_SAMPLES, 6):
        return changes

    base_a = {
        "weekly_monthly_trend": 2,
        "daily_trend": 3,
        "gap_first_pullback": 3,
        "intraday_reclaim": 4,
    }
    base_b = {
        "weekly_monthly_trend": 1,
        "daily_trend": 2,
        "gap_first_pullback": 2,
        "intraday_reclaim": 2,
    }
    labels = MID_PULLBACK_BUCKET_LABELS
    a_map = _safe_nested_dict(_dynamic, "mid_pullback_bucket_a_confirm_min", base_a)
    b_map = _safe_nested_dict(_dynamic, "mid_pullback_bucket_b_confirm_min", base_b)

    for bucket, label in labels.items():
        subset = [r for r in mid_recs if str(r.get("mid_pullback_bucket", "") or "daily_trend") == bucket]
        if len(subset) < 4:
            continue
        win = sum(1 for r in subset if r.get("pnl_pct", 0) > 0) / len(subset)
        avg = sum(float(r.get("pnl_pct", 0) or 0) for r in subset) / len(subset)
        old_a = int(a_map.get(bucket, base_a.get(bucket, 3)) or base_a.get(bucket, 3))
        old_b = int(b_map.get(bucket, base_b.get(bucket, 1)) or base_b.get(bucket, 1))
        new_a, new_b = old_a, old_b
        if win < 0.40 or avg < -0.5:
            new_a = min(old_a + 1, 5)
            new_b = min(old_b + 1, max(4, new_a))
        elif win > 0.68 and avg > 0.8:
            new_a = max(old_a - 1, 1)
            new_b = max(old_b - 1, 0)
        if (new_a, new_b) != (old_a, old_b):
            a_map[bucket] = new_a
            b_map[bucket] = new_b
            changes.append(
                f"рҹҸ·пёҸ лҲҢлҰјлӘ© мң нҳ•[{label}] A/B кІҢмқҙнҠё мЎ°м •: {old_a}/{old_b}вҶ’{new_a}/{new_b} "
                f"(мҠ№лҘ  {win*100:.0f}%, нҸүк·  {avg:+.1f}%, n={len(subset)})"
            )

    _dynamic["mid_pullback_bucket_a_confirm_min"] = a_map
    _dynamic["mid_pullback_bucket_b_confirm_min"] = b_map

    close_rows = [r for r in mid_recs if bool((r.get("feature_snapshot") or {}).get("mid_close_window"))]
    for stage, key, default_window in (("KRX", "mid_pullback_close_window_min_krx", 20), ("NXT", "mid_pullback_close_window_min_nxt", 25)):
        subset = [r for r in close_rows if str((r.get("feature_snapshot") or {}).get("mid_close_stage", "") or "") == stage]
        if len(subset) < 4:
            continue
        win = sum(1 for r in subset if r.get("pnl_pct", 0) > 0) / len(subset)
        avg = sum(float(r.get("pnl_pct", 0) or 0) for r in subset) / len(subset)
        old_window = int(_dynamic.get(key, default_window) or default_window)
        new_window = old_window
        old_gate = int(_dynamic.get("mid_pullback_close_gate_level", 1) or 1)
        new_gate = old_gate
        if win < 0.40 or avg < -0.7:
            new_window = min(old_window + 5, 45)
            new_gate = min(old_gate + 1, 3)
        elif win > 0.68 and avg > 0.8:
            new_window = max(old_window - 5, 5)
            new_gate = max(old_gate - 1, 0)
        if new_window != old_window:
            _dynamic[key] = new_window
            changes.append(f"рҹ•’ лҲҢлҰјлӘ© л§Ҳк°җліҙмҲҳ[{stage}] мңҲлҸ„мҡ° мЎ°м •: {old_window}вҶ’{new_window}л¶„ (мҠ№лҘ  {win*100:.0f}%, n={len(subset)})")
        if new_gate != old_gate:
            _dynamic["mid_pullback_close_gate_level"] = new_gate
            changes.append(f"рҹ•’ лҲҢлҰјлӘ© л§Ҳк°җліҙмҲҳ кІҢмқҙнҠё: {old_gate}вҶ’{new_gate} (stage {stage}, нҸүк·  {avg:+.1f}%)")

    return changes



def _signal_feedback_sort_key(rec: dict | None = None) -> tuple:
    rec = dict(rec or {})
    exit_ts = f"{rec.get('exit_date','')} {rec.get('exit_time','')}".strip()
    detect_ts = f"{rec.get('detect_date','')} {rec.get('detect_time','')}".strip()
    hit_ts = str(rec.get('entry_hit_time') or '').strip()
    return (exit_ts, hit_ts, detect_ts, str(rec.get('code') or ''), str(rec.get('signal_type') or ''))


def _auto_tune_entry_pullback_ratio_feedback(data: dict, completed: list, tune_state: dict) -> list:
    """мғҒмҠ№мқҙнғҲ лҲ„м Ғ мӢң entry_pullback_ratio мҷ„нҷ”, мҶҗмӢӨ м•…нҷ” мӢң ліҙмҲҳ ліөмӣҗ."""
    changes = []
    try:
        if not isinstance(data, dict):
            return changes

        cur_ratio = round(float(_dynamic.get('entry_pullback_ratio', ENTRY_PULLBACK_RATIO) or ENTRY_PULLBACK_RATIO), 2)
        base_ratio = round(float(get_regime_pullback_ratio() or ENTRY_PULLBACK_RATIO), 2)

        miss_all = []
        for rec in data.values():
            if not isinstance(rec, dict):
                continue
            if str(rec.get('status') or '') != 'м§„мһ…лҜёлӢ¬':
                continue
            miss_all.append(dict(rec))
        miss_all.sort(key=_signal_feedback_sort_key)
        recent_miss = miss_all[-ENTRY_PULLBACK_MISS_LOOKBACK:]

        surge_miss = [r for r in recent_miss if 'мғҒмҠ№мқҙнғҲ' in str(r.get('exit_reason', '') or '')]
        expire_miss = [r for r in recent_miss if 'кё°к°„л§ҢлЈҢ' in str(r.get('exit_reason', '') or '')]

        if len(recent_miss) >= ENTRY_PULLBACK_MISS_MIN_SAMPLES:
            surge_share = len(surge_miss) / len(recent_miss) if recent_miss else 0.0
            avg_surge_away = 0.0
            if surge_miss:
                avg_surge_away = sum(float(r.get('entry_miss_away', 0) or 0) for r in surge_miss) / len(surge_miss)
            if (len(surge_miss) >= max(4, len(expire_miss) + 2)
                    and surge_share >= 0.45
                    and cur_ratio > ENTRY_PULLBACK_RATIO_MIN):
                new_ratio = round(max(ENTRY_PULLBACK_RATIO_MIN, cur_ratio - ENTRY_PULLBACK_ADJUST_STEP), 2)
                if new_ratio != cur_ratio:
                    _dynamic['entry_pullback_ratio'] = new_ratio
                    tune_state['last_entry_pullback_reason'] = f'surge_miss_{len(surge_miss)}of{len(recent_miss)}'
                    tune_state['last_entry_pullback_ts'] = time.time()
                    changes.append(
                        f"рҹҺҜ м§„мһ…к°Җ л№„мңЁ мҷ„нҷ”: {cur_ratio:.2f}вҶ’{new_ratio:.2f} "
                        f"(мөңк·ј м§„мһ…лҜёлӢ¬ {len(recent_miss)}кұҙ мӨ‘ мғҒмҠ№мқҙнғҲ {len(surge_miss)}кұҙ, нҸүк·  {avg_surge_away:+.1f}%)"
                    )
                    cur_ratio = new_ratio

        recent_completed = sorted([dict(r) for r in completed if isinstance(r, dict)], key=_signal_feedback_sort_key)[-ENTRY_PULLBACK_RESULT_LOOKBACK:]
        if len(recent_completed) >= ENTRY_PULLBACK_RESULT_MIN_SAMPLES and cur_ratio < base_ratio:
            losses = [r for r in recent_completed if float(r.get('pnl_pct', 0) or 0) <= 0]
            loss_rate = len(losses) / len(recent_completed) if recent_completed else 0.0
            avg_pnl = sum(float(r.get('pnl_pct', 0) or 0) for r in recent_completed) / len(recent_completed) if recent_completed else 0.0
            stop_hits = sum(1 for r in recent_completed if str(r.get('exit_reason') or '') == 'мҶҗм Ҳк°Җ')
            stop_ratio = stop_hits / len(recent_completed) if recent_completed else 0.0
            if loss_rate >= 0.60 or avg_pnl <= -1.0 or stop_ratio >= 0.35:
                restore_to = round(min(base_ratio, cur_ratio + ENTRY_PULLBACK_ADJUST_STEP), 2)
                if restore_to != cur_ratio:
                    _dynamic['entry_pullback_ratio'] = restore_to
                    tune_state['last_entry_pullback_reason'] = f'loss_guard_{len(recent_completed)}'
                    tune_state['last_entry_pullback_ts'] = time.time()
                    changes.append(
                        f"рҹӣЎ м§„мһ…к°Җ л№„мңЁ ліҙмҲҳ ліөмӣҗ: {cur_ratio:.2f}вҶ’{restore_to:.2f} "
                        f"(мөңк·ј мҷ„лЈҢ {len(recent_completed)}кұҙ мҶҗмӢӨл№„мӨ‘ {loss_rate*100:.0f}% / нҸүк·  {avg_pnl:+.1f}%)"
                    )
                    cur_ratio = restore_to
                old_min = int(_dynamic.get('min_score_normal', 56) or 56)
                new_min = min(old_min + 2, 85)
                if new_min != old_min:
                    _dynamic['min_score_normal'] = new_min
                    changes.append(f"рҹӣЎ мҶҗмӢӨ к°Җл“ң мөңмҶҢм җмҲҳ к°•нҷ”: {old_min}вҶ’{new_min}м җ")
                if stop_ratio >= 0.35:
                    old_atr = round(float(_dynamic.get('atr_stop_mult', ATR_STOP_MULT) or ATR_STOP_MULT), 2)
                    new_atr = round(min(old_atr + 0.1, 2.5), 1)
                    if new_atr != old_atr:
                        _dynamic['atr_stop_mult'] = new_atr
                        changes.append(f"рҹӣЎ мҶҗмӢӨ к°Җл“ң ATR мҶҗм Ҳл°°мҲҳ нҷ•лҢҖ: {old_atr}вҶ’{new_atr}")
    except Exception as e:
        _log_error('_auto_tune_entry_pullback_ratio_feedback', e)
    return changes

def auto_tune(notify: bool = True):
    """
    signal_log.json кё°л°ҳмңјлЎң мӢ нҳё мң нҳ•лі„ м„ұкіјлҘј л¶„м„қн•ҙм„ң
    мЎ°кұҙмқ„ мһҗлҸҷмңјлЎң мЎ°м •. мһҘ л§Ҳк°җл§ҲлӢӨ нҳём¶ң.

    мЎ°м • мӣҗм№ҷ:
      - мҠ№лҘ  < 40%  вҶ’ мЎ°кұҙ к°•нҷ” (лҚ” к№ҢлӢӨлЎӯкІҢ)
      - мҠ№лҘ  > 70%  вҶ’ мЎ°кұҙ мҷ„нҷ” (лҚ” л§Һмқҙ мһЎкё°)
      - 40~70%      вҶ’ мң м§Җ
      - мғҳн”Ң < MIN_SAMPLES(5кұҙ) мқҙл©ҙ мЎ°м • м•Ҳ н•Ё
      - м—°мҶҚ мҶҗм Ҳ 3нҡҢ мқҙмғҒ вҶ’ кёҙкёү мҰүмӢң к°•нҷ”
      - мӢңк°„лҢҖлі„ мҠ№лҘ  лӮ®мқҖ кө¬к°„ вҶ’ н•ҙлӢ№ кө¬к°„ мөңмҶҢм җмҲҳ мғҒн–Ҙ
      - ATR мҶҗм Ҳл°°мҲҳ лҸҷм Ғ мЎ°м •
    """
    global _dynamic, _early_price_min_dynamic, _early_volume_min_dynamic
    global _consecutive_loss_count

    if not _try_acquire_leader_lock():
        print("  вҸё auto_tune мғқлһө вҖ” нҳ„мһ¬ replicaлҠ” лҰ¬лҚ” м•„лӢҳ")
        return

    try:
        before_sig = _current_dynamic_signature()
        before_hash = _payload_hash(before_sig)
        tune_state = _get_auto_tune_state()

        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception:
            return

        # auto_tuneмқҖ мқҙлЎ  лҚ°мқҙн„° м „л¶Җ мӮ¬мҡ© (лҜём§„мһ… нҸ¬н•Ё вҖ” лҙҮ мЎ°кұҙ мөңм Ғнҷ”мҡ©)
        completed = [v for v in data.values()
                     if v.get("status") in ["мҲҳмқө", "мҶҗмӢӨ", "ліём „"]]
        if len(completed) < MIN_SAMPLES:
            return

        changes = []
        changes.extend(_auto_tune_korea_etf_weights(completed))

        # в”Җв”Җ 0) params_snapshot кё°л°ҳ м„ұлҠҘ нҠңлӢқ (мөңм ҒмЎ°кұҙ л§Ңл“Өкё° н•өмӢ¬) в”Җв”Җ
        best = _select_best_params(completed)
        if best:
            try:
                cur_min_n = int(_dynamic.get("min_score_normal", 60))
                cur_min_s = int(_dynamic.get("min_score_strict", 70))
                cur_atr_s = _safe_float(_dynamic.get("atr_stop_mult", 1.5), 1.5)
                cur_atr_t = _safe_float(_dynamic.get("atr_target_mult", 3.0), 3.0)

                cand_min_n = int(best.get("min_score_normal", cur_min_n))
                cand_min_s = int(best.get("min_score_strict", cur_min_s))
                cand_atr_s = _safe_float(best.get("atr_stop_mult", cur_atr_s), cur_atr_s)
                cand_atr_t = _safe_float(best.get("atr_target_mult", cur_atr_t), cur_atr_t)

                new_min_n = int(round(cur_min_n * (1 - TUNE_ALPHA) + cand_min_n * TUNE_ALPHA))
                new_min_s = int(round(cur_min_s * (1 - TUNE_ALPHA) + cand_min_s * TUNE_ALPHA))
                new_atr_s = round(cur_atr_s * (1 - TUNE_ALPHA) + cand_atr_s * TUNE_ALPHA, 2)
                new_atr_t = round(cur_atr_t * (1 - TUNE_ALPHA) + cand_atr_t * TUNE_ALPHA, 2)

                new_min_n = max(45, min(new_min_n, 80))
                new_min_s = max(55, min(new_min_s, 90))
                new_atr_s = max(0.8, min(new_atr_s, 3.5))
                new_atr_t = max(1.5, min(new_atr_t, 6.0))

                if (new_min_n, new_min_s, new_atr_s, new_atr_t) != (cur_min_n, cur_min_s, cur_atr_s, cur_atr_t):
                    _dynamic["min_score_normal"] = new_min_n
                    _dynamic["min_score_strict"] = new_min_s
                    _dynamic["atr_stop_mult"]    = new_atr_s
                    _dynamic["atr_target_mult"]  = new_atr_t

                    changes.append(
                        f"рҹ§  <b>м„ұлҠҘ кё°л°ҳ нҠңлӢқ</b> (мөңк·ј {TUNE_LOOKBACK_DAYS}мқј / n={best.get('_n','?')})\n"
                        f"- score {best.get('_score','?')} кё°мӨҖ best paramsлЎң мҠӨл¬ҙл”© м Ғмҡ©\n"
                        f"- min_score: {cur_min_n}/{cur_min_s} вҶ’ {new_min_n}/{new_min_s}\n"
                        f"- atr_stop/target: {cur_atr_s} / {cur_atr_t} вҶ’ {new_atr_s} / {new_atr_t}"
                    )
            except Exception as te:
                _log_error("auto_tune.params_snapshot", te)

        by_type = {}
        for v in completed:
            t = v.get("signal_type", "кё°нғҖ")
            by_type.setdefault(t, []).append(v)

        # в”Җв”Җ в‘  кёҙкёү нҠңлӢқ: к°ҷмқҖ мғҒнғң мӨ‘ліө мһ¬мӢӨн–ү кёҲм§Җ, м•…нҷ” мӢңл§Ң м¶”к°Җ к°•нҷ” в”Җв”Җ
        recent = sorted(completed, key=lambda x: x.get("exit_date","") + x.get("exit_time",""))[-5:]
        recent_loss_streak = 0
        for r in reversed(recent):
            if r.get("pnl_pct", 0) <= 0:
                recent_loss_streak += 1
            else:
                break

        cur_stage = _emergency_stage(recent_loss_streak)
        prev_stage = int(tune_state.get("emergency_stage", 0) or 0)
        if cur_stage <= 0:
            if tune_state.get("emergency_active") or prev_stage > 0:
                tune_state["emergency_active"] = False
                tune_state["emergency_stage"] = 0
                tune_state["last_emergency_reason"] = "streak_cleared"
                tune_state["last_emergency_ts"] = time.time()
        else:
            tune_state["emergency_active"] = True
            if cur_stage > prev_stage:
                old_n = _dynamic["min_score_normal"]
                old_s = _dynamic["min_score_strict"]
                bump = {1: 8, 2: 5, 3: 5}.get(cur_stage, 4)
                _dynamic["min_score_normal"] = min(old_n + bump, 85)
                _dynamic["min_score_strict"] = min(old_s + bump, 90)
                changes.append(
                    f"рҹҡЁ <b>кёҙкёү нҠңлӢқ[{_emergency_stage_label(cur_stage)}]</b>: м—°мҶҚ мҶҗм Ҳ {recent_loss_streak}нҡҢ\n"
                    f"   мөңмҶҢм җмҲҳ мҰүмӢң к°•нҷ”: {old_n}вҶ’{_dynamic['min_score_normal']}м җ"
                )
                tune_state["emergency_stage"] = cur_stage
                tune_state["last_emergency_reason"] = f"loss_streak_{recent_loss_streak}"
                tune_state["last_emergency_ts"] = time.time()
            else:
                tune_state["emergency_stage"] = max(prev_stage, cur_stage)

        # в”Җв”Җ в‘Ў EARLY_DETECT мЎ°м • в”Җв”Җ
        early_recs = by_type.get("EARLY_DETECT", [])
        if len(early_recs) >= MIN_SAMPLES:
            rate = sum(1 for r in early_recs if r["pnl_pct"] > 0) / len(early_recs)
            old_p = _dynamic["early_price_min"]
            old_v = _dynamic["early_volume_min"]
            if rate < 0.40:
                _dynamic["early_price_min"]  = min(old_p + 2.0, 18.0)
                _dynamic["early_volume_min"] = min(old_v + 2.0, 18.0)
                changes.append(f"рҹ”Қ мЎ°кё°нҸ¬м°© мЎ°кұҙ к°•нҷ” (мҠ№лҘ  {rate*100:.0f}%)\n"
                                f"   к°ҖкІ© {old_p}вҶ’{_dynamic['early_price_min']}%  "
                                f"кұ°лһҳлҹү {old_v}вҶ’{_dynamic['early_volume_min']}л°°")
            elif rate > 0.70:
                _dynamic["early_price_min"]  = max(old_p - 1.0, 7.0)
                _dynamic["early_volume_min"] = max(old_v - 1.0, 7.0)
                changes.append(f"рҹ”Қ мЎ°кё°нҸ¬м°© мЎ°кұҙ мҷ„нҷ” (мҠ№лҘ  {rate*100:.0f}%)\n"
                                f"   к°ҖкІ© {old_p}вҶ’{_dynamic['early_price_min']}%  "
                                f"кұ°лһҳлҹү {old_v}вҶ’{_dynamic['early_volume_min']}л°°")
            _early_price_min_dynamic  = _dynamic["early_price_min"]
            _early_volume_min_dynamic = _dynamic["early_volume_min"]

        # в”Җв”Җ в‘ў MID_PULLBACK мЎ°м • в”Җв”Җ
        mid_recs = by_type.get("MID_PULLBACK", [])
        if len(mid_recs) >= MIN_SAMPLES:
            rate      = sum(1 for r in mid_recs if r["pnl_pct"] > 0) / len(mid_recs)
            old_surge = _dynamic["mid_surge_min_pct"]
            old_min   = _dynamic["mid_pullback_min"]
            old_max   = _dynamic["mid_pullback_max"]
            if rate < 0.40:
                _dynamic["mid_surge_min_pct"] = min(old_surge + 3.0, 25.0)
                _dynamic["mid_pullback_min"]  = min(old_min + 2.0, 15.0)
                _dynamic["mid_pullback_max"]  = max(old_max - 5.0, 30.0)
                changes.append(f"рҹҸҶ лҲҢлҰјлӘ© мЎ°кұҙ к°•нҷ” (мҠ№лҘ  {rate*100:.0f}%)\n"
                                f"   1м°Ёкёүл“ұ {old_surge}вҶ’{_dynamic['mid_surge_min_pct']}%\n"
                                f"   лҲҢлҰјлІ”мң„ {old_min}~{old_max}вҶ’"
                                f"{_dynamic['mid_pullback_min']}~{_dynamic['mid_pullback_max']}%")
            elif rate > 0.70:
                _dynamic["mid_surge_min_pct"] = max(old_surge - 2.0, 10.0)
                _dynamic["mid_pullback_min"]  = max(old_min - 2.0, 8.0)
                changes.append(f"рҹҸҶ лҲҢлҰјлӘ© мЎ°кұҙ мҷ„нҷ” (мҠ№лҘ  {rate*100:.0f}%)\n"
                                f"   1м°Ёкёүл“ұ {old_surge}вҶ’{_dynamic['mid_surge_min_pct']}%")
            changes.extend(_auto_tune_mid_pullback_bucket_params(mid_recs))

        # в”Җв”Җ в‘ў-1 м§„мһ…к°Җ лҜёлӢ¬/мҶҗмӢӨ н”јл“ңл°ұ лЈЁн”„ в”Җв”Җ
        changes.extend(_auto_tune_entry_pullback_ratio_feedback(data, completed, tune_state))

        # в”Җв”Җ в‘Ј мөңмҶҢ м җмҲҳ мЎ°м • в”Җв”Җ
        if len(completed) >= MIN_SAMPLES:
            rate  = sum(1 for r in completed if r["pnl_pct"] > 0) / len(completed)
            old_n = _dynamic["min_score_normal"]
            old_s = _dynamic["min_score_strict"]
            if rate < 0.40:
                _dynamic["min_score_normal"] = min(old_n + 5, 80)
                _dynamic["min_score_strict"] = min(old_s + 5, 85)
                changes.append(f"вӯҗ мөңмҶҢ м җмҲҳ к°•нҷ”: {old_n}вҶ’{_dynamic['min_score_normal']}м җ")
            elif rate > 0.70:
                _dynamic["min_score_normal"] = max(old_n - 3, 50)
                _dynamic["min_score_strict"] = max(old_s - 3, 60)
                changes.append(f"вӯҗ мөңмҶҢ м җмҲҳ мҷ„нҷ”: {old_n}вҶ’{_dynamic['min_score_normal']}м җ")

        # в”Җв”Җ в‘Ө ATR мҶҗм Ҳл°°мҲҳ лҸҷм Ғ мЎ°м • в”Җв”Җ
        stop_hits   = sum(1 for r in completed if r.get("exit_reason") == "мҶҗм Ҳк°Җ")
        timeout_hit = sum(1 for r in completed if r.get("exit_reason") in ["л§ҢлЈҢ", "timeout", TRACK_TIMEOUT_RESULT])
        old_atr     = _dynamic["atr_stop_mult"]
        if len(completed) >= MIN_SAMPLES:
            stop_ratio    = stop_hits   / len(completed)
            timeout_ratio = timeout_hit / len(completed)
            if stop_ratio > 0.50 and old_atr < 2.5:
                _dynamic["atr_stop_mult"] = round(min(old_atr + 0.2, 2.5), 1)
                changes.append(f"рҹ“җ ATR мҶҗм Ҳл°°мҲҳ нҷ•лҢҖ: {old_atr}вҶ’{_dynamic['atr_stop_mult']} (мҶҗм Ҳ л„Ҳл¬ҙ л№ҲлІҲ)")
            elif timeout_ratio > 0.40 and old_atr > 1.0:
                _dynamic["atr_stop_mult"] = round(max(old_atr - 0.2, 1.0), 1)
                changes.append(f"рҹ“җ ATR мҶҗм Ҳл°°мҲҳ м¶•мҶҢ: {old_atr}вҶ’{_dynamic['atr_stop_mult']} (мҶҗм Ҳ л„Ҳл¬ҙ лҠҗмҠЁ)")

        # в”Җв”Җ в‘Ҙ мӢңк°„лҢҖлі„ мҠ№лҘ  л¶„м„қ вҶ’ лӮ®мқҖ кө¬к°„ мөңмҶҢм җмҲҳ мғҒн–Ҙ в”Җв”Җ
        slot_stats = analyze_timeslot_winrate(completed)
        new_slot_adj = dict(_dynamic["timeslot_score_adj"])
        slot_changes = []
        for slot, st in slot_stats.items():
            if st["total"] < 3:
                continue
            old_adj = new_slot_adj.get(slot, 0)
            if st["rate"] < 35 and old_adj < 20:
                new_slot_adj[slot] = old_adj + 5
                slot_changes.append(f"{slot}(мҠ№лҘ {st['rate']:.0f}%вҶ’+{new_slot_adj[slot]}м җ)")
            elif st["rate"] > 70 and old_adj > 0:
                new_slot_adj[slot] = max(old_adj - 3, 0)
                slot_changes.append(f"{slot}(мҠ№лҘ {st['rate']:.0f}%вҶ’м җмҲҳ мҷ„нҷ”)")
        if slot_changes:
            _dynamic["timeslot_score_adj"] = new_slot_adj
            changes.append(f"рҹ•җ мӢңк°„лҢҖлі„ м җмҲҳ мЎ°м •: {', '.join(slot_changes)}")

        # в”Җв”Җ в‘Ұ лӢЁлҸ… vs н…Ңл§Ҳ кІ©м°Ё л¶„м„қ в”Җв”Җ
        solo_recs   = [r for r in completed if not r.get("sector_bonus", 0)]
        themed_recs = [r for r in completed if r.get("sector_bonus", 0)]
        if len(solo_recs) >= 3 and len(themed_recs) >= 3:
            solo_rate   = sum(1 for r in solo_recs   if r["pnl_pct"] > 0) / len(solo_recs)
            themed_rate = sum(1 for r in themed_recs if r["pnl_pct"] > 0) / len(themed_recs)
            gap         = themed_rate - solo_rate
            old_bonus   = _dynamic["themed_score_bonus"]
            if gap > 0.20:
                _dynamic["themed_score_bonus"] = min(old_bonus + 5, 25)
                changes.append(f"рҹҸӯ н…Ңл§Ҳ ліҙл„ҲмҠӨ к°•нҷ”: {old_bonus}вҶ’{_dynamic['themed_score_bonus']}м җ")
            elif gap < -0.10 and old_bonus > 5:
                _dynamic["themed_score_bonus"] = max(old_bonus - 3, 5)
                changes.append(f"рҹҸӯ н…Ңл§Ҳ ліҙл„ҲмҠӨ м¶•мҶҢ: {old_bonus}вҶ’{_dynamic['themed_score_bonus']}м җ")

        # в”Җв”Җ в‘§-1 мҳӨлІ„лӮҳмқҙнҠё мӢ нҳё/кІ°кіј л¶„м„қ в”Җв”Җ
        overnight_recs = [r for r in completed if r.get("feature_flags", {}).get("gap_signal") in ["gap_up", "gap_down", "flat"]]
        if len(overnight_recs) >= 5:
            gap_groups = {}
            for r in overnight_recs:
                g = r.get("feature_flags", {}).get("gap_signal", "flat")
                gap_groups.setdefault(g, []).append(r)
            for gap_label, dyn_key in (("gap_up", "overnight_gapup_bonus"), ("gap_down", "overnight_gapdown_penalty")):
                grp = gap_groups.get(gap_label, [])
                if len(grp) < 3:
                    continue
                win_rate = sum(1 for r in grp if r.get("pnl_pct", 0) > 0) / len(grp)
                avg_pnl = sum(r.get("pnl_pct", 0) for r in grp) / len(grp)
                old_v = int(_dynamic.get(dyn_key, 0) or 0)
                new_v = old_v
                if gap_label == "gap_up":
                    if win_rate > 0.70 and avg_pnl > 1.5:
                        new_v = min(old_v + 2, 8)
                    elif win_rate < 0.40 or avg_pnl < -1.0:
                        new_v = max(old_v - 2, -2)
                else:
                    if win_rate < 0.40 or avg_pnl < -1.0:
                        new_v = min(old_v + 2, 10)
                    elif win_rate > 0.60 and avg_pnl > 0.5:
                        new_v = max(old_v - 1, 0)
                if new_v != old_v:
                    _dynamic[dyn_key] = new_v
                    changes.append(f"рҹҢҷ мҳӨлІ„лӮҳмқҙнҠё[{gap_label}] ліҙм •: {old_v:+d}вҶ’{new_v:+d}м җ (мҠ№лҘ  {win_rate*100:.0f}% / нҸүк·  {avg_pnl:+.1f}%)")

        # в”Җв”Җ в‘Ё мӢӨм Ғ лҰ¬мҠӨнҒ¬ мһҗлҸҷн•ҷмҠө в”Җв”Җ
        risk_recs = [r for r in completed if r.get("feature_flags", {}).get("earnings_risk") in ["warn", "high", "none"]]
        if len(risk_recs) >= MIN_SAMPLES:
            for risk_key, dyn_key, base_default, floor_v in (("warn", "earnings_warn_mult", 0.85, 0.60), ("high", "earnings_high_mult", 0.72, 0.40)):
                with_risk = [r for r in risk_recs if r.get("feature_flags", {}).get("earnings_risk") == risk_key]
                base_recs  = [r for r in risk_recs if r.get("feature_flags", {}).get("earnings_risk") == "none"]
                if len(with_risk) < 3 or len(base_recs) < 3:
                    continue
                win_with  = sum(1 for r in with_risk if r.get("pnl_pct", 0) > 0) / len(with_risk)
                win_base  = sum(1 for r in base_recs  if r.get("pnl_pct", 0) > 0) / len(base_recs)
                avg_with  = sum(r.get("pnl_pct", 0) for r in with_risk) / len(with_risk)
                avg_base  = sum(r.get("pnl_pct", 0) for r in base_recs) / len(base_recs)
                edge = (win_with - win_base) + (avg_with - avg_base) / 20.0
                old_mult = float(_dynamic.get(dyn_key, base_default) or base_default)
                new_mult = old_mult
                if edge < -0.10:
                    new_mult = round(max(old_mult - 0.05, floor_v), 2)
                elif edge > 0.10:
                    new_mult = round(min(old_mult + 0.03, 1.00), 2)
                if new_mult != old_mult:
                    _dynamic[dyn_key] = new_mult
                    changes.append(
                        f"рҹ“… мӢӨм Ғ лҰ¬мҠӨнҒ¬[{risk_key}] л°°мңЁ мЎ°м •: {old_mult:.2f}вҶ’{new_mult:.2f} "
                        f"(мҠ№лҘ  {win_with*100:.0f}% vs л¬ҙлҰ¬мҠӨнҒ¬ {win_base*100:.0f}%)"
                    )

        # в”Җв”Җ в‘Ё-2 feature_snapshot(ліҖлҸҷлҘ /кұ°лһҳлҹү) мһҗлҸҷн•ҷмҠө в”Җв”Җ
        snap_recs = [r for r in completed if isinstance(r.get("feature_snapshot"), dict)]
        if len(snap_recs) >= MIN_SAMPLES * 2:
            for dyn_key, bucket_fn, source_key, label in (
                ("feature_change_adj", _feature_change_bucket, "change_rate", "ліҖлҸҷлҘ "),
                ("feature_volume_adj", _feature_volume_bucket, "volume_ratio", "кұ°лһҳлҹү"),
            ):
                cur_map = _safe_nested_dict(_dynamic, dyn_key, {})
                bucket_groups = {}
                for r in snap_recs:
                    fs = r.get("feature_snapshot") or {}
                    bucket = bucket_fn(fs.get(source_key, 0))
                    bucket_groups.setdefault(bucket, []).append(r)
                for bucket, group in bucket_groups.items():
                    other = [r for b, rs in bucket_groups.items() if b != bucket for r in rs]
                    if len(group) < 3 or len(other) < 3:
                        continue
                    win_g = sum(1 for r in group if r.get("pnl_pct", 0) > 0) / len(group)
                    win_o = sum(1 for r in other if r.get("pnl_pct", 0) > 0) / len(other)
                    avg_g = sum(r.get("pnl_pct", 0) for r in group) / len(group)
                    avg_o = sum(r.get("pnl_pct", 0) for r in other) / len(other)
                    edge = (win_g - win_o) + (avg_g - avg_o) / 18.0
                    old_adj = int(cur_map.get(bucket, 0) or 0)
                    new_adj = old_adj
                    if edge < -0.10:
                        new_adj = max(old_adj - 2, -10)
                    elif edge > 0.10:
                        new_adj = min(old_adj + 2, 10)
                    if new_adj != old_adj:
                        cur_map[bucket] = new_adj
                        changes.append(
                            f"рҹ§Ә {label} н•ҷмҠө[{bucket}] ліҙм •: {old_adj:+d}вҶ’{new_adj:+d}м җ "
                            f"(мҠ№лҘ  {win_g*100:.0f}% vs нғҖкө¬к°„ {win_o*100:.0f}%)"
                        )
                _dynamic[dyn_key] = cur_map

        # в”Җв”Җ в‘Ё-3 м§Җм •н•ҷ м„№н„°лі„ ліҙм • л°°мңЁ мһҗлҸҷн•ҷмҠө в”Җв”Җ
        geo_recs = [r for r in completed if r.get("feature_flags", {}).get("geo_active") and isinstance(r.get("geo_sector_bias"), dict)]
        if len(geo_recs) >= MIN_SAMPLES:
            geo_weights = _safe_nested_dict(_dynamic, "geo_sector_weights", {})
            sector_perf = {}
            for r in geo_recs:
                bias = r.get("geo_sector_bias") or {}
                for sec, raw in bias.items():
                    try:
                        raw_v = float(raw or 0)
                    except Exception:
                        raw_v = 0.0
                    if abs(raw_v) < 1:
                        continue
                    sector_perf.setdefault(sec, []).append(r.get("pnl_pct", 0))
            global_avg = sum(r.get("pnl_pct", 0) for r in geo_recs) / len(geo_recs)
            for sec, pnls in sector_perf.items():
                if len(pnls) < 3:
                    continue
                avg_sec = sum(pnls) / len(pnls)
                old_w = float(geo_weights.get(sec, 1.0) or 1.0)
                new_w = old_w
                if avg_sec < global_avg - 1.5:
                    new_w = round(max(old_w - 0.10, 0.6), 2)
                elif avg_sec > global_avg + 1.5:
                    new_w = round(min(old_w + 0.08, 1.4), 2)
                if new_w != old_w:
                    geo_weights[sec] = new_w
                    changes.append(
                        f"рҹҢҚ м§Җм •н•ҷ м„№н„°[{sec}] л°°мңЁ мЎ°м •: {old_w:.2f}вҶ’{new_w:.2f} "
                        f"(нҸүк·  {avg_sec:+.1f}% vs м „мІҙ {global_avg:+.1f}%)"
                    )
            _dynamic["geo_sector_weights"] = geo_weights

        # в”Җв”Җ в‘© кё°лҠҘлі„ кё°м—¬лҸ„ л¶„м„қ + мһҗлҸҷ к°ҖмӨ‘м№ҳ мЎ°м • в”Җв”Җ
        feat_recs = [r for r in completed if r.get("feature_flags")]
        if len(feat_recs) >= MIN_SAMPLES * 2:
            feat_analyses = {
                "feat_w_rsi":    ("rsi",         lambda r: r.get("feature_flags",{}).get("indic_score_adj",0) != 0),
                "feat_w_ma":     ("ma_aligned",  lambda r: r.get("feature_flags",{}).get("ma_aligned") is True),
                "feat_w_bb":     ("bb_breakout", lambda r: r.get("feature_flags",{}).get("bb_breakout") is True),
                "feat_w_sector": ("sector",      lambda r: r.get("feature_flags",{}).get("sector_bonus",0) > 0),
                "feat_w_nxt":    ("nxt",         lambda r: r.get("feature_flags",{}).get("nxt_delta",0) != 0),
                "feat_w_geo":    ("geo",         lambda r: r.get("feature_flags",{}).get("geo_active", False)),
            }
            for feat_key, (feat_name, feat_filter) in feat_analyses.items():
                with_feat    = [r for r in feat_recs if feat_filter(r)]
                without_feat = [r for r in feat_recs if not feat_filter(r)]
                if len(with_feat) < 3 or len(without_feat) < 3:
                    continue
                win_with    = sum(1 for r in with_feat    if r["pnl_pct"] > 0) / len(with_feat)
                win_without = sum(1 for r in without_feat if r["pnl_pct"] > 0) / len(without_feat)
                avg_with    = sum(r["pnl_pct"] for r in with_feat)    / len(with_feat)
                avg_without = sum(r["pnl_pct"] for r in without_feat) / len(without_feat)
                old_w = _dynamic.get(feat_key, 1.0)
                contribution = (win_with - win_without) + (avg_with - avg_without) / 20

                if contribution < -0.15 and old_w > 0.3:
                    new_w = round(max(old_w - 0.2, 0.2), 1)
                    _dynamic[feat_key] = new_w
                    changes.append(
                        f"рҹ”» [{feat_name}] кё°м—¬лҸ„ м ҖмЎ° вҶ’ к°ҖмӨ‘м№ҳ {old_w}вҶ’{new_w} "
                        f"(мһҲмқ„л•Ң мҠ№лҘ {win_with*100:.0f}% vs м—Ҷмқ„л•Ң {win_without*100:.0f}%)"
                    )
                elif contribution > 0.15 and old_w < 1.5:
                    new_w = round(min(old_w + 0.1, 1.5), 1)
                    _dynamic[feat_key] = new_w
                    changes.append(
                        f"рҹ”ә [{feat_name}] кё°м—¬лҸ„ м–‘нҳё вҶ’ к°ҖмӨ‘м№ҳ {old_w}вҶ’{new_w} "
                        f"(мһҲмқ„л•Ң мҠ№лҘ {win_with*100:.0f}% vs м—Ҷмқ„л•Ң {win_without*100:.0f}%)"
                    )

        # в”Җв”Җ в‘§ RSI кё°к°„ мһҗлҸҷ мЎ°м • в”Җв”Җ
        if len(completed) >= MIN_SAMPLES * 2:
            all_rsi_high = [r for r in completed if r.get("rsi_at_signal", 50) >= 65]
            if len(all_rsi_high) >= 3:
                rsi_high_rate = sum(1 for r in all_rsi_high if r["pnl_pct"] > 0) / len(all_rsi_high)
                old_ob = _dynamic["rsi_overbuy"]
                if rsi_high_rate > 0.65 and old_ob < 80:
                    _dynamic["rsi_overbuy"] = min(old_ob + 2, 80)
                    changes.append(f"рҹ“Ҡ RSI кіјл§ӨмҲҳ кё°мӨҖ мҷ„нҷ”: {old_ob:.0f}вҶ’{_dynamic['rsi_overbuy']:.0f} (кі RSI м„ұкіөлҘ  {rsi_high_rate*100:.0f}%)")
                elif rsi_high_rate < 0.35 and old_ob > 60:
                    _dynamic["rsi_overbuy"] = max(old_ob - 2, 60)
                    changes.append(f"рҹ“Ҡ RSI кіјл§ӨмҲҳ кё°мӨҖ к°•нҷ”: {old_ob:.0f}вҶ’{_dynamic['rsi_overbuy']:.0f} (кі RSI м„ұкіөлҘ  м ҖмЎ°)")

        # в”Җв”Җ v41.63 #3: signal_log н”јл“ңл°ұ лЈЁн”„ нҶөн•© в”Җв”Җ
        try:
            kpi = compute_signal_kpi(completed)
            health_changes = _check_strategy_health(kpi, notify=notify)
            changes.extend(health_changes)

            # KPI кё°лҢҖмҲҳмқөмқҙ мқҢмҲҳмқҙл©ҙ м „мІҙ кё°мӨҖ к°•нҷ”
            if kpi["overall"].get("n", 0) >= KPI_MIN_SAMPLES:
                exp = kpi["overall"].get("expectancy", 0)
                if exp < -0.5:
                    old_n = _dynamic["min_score_normal"]
                    bump = 3 if exp < -1.0 else 2
                    _dynamic["min_score_normal"] = min(old_n + bump, 85)
                    changes.append(
                        f"рҹ“ү кё°лҢҖмҲҳмқө {exp:+.2f}% вҶ’ мөңмҶҢм җмҲҳ +{bump}м җ "
                        f"({old_n}вҶ’{_dynamic['min_score_normal']})"
                    )
                elif exp > 1.5 and _dynamic["min_score_normal"] > 55:
                    _dynamic["min_score_normal"] = max(_dynamic["min_score_normal"] - 2, 50)
                    changes.append(
                        f"рҹҢҹ кё°лҢҖмҲҳмқө {exp:+.2f}% вҶ’ мөңмҶҢм җмҲҳ мҷ„нҷ” "
                        f"(вҶ’{_dynamic['min_score_normal']})"
                    )
        except Exception as _kpi_err:
            _log_error("auto_tune.kpi_feedback", _kpi_err)

        after_sig = _current_dynamic_signature()
        after_hash = _payload_hash(after_sig)

        if after_hash == before_hash:
            _save_auto_tune_state(tune_state)
            print(f"  рҹ§  мһҗлҸҷ мЎ°м •: мң нҡЁ нҢҢлқјлҜён„° ліҖкІҪ м—ҶмқҢ ({len(completed)}кұҙ л¶„м„қ)")
            return

        tune_log = {}
        try:
            with open(AUTO_TUNE_FILE, "r", encoding="utf-8") as f:
                tune_log = json.load(f)
        except Exception:
            pass

        ts_key = datetime.now().strftime("%Y%m%d_%H%M%S")
        while ts_key in tune_log:
            ts_key = datetime.now().strftime("%Y%m%d_%H%M%S") + f"_{random.randint(10,99)}"

        tune_log[ts_key] = {
            "changes": changes,
            "params": {k: v for k, v in _dynamic.items() if k != "timeslot_score_adj"},
            "samples": len(completed),
            "effective_hash": after_hash,
            "instance_id": _INSTANCE_ID,
        }
        _write_json_atomic(AUTO_TUNE_FILE, tune_log, indent=2)

        notify_hash = _payload_hash({
            "effective_hash": after_hash,
            "changes": changes,
            "samples": len(completed),
        })
        if notify:
            if tune_state.get("last_notify_hash") == notify_hash:
                print("  рҹ“Ё мЎ°кұҙ мһҗлҸҷ мЎ°м • м•ҢлҰј мӨ‘ліө мғқлһө (лҸҷмқј ліҖкІҪ)")
            else:
                change_text = "\n".join(changes)
                send(f"рҹ”§ <b>мЎ°кұҙ мһҗлҸҷ мЎ°м • мҷ„лЈҢ</b>\n"
                     f"к·јкұ°: {len(completed)}кұҙ кІ°кіј л¶„м„қ\n"
                     f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                     f"{change_text}\n\n"
                     f"/stats лЎң м „мІҙ нҶөкі„ нҷ•мқё")
                tune_state["last_notify_hash"] = notify_hash

        tune_state["last_effective_hash"] = after_hash
        _save_auto_tune_state(tune_state)
        _save_dynamic_params()

    except Exception as e:
        _log_error("auto_tune", e, critical=True)

