def _record_entry_miss(watch: dict, reason: str, final_price: int):
    """м§„мһ…к°Җ лҜёлҸ„лӢ¬ л§ҢлЈҢ мӢң signal_logм—җ кё°лЎқ вҶ’ auto_tune н•ҷмҠө"""
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception: pass
        entry     = watch.get("entry_price", 0)
        miss_away = round((final_price - entry) / entry * 100, 1) if entry else 0
        peak      = watch.get("peak_price", final_price)
        peak_away = round((peak - entry) / entry * 100, 1) if entry else 0
        target_log_key = str(watch.get("signal_log_key") or "").strip()
        for log_key, rec in data.items():
            if target_log_key and log_key != target_log_key:
                continue
            if (rec.get("code") == watch["code"]
                    and rec.get("status") in ("м¶”м ҒмӨ‘", "м§„мһ…мӨҖл№„")
                    and rec.get("signal_type") == watch.get("signal_type")):
                rec["entry_miss"]      = reason
                rec["entry_miss_away"] = miss_away
                rec["entry_peak_away"] = peak_away
                rec["miss_count"]      = watch.get("miss_count", 0)
                if watch.get("entry_reference_market") or rec.get("entry_reference_market"):
                    rec["status"]      = "NXTм°ёкі лҸ„лӢ¬"
                    rec["pnl_pct"]     = 0.0
                    _ref_market = watch.get("entry_reference_market") or rec.get("entry_reference_market") or "NXT"
                    _ref_reason = watch.get("entry_reference_reason") or rec.get("entry_reference_reason") or reason
                    rec["exit_reason"] = f"{_ref_market}м°ёкі лҸ„лӢ¬_{_ref_reason}"
                elif watch.get("entry_blocked") or rec.get("entry_blocked"):
                    rec["status"]      = "м§„мһ…л¶Ҳк°Җ"
                    rec["pnl_pct"]     = 0.0
                    _blk_reason = watch.get("entry_blocked_reason") or rec.get("entry_blocked_reason") or reason
                    rec["exit_reason"] = f"м§„мһ…л¶Ҳк°Җ_{_blk_reason}"
                else:
                    rec["status"]      = "м§„мһ…лҜёлӢ¬"
                    rec["pnl_pct"]     = 0.0
                    rec["exit_reason"] = f"м§„мһ…лҜёлӢ¬_{reason}"
                break
        _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
        print(f"  рҹ“қ м§„мһ…лҜёлӢ¬ кё°лЎқ: {watch['name']} {reason} (м§„мһ…к°Җ лҢҖл№„ {miss_away:+.1f}%)")
    except Exception as e:
        print(f"вҡ пёҸ м§„мһ…лҜёлӢ¬ кё°лЎқ мҳӨлҘҳ: {e}")


# [v58] мғҒмҠ№мқҙнғҲ нӣ„мҶҚ м¶”м Ғ вҖ” мқҙнғҲ мў…лӘ©мқҙ мқҙнӣ„ м–јл§ҲлӮҳ лҚ” мҳ¬лһҗлҠ”м§Җ кё°лЎқ
def _track_escape_aftermath() -> list:
    """
    лӢ№мқј мғҒмҠ№мқҙнғҲлҗң мў…лӘ©мқҳ нҳ„мһ¬к°ҖлҘј мЎ°нҡҢн•ҙ 'мқҙнғҲ нӣ„ м¶”к°Җ мғҒмҠ№лҘ 'мқ„ signal_logм—җ кё°лЎқ.
    run_daily_self_audit мӢңм җм—җ нҳём¶ң вҶ’ entry_pullback_ratio м •л°Җ мЎ°м • лҚ°мқҙн„°лЎң нҷңмҡ©.
    л°ҳнҷҳ: ліҖкІҪ мҡ”м•Ҫ лҰ¬мҠӨнҠё
    """
    changes = []
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE) if os.path.exists(SIGNAL_LOG_FILE) else {}
        if not isinstance(data, dict):
            return changes
        today = _now_kst().strftime("%Y%m%d")
        updated = False

        for log_key, rec in data.items():
            if not isinstance(rec, dict):
                continue
            # мҳӨлҠҳ мғҒмҠ№мқҙнғҲлҗң мў…лӘ©л§Ң
            if str(rec.get("status") or "") != "м§„мһ…лҜёлӢ¬":
                continue
            if "мғҒмҠ№мқҙнғҲ" not in str(rec.get("exit_reason") or ""):
                continue
            if str(rec.get("detect_date") or "")[:8] != today and str(rec.get("exit_date") or "")[:8] != today:
                continue
            # мқҙлҜё нӣ„мҶҚ м¶”м Ғ мҷ„лЈҢлҗң кұҙмқҖ кұҙл„Ҳлӣ°кё°
            if rec.get("escape_aftermath_pct") is not None:
                continue

            code = normalize_stock_code(rec.get("code"))
            if not code:
                continue
            entry = safe_int(rec.get("entry_price", 0), 0)
            if not entry:
                continue

            # нҳ„мһ¬к°Җ мЎ°нҡҢ
            try:
                cur = get_stock_price(code)
                price = cur.get("price", 0)
                if not price:
                    nxt_cur = get_nxt_stock_price(code)
                    price = nxt_cur.get("price", 0)
                if not price:
                    continue
            except Exception:
                continue

            # м§„мһ…к°Җ лҢҖл№„ нҳ„мһ¬к°Җ мғҒмҠ№лҘ  = "м§„мһ…н–ҲлҚ”лқјл©ҙ м–јл§ҲлӮҳ лІҢм—Ҳмқ„к№Ң"
            aftermath_pct = round((price - entry) / entry * 100, 2)
            # мқҙнғҲ мӢңм җ к°ҖкІ© лҢҖл№„ м¶”к°Җ мғҒмҠ№лҘ 
            escape_price = safe_int(rec.get("entry_peak_away", 0), 0)
            miss_away = float(rec.get("entry_miss_away", 0) or 0)

            rec["escape_aftermath_pct"] = aftermath_pct
            rec["escape_aftermath_price"] = price
            rec["escape_aftermath_ts"] = _now_kst().strftime("%Y-%m-%d %H:%M:%S")
            updated = True

            name = rec.get("name", code)
            changes.append(
                f"рҹ“Ҡ мғҒмҠ№мқҙнғҲ нӣ„мҶҚ: {name} м§„мһ…к°Җ {entry:,}мӣҗ вҶ’ нҳ„мһ¬ {price:,}мӣҗ ({aftermath_pct:+.1f}%)"
            )

        if updated:
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)

        # entry_pullback_ratio м •л°Җ мЎ°м • лҚ°мқҙн„°лЎң нҷңмҡ©
        if changes:
            _refine_pullback_ratio_from_escape(data)

    except Exception as e:
        print(f"вҡ пёҸ мғҒмҠ№мқҙнғҲ нӣ„мҶҚ м¶”м Ғ мҳӨлҘҳ: {e}")
    return changes


def _refine_pullback_ratio_from_escape(data: dict):
    """
    мғҒмҠ№мқҙнғҲ нӣ„мҶҚ м¶”м Ғ лҚ°мқҙн„° кё°л°ҳ entry_pullback_ratio лҜём„ё мЎ°м •.
    мқҙнғҲ нӣ„м—җлҸ„ кі„мҶҚ мҳӨлҘё мў…лӘ©мқҙ л§Һмңјл©ҙ вҶ’ м§„мһ…к°ҖлҘј мўҖ лҚ” нҳ„мһ¬к°Җм—җ к°Җк№қкІҢ (мҷ„нҷ”)
    мқҙнғҲ нӣ„ н•ҳлқҪн•ң мў…лӘ©мқҙ л§Һмңјл©ҙ вҶ’ нҳ„мһ¬ м§„мһ…к°Җ м„Өм •мқҙ м Ғм Ҳ (мң м§Җ)
    """
    try:
        # мөңк·ј 20кұҙмқҳ мғҒмҠ№мқҙнғҲ нӣ„мҶҚ лҚ°мқҙн„°
        escape_recs = [
            rec for rec in data.values()
            if isinstance(rec, dict)
            and rec.get("escape_aftermath_pct") is not None
            and "мғҒмҠ№мқҙнғҲ" in str(rec.get("exit_reason") or "")
        ]
        escape_recs.sort(key=lambda r: str(r.get("escape_aftermath_ts") or ""))
        recent = escape_recs[-20:]
        if len(recent) < 5:
            return

        # мқҙнғҲ нӣ„ +10% мқҙмғҒ лҚ” мҳӨлҘё мў…лӘ© л№„мңЁ
        still_rising = [r for r in recent if float(r.get("escape_aftermath_pct", 0) or 0) >= 10.0]
        still_rising_pct = len(still_rising) / len(recent)

        # мқҙнғҲ нӣ„ 0% мқҙн•ҳ(м§„мһ…к°Җ м•„лһҳ)лЎң лӮҙл Өк°„ мў…лӘ© л№„мңЁ
        came_back = [r for r in recent if float(r.get("escape_aftermath_pct", 0) or 0) <= 0]
        came_back_pct = len(came_back) / len(recent)

        avg_aftermath = sum(float(r.get("escape_aftermath_pct", 0) or 0) for r in recent) / len(recent)

        cur_ratio = round(float(_dynamic.get('entry_pullback_ratio', ENTRY_PULLBACK_RATIO) or ENTRY_PULLBACK_RATIO), 2)

        # мқҙнғҲ нӣ„ кі„мҶҚ мҳӨлҘҙлҠ” л№„мңЁмқҙ 60% мқҙмғҒ + нҸүк·  +15% мқҙмғҒ вҶ’ мҷ„нҷ” м••л Ҙ
        if still_rising_pct >= 0.60 and avg_aftermath >= 15.0 and cur_ratio > ENTRY_PULLBACK_RATIO_MIN:
            new_ratio = round(max(ENTRY_PULLBACK_RATIO_MIN, cur_ratio - 0.3), 2)
            if new_ratio != cur_ratio:
                _dynamic['entry_pullback_ratio'] = new_ratio
                _save_dynamic_params()
                print(f"  рҹ“Ҡ мқҙнғҲ нӣ„мҶҚ кё°л°ҳ м§„мһ…к°Җ мҷ„нҷ”: {cur_ratio:.2f}вҶ’{new_ratio:.2f} "
                      f"(мқҙнғҲ нӣ„ +10%вҶ‘ {len(still_rising)}/{len(recent)}, нҸүк·  {avg_aftermath:+.1f}%)")

        # мқҙнғҲ нӣ„ лҗҳлҸҢм•„мҳЁ л№„мңЁмқҙ 40% мқҙмғҒ вҶ’ нҳ„мһ¬ м„Өм • м Ғм Ҳ, ліҙмҲҳнҷ” н•„мҡ” м—ҶмқҢ
        elif came_back_pct >= 0.40:
            print(f"  рҹ“Ҡ мқҙнғҲ нӣ„мҶҚ л¶„м„қ: мқҙнғҲ нӣ„ лҗҳлҸҢлҰј {len(came_back)}/{len(recent)} вҖ” нҳ„мһ¬ л№„мңЁ {cur_ratio:.2f} мң м§Җ")

    except Exception as e:
        print(f"вҡ пёҸ мқҙнғҲ нӣ„мҶҚ л№„мңЁ мЎ°м • мҳӨлҘҳ: {e}")


def _mark_entry_hit_in_signal_log(code: str, signal_type: str, hit_price: int | None = None, hit_time: str | None = None, log_key: str | None = None) -> None:
    """м§„мһ…к°Җ лҸ„лӢ¬(HIT) мқҙлІӨнҠёлҘј signal_logм—җ кё°лЎқ. (к°ҖмғҒм§„мһ…/н•ҷмҠөмҡ©)"""
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception:
            return
        now_s = str(hit_time or datetime.now().strftime('%Y-%m-%d %H:%M:%S'))
        hit_date, hit_clock = "", ""
        if " " in now_s:
            hit_date, hit_clock = now_s.split(" ", 1)
        elif len(now_s) >= 10:
            hit_date = now_s[:10]

        target_key = ""
        if log_key and log_key in data:
            _rec = data.get(log_key) or {}
            if _rec.get('code') == code and _rec.get('status') in ('м¶”м ҒмӨ‘', 'м§„мһ…мӨҖл№„'):
                target_key = log_key

        if not target_key:
            candidates = []
            for _k, rec in data.items():
                if rec.get('code') == code and rec.get('status') in ('м¶”м ҒмӨ‘', 'м§„мһ…мӨҖл№„') and rec.get('signal_type') == signal_type:
                    detect_key = f"{rec.get('detect_date','')}{rec.get('detect_time','')}".replace(":", "")
                    candidates.append((detect_key, _k))
            if candidates:
                candidates.sort()
                target_key = candidates[-1][1]

        if target_key:
            rec = data.get(target_key) or {}
            rec['entry_hit'] = True
            rec['entry_hit_time'] = now_s
            rec['entry_blocked'] = False
            rec['entry_blocked_reason'] = ''
            rec['entry_reachable_but_untradable'] = False
            rec['entry_reference_only'] = False
            rec['entry_reference_market'] = ''
            rec['entry_reference_reason'] = ''
            rec['entry_reference_time'] = ''
            rec['entry_reference_date'] = ''
            rec['entry_reference_clock'] = ''
            rec['entry_reference_price'] = 0
            if hit_price:
                rec['entry_hit_price'] = int(hit_price)
            if hit_date:
                rec['entry_hit_date'] = hit_date
            if hit_clock:
                rec['entry_hit_clock'] = hit_clock
            data[target_key] = rec
            _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)
    except Exception as e:
        print(f"вҡ пёҸ entry_hit кё°лЎқ мҳӨлҘҳ: {e}")


def _lookup_entry_hit_fallback(rec: dict | None) -> dict:
    """recм—җ лҸ„лӢ¬ л©”нғҖк°Җ л№„м–ҙ мһҲмқ„ л•Ң signal_log/_entry_watchм—җм„ң ліҙк°•мҡ© entry_hit м •ліҙлҘј мЎ°нҡҢ."""
    rec = rec or {}
    out = {}
    code = str(rec.get('code') or '').strip()
    signal_type = str(rec.get('signal_type') or '').strip()
    log_key = str(rec.get('log_key') or '').strip()

    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
        if isinstance(data, dict):
            target = None
            if log_key and isinstance(data.get(log_key), dict):
                _exact = data.get(log_key) or {}
                if not code or _exact.get('code') == code:
                    target = _exact
            if not target and code:
                candidates = []
                for _k, _rec in data.items():
                    if not isinstance(_rec, dict):
                        continue
                    if _rec.get('code') != code:
                        continue
                    if signal_type and _rec.get('signal_type') != signal_type:
                        continue
                    has_hit_meta = any(_rec.get(_k) not in (None, '', False) for _k in (
                        'entry_hit_time', 'entry_hit_price', 'legacy_entry_hit_time', 'legacy_entry_hit_price'
                    ))
                    if not has_hit_meta and _rec.get('status') not in ('м¶”м ҒмӨ‘', 'м§„мһ…мӨҖл№„'):
                        continue
                    detect_key = f"{_rec.get('detect_date','')}{_rec.get('detect_time','')}".replace(":", "")
                    candidates.append((detect_key, _rec))
                if candidates:
                    candidates.sort(key=lambda x: x[0])
                    target = candidates[-1][1]
            if isinstance(target, dict):
                for _k in ('entry_hit', 'entry_hit_price', 'entry_hit_time', 'entry_hit_date', 'entry_hit_clock'):
                    if target.get(_k) not in (None, '', False):
                        out[_k] = target.get(_k)
                legacy_map = {
                    'legacy_entry_hit_price': 'entry_hit_price',
                    'legacy_entry_hit_time': 'entry_hit_time',
                    'legacy_entry_hit_date': 'entry_hit_date',
                    'legacy_entry_hit_clock': 'entry_hit_clock',
                }
                for _src, _dst in legacy_map.items():
                    if out.get(_dst) in (None, '', False) and target.get(_src) not in (None, '', False):
                        out[_dst] = target.get(_src)
    except Exception:
        pass

    if code and (not out.get('entry_hit_time') or not out.get('entry_hit_price')):
        try:
            watch = _latest_entry_watch_by_code(code)
            if isinstance(watch, dict) and watch.get('entry_hit'):
                for _k in ('entry_hit', 'entry_hit_price', 'entry_hit_time', 'entry_hit_date', 'entry_hit_clock'):
                    if watch.get(_k) not in (None, '', False):
                        out[_k] = watch.get(_k)
        except Exception:
            pass
    return out


def _get_entry_hit_display(rec: dict | None) -> tuple[int | None, str]:
    """м§„мһ…к°Җ лҸ„лӢ¬ кҙҖл Ё н‘ңмӢңмҡ© лҚ°мқҙн„°(лҸ„лӢ¬к°Җ, лҸ„лӢ¬мӢңк°Ғ л¬ёмһҗм—ҙ) л°ҳнҷҳ."""
    rec = dict(rec or {})
    if rec.get('entry_hit_price') in (None, '', False) and rec.get('legacy_entry_hit_price') not in (None, '', False):
        rec['entry_hit_price'] = rec.get('legacy_entry_hit_price')
    if rec.get('entry_hit_time') in (None, '', False) and rec.get('legacy_entry_hit_time') not in (None, '', False):
        rec['entry_hit_time'] = rec.get('legacy_entry_hit_time')
    if rec.get('entry_hit_date') in (None, '', False) and rec.get('legacy_entry_hit_date') not in (None, '', False):
        rec['entry_hit_date'] = rec.get('legacy_entry_hit_date')
    if rec.get('entry_hit_clock') in (None, '', False) and rec.get('legacy_entry_hit_clock') not in (None, '', False):
        rec['entry_hit_clock'] = rec.get('legacy_entry_hit_clock')

    if not rec.get('entry_hit_time') or not rec.get('entry_hit_price'):
        try:
            rec.update(_lookup_entry_hit_fallback(rec))
        except Exception:
            pass

    hit_price = None
    try:
        _hp = rec.get('entry_hit_price')
        if _hp:
            hit_price = int(_hp)
    except Exception:
        hit_price = None

    hit_time = str(rec.get('entry_hit_time') or '').strip()
    if not hit_time:
        hit_date = str(rec.get('entry_hit_date') or '').strip()
        hit_clock = str(rec.get('entry_hit_clock') or '').strip()
        if hit_date and hit_clock:
            hit_time = f"{hit_date} {hit_clock}"
        else:
            hit_time = hit_date or hit_clock
    return hit_price, hit_time

def _build_entry_hit_line(entry: int, rec: dict | None = None, include_hit_price: bool = False, include_hit_time: bool = True) -> str:
    parts = [f"рҹҺҜ м§„мһ…к°Җ: <b>{int(entry):,}мӣҗ</b>"]
    hit_price, hit_time = _get_entry_hit_display(rec)
    if include_hit_price and hit_price:
        parts.append(f"лҸ„лӢ¬к°Җ <b>{hit_price:,}мӣҗ</b>")
    if include_hit_time and hit_time:
        parts.append(f"лҸ„лӢ¬мӢңк°Ғ {hit_time}")
    return "  |  ".join(parts)

def _has_entry_hit_metadata(rec: dict | None = None) -> bool:
    try:
        hit_price, hit_time = _get_entry_hit_display(dict(rec or {}))
        return hit_price not in (None, '', False) and bool(str(hit_time or '').strip())
    except Exception:
        return False

def _should_send_trailing_mode_message(rec: dict | None = None) -> bool:
    return _has_entry_hit_metadata(rec)

def _tracking_record_sort_key(rec: dict | None = None):
    rec = dict(rec or {})
    detect_ts = f"{rec.get('detect_date','')} {rec.get('detect_time','')}".strip()
    hit_ts = str(rec.get('entry_hit_time') or '').strip()
    target = float(rec.get('target_price', 0) or 0)
    entry = float(rec.get('entry_price', 0) or 0)
    return (bool(rec.get('entry_hit')), hit_ts, detect_ts, target, entry)

def _is_representative_tracking_record(data: dict | None, log_key: str, rec: dict | None = None) -> bool:
    data = data or {}
    rec = dict(rec or {})
    code = str(rec.get('code') or '').strip()
    if not code:
        return True
    same = []
    for k, v in data.items():
        if not isinstance(v, dict):
            continue
        if str(v.get('code') or '').strip() != code:
            continue
        if v.get('status') != 'м¶”м ҒмӨ‘':
            continue
        same.append((k, v))
    if not same:
        return True
    best_key, _ = max(same, key=lambda kv: _tracking_record_sort_key(kv[1]))
    return best_key == log_key

def _format_nxt_transition_delta_block(watch: dict) -> str:
    lines = []
    base_grade = str(watch.get("execution_grade_at_detect") or watch.get("grade_at_detect") or watch.get("grade") or "").upper()
    cur_grade = str(watch.get("execution_grade") or watch.get("grade") or "").upper()
    if base_grade and cur_grade and base_grade != cur_grade:
        lines.append(f"- л“ұкёү ліҖнҷ”: {base_grade} вҶ’ {cur_grade}")
    base_entry = safe_int(watch.get("entry_price_at_detect", watch.get("entry_price_orig", watch.get("entry_price", 0))), 0)
    cur_entry = safe_int(watch.get("entry_price", 0), 0)
    if base_entry > 0 and cur_entry > 0 and base_entry != cur_entry:
        pct = ((cur_entry - base_entry) / base_entry) * 100.0
        lines.append(f"- м§„мһ…к°Җ мЎ°м •: {base_entry:,}мӣҗ вҶ’ {cur_entry:,}мӣҗ ({pct:+.1f}%)")
    if not lines:
        return ""
    return "рҹ”„ <b>NXT л°ҳмҳҒ ліҖнҷ”</b>\n" + "\n".join(lines) + "\n\n"


def check_entry_watch():
    if not _entry_watch: return
    expired: list[tuple[str, str, str]] = []
    changed_active = False
    for log_key, watch in list(_entry_watch.items()):
        # в”Җв”Җ л§ҢлЈҢ мІҙнҒ¬ (3мқј) в”Җв”Җ
        if time.time() > watch.get("expire_ts", watch["registered_ts"] + 86400):
            _record_entry_miss(watch, "кё°к°„л§ҢлЈҢ", watch.get("peak_price", 0))
            miss_count = watch.get("miss_count", 0) + 1
            if miss_count >= 3:
                old_ratio = _dynamic.get("entry_pullback_ratio", ENTRY_PULLBACK_RATIO)
                if old_ratio > 0.15:
                    _dynamic["entry_pullback_ratio"] = round(old_ratio - 0.05, 2)
                    _save_dynamic_params()
                    print(f"  рҹ”§ м§„мһ…к°Җ л№„мңЁ мҷ„нҷ”: {old_ratio:.2f}вҶ’{_dynamic['entry_pullback_ratio']:.2f} (лҜёлҸ„лӢ¬ {miss_count}нҡҢ)")
            expired.append((log_key, "кё°к°„л§ҢлЈҢ", _entry_watch_final_status(watch))); continue

        try:
            code = watch["code"]
            krx_ok = is_market_open()
            nxt_ok = (not krx_ok) and is_nxt_open() and is_nxt_listed(code)
            nxt_reference_ok = krx_ok and is_nxt_open() and is_nxt_listed(code)
            use_nxt = False
            reference_only = False
            reference_reason = ""

            if krx_ok:
                cur = get_stock_price(code)
                price = cur.get("price", 0)
                if not price:
                    continue
                if nxt_reference_ok and _is_krx_vi_reference_mode(cur, code):
                    nxt_cur = get_nxt_stock_price(code)
                    nxt_price = nxt_cur.get("price", 0)
                    if nxt_price:
                        cur = nxt_cur
                        price = nxt_price
                        reference_only = True
                        reference_reason = "krx_vi_reference"
                        # v41.77 #2: м°ЁлӢЁ лҢҖмӢ  KRX м •к·ңмһҘ м¶”м Ғ м „нҷҳ л“ұлЎқ
                        if not watch.get("nxt_surge_tracked"):
                            _register_nxt_surge_to_krx_watch(watch, nxt_price)
            elif nxt_ok:
                use_nxt = True
                cur = get_nxt_stock_price(code)
                price = cur.get("price", 0)
                if not price:
                    continue
            else:
                continue

            # мөңкі к°Җ к°ұмӢ 
            if price > watch.get("peak_price", 0):
                watch["peak_price"] = price
                changed_active = True
            low_price = safe_int(watch.get("low_price", 0), 0)
            if low_price <= 0 or price <= low_price:
                watch["low_price"] = int(price or 0)
                watch["low_price_time"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                watch["volume_at_low"] = safe_int(cur.get("today_vol", watch.get("volume_at_low", 0)), safe_int(watch.get("volume_at_low", 0), 0))
                changed_active = True
            if watch.get("entry_hit_locked"):
                continue

            entry    = watch["entry_price"]
            diff_pct = (price - entry) / entry * 100

            # в”Җв”Җ мғҒмҠ№ мқҙнғҲ: ATRГ—көӯл©ҙ кё°л°ҳ кё°мӨҖ мқҙмғҒ мҳӨлҘҙл©ҙ нҸ¬кё° в”Җв”Җ
            _escape_pct = calc_surge_escape_pct(watch["code"], entry)
            if diff_pct >= _escape_pct:
                _record_entry_miss(watch, "мғҒмҠ№мқҙнғҲ", price)
                send_with_chart_buttons(
                    f"рҹ“Ҳ <b>[м§„мһ…к°Җ мқҙнғҲ]</b>\n"
                    f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                    f"<b>{watch['name']}</b>  <code>{watch['code']}</code>\n"
                    f"м§„мһ…к°Җ {entry:,}мӣҗм—җм„ң +{diff_pct:.1f}% мғҒмҠ№ мқҙнғҲ\n"
                    f"м§„мһ… кё°нҡҢ м—Ҷмқҙ мғҒмҠ№ вҶ’ к°җмӢң мў…лЈҢ",
                    watch["code"], watch["name"]
                )
                expired.append((log_key, "мғҒмҠ№мқҙнғҲ", _entry_watch_final_status(watch, "м§„мһ…лҜёлӢ¬"))); continue

            # в”Җв”Җ м—„кІ©нҳ• м§„мһ…к°Җ лҸ„лӢ¬: нҳ„мһ¬к°Җк°Җ м§„мһ…к°Җ мқҙн•ҳмқј л•Ңл§Ң мқём • в”Җв”Җ
            if price <= entry:
                if reference_only:
                    if not watch.get("entry_reference_only"):
                        watch["entry_reference_only"] = True
                        watch["entry_reference_market"] = "NXT"
                        watch["entry_reference_reason"] = reference_reason or "krx_vi_reference"
                        watch["entry_reference_time"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                        watch["entry_reference_price"] = int(price or 0)
                        changed_active = True
                        _record_entry_reference_reach(watch, price, market="NXT", reason=reference_reason or "krx_vi_reference")
                        _log_suppressed_alert(
                            watch["code"], watch["name"],
                            f"NXT м°ёкі  лҸ„лӢ¬ ({reference_reason or 'krx_vi_reference'})",
                            watch.get("signal_type", ""),
                            {"entry_price": entry, "reference_price": int(price or 0), "market": "NXT"}
                        )
                    continue

                now_ts       = time.time()
                last_ts      = watch.get("last_notified_ts", 0)
                notify_count = watch.get("notify_count", 0)
                cooldown_sec = ENTRY_REWATCH_MINS * 60
                # v41.66: 1м°Ё(0нҡҢ)+2м°Ё(1нҡҢ) = мөңлҢҖ 2нҡҢ м•ҢлҰј
                if notify_count >= 2:
                    expired.append((log_key, "м•ҢлҰјнҡҹмҲҳл§ҢлЈҢ", _entry_watch_final_status(watch, "м§„мһ…лҜёлӢ¬")))
                    continue
                if now_ts - last_ts < cooldown_sec: continue

                _entry_exec_metrics = _entry_exec_metrics if isinstance(locals().get("_entry_exec_metrics"), dict) else get_execution_speed_metrics(watch["code"], current_price=price)
                if not should_skip_expiration_for_dart_watch(watch):
                    strength_now = _classify_signal_strength(watch, _entry_exec_metrics)
                    vol_now = float(cur.get("volume_ratio", watch.get("volume_ratio", 0)) or 0)
                    vol_at_detect = float(watch.get("volume_ratio_at_detect", watch.get("volume_ratio", vol_now)) or vol_now)
                    if strength_now == "м•Ҫн•ң":
                        _record_entry_dropped(watch, "к·јкұ°м•Ҫнҷ”_мӢ нҳёк°•лҸ„м•Ҫн•Ё", price)
                        expired.append((log_key, "к·јкұ°м•Ҫнҷ”_мӢ нҳёк°•лҸ„м•Ҫн•Ё", "к·јкұ°нғҲлқҪ"))
                        continue
                    if vol_at_detect > 0 and vol_now < vol_at_detect * 0.5:
                        _record_entry_dropped(watch, "к·јкұ°м•Ҫнҷ”_кұ°лһҳлҹүнҸӯлқҪ", price)
                        expired.append((log_key, "к·јкұ°м•Ҫнҷ”_кұ°лһҳлҹүнҸӯлқҪ", "к·јкұ°нғҲлқҪ"))
                        continue

                # v40.0-#2: м„№н„° м•Ҫм„ё мӢң м§„мһ…к°Җ лҸ„лӢ¬ м•ҢлҰј м°ЁлӢЁ (лӮҙл¶Җ лЎңк·ёл§Ң)
                _sector_blocked = False
                try:
                    _s_theme = watch.get("sector_theme", "")
                    if _s_theme and _s_theme != "кё°нғҖм—…мў…":
                        for _tk, _ti in THEME_MAP.items():
                            if _tk == _s_theme or _s_theme in _ti.get("desc", ""):
                                _chg_list = []
                                for _sc, _sn in _ti.get("stocks", [])[:5]:
                                    try:
                                        _sp = get_stock_price(_sc)
                                        _cr = _sp.get("change_rate", 0)
                                        if _cr is not None:
                                            _chg_list.append(float(_cr))
                                        time.sleep(0.05)
                                    except Exception:
                                        continue
                                if _chg_list and (sum(_chg_list) / len(_chg_list)) <= -3.0:
                                    _sector_blocked = True
                                    _log_suppressed_alert(
                                        watch["code"], watch["name"],
                                        f"м„№н„° м•Ҫм„ё м°ЁлӢЁ (м„№н„° {_s_theme} нҸүк·  {sum(_chg_list)/len(_chg_list):.1f}%)",
                                        watch.get("signal_type", ""),
                                        {"sector_avg_chg": round(sum(_chg_list)/len(_chg_list), 1)}
                                    )
                                break
                except Exception:
                    pass
                if _sector_blocked:
                    continue  # мӮ¬мҡ©мһҗ м•ҢлҰј м°ЁлӢЁ, лӮҙл¶Җ лЎңк·ёл§Ң кё°лЎқ

                _blocked_reason = _detect_entry_block_reason(cur, watch, price, entry)
                if _blocked_reason:
                    if _blocked_reason == "no_ask_liquidity" and _should_soft_allow_no_ask_liquidity(cur, watch):
                        _log_suppressed_alert(
                            watch["code"], watch["name"],
                            f"м§„мһ…нҳёк°Җ кІҪкі (soft) ({_blocked_reason})",
                            watch.get("signal_type", ""),
                            {"entry_price": entry, "blocked_price": int(price or 0), "change_rate": cur.get("change_rate", 0), "ask_qty": cur.get("ask_qty", 0), "bid_qty": cur.get("bid_qty", 0)}
                        )
                        continue
                    watch["entry_blocked"] = True
                    watch["entry_blocked_reason"] = _blocked_reason
                    watch["entry_blocked_time"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                    watch["entry_blocked_price"] = int(price or 0)
                    changed_active = True
                    _record_entry_blocked(watch, _blocked_reason, price)
                    _log_suppressed_alert(
                        watch["code"], watch["name"],
                        f"м§„мһ…л¶Ҳк°Җ м°ЁлӢЁ ({_blocked_reason})",
                        watch.get("signal_type", ""),
                        {"entry_price": entry, "blocked_price": int(price or 0), "change_rate": cur.get("change_rate", 0), "ask_qty": cur.get("ask_qty", 0), "bid_qty": cur.get("bid_qty", 0)}
                    )
                    continue

                watch["last_notified_ts"] = now_ts
                watch["notify_count"]     = notify_count + 1
                watch["entry_reference_only"] = False
                watch["entry_reference_market"] = ""
                watch["entry_reference_reason"] = ""
                watch["entry_reference_time"] = ""
                watch["entry_reference_price"] = 0
                changed_active = True
                sig_labels = {
                    "UPPER_LIMIT":"мғҒн•ңк°Җ","NEAR_UPPER":"мғҒн•ңк°Җк·јм ‘","SURGE":"кёүл“ұ",
                    "EARLY_DETECT":"мЎ°кё°нҸ¬м°©","MID_PULLBACK":"лҲҢлҰјлӘ©","ENTRY_POINT":"лҲҢлҰјлӘ©",
                    "PRECLOSE_GAP_ENTRY":"мў…к°Җм„ м§„мһ…",
                }
                sig       = sig_labels.get(watch["signal_type"], watch["signal_type"])
                diff_str  = f"+{diff_pct:.1f}%" if diff_pct >= 0 else f"{diff_pct:.1f}%"
                stop_pct  = round((watch["stop_loss"]    - entry) / entry * 100, 1) if entry else 0
                tgt_pct   = round((watch["target_price"] - entry) / entry * 100, 1) if entry else 0
                nxt_notice = "\nрҹ“Ў <b>NXT кё°мӨҖ к°ҖкІ©</b>" if use_nxt else ""

                # в”Җв”Җ кіөнҶө лё”лЎқ мғқм„ұ в”Җв”Җ
                _reasons = watch.get("reasons", [])
                reasons_block = ""
                if _reasons:
                    reasons_lines = "\n".join([f"  {r}" for r in _reasons[:3]])
                    reasons_block = f"\nрҹ“Ӣ <b>нҸ¬м°© мқҙмң </b>\n{reasons_lines}\n"
                sector_block = ""
                try:
                    sector_info = calc_sector_momentum(watch["code"], watch["name"])
                    _theme = str(sector_info.get("theme", "") or "").strip()
                    _summary = str(sector_info.get("summary", "") or "").strip()
                    _rising = sector_info.get("rising", []) or []
                    _sector_lines = []
                    if _theme:
                        _sector_lines.append(f"рҹҸӯ <b>м„№н„° лӘЁл©ҳн…Җ</b> [{_theme}]")
                    elif _summary or _rising:
                        _sector_lines.append("рҹҸӯ <b>м„№н„° лӘЁл©ҳн…Җ</b>")
                    if _summary:
                        _sector_lines.append(f"  {_summary}")
                    if _rising:
                        _co_rise = ", ".join([
                            f"{_resolve_stock_name(r['code'], r.get('name',''))} {r['change_rate']:+.1f}%"
                            for r in _rising[:4]
                        ])
                        _sector_lines.append(f"  рҹ“Ң лҸҷл°ҳ мғҒмҠ№: {_co_rise}")
                    if _sector_lines:
                        sector_block = "\n" + "\n".join(_sector_lines) + "\n"
                except Exception:
                    sector_block = ""
                _entry_hit_ts = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                _similar_stats = _get_similar_pattern_stats(
                    watch["code"],
                    watch.get("signal_type", ""),
                    float(watch.get("change_at_detect", cur.get("change_rate", 0)) or 0),
                    float(watch.get("volume_ratio", cur.get("volume_ratio", 0)) or 0),
                )
                _entry_exec_metrics = get_execution_speed_metrics(watch["code"], current_price=price)
                _entry_exec_block = _entry_execution_status_block(
                    watch["code"],
                    price=price,
                    metrics=_entry_exec_metrics,
                    fallback_metrics=dict(watch.get("execution_metrics") or {}),
                )
                similar_block = ""
                try:
                    _similar_line = _build_similar_pattern_summary_block(_similar_stats, top_exposed=True)
                    if _similar_line:
                        similar_block = f"{_similar_line}\n\n"
                except Exception:
                    similar_block = ""

                # в”Җв”Җ v41.66: 1м°Ё/2м°Ё л¶„кё° в”Җв”Җ
                is_phase1 = (notify_count == 0)
                is_phase2 = (notify_count == 1)

                # мӢ нҳё к°•лҸ„ нҢҗм •
                _strength = _classify_signal_strength(watch, _entry_exec_metrics)
                _split_rule = _get_entry_split_rule(_strength)

                if is_phase1 and _strength == "м•Ҫн•ң":
                    _log_suppressed_alert(
                        watch["code"], watch["name"],
                        "1м°Ё м •мұ…м ңмҷё (м•Ҫн•ң мӢ нҳё кҙҖм°° м „мҡ©)",
                        watch.get("signal_type", ""),
                        {"entry_price": entry, "filtered_price": int(price or 0), "strength": _strength}
                    )
                    _record_entry_policy_filtered(watch, "м•Ҫн•ңмӢ нҳё_кҙҖм°°м „мҡ©", price)
                    expired.append((log_key, "м •мұ…м ңмҷё_м•Ҫн•ңмӢ нҳё", "м •мұ…м ңмҷё"))
                    continue

                if is_phase1:
                    # в”Ғв”Ғв”Ғ 1м°Ё м§„мһ…к°Җ лҸ„лӢ¬ в”Ғв”Ғв”Ғ
                    _p1_pct = _split_rule["phase1_pct"]
                    _strength_emoji = {"к°•н•ң": "рҹ”Ҙ", "ліҙнҶө": "рҹ“Ҡ", "м•Ҫн•ң": "вҡ пёҸ"}.get(_strength, "рҹ“Ҡ")
                    _nxt_delta_block = _format_nxt_transition_delta_block(watch)
                    send_with_chart_buttons(
                        f"рҹ”” <b>[1м°Ё м§„мһ…к°Җ лҸ„лӢ¬]</b>{nxt_notice}\n"
                        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                        f"рҹ”ҙ <b>{watch['name']}</b>  <code>{watch['code']}</code>\n"
                        f"мӣҗмӢ нҳё: {sig}  |  нҸ¬м°©: {_format_capture_datetime_label(detect_date=watch.get('detect_date',''), detect_time=watch.get('detect_time',''))}  |  лҸ„лӢ¬: {_entry_hit_ts}\n\n"
                        f"{_nxt_delta_block}{similar_block}"
                        f"{reasons_block}"
                        f"{sector_block}"
                        f"{_entry_exec_block}"
                        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                        f"в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n"
                        f"в”Ӯ {_strength_emoji} <b>1м°Ё м§„мһ… кө¬к°„</b>  (мӢ нҳё: {_strength})\n"
                        f"в”Ӯ рҹ“Қ нҳ„мһ¬к°Җ  <b>{price:,}мӣҗ</b>  ({diff_str})\n"
                        f"в”Ӯ рҹҺҜ м§„мһ…к°Җ  <b>{entry:,}мӣҗ</b>  в—Җ лӘ©н‘ң!\n"
                        f"в”Ӯ рҹ’° <b>к¶ҢмһҘ м§„мһ…: {_p1_pct}%</b>\n"
                        f"в”Ӯ рҹӣЎ мҶҗм Ҳк°Җ  <b>{watch['stop_loss']:,}мӣҗ</b>  ({stop_pct:+.1f}%)\n"
                        f"в”Ӯ рҹҸҶ лӘ©н‘ңк°Җ  <b>{watch['target_price']:,}мӣҗ</b>  ({tgt_pct:+.1f}%)\n"
                        f"в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ",
                        watch["code"], watch["name"]
                    )
                    watch["phase1_price"] = price
                    watch["phase1_pct"] = _p1_pct
                    watch["signal_strength"] = _strength
                    _bottom_check = confirm_bottom_and_signal(
                        watch,
                        price,
                        {"volume_ratio": cur.get("volume_ratio", 0), "execution_metrics": _entry_exec_metrics, **dict(cur or {})},
                    )
                    if _bottom_check.get("is_bottom_confirmed") and _bottom_check.get("should_send_signal"):
                        _bottom_title = "вң… л°”лӢҘ нҷ•мқё + мһ¬мғҒмҠ№ мӢ нҳё" if _bottom_check.get("signal_type") == "entry_signal" else "рҹ‘Җ л°”лӢҘ нҳ•м„ұ нҷ•мқё"
                        send_with_chart_buttons(
                            f"{_bottom_title}{nxt_notice}\n"
                            f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                            f"рҹ”ҙ <b>{watch['name']}</b>  <code>{watch['code']}</code>\n"
                            f"{_bottom_check.get('reason','')}",
                            watch["code"], watch["name"]
                        )

                elif is_phase2:
                    # в”Ғв”Ғв”Ғ 2м°Ё м¶”к°Җм§„мһ… нҢҗлӢЁ в”Ғв”Ғв”Ғ
                    _p1_price = watch.get("phase1_price", entry)
                    _p1_pct = watch.get("phase1_pct", _split_rule["phase1_pct"])

                    # v41.80: м•Ҫн•ң мӢ нҳё(phase2_allowed=False)мқҙл©ҙ API нҳём¶ң м—Ҷмқҙ мҰүмӢң кёҲм§Җ
                    if not _split_rule["phase2_allowed"]:
                        _p2_pct = 0
                        _total_pct = _p1_pct
                        _avg_price = _p1_price
                        _decision_emoji = "рҹ”ө"
                        _decision_label = "м¶”к°Җм§„мһ…: кёҲм§Җ"
                        _p2_reasons = ["рҹ”ө м•Ҫн•ң мӢ нҳё вҖ” 2м°Ё м¶”к°Җл§ӨмҲҳ кёҲм§Җ лҢҖмғҒ"]
                        _p2_detail = "мӢ нҳё к°•лҸ„ л¶ҖмЎұ вҖ” 1м°Ё м§„мһ…л¶„л§Ң мң м§Җ, м¶”к°Җл§ӨмҲҳ л¶Ҳк°Җ"
                        _stop_adj = "мң м§Җ"
                    else:
                        _p2_judgement = _judge_phase2_entry(watch, cur, price, _entry_exec_metrics)
                        _p2_decision = _p2_judgement["decision"]
                        _p2_reasons = _p2_judgement["reasons"]
                        _p2_detail = _p2_judgement["detail"]

                        if _p2_decision == "к°ҖлҠҘ":
                            _p2_pct = _split_rule["phase2_pct"]
                            _total_pct = _p1_pct + _p2_pct
                            _avg_price = _calc_avg_entry_price(_p1_price, price, _p1_pct, _p2_pct)
                            _decision_emoji = "вң…"
                            _decision_label = "м¶”к°Җм§„мһ…: к°ҖлҠҘ"
                        elif _p2_decision == "ліҙлҘҳ":
                            _p2_pct = 0
                            _total_pct = _p1_pct
                            _avg_price = _p1_price
                            _decision_emoji = "рҹҹЎ"
                            _decision_label = "м¶”к°Җм§„мһ…: ліҙлҘҳ"
                        else:  # кёҲм§Җ
                            _p2_pct = 0
                            _total_pct = _p1_pct
                            _avg_price = _p1_price
                            _decision_emoji = "рҹ”ө"
                            _decision_label = "м¶”к°Җм§„мһ…: кёҲм§Җ"

                        # мҶҗм Ҳ мЎ°м • м—¬л¶Җ
                        _stop_adj = "мң м§Җ"
                        if _p2_decision == "к°ҖлҠҘ" and _p2_pct > 0:
                            _new_stop = int(_avg_price * (1 - abs(stop_pct) / 100)) if stop_pct else watch["stop_loss"]
                            if _new_stop != watch["stop_loss"]:
                                _stop_adj = f"мЎ°м • ({watch['stop_loss']:,}вҶ’{_new_stop:,}мӣҗ)"
                            else:
                                _stop_adj = "мң м§Җ"

                    _reasons_str = "\n".join([f"  {r}" for r in _p2_reasons])
                    send_with_chart_buttons(
                        f"рҹ””рҹ”” <b>[2м°Ё м§„мһ… нҢҗлӢЁ]</b>{nxt_notice}\n"
                        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                        f"рҹ”ҙ <b>{watch['name']}</b>  <code>{watch['code']}</code>\n"
                        f"мӣҗмӢ нҳё: {sig}  |  лҸ„лӢ¬: {_entry_hit_ts}\n\n"
                        f"{_entry_exec_block}"
                        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                        f"в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n"
                        f"в”Ӯ {_decision_emoji} <b>{_decision_label}</b>\n"
                        f"в”Ӯ рҹ“Қ нҳ„мһ¬к°Җ  <b>{price:,}мӣҗ</b>  ({diff_str})\n"
                        f"в”Ӯ рҹ’° к¶ҢмһҘ м¶”к°Җл№„мӨ‘: <b>{_p2_pct}%</b>\n"
                        f"в”Ӯ рҹ“Ҡ мҙқ лҲ„м Ғ к¶ҢмһҘл№„мӨ‘: <b>{_total_pct}%</b>\n"
                        f"в”Ӯ рҹ“җ нҸүк· лӢЁк°Җ мҳҲмғҒ: <b>{_avg_price:,}мӣҗ</b>\n"
                        f"в”Ӯ рҹӣЎ мҶҗм Ҳк°Җ: <b>{_stop_adj}</b>\n"
                        f"в”ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n"
                        f"в”Ӯ <b>нҢҗлӢЁ к·јкұ°</b>\n"
                        f"{_reasons_str}\n"
                        f"в”Ӯ вҶ’ {_p2_detail}\n"
                        f"в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ",
                        watch["code"], watch["name"]
                    )

                watch['entry_hit'] = True
                watch['entry_hit_time'] = _entry_hit_ts
                watch['entry_hit_price'] = price
                changed_active = True
                if ' ' in _entry_hit_ts:
                    watch['entry_hit_date'], watch['entry_hit_clock'] = _entry_hit_ts.split(' ', 1)
                try:
                    _mark_entry_hit_in_signal_log(watch['code'], watch.get('signal_type',''), hit_price=price, hit_time=_entry_hit_ts, log_key=watch.get('signal_log_key'))
                except Exception:
                    pass
                _phase_label = "1м°Ё" if is_phase1 else "2м°Ё"
                print(f"  рҹҺҜ {_phase_label} м§„мһ…к°Җ лҸ„лӢ¬: {watch['name']} {price:,} / м§„мһ… {entry:,}")
        except Exception:
            continue
    for item in expired:
        if isinstance(item, tuple):
            k, consume_reason, final_status = item
        else:
            k, consume_reason, final_status = item, "", ""
        watch = _entry_watch.pop(k, None)
        if watch:
            _archive_entry_watch_record(k, watch, consume_reason=consume_reason, final_status=final_status or _entry_watch_final_status(watch))
            changed_active = True
    if changed_active:
        _save_entry_watch_active()

# ============================================================
# рҹӣЎ мһҘл§Ҳк°җ м „/нӣ„ мҶҗмқө л°©м–ҙ к°Җмқҙл“ң (entry_hit к°җмӢң мў…лӘ©)
#   - 'м§„мһ…к°Җ лҸ„лӢ¬' нӣ„ лӘЁлӢҲн„°л§Ғ мӨ‘мқё мў…лӘ©м—җ
#     м§Җм •н•ҷ/лүҙмҠӨ/DART/м§Җн‘ң лҰ¬мҠӨнҒ¬к°Җ мғқкё°л©ҙ мҶҗмқө л°©м–ҙ м•ҲлӮҙлҘј мһҗлҸҷ л°ңмҶЎ
# ============================================================
DEFENSE_KRX_CLOSE_WINDOW_MIN = int(os.getenv("DEFENSE_KRX_CLOSE_WINDOW_MIN", "25") or "25")  # 15:05~15:30
DEFENSE_NXT_CLOSE_WINDOW_MIN = int(os.getenv("DEFENSE_NXT_CLOSE_WINDOW_MIN", "25") or "25")  # 19:35~20:00
DEFENSE_ALERT_COOLDOWN_SEC   = int(os.getenv("DEFENSE_ALERT_COOLDOWN_SEC", "1800") or "1800")  # 30л¶„
DEFENSE_LOSS_WARN_PCT        = float(os.getenv("DEFENSE_LOSS_WARN_PCT", "1.2") or "1.2")  # -1.2% мқҙн•ҳл©ҙ кІҪкі  к°•нҷ”
DEFENSE_PROFIT_LOCK_PCT      = float(os.getenv("DEFENSE_PROFIT_LOCK_PCT", "2.0") or "2.0")  # +2% мқҙмғҒмқҙл©ҙ мқөм Ҳ л°©м–ҙ к¶Ңкі 

_NEG_NEWS_KWS = [
    "кёүлқҪ","н•ҳлқҪ","мҮјнҒ¬","мҡ°л Ө","л¶Ҳнҷ•мӢӨ","лҰ¬мҠӨнҒ¬","м ңмһ¬","кҙҖм„ё","м „мҹҒ","кіөмҠө","лҜёмӮ¬мқј","м¶©лҸҢ","лҙүмҮ„",
    "м••мҲҳмҲҳмғү","кІҖм°°","мЎ°мӮ¬","нҡЎл №","л°°мһ„","нҢҢмӮ°","нҡҢмғқ","мӣҢнҒ¬м•„мӣғ","мғҒмһҘнҸҗм§Җ","кұ°лһҳм •м§Җ","кҙҖлҰ¬мў…лӘ©",
    "н•ҳн–Ҙ","кІҪкі ","л¶Җм •","м Ғмһҗм „нҷҳ","мӢӨм Ғл¶Җм§„","лҰ¬мҪң","мӮ¬кі ","н•ҙнӮ№",
]

def _is_close_defense_window(now: datetime | None = None) -> bool:
    now = now or _now_kst()
    t = now.time()
    # KRX: 15:30 л§Ҳк°җ кё°мӨҖ
    krx_start = (datetime.combine(now.date(), dtime(15,30), tzinfo=_KST) - timedelta(minutes=DEFENSE_KRX_CLOSE_WINDOW_MIN)).time()
    krx_end   = dtime(15,30)
    # NXT: 20:00 л§Ҳк°җ кё°мӨҖ (NXTл§Ң м—ҙлҰҙ мҲҳлҸ„ мһҲмқҢ)
    nxt_start = (datetime.combine(now.date(), dtime(20,0), tzinfo=_KST) - timedelta(minutes=DEFENSE_NXT_CLOSE_WINDOW_MIN)).time()
    nxt_end   = dtime(20,0)
    in_krx = (t >= krx_start and t <= krx_end)
    in_nxt = (t >= nxt_start and t <= nxt_end)
    return in_krx or in_nxt

def _detect_defense_issues(code: str, name: str, entry: int, stop_loss: int) -> tuple[int, list[str]]:
    """лҰ¬мҠӨнҒ¬ м җмҲҳ(0~100)мҷҖ мӮ¬мң  лҰ¬мҠӨнҠё л°ҳнҷҳ."""
    score = 0
    reasons = []
    try:
        # 1) DART лҰ¬мҠӨнҒ¬
        try:
            dr = check_dart_risk(code, name)
            if isinstance(dr, dict) and dr.get("is_risk"):
                score += 60
                reasons.append(f"вҡ пёҸ DART лҰ¬мҠӨнҒ¬: {dr.get('title','')}".strip())
        except Exception:
            pass

        # 2) м§Җм •н•ҷ/кұ°мӢң лҰ¬мҠӨнҒ¬(мӢңмһҘ)
        try:
            geo = _geo_event_state or {}
            if geo.get("active") and time.time() - float(geo.get("ts",0) or 0) < 3600*12:
                unc = str(geo.get("uncertainty","mid"))
                adj = int(geo.get("score_adj",0) or 0)
                if unc == "high" and adj <= -5:
                    score += 20
                    reasons.append("рҹҢҚ м§Җм •н•ҷ л¶Ҳнҷ•мӢӨм„ұ(HIGH) вҖ” мӢңмһҘ лҰ¬мҠӨнҒ¬мҳӨн”„ к°ҖлҠҘ")
                elif adj <= -8:
                    score += 15
                    reasons.append("рҹҢҚ м§Җм •н•ҷ мқҙлІӨнҠё вҖ” ліҖлҸҷм„ұ нҷ•лҢҖ к°ҖлҠҘ")
        except Exception:
            pass

        # 3) мөңк·ј лүҙмҠӨ(нғҖмқҙнӢҖ кё°л°ҳ к°„лӢЁ н•„н„°)
        try:
            news = fetch_news_for_stock(code, name) or []
            hits = []
            for n in news[:10]:
                for kw in _NEG_NEWS_KWS:
                    if kw in n and kw not in hits:
                        hits.append(kw)
            if hits:
                score += 15
                reasons.append(f"рҹ“° л¶Җм • нӮӨмӣҢл“ң к°җм§Җ: {', '.join(hits[:4])}")
        except Exception:
            pass

        # 4) к°ҖкІ©/мҶҗмқө мғҒнғң
        try:
            cur = get_stock_price(code) or {}
            price = int(cur.get("price") or 0)
            if price and entry:
                pnl = (price - entry) / entry * 100
                if pnl <= -DEFENSE_LOSS_WARN_PCT:
                    score += 20
                    reasons.append(f"рҹ“ү м§„мһ…к°Җ лҢҖл№„ {pnl:.1f}% (л°©м–ҙ н•„мҡ”)")
                elif pnl >= DEFENSE_PROFIT_LOCK_PCT:
                    score += 10
                    reasons.append(f"рҹ“Ҳ м§„мһ…к°Җ лҢҖл№„ +{pnl:.1f}% (мқөм Ҳ л°©м–ҙ к¶ҢмһҘ)")
                # мҶҗм Ҳм„  к·јм ‘
                if stop_loss and price <= stop_loss * 1.01:
                    score += 20
                    reasons.append("рҹӣЎ мҶҗм Ҳм„  к·јм ‘(1% мқҙлӮҙ)")
        except Exception:
            pass

    except Exception:
        pass

    score = max(0, min(score, 100))
    return score, reasons

def run_entry_defense_monitor():
    """run_scan лЈЁн”„м—җм„ң нҳём¶ң: л§Ҳк°җ кө¬к°„м—җ entry_hit мў…лӘ©мқҳ лҰ¬мҠӨнҒ¬лҘј к°җм§Җн•ҙ мҶҗмқө л°©м–ҙ к°Җмқҙл“ң л°ңмҶЎ."""
    try:
        if not _entry_watch:
            return
        changed_active = False
        # л§Ҳк°җ кө¬к°„мқҙ м•„лӢҲл©ҙ л¶Ҳн•„мҡ”н•ң API нҳём¶ң мӨ„мқҙкё°
        if not _is_close_defense_window():
            return

        now_ts = time.time()
        use_nxt = (not is_market_open()) and is_nxt_open()

        for _k, w in list(_entry_watch.items()):
            if not isinstance(w, dict):
                continue
            if not w.get("entry_hit"):
                continue

            # мҝЁлӢӨмҡҙ(мў…лӘ©лі„)
            last = float(w.get("defense_last_ts", 0) or 0)
            if now_ts - last < DEFENSE_ALERT_COOLDOWN_SEC:
                continue

            code = w.get("code")
            name = w.get("name") or code
            entry = int(w.get("entry_price") or 0)
            stop  = int(w.get("stop_loss") or 0)
            if not code or not entry:
                continue

            # нҳ„мһ¬к°Җ
            cur = get_nxt_stock_price(code) if use_nxt else get_stock_price(code)
            price = int((cur or {}).get("price") or 0)
            if not price:
                continue

            risk_score, reasons = _detect_defense_issues(code, name, entry, stop)
            if risk_score < 35 or not reasons:
                continue

            pnl = (price - entry) / entry * 100 if entry else 0.0

            # к°Җмқҙл“ң кө¬м„ұ(мӢӨм „ мҲҳмқө л°©м–ҙ мӨ‘мӢ¬)
            guide = []
            if pnl >= DEFENSE_PROFIT_LOCK_PCT:
                guide.append("вң… <b>мҲҳмқө л°©м–ҙ</b>: 1м°Ё л¶„н• мқөм Ҳ(мҳҲ: 30~50%) + мһ”лҹүмқҖ <b>м§„мһ…к°Җ/лӢЁкё°м Җм җ мқҙнғҲ мӢң м •лҰ¬</b>")
                guide.append("вң… <b>нҠёл Ҳмқјл§Ғ</b>: м „мқјм Җк°Җ лҳҗлҠ” 5л¶„ м Җм җ кё°мӨҖмңјлЎң мҶҗм Ҳм„ мқ„ лҒҢм–ҙмҳ¬лҰ¬кё°")
            else:
                guide.append("рҹӣЎ <b>мҶҗмӢӨ л°©м–ҙ</b>: мҶҗм Ҳм„  м—„мҲҳ(мқҙнғҲ мӢң кё°кі„м ҒмңјлЎң м •лҰ¬) + л¬ҙлҰ¬н•ң л¬јнғҖкё° кёҲм§Җ")
                guide.append("рҹӣЎ <b>лҰ¬мҠӨнҒ¬ л°ңмғқ</b>: ліҖлҸҷм„ұ нҷ•лҢҖ кө¬к°„мқҙлҜҖлЎң м§„мһ…/м¶”к°Җл§ӨмҲҳлҠ” ліҙмҲҳм ҒмңјлЎң")

            # л§Ҳк°җ мһ„л°• м¶”к°Җ мҪ”л©ҳнҠё
            if is_nxt_open() and not is_market_open():
                guide.append("рҹ“Ў <b>NXT лӢЁлҸ… мӢңк°„</b>: мң лҸҷм„ұ м–ҮмқҢ вҶ’ мҠ¬лҰ¬н”јм§Җ/кёүліҖ к°ҖлҠҘ, ліҙмҲҳм Ғ лҢҖмқ‘ к¶ҢмһҘ")
            else:
                guide.append("вҸі <b>мһҘл§Ҳк°җ мһ„л°•</b>: лүҙмҠӨ/кіөмӢң м¶©кІ©мқҖ мқөмқј к°ӯмңјлЎң мқҙм–ҙм§Ҳ мҲҳ мһҲм–ҙ л°©м–ҙ мҡ°м„ ")
            parts = [
                f"рҹӣЎ <b>[мҶҗмқө л°©м–ҙ м•ҢлҰј]</b> (лҰ¬мҠӨнҒ¬ {risk_score}/100)",
                "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ",
                f"<b>{name}</b>  <code>{code}</code>",
                f"нҳ„мһ¬к°Җ <b>{price:,}</b> / м§„мһ… {entry:,}  ({pnl:+.1f}%)",
                (f"мҶҗм Ҳ {stop:,}" if stop else ""),
                "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ",
                *reasons[:4],
                "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ",
                *guide[:4],
            ]
            msg = "\n".join([p for p in parts if p])
            send_with_chart_buttons(msg, code, name)

            # кё°лЎқ
            w["defense_last_ts"] = now_ts
            changed_active = True

        if changed_active:
            _save_entry_watch_active()
    except Exception as e:
        _log_error("run_entry_defense_monitor", e)

def _sanitize_telegram_text(text: str | None) -> str | None:
    """н…”л Ҳк·ёлһЁ л°ңмҶЎ м „ н‘ңмӢңмғҒ м–ҙмғүн•ң л¬ёмһҗлҘј м •лҰ¬н•ңлӢӨ."""
    if text is None:
        return None
    try:
        return str(text).replace(chr(0x2B1C), "").replace(chr(0x26AA), "")
    except Exception:
        return text

_TG_CONNECT_TIMEOUT = float(os.getenv("TG_CONNECT_TIMEOUT", "3.5") or "3.5")
_TG_READ_TIMEOUT = float(os.getenv("TG_READ_TIMEOUT", "25") or "25")
_TG_LONGPOLL_READ_TIMEOUT = float(os.getenv("TG_LONGPOLL_READ_TIMEOUT", "8") or "8")
_TG_FILE_READ_TIMEOUT = float(os.getenv("TG_FILE_READ_TIMEOUT", "45") or "45")
_TG_ERROR_LOG_COOLDOWN_SEC = int(os.getenv("TG_ERROR_LOG_COOLDOWN_SEC", "120") or "120")
_tg_error_last_ts: dict[str, float] = {}


def _tg_log_once(key: str, message: str) -> None:
    now_ts = time.time()
    last_ts = float(_tg_error_last_ts.get(key, 0.0) or 0.0)
    if now_ts - last_ts >= _TG_ERROR_LOG_COOLDOWN_SEC:
        print(message)
        _tg_error_last_ts[key] = now_ts


def _tg_timeout_tuple(read_timeout: float | int | None = None) -> tuple[float, float]:
    rt = float(read_timeout if read_timeout is not None else _TG_READ_TIMEOUT)
    return (float(_TG_CONNECT_TIMEOUT), max(1.0, rt))


def _tg_http_request(
    http_method: str,
    api_method: str,
    *,
    json_payload: dict | None = None,
    data_payload: dict | None = None,
    files: dict | None = None,
    params: dict | None = None,
    read_timeout: float | int | None = None,
    attempts: int = 1,
    quiet: bool = False,
):
    if not TELEGRAM_BOT_TOKEN:
        return None
    url = f"https://api.telegram.org/bot{TELEGRAM_BOT_TOKEN}/{api_method}"
    timeout = _tg_timeout_tuple(read_timeout)
    tries = max(1, int(attempts or 1))
    for attempt in range(1, tries + 1):
        try:
            if http_method.lower() == "get":
                return requests.get(url, params=params, timeout=timeout)
            return requests.post(url, json=json_payload, data=data_payload, files=files, params=params, timeout=timeout)
        except requests.exceptions.ReadTimeout as e:
            if attempt < tries:
                time.sleep(0.6 * attempt)
                continue
            if not quiet:
                _tg_log_once(f"{api_method}:read_timeout", f"вҡ пёҸ н…”л Ҳк·ёлһЁ {api_method} мқҪкё° м§Җм—°: {e}")
            return None
        except requests.exceptions.ConnectTimeout as e:
            if not quiet:
                _tg_log_once(f"{api_method}:connect_timeout", f"вҡ пёҸ н…”л Ҳк·ёлһЁ {api_method} м—°кІ° м§Җм—°: {e}")
            return None
        except requests.exceptions.RequestException as e:
            if not quiet:
                _tg_log_once(f"{api_method}:request_error", f"вҡ пёҸ н…”л Ҳк·ёлһЁ {api_method} мҳӨлҘҳ: {e}")
            return None
        except Exception as e:
            if not quiet:
                _tg_log_once(f"{api_method}:exception", f"вҡ пёҸ н…”л Ҳк·ёлһЁ {api_method} мҳӨлҘҳ: {e}")
            return None
    return None


def _tg_request(method: str, payload: dict, timeout: int | float = 10) -> dict | None:
    """Telegram Bot API мҡ”мІӯ. м„ұкіө мӢң response json л°ҳнҷҳ, мӢӨнҢЁ мӢң None."""
    try:
        if isinstance(payload, dict):
            if isinstance(payload.get('text'), str):
                payload['text'] = _decorate_ui_score_text(payload['text'])
            if isinstance(payload.get('caption'), str):
                payload['caption'] = _decorate_ui_score_text(payload['caption'])
    except Exception:
        pass
    r = _tg_http_request("post", method, json_payload=payload, read_timeout=timeout, attempts=1)
    if r is None:
        return None
    try:
        return r.json()
    except Exception:
        return None


def send_with_chart_buttons(text: str, code: str, name: str):
    """
    н…ҚмҠӨнҠё л©”мӢңм§Җ + мқёлқјмқё нӮӨліҙл“ң лІ„нҠј(л„ӨмқҙлІ„ м°ЁнҠё л§ҒнҒ¬) м „мҶЎ
    лІ„нҠјмқҖ кё°кё° кё°ліё лёҢлқјмҡ°м Җ(мҷёл¶Җ)лЎң м—ҙлҰј
    """
    safe_name = _resolve_stock_name(code, name)
    naver = f"https://finance.naver.com/item/fchart.naver?code={code}"
    keyboard = {
        "inline_keyboard": [[
            {"text": f"рҹ“Ҳ {safe_name} м°ЁнҠё ліҙкё° (л„ӨмқҙлІ„)", "url": naver},
        ]]
    }
    send(text, reply_markup=keyboard)

def send(text: str, *, reply_markup: dict | None = None) -> int | None:
    """л©”мӢңм§Җ м „мҶЎ. м„ұкіө мӢң message_id л°ҳнҷҳ."""
    decorated_text = _decorate_ui_score_text(text)
    payload = {"chat_id": TELEGRAM_CHAT_ID, "text": _sanitize_telegram_text(decorated_text), "parse_mode": "HTML"}
    if reply_markup:
        payload["reply_markup"] = reply_markup
    res = _tg_request("sendMessage", payload)
    try:
        if res and res.get("ok") and "result" in res:
            return res["result"].get("message_id")
    except Exception:
        pass
    return None

# =======================================================
# Crash guard (Step 1): unhandled exception hook
# =======================================================
_CRASH_NOTIFY_COOLDOWN_SEC = int(os.getenv("CRASH_NOTIFY_COOLDOWN_SEC", "1800") or "1800")
_last_crash_sig: str | None = None
_last_crash_ts: float = 0.0


def install_excepthook() -> None:
    """Unhandled мҳҲмҷёлҘј нҢҢмқјлЎң м ҖмһҘн•ҳкі (мҳҒкө¬м ҖмһҘ), н…”л Ҳк·ёлһЁ м•ҢлҰјмқ„ мҝЁлӢӨмҡҙ(кё°ліё 30л¶„)мңјлЎң м ңн•ң."""
    import sys, time, traceback as _tb
    from pathlib import Path

    def _handler(exc_type, exc, tb):
        global _last_crash_sig, _last_crash_ts
        try:
            data_dir = DATA_DIR
            crash_dir = Path(data_dir) / "crash_logs"
            crash_dir.mkdir(parents=True, exist_ok=True)
            ts = datetime.now().strftime("%Y%m%d_%H%M%S")
            fname = f"crash_{ts}.txt"
            fpath = crash_dir / fname
            with open(fpath, "w", encoding="utf-8") as f:
                f.write("".join(_tb.format_exception(exc_type, exc, tb)))
            print(f"рҹҡЁ Unhandled exception saved: {fpath}", flush=True)

            sig = f"{exc_type.__name__}:{str(exc)[:200]}"
            now = time.time()
            if (_last_crash_sig != sig) or (now - _last_crash_ts > _CRASH_NOTIFY_COOLDOWN_SEC):
                _last_crash_sig, _last_crash_ts = sig, now
                try:
                    send(
                        f"рҹҡЁ лҙҮ мҳӨлҘҳ к°җм§Җ\n"
                        f"- type: <b>{exc_type.__name__}</b>\n"
                        f"- msg: <code>{str(exc)[:250]}</code>\n"
                        f"- crash log: <code>{fname}</code>\n"
                        f"(к°ҷмқҖ мҳӨлҘҳлҠ” {_CRASH_NOTIFY_COOLDOWN_SEC//60}л¶„м—җ 1нҡҢл§Ң м•ҢлҰј)"
                    )
                except Exception:
                    pass
        except Exception:
            pass

        try:
            sys.__excepthook__(exc_type, exc, tb)
        except Exception:
            pass

    sys.excepthook = _handler


def edit_message(message_id: int, text: str, *, reply_markup: dict | None = None) -> bool:
    decorated_text = _decorate_ui_score_text(text)
    payload = {"chat_id": TELEGRAM_CHAT_ID, "message_id": message_id, "text": decorated_text, "parse_mode": "HTML"}
    if reply_markup:
        payload["reply_markup"] = reply_markup
    res = _tg_request("editMessageText", payload)
    return bool(res and res.get("ok"))

def _load_dashboard_state() -> dict:
    try:
        with open(DASHBOARD_STATE_FILE, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return {}

def get_today_performance_summary() -> str:
    """signal_log кё°мӨҖ лӢ№мқј мҷ„лЈҢ м„ұкіјлҘј н•ң мӨ„лЎң мҡ”м•Ҫ."""
    try:
        today = datetime.now().strftime("%Y%m%d")
        data = _read_json_locked(SIGNAL_LOG_FILE)
        if not isinstance(data, dict):
            return ""
        done_today = [
            v for v in data.values()
            if (v.get("exit_date") or v.get("detect_date")) == today
            and v.get("status") in ["мҲҳмқө", "мҶҗмӢӨ", "ліём „"]
        ]
        if not done_today:
            return ""
        wins = sum(1 for v in done_today if float(v.get("pnl_pct", 0) or 0) > 0)
        total = len(done_today)
        win_rate = round(wins / total * 100) if total else 0
        avg_pnl = sum(float(v.get("pnl_pct", 0) or 0) for v in done_today) / total if total else 0.0
        return f"{total}кұҙ В· мҠ№лҘ  {win_rate}% В· нҸүк·  {avg_pnl:+.1f}%"
    except Exception:
        return ""

def _save_dashboard_state(state: dict) -> None:
    try:
        os.makedirs(os.path.dirname(DASHBOARD_STATE_FILE), exist_ok=True)
        _write_json_atomic(DASHBOARD_STATE_FILE, state)
    except Exception:
        pass

def update_dashboard(force: bool = False) -> None:
    # мһҘ мҡҙмҳҒ мӢңк°„м—җл§Ң н…”л Ҳк·ёлһЁ лҢҖмӢңліҙл“ң к°ұмӢ 
    if not is_any_market_open():
        return

    # ensure MARKET_REGIME is populated; fall back to US signals if needed
    try:
        us = get_us_market_signals()
        if isinstance(us, dict) and us.get('us_regime'):
            MARKET_REGIME['label'] = us.get('us_regime') or MARKET_REGIME.get('label','neutral')
    except Exception:
        pass

    """лҢҖмӢңліҙл“ң л©”мӢңм§Җ(1к°ң)лҘј нҺём§‘ м—…лҚ°мқҙнҠё вҖ” v39.4: ліҖлҸҷмӮ¬н•ӯ мһҲмқ„ л•Ңл§Ң."""
    global _LAST_DASHBOARD_TS, _LAST_DASHBOARD_HASH
    now = time.time()
    if (not force) and (now - _LAST_DASHBOARD_TS) < DASHBOARD_UPDATE_EVERY_SEC:
        return
    _LAST_DASHBOARD_TS = now

    tracked_n = 0
    try:
        tracked_n = len(_entry_watch.get("watch", {})) if isinstance(_entry_watch, dict) else 0
    except Exception:
        tracked_n = 0
    raw_regime = (MARKET_REGIME.get("label") or "neutral")
    regime = regime_label_ko(raw_regime)
    det = market_regime_details() or {}
    det_txt = ""
    try:
        fut = det.get("nasdaq_fut_pct")
        vix = det.get("vix")
        dxy = det.get("dxy")
        if fut is not None:
            det_txt = f" (FUT {float(fut):+.1f}% / VIX {vix} / DXY {dxy})"
    except Exception:
        det_txt = ""

    perf = ""
    try:
        perf = get_today_performance_summary()  # мһҲмңјл©ҙ мӮ¬мҡ©
    except Exception:
        perf = ""

    text = (
        "рҹ“Ң <b>мҡҙмҳҒ лҢҖмӢңліҙл“ң</b>\n"
        f"вҖў л Ҳм§җ: <b>{regime}</b>{det_txt}\n"
        f"вҖў м§„мһ… к°җмӢң: <b>{tracked_n}</b> мў…лӘ©\n"
    )
    if perf:
        text += f"вҖў мҳӨлҠҳ м„ұкіј: {perf}\n"
    text += f"вҖў м—…лҚ°мқҙнҠё: {datetime.now().strftime('%m-%d %H:%M')}\n"

    # v39.4-#6: лӮҙмҡ© н•ҙмӢң л№„көҗ вҶ’ ліҖлҸҷ м—Ҷмңјл©ҙ мҠӨнӮө (л©”мӢңм§Җлҹү к°җмҶҢ)
    content_hash = hashlib.md5(f"{regime}{tracked_n}{perf}".encode()).hexdigest()[:8]
    if not force and hasattr(update_dashboard, '_last_hash') and update_dashboard._last_hash == content_hash:
        return  # ліҖлҸҷ м—ҶмқҢ вҶ’ м—…лҚ°мқҙнҠё л¶Ҳн•„мҡ”
    update_dashboard._last_hash = content_hash

    state = _load_dashboard_state()
    mid = state.get("message_id")
    if isinstance(mid, int):
        ok = edit_message(mid, text)
        if not ok:
            mid2 = send(text)
            if mid2:
                state["message_id"] = mid2
                _save_dashboard_state(state)
    else:
        mid2 = send(text)
        if mid2:
            state["message_id"] = mid2
            _save_dashboard_state(state)

def send_by_level(text: str, level: str = ALERT_LEVEL_NORMAL,
                  code: str = "", name: str = ""):
    """
    мӨ‘мҡ”лҸ„лі„ м•ҢлҰј л°ңмҶЎ
    CRITICAL / NORMAL вҶ’ мҰүмӢң л°ңмҶЎ
    INFO              вҶ’ _pending_info_alerts лҢҖкё°м—ҙм—җ м¶”к°Җ (10л¶„л§ҲлӢӨ л¬¶мқҢ л°ңмҶЎ)
    """
    if level in (ALERT_LEVEL_CRITICAL, ALERT_LEVEL_NORMAL):
        if code and name:
            send_with_chart_buttons(text, code, name)
        else:
            send(text)
    else:  # INFO
        _pending_info_alerts.append({"text": text, "ts": time.time()})

def flush_info_alerts():
    """INFO м•ҢлҰј л¬¶мқҢ л°ңмҶЎ (5л¶„л§ҲлӢӨ мҠӨмјҖмӨ„) + мҳӨлһҳлҗң н•ӯлӘ© мһҗлҸҷ м ңкұ°"""
    if not _pending_info_alerts: return
    now = time.time()
    # v37.0: мҠ¬лқјмқҙмҠӨ н• лӢ№мңјлЎң м•Ҳм „н•ң лҰ¬мҠӨнҠё мҲҳм • (лҸҷмӢңм ‘к·ј кІҪмҹҒ мЎ°кұҙ м ңкұ°)
    # 1мӢңк°„ мқҙмғҒ лҗң н•ӯлӘ© м ңкұ° + мөңлҢҖ 20к°ң мң м§Җ
    fresh = [a for a in _pending_info_alerts if now - a["ts"] <= 3600][-20:]
    # 5л¶„ мқҙмғҒ лҗң кІғл§Ң л°ңмҶЎ лҢҖмғҒ
    to_send = [a for a in fresh if now - a["ts"] >= 300]
    remaining = [a for a in fresh if now - a["ts"] < 300]
    _pending_info_alerts[:] = remaining  # мӣҗмһҗм Ғ көҗмІҙ
    if not to_send: return
    if len(to_send) == 1:
        send(to_send[0]["text"])
    else:
        combined = f"рҹҹЎ <b>м°ёкі  м•ҢлҰј л¬¶мқҢ</b>  {len(to_send)}кұҙ\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
        for a in to_send:
            first_line = a["text"].split("\n")[0][:60]
            combined  += f"вҖў {first_line}\n"
        send(combined)

def get_alert_level(signal_type: str, score: int, nxt_delta: int = 0) -> str:
    """
    мӢ нҳё мң нҳ• + м җмҲҳ вҶ’ мӨ‘мҡ”лҸ„ л ҲлІЁ кІ°м •
    CRITICAL: мғҒн•ңк°ҖВ·к°•л Ҙл§ӨмҲҳВ·NXTліҙм • +10 мқҙмғҒ кі м җмҲҳ
    NORMAL:   кёүл“ұВ·мЎ°кё°нҸ¬м°©В·лҲҢлҰјлӘ©
    INFO:     м°ёкі мҡ© м„№н„° м—…лҚ°мқҙнҠёВ·лӮ®мқҖ м җмҲҳ
    """
    if signal_type in ("UPPER_LIMIT", "STRONG_BUY"): return ALERT_LEVEL_CRITICAL
    if signal_type == "NEAR_UPPER" and score >= 85:  return ALERT_LEVEL_CRITICAL
    if nxt_delta >= 10 and score >= 80:              return ALERT_LEVEL_CRITICAL
    if score >= 75:                                   return ALERT_LEVEL_NORMAL
    if score >= 60:                                   return ALERT_LEVEL_NORMAL
    return ALERT_LEVEL_INFO

def _calc_rr_text(entry: int, stop: int, target: int) -> str:
    try:
        if entry and stop and target and entry > stop:
            rr = (target - entry) / max(1, (entry - stop))
            return f"1 : {rr:.1f}"
    except Exception:
        pass
    return "кі„мӮ°л¶Ҳк°Җ"


def _find_cached_deep_news_result(code: str, articles: list) -> dict:
    try:
        if not code or not articles:
            return {}
        first_title = str((articles[0] or {}).get('title', '') or '')
        cache_key = f"{code}_{first_title[:20]}"
        cached = _deep_news_cache.get(cache_key) or {}
        if cached and time.time() - cached.get('ts', 0) < 3600:
            return dict(cached)
    except Exception:
        pass
    return {}


def _build_quick_news_analysis(articles: list, stock_name: str) -> dict:
    titles = [str((a or {}).get('title', '') or '').strip() for a in (articles or []) if str((a or {}).get('title', '') or '').strip()]
    if not titles:
        return {}
    try:
        sent = analyze_news_sentiment(titles, stock_name)
        raw_score = int(sent.get('score', 0) or 0)
        if raw_score >= 10:
            verdict, adj = 'мӢӨм§Ҳнҳёмһ¬', +8
        elif raw_score >= 4:
            verdict, adj = 'мӢӨм§Ҳнҳёмһ¬', +4
        elif raw_score <= -10:
            verdict, adj = 'мӢӨм§Ҳм•…мһ¬', -10
        elif raw_score <= -4:
            verdict, adj = 'мӢӨм§Ҳм•…мһ¬', -5
        else:
            verdict, adj = 'мӨ‘лҰҪ', 0
        label = str(sent.get('label', 'мӨ‘лҰҪ') or 'мӨ‘лҰҪ')
        if verdict == 'мӨ‘лҰҪ':
            reason = 'н—Өл“ңлқјмқё л°©н–Ҙм„ұ мӨ‘лҰҪ'
        elif verdict == 'мӢӨм§Ҳнҳёмһ¬':
            reason = f'н—Өл“ңлқјмқё {label} мҡ°м„ё'
        else:
            reason = f'н—Өл“ңлқјмқё {label} мҡ°м„ё вҖ” ліҖлҸҷм„ұ мЈјмқҳ'
        matched = sent.get('matched', []) or titles[:1]
        return {
            'verdict': verdict,
            'score_adj': adj,
            'reason': reason,
            'risk_points': [],
            'key_event': '',
            'confidence': 'low',
            'headline_source': 'quick',
            'headline_sample': matched[:2],
            'ts': time.time(),
        }
    except Exception:
        return {}


def _ensure_alert_news_payload(s: dict, allow_fetch: bool = False) -> tuple[dict, list]:
    if not isinstance(s, dict):
        return {}, []
    analysis = dict(s.get('news_analysis') or {})
    articles = list(s.get('news_articles') or [])
    code = str(s.get('code', '') or '').strip()
    name = _resolve_stock_name(code, str(s.get('name', '') or ''))

    if not articles and allow_fetch and code:
        try:
            articles = list(fetch_news_for_stock(code, name) or [])
        except Exception:
            articles = []

    if not analysis and articles:
        analysis = _find_cached_deep_news_result(code, articles) or _build_quick_news_analysis(articles, name)

    if analysis:
        s['news_analysis'] = analysis
    if articles:
        s['news_articles'] = articles
    return analysis, articles


def _build_news_summary_block(s: dict, allow_fetch: bool = False) -> str:
    analysis, articles = _ensure_alert_news_payload(s, allow_fetch=allow_fetch)
    if not analysis and not articles:
        return ''

    verd = str((analysis or {}).get('verdict', 'мӨ‘лҰҪ') or 'мӨ‘лҰҪ')
    adj = int((analysis or {}).get('score_adj', 0) or 0)
    reason = str((analysis or {}).get('reason', '') or '').strip()
    key_event = str((analysis or {}).get('key_event', '') or '').strip()
    risk_points = [str(x).strip() for x in ((analysis or {}).get('risk_points', []) or []) if str(x).strip()]
    conf = str((analysis or {}).get('confidence', 'low') or 'low')
    conf_icon = {'high': 'рҹ”Қ', 'mid': 'рҹ“°', 'low': 'рҹ“°'}.get(conf, 'рҹ“°')

    label = verd + (f' {adj:+d}м җ' if adj else '')
    if key_event:
        label += f' В· {key_event}'

    lines = [f"рҹ“° <b>лүҙмҠӨ мҡ”м•Ҫ</b> [{label}]"]
    if reason:
        lines.append(f"  {conf_icon} {reason}")

    shown_titles = []
    for a in articles[:2]:
        title = str((a or {}).get('title', '') or '').strip()
        if title and title not in shown_titles:
            shown_titles.append(title)
    if shown_titles:
        lines.append(f"  рҹ—һ {shown_titles[0]}")
    for rp in risk_points[:2]:
        lines.append(f"  вҡ пёҸ {rp}")
    return "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n" + "\n".join(lines) + "\n"


def _sector_block(s: dict) -> str:
    si = s.get("sector_info")
    if not si:
        return ""

    theme   = si.get("theme", "")
    bonus   = si.get("bonus", 0)
    summary = si.get("summary", "")
    detail  = si.get("detail", [])
    rising  = si.get("rising", [])
    flat    = si.get("flat", [])
    sources = si.get("sources", {})

    if not detail and not summary:
        return f"рҹҸӯ <b>м„№н„° лӘЁл©ҳн…Җ</b> [{theme}]  м—…мў… мЎ°нҡҢ мӢӨнҢЁ\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n\n"

    bonus_tag = f"  +{bonus}м җ" if bonus > 0 else ""
    block = f"рҹҸӯ <b>м„№н„° лӘЁл©ҳн…Җ</b> [{theme}]{bonus_tag}\n"

    # мҷң мқҙ мў…лӘ©л“Өмқҙ л¬¶мҳҖлҠ”м§Җ н‘ңмӢң
    if "лҸҷм Ғн…Ңл§Ҳ" in sources:
        block += f"  рҹ”— м—°кҙҖ к·јкұ°: к°ҖкІ© мғҒкҙҖкҙҖкі„В·лүҙмҠӨ кіөлҸҷм–ёкёү\n"
    if "н…Ңл§Ҳ" in sources:
        block += f"  рҹ“Ң н…Ңл§Ҳ л“ұлЎқ мў…лӘ©\n"
    if "м—…мў…мҪ”л“ң" in sources and len(sources) == 1:
        block += f"  рҹ“Ӯ лҸҷмқј м—…мў… л¶„лҘҳ\n"

    if summary:
        block += f"  {summary}\n"

    for r in rising[:5]:
        src_tag  = " рҹ”—" if r.get("source") == "лҸҷм Ғн…Ңл§Ҳ" else ""
        vol_tag  = f" рҹ”Ҡ{r['volume_ratio']:.0f}x" if r.get("volume_ratio", 0) >= 2 else ""
        block   += f"  рҹ“Ҳ {_resolve_stock_name(r['code'], r.get('name',''))} <b>{r['change_rate']:+.1f}%</b>{vol_tag}{src_tag}\n"

    for r in flat[:3]:
        src_tag = " рҹ”—" if r.get("source") == "лҸҷм Ғн…Ңл§Ҳ" else ""
        block  += f"  вһ– {_resolve_stock_name(r['code'], r.get('name',''))} {r['change_rate']:+.1f}%{src_tag}\n"

    return block + "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n\n"

def send_alert(s: dict):
    s["name"] = _resolve_stock_name(s.get("code", ""), s.get("name", ""))
    # throttle repetitive alerts (reduce spam)
    try:
        st = s.get('signal_type','')
        if not s.get('_skip_repeat_throttle') and st in ('UPPER_LIMIT','NEAR_UPPER'):
            key = f"{st}:{s.get('code','')}"
            if not _throttle_ok(_LAST_ALERT_TS, key, 3600):
                # v40.0-#7: м°ЁлӢЁ мӮ¬мң  лЎңк·ё
                _log_suppressed_alert(
                    s.get('code',''), s.get('name',''),
                    f"мҝЁлӢӨмҡҙ м°ЁлӢЁ ({st} 1мӢңк°„ мқҙлӮҙ мһ¬м•ҢлҰј)",
                    st
                )
                return
    except Exception:
        pass

    emoji = {"UPPER_LIMIT":"рҹҡЁ","NEAR_UPPER":"рҹ”Ҙ","STRONG_BUY":"рҹ’Һ",
             "SURGE":"рҹ“Ҳ","ENTRY_POINT":"рҹҺҜ","EARLY_DETECT":"рҹ”Қ"}.get(s["signal_type"],"рҹ“Ҡ")
    title = {"UPPER_LIMIT":"мғҒн•ңк°Җ к°җм§Җ","NEAR_UPPER":"мғҒн•ңк°Җ к·јм ‘","STRONG_BUY":"к°•л Ҙ л§ӨмҲҳ мӢ нҳё",
             "SURGE":"кёүл“ұ к°җм§Җ","ENTRY_POINT":"вҳ… лҲҢлҰјлӘ© м§„мһ… мӢңм җ вҳ…",
             "EARLY_DETECT":"вҳ… мЎ°кё° нҸ¬м°© - м„ м§„мһ… кё°нҡҢ вҳ…"}.get(s["signal_type"],"кёүл“ұ к°җм§Җ")

    level    = get_alert_level(s["signal_type"], s.get("score",0), s.get("nxt_delta",0))
    nxt_badge = "\nрҹҹЎ <b>NXT (л„ҘмҠӨнҠёл Ҳмқҙл“ң) кұ°лһҳ</b>" if s.get("market") == "NXT" else ""
    lvl_icon  = {"CRITICAL":"рҹ”ө","NORMAL":"рҹҹЎ","INFO":"рҹҹЎ"}.get(level,"рҹҹЎ")

    # в”Җв”Җ м»ҙнҢ©нҠё лӘЁл“ң в”Җв”Җ
    if _compact_mode:
        name_dot = {"UPPER_LIMIT":"рҹ”ө","NEAR_UPPER":"рҹҹЎ","STRONG_BUY":"рҹ”ҙ",
                    "SURGE":"рҹҹЎ","EARLY_DETECT":"рҹҹЎ","ENTRY_POINT":"рҹҹЈ"}.get(s["signal_type"],"")
        price = int(s.get("price", 0) or 0)
        compact_text = (
            f"{lvl_icon}{emoji} {name_dot}<b>{s['name']}</b>  {s['change_rate']:+.1f}%  "
            f"{s['score']}м җ ({_signal_total_score_label(s['score'])}){nxt_badge}\n"
            f"нҳ„мһ¬к°Җ {price:,}мӣҗ"
        )
        send_by_level(compact_text, level, s["code"], s["name"])
        return

    # в”Җв”Җ мғҒм„ё лӘЁл“ң (кё°мЎҙ) в”Җв”Җ
    name_dot = {
        "UPPER_LIMIT": "рҹ”ө",
        "NEAR_UPPER":  "рҹҹЎ",
        "STRONG_BUY":  "рҹ”ҙ",
        "SURGE":       "рҹҹЎ",
        "EARLY_DETECT":"рҹҹЎ",
        "ENTRY_POINT": "рҹҹЈ",
    }.get(s["signal_type"], "")

    stars    = "вҳ…" * min(int(s["score"]/20), 5)
    now_str  = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    regime_line = regime_message_line()
    stop_pct = s.get("stop_pct",7.0); target_pct = s.get("target_pct",15.0)
    atr_tag  = " (ATR)" if s.get("atr_used") else " (кі м •)"
    strict_warn = "\nвҸ° <b>мһҘ мӢңмһ‘В·л§Ҳк°җ к·јм ‘ вҖ” ліҖлҸҷм„ұ мЈјмқҳ</b>\n" if is_strict_time() else ""
    prev_tag    = "\nрҹ”Ғ <b>м „мқј мғҒн•ңк°Җ!</b> м—°мҶҚ мғҒн•ңк°Җ к°ҖлҠҘм„ұ" if s.get("prev_upper") else ""

    # м§„мһ…к°Җ к°•мЎ° лё”лЎқ
    entry  = s.get("entry_price", 0)
    stop   = s.get("stop_loss", 0)
    target = s.get("target_price", 0)
    price  = s.get("price", 0)
    diff_from_entry = ((price - entry) / entry * 100) if entry and price else 0

    detected_at = s.get("detected_at", datetime.now())
    exec_block = _build_execution_speed_block(s)
    if s["signal_type"] == "ENTRY_POINT":
        rr_text = _calc_rr_text(entry, stop, target)
        entry_block = (
            f"в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n"
            f"в”Ӯ вҡЎпёҸ <b>м§ҖкёҲ м§„мһ… кө¬к°„!</b>\n"
            f"в”Ӯ рҹҺҜ м§„мһ…к°Җ  <b>{entry:,}мӣҗ</b>  вҶҗ нҳ„мһ¬ {diff_from_entry:+.1f}%\n"
            f"в”Ӯ рҹӣЎ мҶҗм Ҳк°Җ  <b>{stop:,}мӣҗ</b>  (-{stop_pct:.1f}%){atr_tag}\n"
            f"в”Ӯ рҹҸҶ лӘ©н‘ңк°Җ  <b>{target:,}мӣҗ</b>  (+{target_pct:.1f}%){atr_tag}\n"
            f"в”Ӯ вҡ–пёҸ мҶҗмқөл№„  <b>{rr_text}</b>\n"
            f"в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ"
        )
    elif s["signal_type"] == "EARLY_DETECT":
        rr_text = _calc_rr_text(entry, stop, target)
        entry_block = (
            f"в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n"
            f"в”Ӯ вҡЎпёҸ <b>м„ м§„мһ… кі л Ө!</b>\n"
            f"в”Ӯ рҹҺҜ лӘ©н‘ңм§„мһ…  <b>{entry:,}мӣҗ</b>  вҶҗ нҳ„мһ¬ {diff_from_entry:+.1f}%\n"
            f"в”Ӯ рҹӣЎ мҶҗм Ҳк°Җ   <b>{stop:,}мӣҗ</b>  (-{stop_pct:.1f}%){atr_tag}\n"
            f"в”Ӯ рҹҸҶ лӘ©н‘ңк°Җ   <b>{target:,}мӣҗ</b>  (+{target_pct:.1f}%){atr_tag}\n"
            f"в”Ӯ вҡ–пёҸ мҶҗмқөл№„   <b>{rr_text}</b>\n"
            f"в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ"
        )
    else:
        elapsed = minutes_since(detected_at)
        wait_msg = f"вҸ° лҲҢлҰјлӘ© лҢҖкё° ({30-elapsed}л¶„ нӣ„ мІҙнҒ¬)" if elapsed < 30 else "рҹ“Ў лҲҢлҰјлӘ© мӢӨмӢңк°„ мІҙнҒ¬ мӨ‘"
        rr_text = _calc_rr_text(entry, stop, target)
        entry_block = (
            f"в”Ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n"
            f"в”Ӯ {wait_msg}\n"
            f"в”Ӯ рҹҺҜ лӘ©н‘ңм§„мһ…  <b>{entry:,}мӣҗ</b>  вҶҗ нҳ„мһ¬ {diff_from_entry:+.1f}%\n"
            f"в”Ӯ рҹӣЎ мҶҗм Ҳк°Җ   <b>{stop:,}мӣҗ</b>  (-{stop_pct:.1f}%){atr_tag}\n"
            f"в”Ӯ рҹҸҶ лӘ©н‘ңк°Җ   <b>{target:,}мӣҗ</b>  (+{target_pct:.1f}%){atr_tag}\n"
            f"в”Ӯ вҡ–пёҸ мҶҗмқөл№„   <b>{rr_text}</b>\n"
            f"в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ"
        )

    # NXT м—¬л¶Җ (мғҒм„ё лӘЁл“ңмҡ© - м»ҙнҢ©нҠёлҠ” мң„м—җм„ң мІҳлҰ¬лҗЁ)
    nxt_badge = "\nрҹҹЎ <b>NXT (л„ҘмҠӨнҠёл Ҳмқҙл“ң) кұ°лһҳ</b>" if s.get("market") == "NXT" else ""


    # ліҙмЎ°м§Җн‘ң + нҸ¬м§Җм…ҳ мӮ¬мқҙм§• + мң мӮ¬нҢЁн„ҙ лё”лЎқ
    indic = s.get("indic") or calc_indicators(s.get("code", ""))
    rsi     = indic.get("rsi", 50)
    ma_desc = indic.get("ma", {}).get("desc", "")
    bb_desc = indic.get("bb", {}).get("desc", "")
    indic_block = (
        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
        f"рҹ“җ <b>ліҙмЎ°м§Җн‘ң</b>\n"
        f"  RSI {rsi}  |  {ma_desc}\n"
        f"  ліјлҰ°м Җ: {bb_desc}\n"
    ) if ma_desc else ""

    pos = s.get("position", {})
    if pos:
        pct   = pos.get("pct", 8.0)
        guide = pos.get("guide", "")
        wr    = pos.get("win_rate")
        samp  = pos.get("samples", 0)
        wr_str = f"  кіјкұ°мҠ№лҘ  {wr:.0f}% ({samp}кұҙ)\n" if wr else ""
        position_block = (
            f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
            f"рҹ’° <b>нҸ¬м§Җм…ҳ к°Җмқҙл“ң</b>  к¶ҢмһҘ <b>{pct}%</b>\n"
            f"{wr_str}"
            f"  {guide}\n"
        )
    else:
        position_block = ""

    pattern_stats = s.get("similar_pattern_stats") or _get_similar_pattern_stats(
        s["code"], s["signal_type"], s.get("change_rate", 0), s.get("volume_ratio", 0)
    )
    pattern_block = _build_similar_pattern_detail_block(pattern_stats)
    if pattern_block:
        pattern_block = "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n" + pattern_block + "\n"

    _send_alert_detail(s, emoji, title, nxt_badge, name_dot, stars, now_str,
                       stop_pct, target_pct, atr_tag, strict_warn, prev_tag,
                       entry_block, indic_block, position_block, pattern_block, level)

# в”Җв”Җ лӮҙл¶Җ н—¬нҚј: мғҒм„ё лӘЁл“ң мӢӨм ң л°ңмҶЎ (send_alertм—җм„ң нҳём¶ң) в”Җв”Җ
def _is_capture_focus_reason(txt: str) -> bool:
    t = str(txt or '').strip()
    if not t:
        return False
    if 'н•ҷмҠө ліҙм •' in t:
        return False
    if t.startswith((
        'рҹ“Ҳ кёүл“ұ ', 'рҹ”Ҙ мғҒн•ңк°Җ к·јм ‘', 'рҹҡЁ мғҒн•ңк°Җ лҸ„лӢ¬',
        'рҹ’Ҙ кұ°лһҳлҹү ', 'рҹ“Ҡ кұ°лһҳлҹү ',
        'рҹ’Һ мҷёкөӯмқё+кё°кҙҖ л§ӨмҲҳ / к°ңмқё л§ӨлҸ„', 'вң… мҷёкөӯмқё+кё°кҙҖ лҸҷмӢң мҲңл§ӨмҲҳ',
        'рҹҹЎ мҷёкөӯмқё мҲңл§ӨмҲҳ', 'рҹҹЎ кё°кҙҖ мҲңл§ӨмҲҳ',
        'рҹ”ҙ NXT мҷёмқё+кё°кҙҖ лҸҷмӢңл§ӨмҲҳ',
        'рҹҡҰ мөңк·ј мІҙкІ°нқҗлҰ„ ', 'вҡЎ мІҙкІ°м§ҖмҶҚмҶҚлҸ„ ',
        'рҹ§ӯ лҲҢлҰј мң нҳ•:', 'рҹҺҜ мӢӨн–ү A мЎ°кұҙ:', 'вҡ пёҸ мӢӨн–ү ліҙм •:', 'рҹ•’ мһҘл§Ҳк°җ к·јм ‘:'
    )):
        return True
    return False


_CAPTURE_SIGNED_POINT_RE = re.compile(r'(?P<value>[+-]\d+)м җ(?!\s*[([<])')


def _score_delta_impact_label(delta: int) -> str:
    d = int(delta or 0)
    if d >= 25:
        return 'лҢҖк°Җ'
    if d >= 10:
        return 'мӨ‘к°Җ'
    if d >= 1:
        return 'мҶҢк°Җ'
    if d <= -15:
        return 'лҢҖк°җ'
    if d <= -8:
        return 'мӨ‘к°җ'
    if d <= -1:
        return 'мҶҢк°җ'
    return ''


def _signal_total_score_label(score: int) -> str:
    s = int(score or 0)
    if s >= 100:
        return 'мөңмғҒ'
    if s >= 85:
        return 'к°•н•Ё'
    if s >= 70:
        return 'м–‘нҳё'
    if s >= 55:
        return 'ліҙнҶө'
    if s >= 40:
        return 'м•Ҫн•Ё'
    return 'мң„н—ҳ'




def _risk_total_score_label(score: int) -> str:
    s = int(score or 0)
    if s >= 50:
        return 'мң„н—ҳ'
    if s >= 20:
        return 'кІҪкі„'
    return 'м•Ҳм •'


def _ui_total_score_label_for_line(line: str, score: int) -> str:
    txt = str(line or '')
    stripped = txt.strip()
    if (
        'лҰ¬мҠӨнҒ¬' in txt or 'VIX' in txt or 'көӯлӮҙ м¶”м„ё л¶•кҙҙ' in txt or 'м§Җм •н•ҷ' in txt
        or stripped.startswith(('рҹ’§', 'рҹҢҚ', 'рҹ“ү'))
    ):
        return _risk_total_score_label(score)
    if any(key in txt for key in ('мІҙкІ°м§ҖмҶҚмҶҚлҸ„', 'лҲҢлҰј мң м§Җ', 'мҳҲл№„нҢҗлӢЁ')):
        return _execution_score_label(score)
    return _signal_total_score_label(score)


_UI_SIGNED_POINT_RE = re.compile(r'(?P<value>[+-]\d+)м җ(?:\s*\([^\)\n]{1,20}\))?')
_UI_UNSIGNED_POINT_RE = re.compile(r'(?<![+\-\d])(?P<value>\d+)м җ(?:\s*\([^\)\n]{1,20}\))?(?!\s*[>%])')


def _format_signed_score_delta(value: int, compact: bool = False) -> str:
    val = int(value or 0)
    label = _score_delta_impact_label(val)
    if not label:
        return f"{val:+d}м җ"
    return f"{val:+d}м җ({label})" if compact else f"{val:+d}м җ ({label})"


def _decorate_ui_score_line(line: str) -> str:
    raw = str(line or '')
    if 'м җ' not in raw:
        return raw

    out = _UI_SIGNED_POINT_RE.sub(lambda match: _format_signed_score_delta(int(match.group('value')), compact=True), raw)

    def _unsigned_repl(match: re.Match) -> str:
        value = int(match.group('value'))
        label = _ui_total_score_label_for_line(out, value)
        return f"{value}м җ({label})" if label else f"{value}м җ"

    out = _UI_UNSIGNED_POINT_RE.sub(_unsigned_repl, out)
    return out


def _decorate_ui_score_text(text: str) -> str:
    if not text or 'м җ' not in str(text):
        return text
    return '\n'.join(_decorate_ui_score_line(line) for line in str(text).split('\n'))

def _decorate_capture_reason_line(txt: str) -> str:
    line = str(txt or '').strip()
    if not line:
        return ''

    line = _CAPTURE_SIGNED_POINT_RE.sub(lambda match: _format_signed_score_delta(int(match.group('value')), compact=False), line)
    line = re.sub(
        r'(мІҙкІ°м§ҖмҶҚмҶҚлҸ„\s+)(\d+)м җ(?!\s*\()',
        lambda m: f"{m.group(1)}{m.group(2)}м җ ({_execution_score_label(int(m.group(2)))})",
        line,
    )
    line = re.sub(
        r'(лҲҢлҰј мң м§Җ\s+)(\d+)м җ(?!\s*\()',
        lambda m: f"{m.group(1)}{m.group(2)}м җ ({_execution_score_label(int(m.group(2)))})",
        line,
    )
    return line


def _build_capture_focus_reasons(s: dict) -> list[str]:
    lines = []
    seen = set()
    for raw in s.get('reasons', []) or []:
        txt = str(raw or '').strip()
        if not txt or not _is_capture_focus_reason(txt):
            continue
        if txt in seen:
            continue
        seen.add(txt)
        lines.append(_decorate_capture_reason_line(txt))
    return lines


def _build_capture_focus_sector_block(s: dict) -> str:
    si = s.get('sector_info') or {}
    theme = str(si.get('theme', '') or '').strip()
    if not theme:
        return ''
    bonus = int(si.get('bonus', 0) or 0)
    summary = str(si.get('summary', '') or '').strip()
    rising = si.get('rising', []) or []
    flat = si.get('flat', []) or []
    sources = si.get('sources', {}) or {}

    lines = [f"рҹҸӯ <b>м„№н„° лӘЁл©ҳн…Җ</b> [{theme}]" + (f"  +{bonus}м җ" if bonus > 0 else "")]
    if 'лҸҷм Ғн…Ңл§Ҳ' in sources:
        lines.append('  рҹ”— м—°кҙҖ к·јкұ°: к°ҖкІ© мғҒкҙҖкҙҖкі„В·лүҙмҠӨ кіөлҸҷм–ёкёү')
    if summary:
        lines.append(f'  {summary}')
    for r in rising[:2]:
        src_tag = ' рҹ”—' if r.get('source') == 'лҸҷм Ғн…Ңл§Ҳ' else ''
        lines.append(f"  рҹ“Ҳ {_resolve_stock_name(r.get('code',''), r.get('name',''))} <b>{float(r.get('change_rate',0) or 0):+.1f}%</b>{src_tag}")
    for r in flat[:1]:
        src_tag = ' рҹ”—' if r.get('source') == 'лҸҷм Ғн…Ңл§Ҳ' else ''
        lines.append(f"  вһ– {_resolve_stock_name(r.get('code',''), r.get('name',''))} {float(r.get('change_rate',0) or 0):+.1f}%{src_tag}")
    return "\n".join(lines) + "\n"


def _build_capture_focus_price_line(s: dict) -> str:
    price = int(s.get('price', 0) or 0)
    if not price:
        return ''
    return f"рҹ’ө нҳ„мһ¬к°Җ <b>{price:,}мӣҗ</b>"


def _build_capture_focus_message(s: dict, header_line: str, capture_label: str, name_dot: str = '') -> str:
    parts = [
        header_line,
        f"рҹ•җ {capture_label}",
        'в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ',
        f"{name_dot} <b>{s['name']}</b>  <code>{s['code']}</code>",
    ]
    price_line = _build_capture_focus_price_line(s)
    focus_reasons = _build_capture_focus_reasons(s)
    sector_block = _build_capture_focus_sector_block(s)
    if price_line:
        parts.append(price_line)
    if focus_reasons:
        parts.append('в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ')
        parts.extend(focus_reasons)
    if sector_block:
        parts.append('в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ')
        parts.extend(sector_block.rstrip().split('\n'))
    return "\n".join([p for p in parts if p]).rstrip()



# в”Җв”Җ лӮҙл¶Җ н—¬нҚј: мғҒм„ё лӘЁл“ң мӢӨм ң л°ңмҶЎ (send_alertм—җм„ң нҳём¶ң) в”Җв”Җ
def _send_alert_detail(s, emoji, title, nxt_badge, name_dot, stars, now_str,
                       stop_pct, target_pct, atr_tag, strict_warn, prev_tag,
                       entry_block, indic_block, position_block, pattern_block, level):
    header_override = str(s.get("_header_override", "") or "").strip()
    header_line = header_override if header_override else f"{emoji} <b>[{title}]</b>"
    msg = _build_capture_focus_message(s, header_line, now_str, name_dot=name_dot)
    send_by_level(msg.rstrip(), level, s["code"], s["name"])



# ============================================================
# рҹ”Қ D: мӢӨнҢЁ нҢЁн„ҙ н•„н„° (v38.6)
# ============================================================

def detect_failure_pattern(code: str, change_rate: float, vol_ratio: float) -> dict:
    """v38.6-D: кёүл“ұ нӣ„ мӢӨнҢЁ нҢЁн„ҙ к°җм§Җ.
    - кёүл“ұ(+5%вҶ‘)мқёлҚ° кұ°лһҳлҹүмқҙ нҸүк·  мқҙн•ҳ вҶ’ кұ°лһҳлҢҖкёҲ л’·л°ӣм№Ё м—ҶлҠ” кёүл“ұ
    - мқјлҙүмғҒ м „мқј кёүл“ұ нӣ„ мҳӨлҠҳ кұ°лһҳлҹү кёүк°җ вҶ’ м¶”кІ©л§ӨмҲҳ н•Ём •
    л°ҳнҷҳ: {"is_fail": bool, "penalty": int, "reason": str}
    """
    try:
        # нҢЁн„ҙ 1: к°ҖкІ©мқҖ кёүл“ұмқёлҚ° кұ°лһҳлҹү л№„мңЁмқҙ лӮ®мқҢ вҶ’ н—ҲмҲҳ кёүл“ұ
        if change_rate >= 5.0 and vol_ratio < 2.0:
            return {"is_fail": True, "penalty": -10,
                    "reason": f"вҡ пёҸ кёүл“ұ {change_rate:+.1f}% but кұ°лһҳлҹү {vol_ratio:.1f}л°° л¶ҖмЎұ (мӢӨнҢЁ нҢЁн„ҙ)"}

        # нҢЁн„ҙ 2: м „мқј кёүл“ұ нӣ„ мҳӨлҠҳ кұ°лһҳлҹү кёүк°җ вҶ’ м¶”кІ©л§ӨмҲҳ н•Ём •
        items = get_daily_data(code, 5)
        if len(items) >= 2:
            prev = items[-2]
            prev_cr = 0
            if prev.get("open") and prev["open"] > 0:
                prev_cr = (prev["close"] - prev["open"]) / prev["open"] * 100
            prev_vol = prev.get("volume", 0)
            today_vol_est = items[-1].get("volume", 0)
            if prev_cr >= 8.0 and today_vol_est > 0 and prev_vol > 0:
                vol_decline = today_vol_est / prev_vol
                if vol_decline < 0.4:
                    return {"is_fail": True, "penalty": -8,
                            "reason": f"вҡ пёҸ м „мқј {prev_cr:+.1f}% кёүл“ұ нӣ„ кұ°лһҳлҹү {vol_decline:.0%}лЎң кёүк°җ (м¶”кІ©л§ӨмҲҳ мЈјмқҳ)"}

        return {"is_fail": False, "penalty": 0, "reason": ""}
    except Exception:
        return {"is_fail": False, "penalty": 0, "reason": ""}


# ============================================================
# л¶„м„қ м—”м§„ (лӢ№мқј кёүл“ұ)
# ============================================================
def analyze(stock: dict) -> dict:
    code = stock.get("code",""); change_rate = stock.get("change_rate",0)
    vol_ratio = stock.get("volume_ratio",0); price = stock.get("price",0)
    if not code or price < 500: return {}

    strict    = is_strict_time()
    min_score = _dynamic["min_score_strict"] if strict else _dynamic["min_score_normal"]
    _slot = _get_timeslot(datetime.now().strftime("%H:%M:%S"))
    _slot_adj = int(_dynamic.get("timeslot_score_adj", {}).get(_slot, 0) or 0)
    min_score += _slot_adj
    _regime_pre = get_market_regime()
    _regime_mode = _regime_pre.get("mode", _dynamic.get("regime_mode", "normal"))
    _regime_mult = float(_dynamic.get("regime_score_mult", 1.0) or 1.0)
    _regime_min_add = int(_dynamic.get("regime_min_add", 0) or 0)
    min_score += _regime_min_add
    # v41.64: NXT мӢңк°„лҢҖлі„ нҢҢлқјлҜён„° ліҙм •
    _nxt_params = get_nxt_params()
    _nxt_score_mult = 1.0
    if _nxt_params and stock.get("market") == "NXT":
        min_score += _nxt_params.get("min_add", 0)
        _nxt_score_mult = _nxt_params.get("score_mult", 1.0)
    score, reasons, signal_type = 0, [], None
    if _slot_adj > 0:
        reasons.append(f"рҹ•җ [{_slot}] н•ҷмҠө ліҙм •: мөңмҶҢм җмҲҳ +{_slot_adj}м җ")
    if _regime_mode != "normal":
        reasons.append(f"рҹҢҺ {regime_label()} н•„н„°: мөңмҶҢм җмҲҳ +{_regime_min_add}м җ / м җмҲҳл°°мңЁ x{_regime_mult:.2f}")
    if _nxt_params and stock.get("market") == "NXT" and _nxt_params.get("min_add", 0) > 0:
        reasons.append(f"рҹҹЎ {_nxt_params.get('label','')} н•„н„°: мөңмҶҢм җмҲҳ +{_nxt_params['min_add']}м җ / м җмҲҳл°°мңЁ x{_nxt_score_mult:.2f}")

    if change_rate >= 29.0:
        score+=40; reasons.append("рҹҡЁ мғҒн•ңк°Җ лҸ„лӢ¬!"); signal_type="UPPER_LIMIT"
    elif change_rate >= UPPER_LIMIT_THRESHOLD:
        score+=25; reasons.append(f"рҹ”Ҙ мғҒн•ңк°Җ к·јм ‘ (+{change_rate:.1f}%)"); signal_type="NEAR_UPPER"
    elif change_rate >= PRICE_SURGE_MIN:
        score+=15; reasons.append(f"рҹ“Ҳ кёүл“ұ +{change_rate:.1f}%"); signal_type="SURGE"
    else: return {}

    current_time = datetime.now().strftime("%H:%M:%S")
    required_vol = get_effective_volume_ratio(signal_type, current_time)
    if vol_ratio < required_vol:
        return {}
    if not check_liquidity(code, quote=stock):
        return {}

    if vol_ratio >= required_vol*2:
        score+=30; reasons.append(f"рҹ’Ҙ кұ°лһҳлҹү {vol_ratio:.1f}л°° нҸӯл°ң (лҸҷм Ғкё°мӨҖ {required_vol:.1f}л°° лҢҖл№„)")
    elif vol_ratio >= required_vol:
        score+=20; reasons.append(f"рҹ“Ҡ кұ°лһҳлҹү {vol_ratio:.1f}л°° кёүмҰқ (лҸҷм Ғкё°мӨҖ {required_vol:.1f}л°° лҢҖл№„)")

    _chg_bucket = _feature_change_bucket(change_rate)
    _vol_bucket = _feature_volume_bucket(vol_ratio)
    _chg_adj = int(_dynamic.get("feature_change_adj", {}).get(_chg_bucket, 0) or 0)
    _vol_adj = int(_dynamic.get("feature_volume_adj", {}).get(_vol_bucket, 0) or 0)
    if _chg_adj:
        score += _chg_adj
        reasons.append(f"рҹ“Ҳ ліҖлҸҷлҘ  н•ҷмҠө ліҙм • [{_chg_bucket}] {_chg_adj:+d}м җ")
    if _vol_adj:
        score += _vol_adj
        reasons.append(f"рҹ“Ҡ кұ°лһҳлҹү н•ҷмҠө ліҙм • [{_vol_bucket}] {_vol_adj:+d}м җ")

    # мҪ”мҠӨн”ј мғҒлҢҖк°•лҸ„ в‘Ҝ
    rs = get_relative_strength(change_rate)
    if rs >= RS_MIN:
        score+=10; reasons.append(f"рҹ’Ә мҪ”мҠӨн”ј мғҒлҢҖк°•лҸ„ {rs:.1f}л°°")

    if score >= 25:
        try:
            inv   = get_investor_trend(code)
            f_net = inv.get("foreign_net",     0)
            i_net = inv.get("institution_net", 0)
            r_net = inv.get("retail_net",      0)
            # 3мһҗ кө¬лҸ„ мҡ°м„  мІҙнҒ¬
            if f_net > 0 and i_net > 0 and r_net < 0:
                score += 30; signal_type = "STRONG_BUY"
                reasons.append(f"рҹ’Һ мҷёкөӯмқё+кё°кҙҖ л§ӨмҲҳ / к°ңмқё л§ӨлҸ„ (мөңк°• мҲҳкёүкө¬лҸ„) +30м җ")
            elif f_net > 0 and i_net > 0:
                score += 30; signal_type = "STRONG_BUY"
                reasons.append(f"вң… мҷёкөӯмқё+кё°кҙҖ лҸҷмӢң мҲңл§ӨмҲҳ +30м җ")
            elif f_net > 0:
                score += 10; reasons.append(f"рҹҹЎ мҷёкөӯмқё мҲңл§ӨмҲҳ ({f_net:+,}мЈј) +10м җ")
            elif i_net > 0:
                score += 10; reasons.append(f"рҹҹЎ кё°кҙҖ мҲңл§ӨмҲҳ ({i_net:+,}мЈј) +10м җ")
            # к°ңмқё мҲҳкёү л§ҘлқҪ л¶„м„қ (лӢЁмҲң м•…мһ¬ лӢЁм • X)
            if r_net > 0 and f_net < 0 and i_net < 0:
                cap_size = stock.get("cap_size") or "unknown"
                if cap_size == "unknown":
                    try:
                        _cp = get_stock_price(code)
                        cap_size = _cp.get("cap_size", "unknown")
                    except Exception: pass
                retail_ev = eval_retail_signal(code, f_net, i_net, r_net, cap_size)
                if retail_ev:
                    score += retail_ev["score_adj"]
                    if retail_ev["score_adj"] != 0:
                        reasons.append(
                            f"{retail_ev['label']} {int(retail_ev['score_adj'] or 0):+d}м җ вҖ” {retail_ev['detail']}"
                        )
                    else:
                        reasons.append(f"{retail_ev['label']} вҖ” {retail_ev['detail']}")
            elif f_net < 0 and i_net < 0:
                reasons.append(f"вҡ пёҸ мҷёкөӯмқё({f_net:+,}) кё°кҙҖ({i_net:+,}) лҸҷмӢң л§ӨлҸ„")
        except Exception as _e:
            _log_error(f"analyze_investor({stock.get('code', '')})", _e); inv = {}; f_net = 0; i_net = 0

    score, reasons, similar_pattern_stats = _apply_similar_pattern_score(
        score, reasons, code, signal_type, change_rate, vol_ratio, weight_mode="strong"
    )

    try:
        _exec_metrics = get_execution_speed_metrics(code, current_price=price)
        _exec_strength = _execution_score_label(int(_exec_metrics.get("execution_speed_score", 0) or 0))
        if _exec_strength == "к°•н•Ё":
            score += 15
            reasons.append("вҡЎ мІҙкІ°мҶҚлҸ„ к°•н•Ё +15м җ")
        elif _exec_strength == "м–‘нҳё":
            score += 5
            reasons.append("вҡЎ мІҙкІ°мҶҚлҸ„ м–‘нҳё +5м җ")
    except Exception:
        pass

    countertrend_ctx = {"is_countertrend": False}
    if signal_type in ("UPPER_LIMIT", "NEAR_UPPER", "SURGE"):
        countertrend_ctx = _get_countertrend_surge_context(code)
        if countertrend_ctx.get("is_countertrend"):
            _ctr_penalty = {"UPPER_LIMIT": 8, "NEAR_UPPER": 12, "SURGE": 12}.get(signal_type, 10)
            score -= _ctr_penalty
            reasons.append(
                f"вҡ пёҸ мһҘкё° н•ҳлқҪ м¶”м„ё мҶҚ кёүл“ұ вҖ” м¶”м„ё м—ӯн–ү -{_ctr_penalty}м җ "
                f"(60мқј {countertrend_ctx.get('ret60',0):+.1f}% / 120мқј кі м җлҢҖл№„ {countertrend_ctx.get('drawdown120',0):+.1f}% / "
                f"20мқјм„ {'<' if countertrend_ctx.get('cond_ma') else 'вүҘ'}60мқјм„ )"
            )

    if _regime_mult != 1.0:
        score = int(round(score * _regime_mult))
    # v41.64: NXT мӢңк°„лҢҖлі„ м җмҲҳ л°°мңЁ м Ғмҡ©
    if _nxt_score_mult != 1.0:
        score = int(round(score * _nxt_score_mult))
    if score < min_score: return {}

    # в”Җв”Җ ліҙмЎ°м§Җн‘ң (RSI / мқҙлҸҷнҸүк·  / ліјлҰ°м Җ) вҶ’ v38.6: к°җм җл§Ң, м°ЁлӢЁ м—ҶмқҢ в”Җв”Җ
    indic = calc_indicators(code)
    score += indic["score_adj"]
    if indic["summary"]:
        for line in indic["summary"].split("\n"):
            if line: reasons.append(line)
    if score < min_score: return {}

    # в”Җв”Җ v38.6-D: мӢӨнҢЁ нҢЁн„ҙ н•„н„° в”Җв”Җ
    fail = detect_failure_pattern(code, change_rate, vol_ratio)
    if fail["is_fail"]:
        score += fail["penalty"]
        reasons.append(fail["reason"])
    if score < min_score: return {}

    # в”Җв”Җ v38.6-J: н•ҙмҷё м„ л¬јвҶ’м„№н„° м—°лҸҷ ліҙм • в”Җв”Җ
    try:
        us = _us_cache if time.time() - _us_cache.get("ts", 0) < 7200 else {}
        if us and sector_info.get("theme"):
            _theme = sector_info["theme"]
            _gold = float(us.get("gold_chg", 0) or 0)
            _oil = float(us.get("oil_chg", 0) or 0)
            _tnx = float(us.get("tnx", 0) or 0)
            _j_adj = 0
            _j_reason = ""
            # кёҲ кёүл“ұ вҶ’ л°©мӮ°В·м•Ҳм „мһҗмӮ° нҳёмһ¬
            if _gold >= 1.5 and _theme in ("л°©мӮ°","мӣҗм „","кёҲ","к·ҖкёҲмҶҚ"):
                _j_adj = 5; _j_reason = f"рҹҘҮ кёҲ+{_gold:.1f}% вҶ’ {_theme} нҳёмһ¬"
            elif _gold <= -1.5 and _theme in ("л°©мӮ°","кёҲ","к·ҖкёҲмҶҚ"):
                _j_adj = -3; _j_reason = f"рҹҘҮ кёҲ{_gold:.1f}% вҶ’ {_theme} л¶ҖлӢҙ"
            # мң к°Җ кёүл“ұ вҶ’ м—җл„Ҳм§ҖВ·м •мң  нҳёмһ¬, н•ӯкіөВ·л¬јлҘҳ м•…мһ¬
            if _oil >= 3.0 and _theme in ("м—җл„Ҳм§Җ","м •мң ","м„қмң ","мӣҗмң ","мЎ°м„ "):
                _j_adj = max(_j_adj, 5); _j_reason = f"рҹӣўпёҸ мң к°Җ+{_oil:.1f}% вҶ’ {_theme} нҳёмһ¬"
            elif _oil >= 3.0 and _theme in ("н•ӯкіө","л¬јлҘҳ","мҡҙмҶЎ","нҷ”н•ҷ"):
                _j_adj = min(_j_adj, -4); _j_reason = f"рҹӣўпёҸ мң к°Җ+{_oil:.1f}% вҶ’ {_theme} л№„мҡ© л¶ҖлӢҙ"
            elif _oil <= -3.0 and _theme in ("н•ӯкіө","л¬јлҘҳ","мҡҙмҶЎ"):
                _j_adj = max(_j_adj, 4); _j_reason = f"рҹӣўпёҸ мң к°Җ{_oil:.1f}% вҶ’ {_theme} л№„мҡ© мҷ„нҷ”"
            # кёҲлҰ¬ мғҒмҠ№ вҶ’ мқҖн–үВ·ліҙн—ҳ нҳёмһ¬, м„ұмһҘмЈјВ·л°”мқҙмҳӨ л¶ҖлӢҙ
            if _tnx >= 4.8 and _theme in ("мқҖн–ү","ліҙн—ҳ","кёҲмңө"):
                _j_adj = max(_j_adj, 4); _j_reason = f"рҹ“Ҳ 10Y{_tnx:.1f}% вҶ’ {_theme} кёҲлҰ¬ нҳёмһ¬"
            elif _tnx >= 4.8 and _theme in ("л°”мқҙмҳӨ","AIл°ҳлҸ„мІҙ","2м°Ём „м§Җ","м„ұмһҘ"):
                _j_adj = min(_j_adj, -3); _j_reason = f"рҹ“Ҳ 10Y{_tnx:.1f}% вҶ’ {_theme} кёҲлҰ¬ л¶ҖлӢҙ"
            if _j_adj != 0:
                score += _j_adj
                reasons.append(_j_reason)
    except Exception:
        pass

    # v37.0: API мӮ¬м „ мәҗмӢұ (get_stock_price мӨ‘ліө нҳём¶ң 3вҶ’1нҡҢ м Ҳк°җ)
    try: _cached_price = get_stock_price(code)
    except Exception: _cached_price = {}

    # м „мқј мғҒн•ңк°Җ в‘Ё
    prev_upper = was_upper_limit_yesterday(code)
    if prev_upper: score+=10; reasons.append("рҹ”Ғ м „мқј мғҒн•ңк°Җ вҶ’ м—°мҶҚ мғҒн•ңк°Җ к°ҖлҠҘм„ұ")

    # кұ°лһҳлҹү Z-score в‘°
    try:
        cur_detail = _cached_price  # v37.0: мәҗмӢұлҗң к°’ мӮ¬мҡ©
        z = get_volume_zscore(code, cur_detail.get("today_vol",0))
        if z >= VOL_ZSCORE_MIN: score+=10; reasons.append(f"рҹ“Ҡ кұ°лһҳлҹү мқҙмғҒ кёүмҰқ (Z-score {z:.1f}Пғ)")
    except Exception: pass

    # м„№н„° лӘЁл©ҳн…Җ
    sector_info = calc_sector_momentum(code, stock.get("name",code))
    _w_sec = _dynamic.get("feat_w_sector", 1.0)
    sector_info["bonus"] = int(sector_info["bonus"] * _w_sec)
    if sector_info["bonus"]>0:
        score+=sector_info["bonus"]; reasons.append(sector_info["summary"])
        if sector_info.get("rising"):
            reasons.append("рҹ“Ң лҸҷл°ҳ мғҒмҠ№: " + ", ".join([f"{_resolve_stock_name(r['code'], r.get('name',''))} {r['change_rate']:+.1f}%" for r in sector_info["rising"][:4]]))
    elif sector_info.get("summary"):
        reasons.append(sector_info["summary"])

    theme_drive_hit = False
    try:
        if signal_type in THEME_DRIVE_SIGNAL_TYPES or change_rate >= THEME_DRIVE_MIN_CHANGE or vol_ratio >= THEME_DRIVE_MIN_VOLUME:
            theme_drive = _get_theme_drive_hint(code, stock.get("name", code), change_rate=change_rate, vol_ratio=vol_ratio, market=str(stock.get("market", "") or ""))
            if theme_drive.get("theme"):
                if sector_info.get("theme", "") in ("", "кё°нғҖм—…мў…", "unknown", "лҜёл¶„лҘҳ"):
                    sector_info["theme"] = theme_drive["theme"]
                    sector_info["theme_key"] = theme_drive.get("theme_key", theme_drive["theme"])
                theme_bonus = int(theme_drive.get("bonus", 0) or 0)
                if theme_bonus > 0:
                    score += theme_bonus
                theme_drive_hit = True
                reasons.append(
                    f"рҹҸӯ н…Ңл§Ҳ лҸҷмЎ°к°•м„ё [{theme_drive['theme']}] {theme_bonus:+d}м җ вҖ” "
                    f"лҰ¬лҚ” {theme_drive.get('leader_name','')} {theme_drive.get('leader_change',0):+.1f}% / "
                    f"лҸҷмЎ° {theme_drive.get('riser_cnt',0)}мў…лӘ©"
                )
    except Exception as _e:
        _log_error(f"theme_drive({code})", _e)

    # в”Җв”Җ NXT ліҙм • (мһҘ мӨ‘м—җл§Ң, л°ұк·ёлқјмҡҙл“ң мҳҒн–Ҙ мөңмҶҢнҷ”) в”Җв”Җ
    nxt_delta, nxt_reason = 0, ""
    try:
        nxt_delta, nxt_reason = nxt_score_bonus(code)
        if nxt_delta != 0:
            _w_nxt = _dynamic.get("feat_w_nxt", 1.0)
            score += int(nxt_delta * _w_nxt)
            if nxt_reason: reasons.append(nxt_reason)
    except Exception: pass

    adaptive_feedback_hit = False
    adaptive_feedback_bonus = 0
    try:
        _fb_bonus, _fb_notes = _calc_adaptive_feedback_bonus(code, sector_info.get("theme", ""), signal_type, change_rate=change_rate, vol_ratio=vol_ratio)
        if _fb_bonus > 0:
            adaptive_feedback_hit = True
            adaptive_feedback_bonus = int(_fb_bonus)
            score += adaptive_feedback_bonus
            reasons.extend(_fb_notes[:2])
    except Exception as _e:
        _log_error(f"adaptive_feedback({code})", _e)

    miss_theme_leader_hit = False
    miss_theme_leader_bonus = 0
    try:
        _mt_bonus, _mt_notes, _mt_breadth = _calc_miss_theme_leader_bonus(
            code, stock.get("name", code), sector_info.get("theme", ""), signal_type,
            change_rate=change_rate, vol_ratio=vol_ratio, market=stock.get("market", "")
        )
        if _mt_bonus > 0:
            miss_theme_leader_hit = True
            miss_theme_leader_bonus = int(_mt_bonus)
            score += miss_theme_leader_bonus
            reasons.extend(_mt_notes[:2])
            if isinstance(_mt_breadth, dict) and _mt_breadth.get("theme") and sector_info.get("theme", "") in ("", "кё°нғҖм—…мў…", "unknown", "лҜёл¶„лҘҳ"):
                sector_info["theme"] = _mt_breadth.get("theme")
                sector_info["theme_key"] = _mt_breadth.get("theme")
    except Exception as _e:
        _log_error(f"miss_theme_leader_feedback({code})", _e)

    nxt_post_leader_hit = False
    nxt_post_leader_bonus = 0
    try:
        _pm_bonus, _pm_notes = _calc_nxt_postmarket_leader_bonus(
            code, stock.get("name", code), sector_info.get("theme", ""), signal_type,
            change_rate=change_rate, vol_ratio=vol_ratio, market=stock.get("market", "")
        )
        if _pm_bonus > 0:
            nxt_post_leader_hit = True
            nxt_post_leader_bonus = int(_pm_bonus)
            score += nxt_post_leader_bonus
            reasons.extend(_pm_notes[:2])
    except Exception as _e:
        _log_error(f"nxt_postmarket_bonus({code})", _e)

    # в”Җв”Җ в‘  мӢңмһҘ көӯл©ҙ ліҙм • в”Җв”Җ
    regime = get_market_regime()
    regime_mode = regime.get("mode", _regime_mode)
    if regime_mode == "crash" and signal_type not in ("UPPER_LIMIT", "STRONG_BUY"):
        return {}   # кёүлқҪмһҘ: мғҒн•ңк°Җ/к°•л Ҙл§ӨмҲҳл§Ң н—Ҳмҡ©
    if score < min_score: return {}
    if regime_mode != "normal":
        reasons.append(f"рҹҢҗ мӢңмһҘ: {regime_label()} (мҪ”мҠӨн”ј {regime.get('chg_1d',0):+.1f}%)")

    # в”Җв”Җ лҜёкөӯ мӢңмһҘ м җмҲҳ ліҙм • в”Җв”Җ
    us = {}  # v37.0: мҙҲкё°нҷ” (end-of-function мӨ‘ліө fetch м ңкұ°)
    try:
        us = get_us_market_signals()
        us_adj = us.get("score_adj", 0)
        if us_adj != 0:
            score = max(0, score + us_adj)
            us_label = {"panic":"рҹ”ө лҜёкөӯ кёүлқҪмһҘ","risk_off":"рҹ”ө лҜёкөӯ м•Ҫм„ёмһҘ",
                        "neutral":"рҹ”ҙ лҜёкөӯ ліҙнҶөмһҘ","risk_on":"рҹ”ҙ лҜёкөӯ к°•м„ёмһҘ"}
            reasons.append(f"{us_label.get(us.get('us_regime','neutral'),'рҹҹЎ')} ({us_adj:+d}м җ)")
        if us.get("gap_signal") == "gap_down":
            reasons.append("в¬ҮпёҸ лӮҙмқј к°ӯн•ҳлқҪ к°ҖлҠҘм„ұ (лҜёкөӯ м•Ҫм„ё)")
        elif us.get("gap_signal") == "gap_up":
            reasons.append("в¬ҶпёҸ лӮҙмқј к°ӯмғҒмҠ№ кё°лҢҖ (лҜёкөӯ к°•м„ё)")
    except Exception as _e: _log_error("analyze_us", _e)

    # в”Җв”Җ н•ҙмҷё н•ңкөӯ ETF(EWY/FLKR) мһҘм „ мӢ¬лҰ¬ + нҺёмһ…л№„мӨ‘ м„№н„° ліҙм • в”Җв”Җ
    try:
        kr_adj, kr_reason = calc_korea_etf_score_adj(code, stock.get("name", code), signal_type, sector_info.get("theme", ""))
        if kr_adj != 0:
            score = max(0, score + kr_adj)
            reasons.append(kr_reason)
    except Exception as _e:
        _log_error("analyze_korea_etf", _e)

    # в”Җв”Җ кіөл§ӨлҸ„ мһ”кі  л№„мңЁ ліҙм • в”Җв”Җ
    short_ratio = 0.0  # v37.0: мҙҲкё°нҷ”
    try:
        short_ratio = get_short_sell_ratio(code)
        if short_ratio < 3.0:
            score += 5
            reasons.append(f"рҹӣЎ кіөл§ӨлҸ„ мһ”кі  {short_ratio:.1f}% вҖ” м Җл¶ҖлӢҙ +5м җ")
        elif short_ratio >= 10:
            score -= 10
            reasons.append(f"вҡ пёҸ кіөл§ӨлҸ„ мһ”кі  {short_ratio:.1f}% вҖ” л°ҳл“ұ мӢң мҲҸм»ӨлІ„ кё°лҢҖ к°ҖлҠҘ")
        elif short_ratio >= 5:
            score -= 5
            reasons.append(f"рҹ“ү кіөл§ӨлҸ„ мһ”кі  {short_ratio:.1f}% вҖ” мЈјмқҳ")
    except Exception: pass

    # в”Җв”Җ мҷёкөӯмқё+кё°кҙҖ м—°мҶҚ мҲңл§ӨмҲҳ ліҙм • в”Җв”Җ
    f_days, i_days = 0, 0  # v37.0: мҙҲкё°нҷ”
    try:
        f_days = get_foreign_consecutive_days(code)
        i_days = get_institution_consecutive_days(code)
        # мҷёкөӯмқё+кё°кҙҖ лҸҷмӢң м—°мҶҚ л§ӨмҲҳ вҶ’ мӢңл„Ҳм§Җ к°ҖмӨ‘
        if f_days >= 3 and i_days >= 3:
            adj = min((f_days + i_days) * 2, 20)
            score += adj
            reasons.append(f"рҹ”ҙ мҷёкөӯмқё {f_days}мқј+кё°кҙҖ {i_days}мқј лҸҷмӢң м—°мҶҚл§ӨмҲҳ (+{adj}м җ)")
        elif f_days >= 3:
            adj = min(f_days * 3, 15)
            score += adj
            reasons.append(f"рҹ”ҙ мҷёкөӯмқё {f_days}мқј м—°мҶҚ мҲңл§ӨмҲҳ (+{adj}м җ)")
        elif i_days >= 3:
            adj = min(i_days * 2, 10)
            score += adj
            reasons.append(f"рҹҸҰ кё°кҙҖ {i_days}мқј м—°мҶҚ мҲңл§ӨмҲҳ (+{adj}м җ)")
        elif f_days <= -3:
            adj = min(abs(f_days) * 3, 15)
            score -= adj
            reasons.append(f"рҹ”ө мҷёкөӯмқё {abs(f_days)}мқј м—°мҶҚ мҲңл§ӨлҸ„ (-{adj}м җ)")
        elif i_days <= -3:
            adj = min(abs(i_days) * 2, 10)
            score -= adj
            reasons.append(f"рҹ”ө кё°кҙҖ {abs(i_days)}мқј м—°мҶҚ мҲңл§ӨлҸ„ (-{adj}м җ)")
    except Exception: pass

    # в”Җв”Җ лүҙмҠӨ мӢ¬мёө л¶„м„қ (ліёл¬ё + Claude API) в”Җв”Җ
    news_articles = []
    news_analysis = {}
    direct_news_hit = False
    emergent_theme_hit = False
    try:
        _articles = fetch_news_for_stock(code, stock.get("name", code))
        if _articles:
            news_articles = list(_articles[:3])
            deep = analyze_news_deep(_articles, stock.get("name", code), code)
            news_analysis = dict(deep or {})
            adj  = int(deep.get("score_adj", 0) or 0)
            verd = deep.get("verdict", "мӨ‘лҰҪ")
            conf = deep.get("confidence", "low")
            conf_emoji = {"high":"рҹ”Қ","mid":"рҹ“°","low":"рҹ“°"}.get(conf,"рҹ“°")

            if adj != 0:
                score += adj
                # н‘ңл©ҙнҳёмһ¬мӢӨм§Ҳм•…мһ¬ нҠ№лі„ кІҪкі 
                if verd == "н‘ңл©ҙнҳёмһ¬мӢӨм§Ҳм•…мһ¬":
                    reasons.append(f"вҡ пёҸ н‘ңл©ҙнҳёмһ¬мӢӨм§Ҳм•…мһ¬ мЈјмқҳ ({deep.get('reason','')}) {adj:+d}м җ")
                elif verd == "н‘ңл©ҙм•…мһ¬мӢӨм§Ҳнҳёмһ¬":
                    reasons.append(f"рҹ’Ў н‘ңл©ҙм•…мһ¬мӢӨм§Ҳнҳёмһ¬ ({deep.get('reason','')}) {adj:+d}м җ")
                else:
                    reasons.append(f"{conf_emoji} лүҙмҠӨ {verd} ({deep.get('reason','')}) {adj:+d}м җ")

            # лҰ¬мҠӨнҒ¬ нҸ¬мқёнҠё мһҲмңјл©ҙ м¶”к°Җ н‘ңмӢң
            for rp in deep.get("risk_points", [])[:2]:
                reasons.append(f"  вҡ пёҸ {rp}")

            direct_theme = _infer_direct_news_theme(code, stock.get("name", code), news_articles)
            if direct_theme.get("theme") and (signal_type in ("UPPER_LIMIT", "NEAR_UPPER", "STRONG_BUY", "SURGE") or change_rate >= 7.0):
                if sector_info.get("theme", "") in ("", "кё°нғҖм—…мў…"):
                    sector_info["theme"] = direct_theme["theme"]
                    sector_info["theme_key"] = direct_theme["theme"]
                direct_bonus = int(direct_theme.get("bonus", 0) or 0)
                if direct_bonus > 0:
                    score += direct_bonus
                direct_news_hit = True
                _matched = ", ".join(direct_theme.get("matched", [])[:3])
                reasons.append(
                    f"рҹ“° м§Ғм ‘лүҙмҠӨ н…Ңл§Ҳ [{direct_theme['theme']}] {direct_bonus:+d}м җ вҖ” "
                    f"{direct_theme.get('reason','')}"
                    + (f" ({_matched})" if _matched else "")
                )
            elif signal_type in EMERGENT_THEME_SIGNAL_TYPES or change_rate >= EMERGENT_THEME_MIN_CHANGE or vol_ratio >= EMERGENT_THEME_MIN_VOLUME:
                emergent_theme = _infer_emergent_issue_theme(code, stock.get("name", code), news_articles)
                if emergent_theme.get("theme"):
                    if sector_info.get("theme", "") in ("", "кё°нғҖм—…мў…", "unknown", "лҜёл¶„лҘҳ"):
                        sector_info["theme"] = emergent_theme["theme"]
                        sector_info["theme_key"] = emergent_theme.get("theme_key", emergent_theme["theme"])
                    emergent_bonus = int(emergent_theme.get("bonus", 0) or 0)
                    if emergent_bonus > 0:
                        score += emergent_bonus
                    emergent_theme_hit = True
                    _matched = ", ".join(emergent_theme.get("matched", [])[:3])
                    reasons.append(
                        f"рҹ§  мӢ к·ңмқҙмҠҲ мһҗлҸҷк°җм§Җ [{emergent_theme['theme']}] {emergent_bonus:+d}м җ вҖ” "
                        f"{emergent_theme.get('reason','')}"
                        + (f" ({_matched})" if _matched else "")
                    )
                    _register_emergent_issue_theme(code, stock.get("name", code), emergent_theme, trigger="analyze")
    except Exception as _e: _log_error(f"analyze_news({code})", _e)

    try:
        if direct_news_hit:
            if signal_type in ("UPPER_LIMIT", "SURGE"):
                score += 10
                reasons.append("рҹ“° м§Ғм ‘лүҙмҠӨ Г— кёүл“ұ мӢңк·ёл„җ +10м җ")
            elif signal_type == "STRONG_BUY":
                score += 8
                reasons.append("рҹ“° м§Ғм ‘лүҙмҠӨ Г— к°•л Ҙл§ӨмҲҳ мӢңк·ёл„җ +8м җ")
    except Exception:
        pass

    # в”Җв”Җ м§Җм •н•ҷ мқҙлІӨнҠё ліҙм • в”Җв”Җ
    try:
        if _geo_event_state.get("active") and time.time() - _geo_event_state.get("ts",0) < 3600:
            si           = stock.get("sector_info") or {}
            stock_sector = si.get("theme", "") or si.get("sector", "")
            geo_unc      = _geo_event_state.get("uncertainty", "low")
            unc_label    = {"high":"рҹ”ө","mid":"рҹҹЎ","low":"рҹ”ҙ"}

            # sector_directions мһҲмңјл©ҙ м„№н„°лі„ к°ңлі„ ліҙм •
            sec_dirs = _geo_event_state.get("sector_directions", [])
            matched  = False
            _geo_adj_applied = 0  # feature_flags кё°лЎқмҡ©
            if sec_dirs and stock_sector:
                for sd in sec_dirs:
                    sec_name = sd.get("sector", "")
                    if sec_name in stock_sector or stock_sector in sec_name:
                        adj = max(-15, min(sd.get("score_adj", 0), 15))
                        _dir = sd.get("direction", "мӨ‘лҰҪ")
                        _arrow = _DIR_DISPLAY.get(_dir, "вҖ•")
                        # н•ҳлқҪ м„№н„° + мғҒн•ңк°Җ м•„лӢҢ мӢ нҳё вҶ’ к°•н•ң нҢЁл„җнӢ°
                        if _dir == "н•ҳлқҪ" and signal_type not in ("UPPER_LIMIT", "STRONG_BUY"):
                            adj = min(adj, -8)
                        if adj != 0:
                            _w_geo = _dynamic.get("feat_w_geo", 1.0)
                            _geo_sw = float(_dynamic.get("geo_sector_weights", {}).get(sec_name, 1.0) or 1.0)
                            _geo_sw = max(0.6, min(_geo_sw, 1.4))
                            adj_weighted = int(adj * _w_geo * _geo_sw)
                            score += adj_weighted
                            _geo_adj_applied = adj_weighted
                            reasons.append(
                                f"рҹҢҚ [{sec_name}] {_arrow}  "
                                f"({sd.get('reason','')}) {adj_weighted:+d}м җ"
                            )
                        elif _dir != "мӨ‘лҰҪ":
                            reasons.append(
                                f"рҹҢҚ [{sec_name}] {_arrow}  ({sd.get('reason','')})"
                            )
                        matched = True
                        break

            # sector_directions м—Ҷмңјл©ҙ м „мІҙ score_adj fallback
            if not matched:
                geo_sectors = _geo_event_state.get("sectors", [])
                geo_adj     = int(_geo_event_state.get("score_adj", 0) or 0)
                if stock_sector and (any(s in stock_sector for s in geo_sectors)
                                     or any(stock_sector in s for s in geo_sectors)):
                    if geo_adj != 0:
                        score += geo_adj
                        _geo_adj_applied = geo_adj
                        reasons.append(
                            f"рҹҢҚ м§Җм •н•ҷ кҙҖл Ё м„№н„° {unc_label.get(geo_unc,'')} {geo_adj:+d}м җ"
                        )
    except Exception as _e: _log_error(f"analyze_geo({code})", _e)

    # в”Җв”Җ н…Ңл§Ҳ лЎңн…Ңмқҙм…ҳ ліҙм • в”Җв”Җ
    try:
        rotation  = detect_theme_rotation()
        si        = stock.get("sector_info") or {}
        theme_key = si.get("theme", "") or si.get("theme_key", "")
        if theme_key:
            theme_scores = rotation.get("themes", {})
            t_chg        = theme_scores.get(theme_key, 0)
            strong_themes = [k for k, v in rotation.get("strong", [])]
            weak_themes   = [k for k, v in rotation.get("weak",   [])]
            if theme_key in strong_themes:
                score += 8
                reasons.append(f"рҹ”„ [{theme_key}] н…Ңл§Ҳ к°•м„ё ({t_chg:+.1f}%) +8м җ")
            elif theme_key in weak_themes:
                score -= 8
                reasons.append(f"рҹ”„ [{theme_key}] н…Ңл§Ҳ м•Ҫм„ё ({t_chg:+.1f}%) -8м җ")
    except Exception: pass

    # в”Җв”Җ в‘Ј мӢӨм Ғ л°ңн‘ң н•„н„° в”Җв”Җ
    earnings = check_earnings_risk(code, stock.get("name", code))
    if earnings["risk"] == "high":
        reasons.append(earnings["desc"])
        _ehm = max(0.40, min(float(_dynamic.get("earnings_high_mult", 0.72) or 0.72), 1.0))
        new_score = int(score * _ehm)
        reasons.append(f"рҹ“… мӢӨм Ғ лҰ¬мҠӨнҒ¬ н•ҷмҠө ліҙм • [high] x{_ehm:.2f}")
        score = new_score
        if score < min_score: return {}
    elif earnings["risk"] == "warn":
        reasons.append(earnings["desc"])
        _ewm = max(0.60, min(float(_dynamic.get("earnings_warn_mult", 0.85) or 0.85), 1.0))
        new_score = int(score * _ewm)
        reasons.append(f"рҹ“… мӢӨм Ғ лҰ¬мҠӨнҒ¬ н•ҷмҠө ліҙм • [warn] x{_ewm:.2f}")
        score = new_score
        if score < min_score: return {}

    # в”Җв”Җ в‘Ө DART лҰ¬мҠӨнҒ¬ м°ЁлӢЁ н•„н„° в”Җв”Җ
    # мғҒн•ңк°Җ(UPPER_LIMIT)лҠ” мқҙлҜё мһҘмӨ‘ нҷ•мқёлҗң мў…лӘ©мқҙлҜҖлЎң мҳҲмҷё
    _dart_r = check_dart_risk(code)
    if _dart_r["is_risk"] and signal_type not in ("UPPER_LIMIT",):
        print(f"  рҹҡ« DARTлҰ¬мҠӨнҒ¬м°ЁлӢЁ [{stock.get('name', code)}]: {_dart_r['title']}")
        return {}

    open_est     = price/(1+change_rate/100)
    _pullback_r  = _dynamic.get("entry_pullback_ratio", get_regime_pullback_ratio())
    entry        = int((price-(price-open_est)*_pullback_r)/10)*10

    # в”Җв”Җ в‘ў мҶҗмқөл№„ лҸҷм Ғ мЎ°м • в”Җв”Җ
    stop, target, stop_pct, target_pct, atr_used = calc_dynamic_stop_target(code, entry, signal_type=signal_type)

    # в”Җв”Җ л§Өл¬јлҢҖ/м§Җм§Җм Җн•ӯм„  ліҙм • в”Җв”Җ
    try:
        vp = calc_volume_profile(code, entry)
        if vp.get("score_adj") != 0:
            score += vp["score_adj"]
            if vp.get("reason"): reasons.append(vp["reason"])
    except Exception: pass

    # в”Җв”Җ кіөмӢң м „ мқҙмғҒ кұ°лһҳлҹү ліҙм • в”Җв”Җ
    try:
        pre_dart = detect_pre_dart_volume(code, stock.get("name", code))
        if pre_dart.get("detected") and pre_dart.get("score_adj"):
            score += pre_dart["score_adj"]
            reasons.append(pre_dart["reason"])
    except Exception: pass

    # в”Җв”Җ мҲҳкёү мқҙмғҒ нҢЁн„ҙ ліҙм • в”Җв”Җ
    try:
        cur_p     = _cached_price  # v37.0: мәҗмӢұлҗң к°’ мӮ¬мҡ©
        ask_qty   = cur_p.get("ask_qty", 0)
        bid_qty   = cur_p.get("bid_qty", 0)
        fp        = detect_force_pattern(
            code, stock.get("name", code),
            price=price, change_rate=change_rate, vol_ratio=vol_ratio,
            ask_qty=ask_qty, bid_qty=bid_qty
        )
        fp_adj = fp.get("total_adj", 0)
        if fp_adj != 0:
            score += fp_adj
        for p in fp.get("patterns", []):
            if p.get("score_adj", 0) != 0 or p.get("confidence") == "high":
                conf_emoji = {"high":"рҹ”ө","mid":"рҹҹЎ","low":""}.get(p["confidence"],"")
                reasons.append(
                    f"{conf_emoji} [{p['confidence'].upper()}] {p['label']} "
                    f"{int(p['score_adj'] or 0):+d}м җ вҖ” {p['detail']}"
                )
        if fp.get("risk_flag"):
            reasons.append("вҡ пёҸ мҲҳкёү мқҙнғҲ мӢ нҳё к°җм§Җ вҖ” нҸ¬м§Җм…ҳ м¶•мҶҢ кІҖнҶ ")
    except Exception as _e:
        _log_error(f"detect_force({code})", _e)

    _multi_tf_block = _should_block_multi_tf_downtrend_capture(code, signal_type, signal_meta={"score": score, "change_rate": change_rate, "vol_ratio": vol_ratio, "sector_info": sector_info, "direct_news_hit": direct_news_hit, "market": stock.get("market", ""), "reasons": reasons})
    if _multi_tf_block.get("block"):
        _ctx = _multi_tf_block.get("context", {}) or {}
        _log_suppressed_alert(
            code, stock.get("name", code),
            _multi_tf_block.get("reason", "мЈјлҙүВ·мқјлҙү лҸҷл°ҳ н•ҳлқҪ м¶”м„ё м°ЁлӢЁ"),
            signal_type,
            {
                "daily_ret20": _ctx.get("daily_ret20", 0.0),
                "weekly_ret8": _ctx.get("weekly_ret8", 0.0),
                "daily_flags": _ctx.get("daily_flags", 0),
                "weekly_flags": _ctx.get("weekly_flags", 0),
                "change_rate": change_rate,
                "score": score,
            },
        )
        return {}

    # л“ұкёү кі„мӮ°
    a_cut = 80
    if _should_relax_general_a_threshold(
        signal_type, score, change_rate=change_rate, vol_ratio=vol_ratio,
        sector_info=sector_info, direct_news_hit=direct_news_hit, nxt_delta=nxt_delta,
        market=stock.get("market", ""), reasons=reasons
    ):
        a_cut = min(a_cut, GENERAL_A_RELAXED_SCORE)
        reasons.append(f"рҹҸ· н•ңн…Қнҳ• лҰ¬лҚ” AкІҢмқҙнҠё мҷ„нҷ” ({80}вҶ’{a_cut})")
    if   score >= a_cut: grade = "A"
    elif score >= 60: grade = "B"
    else:             grade = "C"
    if countertrend_ctx.get("is_countertrend") and signal_type in ("UPPER_LIMIT", "NEAR_UPPER", "SURGE") and grade == "A":
        grade = "B"
        reasons.append("вҡ пёҸ мһҘкё° н•ҳлқҪ м¶”м„ё м—ӯн–ү кёүл“ұ вҖ” мөңкі  л“ұкёү A м ңн•ң")

    # в”Җв”Җ в‘Ў нҸ¬м§Җм…ҳ мӮ¬мқҙм§• в”Җв”Җ
    position = calc_position_size(signal_type, score, grade)

    # v37.0: мқҙлҜё мң„м—җм„ң к°Җм ёмҳЁ к°’ мһ¬мӮ¬мҡ© (мӨ‘ліө API нҳём¶ң м ңкұ°)
    return {"code":code,"name":stock.get("name",code),"price":price,
            "change_rate":change_rate,"volume_ratio":vol_ratio,
            "signal_type":signal_type,"score":score,"sector_info":sector_info,
            "sector_theme": sector_info.get("theme", ""),
            "direct_news_hit": direct_news_hit,
            "emergent_theme_hit": emergent_theme_hit,
            "theme_drive_hit": theme_drive_hit,
            "adaptive_feedback_hit": adaptive_feedback_hit,
            "adaptive_feedback_bonus": adaptive_feedback_bonus,
            "miss_theme_leader_hit": miss_theme_leader_hit,
            "miss_theme_leader_bonus": miss_theme_leader_bonus,
            "nxt_post_leader_hit": nxt_post_leader_hit,
            "nxt_post_leader_bonus": nxt_post_leader_bonus,
            "entry_price":entry,"stop_loss":stop,"target_price":target,
            "stop_pct":stop_pct,"target_pct":target_pct,"atr_used":atr_used,
            "prev_upper":prev_upper,"reasons":reasons,"detected_at":datetime.now(),
            "nxt_delta": nxt_delta,
            "regime": regime_mode,
            "us_regime":    us.get("us_regime","neutral"),
            "gap_signal":   us.get("gap_signal","flat"),
            "foreign_days": f_days,
            "institution_days": i_days,
            "short_ratio":  short_ratio,
            "earnings_risk": earnings["risk"],
            "position": position,
            "indic": indic,
            "grade": grade,
            "news_analysis": news_analysis,
            "news_articles": news_articles,
            "similar_pattern_stats": similar_pattern_stats,
            "dart_risk": _dart_r["is_risk"],
            "countertrend_warning": bool(countertrend_ctx.get("is_countertrend")),
            "countertrend_ctx": countertrend_ctx}

# ============================================================
# мЎ°кё° нҸ¬м°©
# ============================================================
def check_nxt_preopen_detection(existing_codes=None) -> list:
    signals = []
    existing = set(existing_codes or [])

    now_t = datetime.now().time()
    if not (is_nxt_open() and dtime(8, 0) <= now_t < dtime(9, 0)):
        return signals

    for stock in get_nxt_surge_stocks():
        code = stock.get("code",""); price = stock.get("price",0)
        vr   = stock.get("volume_ratio",0); cr = stock.get("change_rate",0)
        if not code or price < 500 or code in existing:
            continue
        if cr < 5.0 or vr < 5.0:
            continue   # NXT мһҘ м „ кё°мӨҖ лҚ” м—„кІ©

        nxt = get_nxt_info(code)
        pre_score = 70
        pre_reasons = [
            f"рҹҢ… мһҘ м „ NXT м„ нҸ¬м°©!",
            f"рҹ“Ҳ NXT нҳ„мһ¬ +{cr:.1f}%  (KRX к°ңмһҘ м „)",
            f"рҹ’Ҙ NXT кұ°лһҳлҹү {vr:.1f}л°°",
        ]
        sector_info = calc_sector_momentum(code, stock.get("name", code)) or {}
        direct_news_hit = False
        if nxt.get("inv_bullish"):
            pre_score += 15
            pre_reasons.append(f"рҹ”ҙ NXT мҷёмқё+кё°кҙҖ л§ӨмҲҳ ({nxt['foreign_net']:+,}мЈј)")
        if nxt.get("vs_krx_pct", 0) > 0.5:
            pre_score += 10
            pre_reasons.append(f"рҹ”ҙ NXT н”„лҰ¬лҜём—„ +{nxt['vs_krx_pct']:.1f}% вҶ’ KRX к°ӯмғҒ мЈјлӘ©")
        if sector_info.get("bonus", 0) > 0:
            pre_score += int(sector_info.get("bonus", 0) or 0)
            if sector_info.get("summary"):
                pre_reasons.append(sector_info["summary"])
            if sector_info.get("rising"):
                pre_reasons.append("рҹ“Ң лҸҷл°ҳ мғҒмҠ№: " + ", ".join([f"{_resolve_stock_name(r['code'], r.get('name',''))} {r['change_rate']:+.1f}%" for r in sector_info.get("rising", [])[:4]]))
        try:
            direct_theme = _infer_direct_news_theme(code, stock.get("name", code))
            if direct_theme.get("theme"):
                if str(sector_info.get("theme", "") or "") in ("", "кё°нғҖм—…мў…", "unknown", "лҜёл¶„лҘҳ"):
                    sector_info["theme"] = direct_theme["theme"]
                    sector_info["theme_key"] = direct_theme["theme"]
                direct_bonus = int(direct_theme.get("bonus", 0) or 0)
                if direct_bonus > 0:
                    pre_score += direct_bonus
                direct_news_hit = True
                _matched = ", ".join(direct_theme.get("matched", [])[:3])
                pre_reasons.append(
                    f"рҹ“° м§Ғм ‘лүҙмҠӨ н…Ңл§Ҳ [{direct_theme['theme']}] {direct_bonus:+d}м җ вҖ” "
                    f"{direct_theme.get('reason','')}"
                    + (f" ({_matched})" if _matched else "")
                )
            else:
                emergent_theme = _infer_emergent_issue_theme(code, stock.get("name", code))
                if emergent_theme.get("theme"):
                    if str(sector_info.get("theme", "") or "") in ("", "кё°нғҖм—…мў…", "unknown", "лҜёл¶„лҘҳ"):
                        sector_info["theme"] = emergent_theme["theme"]
                        sector_info["theme_key"] = emergent_theme.get("theme_key", emergent_theme["theme"])
                    emergent_bonus = int(emergent_theme.get("bonus", 0) or 0)
                    if emergent_bonus > 0:
                        pre_score += emergent_bonus
                    _matched = ", ".join(emergent_theme.get("matched", [])[:3])
                    pre_reasons.append(
                        f"рҹ§  мӢ к·ңмқҙмҠҲ мһҗлҸҷк°җм§Җ [{emergent_theme['theme']}] {emergent_bonus:+d}м җ вҖ” "
                        f"{emergent_theme.get('reason','')}"
                        + (f" ({_matched})" if _matched else "")
                    )
                    _register_emergent_issue_theme(code, stock.get("name", code), emergent_theme, trigger="nxt_preopen")
        except Exception:
            pass
        if pre_score < 75:
            continue

        entry = price
        stop, target, stop_pct, target_pct, atr_used = calc_stop_target(code, entry, signal_type="EARLY_DETECT")

        pre_score, pre_reasons, pre_similar_pattern_stats = _apply_similar_pattern_score(
            pre_score, pre_reasons, code, "EARLY_DETECT", cr, vr, weight_mode="strong"
        )
        _nxt_tf_block = _should_block_multi_tf_downtrend_capture(code, "EARLY_DETECT")
        if _nxt_tf_block.get("block"):
            _ctx = _nxt_tf_block.get("context", {}) or {}
            _log_suppressed_alert(
                code, stock.get("name", code),
                _nxt_tf_block.get("reason", "мЈјлҙүВ·мқјлҙү лҸҷл°ҳ н•ҳлқҪ м¶”м„ё м°ЁлӢЁ"),
                "EARLY_DETECT",
                {
                    "daily_ret20": _ctx.get("daily_ret20", 0.0),
                    "weekly_ret8": _ctx.get("weekly_ret8", 0.0),
                    "daily_flags": _ctx.get("daily_flags", 0),
                    "weekly_flags": _ctx.get("weekly_flags", 0),
                    "change_rate": cr,
                    "score": pre_score,
                    "market": "NXT",
                },
            )
            continue

        grade = _derive_general_signal_grade(
            "EARLY_DETECT", pre_score, change_rate=cr, vol_ratio=vr,
            sector_info=sector_info, direct_news_hit=direct_news_hit, nxt_delta=int(nxt.get("vs_krx_pct", 0) or 0),
            market="NXT", reasons=pre_reasons,
        )
        position = calc_position_size("EARLY_DETECT", pre_score, grade)

        signals.append({"code":code,"name":stock.get("name",code),"price":price,
                        "change_rate":cr,"volume_ratio":vr,
                        "signal_type":"EARLY_DETECT","score":pre_score,
                        "grade":grade,"execution_grade":grade,"pattern_grade":grade,
                        "sector_info":sector_info,"sector_theme": sector_info.get("theme", ""),
                        "direct_news_hit": direct_news_hit, "market":"NXT",
                        "similar_pattern_stats":pre_similar_pattern_stats,
                        "position": position,
                        "entry_price":entry,"stop_loss":stop,"target_price":target,
                        "stop_pct":stop_pct,"target_pct":target_pct,"atr_used":atr_used,
                        "prev_upper":False,"reasons":pre_reasons,
                        "detected_at":datetime.now()})
        existing.add(code)

    return signals


def check_nxt_postmarket_detection(existing_codes=None) -> list:
    signals = []
    existing = set(existing_codes or [])
    if not _is_nxt_postmarket_only_window():
        return signals

    slot = get_nxt_time_slot()
    min_score = NXT_POSTMARKET_ALERT_MIN_SCORE + (2 if slot == "post_late" else 0)
    for stock in _collect_nxt_postmarket_candidates(existing_codes=existing):
        code = stock.get("code", "")
        price = int(stock.get("price", 0) or 0)
        vr = float(stock.get("volume_ratio", 0) or 0)
        cr = float(stock.get("change_rate", 0) or 0)
        if not code or price < 500 or code in existing:
            continue
        if cr < NXT_POSTMARKET_MIN_CHANGE or vr < max(1.0, NXT_POSTMARKET_MIN_VOLUME - 0.4):
            continue

        score = 62 if slot == "post_early" else 64
        reasons = [
            "рҹҢҷ мһҘнӣ„ NXT м„ нҸ¬м°©!",
            f"рҹ“Ҳ NXT нҳ„мһ¬ {cr:+.1f}%  (KRX мў…к°Җ мқҙнӣ„)",
            f"рҹ’Ҙ NXT кұ°лһҳлҹү {vr:.1f}л°°",
        ]
        if cr >= 8.0:
            score += 12
            reasons.append("рҹҡҖ мһҘнӣ„ кёүл“ұ к°•лҸ„ мғҒмң„")
        elif cr >= 6.0:
            score += 8
            reasons.append("рҹ“Ҳ мһҘнӣ„ лҰ¬лҚ” кө¬к°„ м§„мһ…")
        if vr >= 3.0:
            score += 10
        elif vr >= 2.0:
            score += 6

        sector_info = calc_sector_momentum(code, stock.get("name", code)) or {}
        direct_news_hit = False
        if sector_info.get("bonus", 0) > 0:
            score += int(sector_info.get("bonus", 0) or 0)
            if sector_info.get("summary"):
                reasons.append(sector_info["summary"])
            if sector_info.get("rising"):
                reasons.append("рҹ“Ң лҸҷл°ҳ мғҒмҠ№: " + ", ".join([f"{_resolve_stock_name(r['code'], r.get('name',''))} {r['change_rate']:+.1f}%" for r in sector_info.get("rising", [])[:4]]))

        try:
            nxt = get_nxt_info(code)
        except Exception:
            nxt = {}
        if nxt.get("inv_bullish"):
            score += 8
            reasons.append(f"рҹ”ҙ NXT мҷёмқё+кё°кҙҖ л§ӨмҲҳ ({int(nxt.get('foreign_net',0) or 0):+,}мЈј)")
        if float(nxt.get("vs_krx_pct", 0.0) or 0.0) >= 1.0:
            score += 8
            reasons.append(f"рҹҹЎ NXT мў…к°Җ н”„лҰ¬лҜём—„ +{float(nxt.get('vs_krx_pct',0.0) or 0.0):.1f}%")

        try:
            direct_theme = _infer_direct_news_theme(code, stock.get("name", code))
            if direct_theme.get("theme"):
                if str(sector_info.get("theme", "") or "") in ("", "кё°нғҖм—…мў…", "unknown", "лҜёл¶„лҘҳ"):
                    sector_info["theme"] = direct_theme["theme"]
                    sector_info["theme_key"] = direct_theme["theme"]
                direct_bonus = int(direct_theme.get("bonus", 0) or 0)
                if direct_bonus > 0:
                    score += direct_bonus
                direct_news_hit = True
                reasons.append(f"рҹ“° м§Ғм ‘лүҙмҠӨ н…Ңл§Ҳ [{direct_theme['theme']}] {direct_bonus:+d}м җ вҖ” {direct_theme.get('reason','')}")
            else:
                emergent_theme = _infer_emergent_issue_theme(code, stock.get("name", code))
                if emergent_theme.get("theme"):
                    if str(sector_info.get("theme", "") or "") in ("", "кё°нғҖм—…мў…", "unknown", "лҜёл¶„лҘҳ"):
                        sector_info["theme"] = emergent_theme["theme"]
                        sector_info["theme_key"] = emergent_theme.get("theme_key", emergent_theme["theme"])
                    emergent_bonus = int(emergent_theme.get("bonus", 0) or 0)
                    if emergent_bonus > 0:
                        score += emergent_bonus
                    reasons.append(f"рҹ§  мӢ к·ңмқҙмҠҲ мһҗлҸҷк°җм§Җ [{emergent_theme['theme']}] {emergent_bonus:+d}м җ вҖ” {emergent_theme.get('reason','')}")
                    _register_emergent_issue_theme(code, stock.get("name", code), emergent_theme, trigger="nxt_postmarket")
        except Exception:
            pass

        try:
            theme_drive = _get_theme_drive_hint(code, stock.get("name", code), change_rate=cr, vol_ratio=vr, market="NXT")
            if theme_drive.get("theme"):
                if str(sector_info.get("theme", "") or "") in ("", "кё°нғҖм—…мў…", "unknown", "лҜёл¶„лҘҳ"):
                    sector_info["theme"] = theme_drive["theme"]
                    sector_info["theme_key"] = theme_drive.get("theme_key", theme_drive["theme"])
                theme_bonus = int(theme_drive.get("bonus", 0) or 0)
                if theme_bonus > 0:
                    score += theme_bonus
                reasons.append(f"рҹҸӯ н…Ңл§Ҳ лҸҷмЎ°к°•м„ё [{theme_drive['theme']}] {theme_bonus:+d}м җ вҖ” лҰ¬лҚ” {theme_drive.get('leader_name','')} {float(theme_drive.get('leader_change',0) or 0):+.1f}%")
        except Exception:
            pass

        try:
            _fb_bonus, _fb_notes = _calc_adaptive_feedback_bonus(code, sector_info.get("theme", ""), "SURGE", change_rate=cr, vol_ratio=vr)
            if _fb_bonus > 0:
                score += int(_fb_bonus)
                reasons.extend(_fb_notes[:1])
        except Exception:
            pass
        try:
            _mt_bonus, _mt_notes, _ = _calc_miss_theme_leader_bonus(code, stock.get("name", code), sector_info.get("theme", ""), "SURGE", change_rate=cr, vol_ratio=vr, market="NXT")
            if _mt_bonus > 0:
                score += int(_mt_bonus)
                reasons.extend(_mt_notes[:1])
        except Exception:
            pass
        try:
            _pm_bonus, _pm_notes = _calc_nxt_postmarket_leader_bonus(code, stock.get("name", code), sector_info.get("theme", ""), "SURGE", change_rate=cr, vol_ratio=vr, market="NXT")
            if _pm_bonus > 0:
                score += int(_pm_bonus)
                reasons.extend(_pm_notes[:1])
        except Exception:
            pass

        score, reasons, similar_pattern_stats = _apply_similar_pattern_score(score, reasons, code, "SURGE", cr, vr, weight_mode="strong")
        if score < min_score:
            continue

        _nxt_tf_block = _should_block_multi_tf_downtrend_capture(code, "SURGE")
        if _nxt_tf_block.get("block"):
            _ctx = _nxt_tf_block.get("context", {}) or {}
            _log_suppressed_alert(code, stock.get("name", code), _nxt_tf_block.get("reason", "мЈјлҙүВ·мқјлҙү лҸҷл°ҳ н•ҳлқҪ м¶”м„ё м°ЁлӢЁ"), "SURGE", {"daily_ret20": _ctx.get("daily_ret20", 0.0), "weekly_ret8": _ctx.get("weekly_ret8", 0.0), "change_rate": cr, "score": score, "market": "NXT"})
            continue

        open_est = price / (1 + cr / 100) if cr > -99 else price
        _pullback_r = _dynamic.get("entry_pullback_ratio", get_regime_pullback_ratio())
        entry = int((price - (price - open_est) * _pullback_r) / 10) * 10
        stop, target, stop_pct, target_pct, atr_used = calc_stop_target(code, entry, signal_type="SURGE")

        grade = _derive_general_signal_grade(
            "SURGE", score, change_rate=cr, vol_ratio=vr,
            sector_info=sector_info, direct_news_hit=direct_news_hit, nxt_delta=int(float(nxt.get("vs_krx_pct", 0.0) or 0.0)),
            market="NXT", reasons=reasons,
        )
        position = calc_position_size("SURGE", score, grade)

        signals.append({
            "code": code, "name": stock.get("name", code), "price": price,
            "change_rate": cr, "volume_ratio": vr,
            "signal_type": "SURGE", "score": score,
            "grade": grade, "execution_grade": grade, "pattern_grade": grade,
            "sector_info": sector_info, "sector_theme": sector_info.get("theme", ""),
            "direct_news_hit": direct_news_hit, "market": "NXT",
            "nxt_post_leader_hit": True,
            "position": position,
            "entry_price": entry, "stop_loss": stop, "target_price": target,
            "stop_pct": stop_pct, "target_pct": target_pct, "atr_used": atr_used,
            "prev_upper": False, "reasons": reasons,
            "similar_pattern_stats": similar_pattern_stats,
            "detected_at": datetime.now(),
        })
        existing.add(code)

    return signals


def check_early_detection() -> list:
    signals = []
    for stock in get_volume_surge_stocks():
        code = stock.get("code",""); change_rate = stock.get("change_rate",0)
        vol_ratio = stock.get("volume_ratio",0); price = stock.get("price",0)
        if not code or price < 500: continue
        if change_rate >= UPPER_LIMIT_THRESHOLD: continue
        price_min  = _early_price_min_dynamic  * (1.3 if is_strict_time() else 1.0)
        volume_min = _early_volume_min_dynamic * (1.3 if is_strict_time() else 1.0)
        if change_rate < price_min or vol_ratio < volume_min: continue
        try:
            detail = get_stock_price(code)
            bid_qty, ask_qty = detail.get("bid_qty",0), detail.get("ask_qty",0)
            if ask_qty > 0 and bid_qty/ask_qty < EARLY_HOGA_RATIO: continue
        except Exception: continue

        now = datetime.now()
        cache = _early_cache.get(code)
        if cache is None:
            _early_cache[code] = {"count":1,"last_price":price,"last_time":now}; continue
        elapsed = (now - cache["last_time"]).seconds
        if 15 <= elapsed <= 80:   # 20мҙҲ мҠӨмә” кё°мӨҖ: 1~4нҡҢ мӮ¬мқҙ мһ¬нҷ•мқё
            if price >= cache["last_price"]:
                cache["count"]+=1; cache["last_price"]=price; cache["last_time"]=now
            else: _early_cache[code]={"count":1,"last_price":price,"last_time":now}; continue
        else: _early_cache[code]={"count":1,"last_price":price,"last_time":now}; continue
        if cache["count"] < EARLY_CONFIRM_COUNT: continue
        del _early_cache[code]

        open_est     = price/(1+change_rate/100)
        _pullback_r  = _dynamic.get("entry_pullback_ratio", get_regime_pullback_ratio())
        entry        = int((price-(price-open_est)*_pullback_r)/10)*10
        stop, target, stop_pct, target_pct, atr_used = calc_stop_target(code, entry, signal_type="EARLY_DETECT")
        hoga_text = f"{bid_qty/ask_qty:.1f}л°°" if ask_qty > 0 else "м••лҸ„м Ғ"
        prev_upper = was_upper_limit_yesterday(code)
        early_score = 85 + (10 if prev_upper else 0)
        reasons = [f"рҹ”Қ мЎ°кё° нҸ¬м°©!",f"рҹ“Ҳ нҳ„мһ¬ +{change_rate:.1f}%",
                   f"рҹ’Ҙ кұ°лһҳлҹү {vol_ratio:.1f}л°° (5мқј нҸүк·  лҢҖл№„)",
                   f"рҹ“Ҡ л§ӨмҲҳ/л§ӨлҸ„ мһ”лҹү {hoga_text}",f"вң… 2л¶„ м—°мҶҚ мғҒмҠ№ нҷ•мқё"]
        if prev_upper: reasons.append("рҹ”Ғ м „мқј мғҒн•ңк°Җ вҶ’ м—°мҶҚ мғҒн•ңк°Җ к°ҖлҠҘм„ұ")
        # мҪ”мҠӨн”ј мғҒлҢҖк°•лҸ„
        rs = get_relative_strength(change_rate)
        if rs >= RS_MIN: early_score+=10; reasons.append(f"рҹ’Ә мҪ”мҠӨн”ј мғҒлҢҖк°•лҸ„ {rs:.1f}л°°")
        # кұ°лһҳлҹү Z-score
        try:
            z = get_volume_zscore(code, detail.get("today_vol",0))
            if z >= VOL_ZSCORE_MIN: early_score+=10; reasons.append(f"рҹ“Ҡ кұ°лһҳлҹү Z-score {z:.1f}Пғ")
        except Exception: pass
        sector_info = calc_sector_momentum(code, stock.get("name",code))
        direct_news_hit = False
        if sector_info["bonus"]>0:
            early_score+=sector_info["bonus"]; reasons.append(sector_info["summary"])
            if sector_info.get("rising"):
                reasons.append("рҹ“Ң лҸҷл°ҳ мғҒмҠ№: "+"".join([f"{_resolve_stock_name(r['code'], r.get('name',''))} {r['change_rate']:+.1f}%" for r in sector_info["rising"][:4]]))
        elif sector_info.get("summary"): reasons.append(sector_info["summary"])

        try:
            direct_theme = _infer_direct_news_theme(code, stock.get("name", code))
            if direct_theme.get("theme") and sector_info.get("theme", "") in ("", "кё°нғҖм—…мў…"):
                sector_info["theme"] = direct_theme["theme"]
                sector_info["theme_key"] = direct_theme["theme"]
                direct_bonus = int(direct_theme.get("bonus", 0) or 0)
                if direct_bonus > 0:
                    early_score += direct_bonus
                direct_news_hit = True
                _matched = ", ".join(direct_theme.get("matched", [])[:3])
                reasons.append(
                    f"рҹ“° м§Ғм ‘лүҙмҠӨ н…Ңл§Ҳ [{direct_theme['theme']}] {direct_bonus:+d}м җ вҖ” "
                    f"{direct_theme.get('reason','')}"
                    + (f" ({_matched})" if _matched else "")
                )
        except Exception:
            pass

        # NXT ліҙм •
        try:
            nd, nr = nxt_score_bonus(code)
            if nd != 0: early_score += nd
            if nr: reasons.append(nr)
        except Exception: pass

        early_score, reasons, similar_pattern_stats = _apply_similar_pattern_score(
            early_score, reasons, code, "EARLY_DETECT", change_rate, vol_ratio, weight_mode="strong"
        )
        _early_tf_block = _should_block_multi_tf_downtrend_capture(code, "EARLY_DETECT")
        if _early_tf_block.get("block"):
            _ctx = _early_tf_block.get("context", {}) or {}
            _log_suppressed_alert(
                code, stock.get("name", code),
                _early_tf_block.get("reason", "мЈјлҙүВ·мқјлҙү лҸҷл°ҳ н•ҳлқҪ м¶”м„ё м°ЁлӢЁ"),
                "EARLY_DETECT",
                {
                    "daily_ret20": _ctx.get("daily_ret20", 0.0),
                    "weekly_ret8": _ctx.get("weekly_ret8", 0.0),
                    "daily_flags": _ctx.get("daily_flags", 0),
                    "weekly_flags": _ctx.get("weekly_flags", 0),
                    "change_rate": change_rate,
                    "score": early_score,
                    "market": stock.get("market", ""),
                },
            )
            continue
        signals.append({"code":code,"name":stock.get("name",code),"price":price,
                        "change_rate":change_rate,"volume_ratio":vol_ratio,
                        "signal_type":"EARLY_DETECT","score":early_score,"sector_info":sector_info,
                        "sector_theme": sector_info.get("theme", ""),
                        "direct_news_hit": direct_news_hit,
                        "similar_pattern_stats":similar_pattern_stats,
                        "entry_price":entry,"stop_loss":stop,"target_price":target,
                        "stop_pct":stop_pct,"target_pct":target_pct,"atr_used":atr_used,
                        "prev_upper":prev_upper,"reasons":reasons,"detected_at":now})

    signals.extend(check_nxt_preopen_detection(existing_codes={s["code"] for s in signals}))

    return signals

