def _normalize_geo_sector_name(sector_name: str) -> str:
    text = str(sector_name or "").strip()
    if not text:
        return ""
    text = text.replace("гҶҚ", "В·").replace("&", "В·").replace("+", "В·")
    text = _re.sub(r"\s*/\s*", "В·", text)
    text = _re.sub(r"\s*(л°Ҹ|мҷҖ|кіј)\s*", "В·", text)
    text = _re.sub(r"\s+", " ", text).strip(" В·")
    return text


def _split_geo_sector_tokens(sector_name: str) -> list:
    normalized = _normalize_geo_sector_name(sector_name)
    if not normalized:
        return []
    clean = _re.sub(r"[\(\)\[\]]", "В·", normalized)
    parts = [p.strip() for p in clean.split("В·") if p.strip()]
    out = []
    seen = set()
    for token in [normalized] + parts:
        token = token.strip()
        if token and token not in seen:
            seen.add(token)
            out.append(token)
    return out


def _derive_geo_sector_stocks(sector_name: str, reason: str = "", max_n: int = 5) -> list:
    normalized = _normalize_geo_sector_name(sector_name)
    tokens = _split_geo_sector_tokens(normalized)
    if not tokens:
        return []

    seen_codes = set()
    results = []

    def _add_stock(code, name):
        code = str(code or "").strip()
        name = str(name or "").strip()
        if not code or not name or code in seen_codes:
            return
        seen_codes.add(code)
        results.append((code, name))

    for token in tokens:
        for c, n in _GEO_SECTOR_STOCKS.get(token, []):
            _add_stock(c, n)
    for key, stocks in _GEO_SECTOR_STOCKS.items():
        if any(key in token or token in key for token in tokens):
            for c, n in stocks:
                _add_stock(c, n)

    for theme_key, theme_info in THEME_MAP.items():
        sectors = [str(s) for s in theme_info.get("sectors", [])]
        hay = [theme_key, str(theme_info.get("desc", ""))] + sectors
        if any(any(token in h or h in token for h in hay if h) for token in tokens):
            for c, n in theme_info.get("stocks", []):
                _add_stock(c, n)

    for tk, ti in _dynamic_theme_map.items():
        sectors = [str(s) for s in ti.get("sectors", [])]
        hay = [tk, str(ti.get("desc", "")), str(ti.get("reason", ""))] + sectors
        if any(any(token in h or h in token for h in hay if h) for token in tokens):
            for item in ti.get("stocks", []):
                if isinstance(item, (list, tuple)) and len(item) >= 2:
                    _add_stock(item[0], item[1])

    reason_text = str(reason or "")
    if reason_text:
        candidate_pool = []
        for stocks in _GEO_SECTOR_STOCKS.values():
            candidate_pool.extend(stocks)
        for ti in THEME_MAP.values():
            candidate_pool.extend(ti.get("stocks", []))
        for ti in _dynamic_theme_map.values():
            candidate_pool.extend([tuple(x[:2]) for x in ti.get("stocks", []) if isinstance(x, (list, tuple)) and len(x) >= 2])
        seen_names = set()
        for c, n in candidate_pool:
            if n in seen_names:
                continue
            seen_names.add(n)
            if n and n in reason_text:
                _add_stock(c, n)

    return results[:max_n]


def _remember_geo_sector_candidates(sec_dirs: list):
    global _dynamic_theme_map
    if not sec_dirs:
        return
    today = datetime.now().strftime("%m%d")
    changed = False
    for sd in sec_dirs:
        sector = _normalize_geo_sector_name(sd.get("sector", ""))
        if not sector:
            continue
        reason = str(sd.get("reason", "") or "")
        stocks = _derive_geo_sector_stocks(sector, reason=reason, max_n=8)
        if not stocks:
            continue
        theme_key = f"geo_{today}_{_re.sub(r'[^0-9A-Za-zк°Җ-нһЈ]+', '_', sector)[:40]}"
        existing = _dynamic_theme_map.get(theme_key, {})
        merged = []
        seen = set()
        for item in list(existing.get("stocks", [])) + stocks:
            if not isinstance(item, (list, tuple)) or len(item) < 2:
                continue
            c, n = str(item[0]), str(item[1])
            if not c or c in seen:
                continue
            seen.add(c)
            merged.append((c, n))
        sectors = []
        for token in _split_geo_sector_tokens(sector):
            if token not in sectors:
                sectors.append(token)
        _dynamic_theme_map[theme_key] = {
            "desc": f"{sector} м—°кҙҖ м§Җм •н•ҷ н…Ңл§Ҳ",
            "reason": reason or str(sd.get("direction", "") or "м§Җм •н•ҷ м„№н„°"),
            "stocks": merged,
            "sectors": sectors,
            "ts": time.time(),
            "source": "geo_sector",
        }
        changed = True
    if changed:
        try:
            with open(DYNAMIC_THEME_FILE, "w", encoding="utf-8") as f:
                json.dump({k: {**v, "stocks": v.get("stocks", [])} for k, v in _dynamic_theme_map.items()},
                          f, ensure_ascii=False, indent=2)
        except Exception:
            pass


def _get_geo_sector_stocks(sector_name: str, max_n: int = 3) -> list:
    """
    м„№н„°лӘ…мңјлЎң кҙҖл Ё мў…лӘ© мЎ°нҡҢ.
    _GEO_SECTOR_STOCKS м§Ғм ‘ л§Өн•‘ + THEME_MAP + лҸҷм Ғ м§Җм •н•ҷ н…Ңл§Ҳк№Ңм§Җ лӢЁкі„м ҒмңјлЎң л°ҳмҳҒ.
    returns: [(code, name), ...]
    """
    return _derive_geo_sector_stocks(sector_name, max_n=max_n)


def _get_geo_sector_history(sector_name: str, stock_list: list) -> str:
    """
    v37.0: м§Җм •н•ҷ м„№н„° мў…лӘ©мқҳ кіјкұ° мӢ нҳё мқҙл Ҙ мЎ°нҡҢ.
    signal_logм—җм„ң к°ҷмқҖ мў…лӘ© + к°ҷмқҖ м„№н„°мқҳ мҷ„лЈҢлҗң мӢ нҳёлҘј м°ҫм•„
    мҠ№лҘ , нҸүк·  мҲҳмқөлҘ , мөңк·ј мӮ¬лЎҖлҘј л°ҳнҷҳ.

    Parameters:
        sector_name: м„№н„°лӘ… (мҳҲ: "л°©мӮ°", "м •мң ")
        stock_list:  [(code, name), ...] вҖ” _get_geo_sector_stocks кІ°кіј

    Returns:
        н…”л Ҳк·ёлһЁ н‘ңмӢңмҡ© л¬ёмһҗм—ҙ ("" = мқҙл Ҙ м—ҶмқҢ)
    """
    try:
        data = _read_json_locked(SIGNAL_LOG_FILE)
    except Exception:
        return ""

    if not data or not stock_list:
        return ""

    stock_codes = {code for code, name in stock_list}
    stock_names = {name for code, name in stock_list}

    # 1лӢЁкі„: к°ҷмқҖ мў…лӘ© мҪ”л“ңлЎң мҷ„лЈҢлҗң мӢ нҳё м°ҫкё°
    matched = []
    for log_key, rec in data.items():
        if rec.get("status") == "м¶”м ҒмӨ‘":
            continue
        pnl = rec.get("pnl_pct", 0)
        if pnl == 0 and not rec.get("exit_price"):
            continue

        code = rec.get("code", "")
        name = rec.get("name", "")
        s_theme = rec.get("sector_theme", "")

        # м§Ғм ‘ мў…лӘ© л§Өм№ӯ лҳҗлҠ” к°ҷмқҖ м„№н„° н…Ңл§Ҳ л§Өм№ӯ
        is_direct = code in stock_codes
        is_sector = (sector_name and s_theme and
                     (sector_name in s_theme or s_theme in sector_name))
        is_geo    = rec.get("feature_flags", {}).get("geo_active", False)

        if is_direct or (is_sector and is_geo):
            matched.append({
                "code":  code,
                "name":  name,
                "pnl":   round(pnl, 1),
                "date":  rec.get("detect_date", ""),
                "geo":   is_geo,
                "direct": is_direct,
            })

    if not matched:
        return ""

    # нҶөкі„ кі„мӮ°
    total  = len(matched)
    wins   = sum(1 for m in matched if m["pnl"] > 0)
    losses = sum(1 for m in matched if m["pnl"] <= 0)
    avg_pnl = round(sum(m["pnl"] for m in matched) / total, 1) if total else 0
    win_rate = round(wins / total * 100) if total else 0

    # мөңк·ј мӮ¬лЎҖ (мөңлҢҖ 3кұҙ, лӮ м§ң м—ӯмҲң)
    recent = sorted(matched, key=lambda x: x["date"], reverse=True)[:3]

    # нҸ¬л§·нҢ…
    win_emoji = "рҹ”ҙ" if win_rate >= 60 else ("рҹҹЎ" if win_rate >= 40 else "рҹ”ө")
    line1 = f"в”Ӯ  {win_emoji} кіјкұ° мң мӮ¬: {total}кұҙ мӨ‘ {wins}кұҙвҶ‘ ({win_rate}%) нҸүк· {avg_pnl:+.1f}%"

    examples = []
    for r in recent:
        d_str = ""
        if r["date"] and len(r["date"]) == 8:
            d_str = f"({r['date'][4:6]}/{r['date'][6:8]})"
        pnl_str = f"{r['pnl']:+.1f}%"
        geo_mark = "рҹҢҚ" if r["geo"] else ""
        examples.append(f"{_resolve_stock_name(r['code'], r.get('name',''))}{geo_mark} {pnl_str}{d_str}")

    line2 = "в”Ӯ     " + " | ".join(examples) if examples else ""

    result = line1
    if line2:
        result += "\n" + line2
    return result

