_tg_offset = 0

def _send_menu(title: str = ""):
    """
    мқёлқјмқё лІ„нҠј л©”лүҙ л°ңмҶЎ
    лІ„нҠјмқ„ лҲ„лҘҙл©ҙ н•ҙлӢ№ лӘ…л №м–ҙ н…ҚмҠӨнҠёк°Җ мұ„нҢ…м°Ҫм—җ мһ…л ҘлҗЁ
    (н…”л Ҳк·ёлһЁ callback_query л°©мӢқ лҢҖмӢ  switch_inline_query_current_chat мӮ¬мҡ©)
    """
    menu_title = title or "рҹ“Ң <b>лӘ…л №м–ҙ л©”лүҙ</b>  вҖ” лІ„нҠјмқ„ лҲҢлҹ¬ мӢӨн–үн•ҳм„ёмҡ”"
    keyboard = {
        "inline_keyboard": [
            [
                {"text": "рҹӨ– лҙҮ мғҒнғң",        "callback_data": "cmd_status"},
                {"text": "рҹ“Ӣ к°җмӢң мў…лӘ©",       "callback_data": "cmd_list"},
                {"text": "рҹҸҶ мҳӨлҠҳ TOP 5",      "callback_data": "cmd_top"},
            ],
            [
                {"text": "рҹ“Ҡ мқјмқј м„ұкіј",       "callback_data": "cmd_daily"},
                {"text": "рҹ“… мқҙлІҲ мЈј м„ұкіј",    "callback_data": "cmd_week"},
                {"text": "рҹ“Ҳ мҠ№лҘ  нҶөкі„",       "callback_data": "cmd_stats"},
            ],
            [
                {"text": "рҹҹЎ NXT нҳ„нҷ©",        "callback_data": "cmd_nxt"},
                {"text": "вҸё м•ҢлҰј м •м§Җ",        "callback_data": "cmd_stop"},
                {"text": "в–¶пёҸ м•ҢлҰј мһ¬к°ң",        "callback_data": "cmd_resume"},
            ],
            [
                {"text": "рҹ—ң м»ҙнҢ©нҠё м „нҷҳ",      "callback_data": "cmd_compact"},
                {"text": "вҡҷпёҸ BotFather м„Өм •лІ•", "callback_data": "cmd_setup"},
            ],
        ]
    }
    mid = send(menu_title, reply_markup=keyboard)
    if mid is None:
        send(menu_title)   # лІ„нҠј мӢӨнҢЁ мӢң н…ҚмҠӨнҠёлЎң нҸҙл°ұ

def _handle_callback(callback_id: str, data: str):
    """мқёлқјмқё лІ„нҠј мҪңл°ұ мІҳлҰ¬"""
    # лІ„нҠј лҲ„лҰ„ нҷ•мқё мқ‘лӢө (н…”л Ҳк·ёлһЁ н•„мҲҳ)
    try:
        _tg_request("answerCallbackQuery", {"callback_query_id": callback_id}, timeout=5)
    except Exception:
        pass

    cmd_map = {
        "cmd_status":  "/status",
        "cmd_list":    "/list",
        "cmd_top":     "/top",
        "cmd_daily":   "/daily",
        "cmd_nxt":     "/nxt",
        "cmd_week":    "/week",
        "cmd_stats":   "/stats",
        "cmd_stop":    "/stop",
        "cmd_resume":  "/resume",
        "cmd_compact": "/compact",
        "cmd_setup":   "/м„Өм •",
    }
    return cmd_map.get(data, "")


def poll_telegram_commands():
    global _tg_offset, _bot_paused
    try:
        resp = _tg_http_request(
            "get",
            "getUpdates",
            params={"offset": _tg_offset, "timeout": 2},
            read_timeout=_TG_LONGPOLL_READ_TIMEOUT,
            attempts=1,
            quiet=True,
        )
        if resp is None:
            return
        try:
            updates = (resp.json() or {}).get("result", [])
        except Exception:
            updates = []
        for update in updates:
            _tg_offset = update["update_id"]+1

            # в”Җв”Җ мқёлқјмқё лІ„нҠј мҪңл°ұ мІҳлҰ¬ в”Җв”Җ
            cb = update.get("callback_query")
            if cb:
                text = _handle_callback(cb["id"], cb.get("data",""))
                if not text: continue
                raw = text
            else:
                raw  = update.get("message",{}).get("text","").strip()
                if not raw: continue

            text = raw.lower()
            if not text.startswith("/"): continue

            # в”Җв”Җ /status в”Җв”Җ
            if text == "/status":
                rate_str = (f"\nрҹ“Ҡ EARLY м„ұкіөлҘ : {_early_feedback['success']}/{_early_feedback['total']} "
                            f"({_early_feedback.get('rate',0)*100:.0f}%)") if _early_feedback.get("total",0)>=5 else ""
                nxt_str  = f"\nрҹҹЎ NXT: {'мҡҙмҳҒ мӨ‘' if is_nxt_open() else 'л§Ҳк°җ'}"
                send(f"рҹӨ– <b>лҙҮ мғҒнғң</b>  {BOT_VERSION}  {'вҸё мқјмӢңм •м§Җ' if _bot_paused else 'в–¶пёҸ мӢӨн–ү мӨ‘'}\n"
                     f"рҹ•җ {datetime.now().strftime('%H:%M:%S')}  рҹ“… {BOT_DATE}\n"
                     f"рҹ“Ў мһҘ {'м—ҙлҰј' if is_market_open() else 'лӢ«нһҳ'}{nxt_str}\n"
                     f"рҹ‘Ғ к°җмӢң: {len(_detected_stocks)}к°ң  |  лҸҷм Ғн…Ңл§Ҳ: {len(_dynamic_theme_map)}к°ң\n"
                     f"вҡҷпёҸ EARLY мЎ°кұҙ: >{_early_price_min_dynamic}%, >{_early_volume_min_dynamic}л°°{rate_str}\n\n"
                     f"рҹ’¬ /result мў…лӘ©лӘ… мҲҳмқөлҘ   лЎң кІ°кіј кё°лЎқ\n"
                     f"мҳҲ) /result лҢҖмЈјмӮ°м—… +12.5")

            # в”Җв”Җ /list в”Җв”Җ
            elif text == "/list":
                pending_lines = []
                active_lines = []
                seen_pending = set()
                seen_active = set()
                quote_cache = {}

                # 1) нҳ„мһ¬ н•өмӢ¬ кё°мӨҖ: _entry_watch мғҒнғң
                try:
                    for _, watch in (_entry_watch or {}).items():
                        try:
                            code = str(watch.get("code") or "").strip()
                            if not code:
                                continue
                            name = watch.get("name") or _resolve_stock_name(code) or code
                            entry = int(watch.get("entry_price", 0) or 0)
                            target = int(watch.get("target_price", 0) or 0)
                            stop = int(watch.get("stop_loss", 0) or 0)
                            detect_time = str(watch.get("detect_time") or "").strip()
                            miss_count = int(watch.get("miss_count", 0) or 0)
                            hit = bool(watch.get("entry_hit"))
                            cur_info = _get_watch_list_current_price(code, watch, quote_cache)
                            cur_price = safe_int(cur_info.get("price", 0), 0)

                            line = f"вҖў <b>{name}</b> ({code})"
                            if miss_count > 0:
                                line += f" вҖ” мһ¬нҸ¬м°© {miss_count}нҡҢ"
                            details = []
                            if cur_price > 0:
                                details.append(f"рҹ“Қ нҳ„мһ¬к°Җ {cur_price:,}мӣҗ")
                            if entry > 0:
                                entry_gap = _format_watch_list_entry_vs_current(entry, cur_price)
                                details.append(f"рҹҺҜ м§„мһ…к°Җ {entry:,}мӣҗ{entry_gap}")
                            if target > 0:
                                details.append(f"рҹҸҶ лӘ©н‘ңк°Җ {target:,}мӣҗ")
                            if stop > 0:
                                details.append(f"рҹӣЎ мҶҗм Ҳк°Җ {stop:,}мӣҗ")
                            if details:
                                line += "\n  " + "  |  ".join(details)
                            if detect_time:
                                line += f"\n  вҸ° нҸ¬м°©мӢңк°Ғ {_format_capture_datetime_label(detect_date=watch.get('detect_date',''), detect_time=detect_time)}"

                            if hit:
                                if code not in seen_active:
                                    active_lines.append(line)
                                    seen_active.add(code)
                            else:
                                if code not in seen_pending:
                                    pending_lines.append(line)
                                    seen_pending.add(code)
                        except Exception:
                            continue
                except Exception:
                    pass

                # 2) ліҙмЎ° кё°мӨҖ: _detected_stocksм—җл§Ң мһҲкі  _entry_watchм—җ м•Ҳ мһЎнһҢ мў…лӘ©
                try:
                    for code, rec in (_detected_stocks or {}).items():
                        try:
                            code = str(code or "").strip()
                            if not code or code in seen_pending or code in seen_active:
                                continue
                            name = rec.get("name") or _resolve_stock_name(code) or code
                            carry_day = int(rec.get("carry_day", 0) or 0)
                            cur_info = _get_watch_list_current_price(code, rec, quote_cache)
                            cur_price = safe_int(cur_info.get("price", 0), 0)
                            line = f"вҖў <b>{name}</b> ({code})"
                            if carry_day > 0:
                                line += f" вҖ” {carry_day}мқјм°Ё"
                            if cur_price > 0:
                                line += f"\n  рҹ“Қ нҳ„мһ¬к°Җ {cur_price:,}мӣҗ"
                            pending_lines.append(line)
                            seen_pending.add(code)
                        except Exception:
                            continue
                except Exception:
                    pass

                if not pending_lines and not active_lines:
                    send("рҹ“Ӣ к°җмӢң мӨ‘мқё мў…лӘ© м—ҶмқҢ")
                else:
                    parts = ["рҹ“Ӣ <b>к°җмӢң мў…лӘ© нҳ„нҷ©</b>"]

                    parts.append("\nрҹҺҜ <b>м§„мһ…к°Җ к°җмӢңмӨ‘ мў…лӘ©</b>")
                    if pending_lines:
                        parts.append("\n".join(pending_lines))
                    else:
                        parts.append("- м—ҶмқҢ")

                    parts.append("\nрҹҸҶ <b>м§„мһ…к°Җ лҸ„лӢ¬ нӣ„ лӘ©н‘ңк°Җ м¶”м ҒмӨ‘ мў…лӘ©</b>")
                    if active_lines:
                        parts.append("\n".join(active_lines))
                    else:
                        parts.append("- м—ҶмқҢ")

                    send("\n".join(parts))

            # в”Җв”Җ /stop / /resume в”Җв”Җ
            elif text == "/stop":
                _bot_paused = True;  send("вҸё <b>лҙҮ мқјмӢңм •м§Җ</b>  /resume мңјлЎң мһ¬к°ң")
            elif text == "/resume":
                _bot_paused = False; send("в–¶пёҸ <b>лҙҮ мһ¬к°ң</b>")

            # в”Җв”Җ /compact вҖ” м»ҙнҢ©нҠё лӘЁл“ң нҶ кёҖ в”Җв”Җ
            elif text in ("/compact", "/м»ҙнҢ©нҠё"):
                global _compact_mode
                _compact_mode = not _compact_mode
                _save_compact_mode()
                mode_str = "рҹ—ң <b>м»ҙнҢ©нҠё лӘЁл“ң ON</b>\nм•ҢлҰјмқҙ 1~2мӨ„ мҡ”м•ҪмңјлЎң л°ңмҶЎлҗ©лӢҲлӢӨ" \
                           if _compact_mode else \
                           "рҹ“Ӣ <b>мғҒм„ё лӘЁл“ң ON</b>\nм•ҢлҰјмқҙ кё°мЎҙ мғҒм„ё нҸ¬л§·мңјлЎң л°ңмҶЎлҗ©лӢҲлӢӨ"
                send(mode_str)

            # в”Җв”Җ /л°ұм—… вҖ” мҰүмӢң мҲҳлҸҷ л°ұм—… в”Җв”Җ
            elif text in ("/л°ұм—…", "/backup"):
                send("рҹ’ҫ <b>мҲҳлҸҷ л°ұм—… мӢңмһ‘...</b>")
                ok_gist = backup_to_gist()
                ok_tg   = False
                if not ok_gist:
                    ok_tg = backup_to_telegram()
                if ok_gist:
                    send(f"вң… <b>GitHub Gist л°ұм—… мҷ„лЈҢ</b>  {BOT_VERSION}\n"
                         f"Gist ID: <code>{_gist_id_runtime}</code>")
                elif ok_tg:
                    send(f"вң… <b>н…”л Ҳк·ёлһЁ нҢҢмқј л°ұм—… мҷ„лЈҢ</b>  {BOT_VERSION}")
                else:
                    send("вқҢ л°ұм—… мӢӨнҢЁ\n"
                         "Railway Variablesм—җ <b>GITHUB_GIST_TOKEN</b> м„Өм • н•„мҡ”\n"
                         "лҳҗлҠ” н…”л Ҳк·ёлһЁ лҙҮ м„Өм • нҷ•мқё")

            # в”Җв”Җ /top вҖ” мҳӨлҠҳмқҳ мөңмҡ°м„  мў…лӘ© мҰүмӢң мЎ°нҡҢ в”Җв”Җ
            elif text == "/top":
                if not _today_top_signals:
                    send("рҹ“Ҡ мҳӨлҠҳ нҸ¬м°©лҗң мӢ нҳё м—ҶмқҢ (мһҘ мӢңмһ‘ нӣ„ мӢ нҳё лҲ„м Ғ мӨ‘)")
                else:
                    send_top_signals()

            # в”Җв”Җ /nxt вҖ” NXT нҳ„мһ¬ лҸҷн–Ҙ мҰүмӢң мЎ°нҡҢ в”Җв”Җ
            elif text == "/nxt":
                if not is_nxt_open():
                    send("рҹҹЎ NXT нҳ„мһ¬ л§Ҳк°җ мӨ‘ (08:00~20:00 мҡҙмҳҒ)")
                else:
                    try:
                        stocks = get_nxt_surge_stocks()
                        if not stocks:
                            send("рҹҹЎ NXT нҳ„мһ¬ кёүл“ұ мў…лӘ© м—ҶмқҢ")
                        else:
                            top = sorted(stocks, key=lambda x: abs(x.get("change_rate",0)), reverse=True)[:7]
                            lines = "\n".join(
                                f"  {'рҹ“Ҳ' if s['change_rate']>0 else 'рҹ“ү'} {s['name']} "
                                f"<b>{s['change_rate']:+.1f}%</b>  рҹ”Ҡ{s.get('volume_ratio',0):.0f}x"
                                for s in top
                            )
                            send(f"рҹҹЎ <b>NXT мӢӨмӢңк°„ лҸҷн–Ҙ</b>  {datetime.now().strftime('%H:%M')}\n"
                                 f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n{lines}")
                    except Exception as e:
                        send(f"вҡ пёҸ NXT мЎ°нҡҢ мҳӨлҘҳ: {e}")

            # в”Җв”Җ /week вҖ” мқҙлІҲ мЈј мһ м • м„ұкіј мҰүмӢң мЎ°нҡҢ в”Җв”Җ
            elif text == "/week":
                try:
                    data = {}
                    data = _read_json_locked(SIGNAL_LOG_FILE)
                    today    = datetime.now()
                    this_mon = (today - timedelta(days=today.weekday())).strftime("%Y%m%d")
                    this_fri = today.strftime("%Y%m%d")
                    week_done    = [v for v in data.values()
                                    if this_mon <= v.get("detect_date","") <= this_fri
                                    and v.get("status") in ["мҲҳмқө","мҶҗмӢӨ","ліём „"]]
                    week_tracking = [v for v in data.values()
                                     if this_mon <= v.get("detect_date","") <= this_fri
                                     and v.get("status") == "м¶”м ҒмӨ‘"
                                     and not _is_orphan_tracking(v)]
                    if not week_done and not week_tracking:
                        send("рҹ“… мқҙлІҲ мЈј мӢ нҳё м—ҶмқҢ"); continue
                    msg = f"рҹ“… <b>мқҙлІҲ мЈј мһ м • м„ұкіј</b>  {this_mon[4:6]}/{this_mon[6:]} ~ {this_fri[4:6]}/{this_fri[6:]}\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                    if week_done:
                        pnls    = [v["pnl_pct"] for v in week_done]
                        wins    = sum(1 for p in pnls if p > 0)
                        avg_pnl = sum(pnls) / len(pnls)
                        msg += (f"\nвң… <b>нҷ•м •</b>  {len(week_done)}кұҙ\n"
                                f"  мҠ№лҘ  {wins/len(week_done)*100:.0f}%  нҸүк·  {avg_pnl:+.1f}%\n")
                        for v in sorted(week_done, key=lambda x: x.get("pnl_pct",0), reverse=True)[:5]:
                            dot = "вң…" if v["pnl_pct"]>0 else "рҹ”ө"
                            msg += f"  {dot} {v['name']} {v['pnl_pct']:+.1f}%\n"
                    if week_tracking:
                        msg += f"\nвҸі <b>м¶”м Ғ мӨ‘</b>  {len(week_tracking)}кұҙ\n"
                        for v in week_tracking[:4]:
                            try:
                                cur   = get_stock_price(v["code"])
                                price = cur.get("price",0)
                                entry = v.get("entry_price",0)
                                if price and entry:
                                    pnl = (price-entry)/entry*100
                                    dot = "рҹ”ҙ" if pnl>=0 else "рҹҹЎ"
                                    msg += f"  {dot} {v['name']} {pnl:+.1f}% (мһ м •)\n"
                            except Exception: continue
                    send(msg)
                except Exception as e:
                    send(f"вҡ пёҸ мЈјк°„ мЎ°нҡҢ мҳӨлҘҳ: {e}")

            # в”Җв”Җ /daily вҖ” мҳӨлҠҳ мқјмқј м„ұкіј мҰүмӢң мЎ°нҡҢ в”Җв”Җ
            elif text in ("/daily", "/мҳӨлҠҳ"):
                try:
                    data = {}
                    data = _read_json_locked(SIGNAL_LOG_FILE)
                    today     = datetime.now().strftime("%Y%m%d")
                    today_str = datetime.now().strftime("%m/%d")
                    sig_labels = {
                        "UPPER_LIMIT":"мғҒн•ңк°Җ","NEAR_UPPER":"мғҒн•ңк°Җк·јм ‘","SURGE":"кёүл“ұ",
                        "EARLY_DETECT":"мЎ°кё°нҸ¬м°©","MID_PULLBACK":"лҲҢлҰјлӘ©",
                        "ENTRY_POINT":"лҲҢлҰјлӘ©","STRONG_BUY":"к°•л Ҙл§ӨмҲҳ",
                    }
                    today_recs   = [v for v in data.values() if v.get("detect_date") == today]
                    done_today   = [v for v in today_recs if v.get("status") != "м¶”м ҒмӨ‘"]
                    tracking_today = [v for v in today_recs if v.get("status") == "м¶”м ҒмӨ‘" and not _is_orphan_tracking(v)]
                    # мқҙмӣ” м¶”м Ғ мӨ‘ нҸ¬н•Ё
                    all_tracking = _get_valid_tracking(data)

                    if not today_recs and not all_tracking:
                        send(f"рҹ“Ҡ {today_str} мҳӨлҠҳ мӢ нҳё м—ҶмқҢ"); continue

                    msg = f"рҹ“Ҡ <b>мқјмқј м„ұкіј</b>  {today_str}  {datetime.now().strftime('%H:%M')}\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"

                    # в”Җв”Җ мҳӨлҠҳ нҷ•м • кІ°кіј в”Җв”Җ
                    if done_today:
                        pnls     = [v.get("pnl_pct",0) for v in done_today]
                        wins     = sum(1 for p in pnls if p > 0)
                        losses   = sum(1 for p in pnls if p < 0)
                        avg_pnl  = sum(pnls) / len(pnls)
                        win_rate = round(wins / len(done_today) * 100)
                        msg += (f"\nвң… <b>мҳӨлҠҳ нҷ•м •  {len(done_today)}кұҙ</b>\n"
                                f"  мҠ№лҘ  <b>{win_rate}%</b>  нҸүк·  <b>{avg_pnl:+.1f}%</b>"
                                f"  мҲҳмқө {wins}кұҙ  мҶҗмӢӨ {losses}кұҙ\n")
                        for v in sorted(done_today, key=lambda x: x.get("pnl_pct",0), reverse=True):
                            pnl  = v.get("pnl_pct", 0)
                            dot  = "вң…" if pnl > 0 else ("рҹ”ө" if pnl < 0 else "вһ–")
                            sig  = sig_labels.get(v.get("signal_type",""), "")
                            msg += f"  {dot} {v['name']} <b>{pnl:+.1f}%</b>  {sig}\n"
                    else:
                        msg += "\nрҹ“ӯ мҳӨлҠҳ нҷ•м •лҗң мӢ нҳё м—ҶмқҢ\n"

                    # в”Җв”Җ м¶”м Ғ мӨ‘ мһ м • мҲҳмқөлҘ  в”Җв”Җ
                    if all_tracking:
                        msg += f"\nвҸі <b>м¶”м Ғ мӨ‘  {len(all_tracking)}кұҙ</b>  (мһ м •)\n"
                        rows = []
                        for v in all_tracking:
                            try:
                                price = 0
                                if is_nxt_open() and is_nxt_listed(v.get("code","")):
                                    price = get_nxt_stock_price(v["code"]).get("price", 0)
                                if not price:
                                    price = get_stock_price(v["code"]).get("price", 0)
                                entry = v.get("entry_price", 0)
                                if price and entry:
                                    pnl = (price - entry) / entry * 100
                                    nxt_tag = " рҹҹЎ" if is_nxt_open() and is_nxt_listed(v.get("code","")) else ""
                                    rows.append((pnl, v["name"], nxt_tag))
                            except Exception: continue
                        for pnl, name, nxt_tag in sorted(rows, key=lambda x: x[0], reverse=True):
                            dot = "рҹ”ҙ" if pnl >= 0 else "рҹҹЎ"
                            msg += f"  {dot} {name} <b>{pnl:+.1f}%</b>{nxt_tag}\n"

                    send(msg)
                except Exception as e:
                    send(f"вҡ пёҸ мқјмқј м„ұкіј мЎ°нҡҢ мҳӨлҘҳ: {e}")

            # в”Җв”Җ /result мў…лӘ©лӘ… мҲҳмқөлҘ  в”Җв”Җ
            elif text.startswith("/result"):
                _handle_result_command(raw)

            # в”Җв”Җ /skip мў…лӘ©лӘ… мқҙмң  в”Җв”Җ
            elif text.startswith("/м§„мһ…"):
                _handle_entry_confirm_command(raw)
            elif text.startswith("/skip"):
                _handle_skip_command(raw)

            # в”Җв”Җ /stats в”Җв”Җ
            elif text == "/stats":
                _send_stats()

            # в”Җв”Җ /menu лҳҗлҠ” /лҸ„мӣҖ вҖ” лІ„нҠј л©”лүҙ в”Җв”Җ
            elif text in ("/menu", "/лҸ„мӣҖ", "/help"):
                _send_menu()

            # в”Җв”Җ /м„Өм • вҖ” BotFather лӘ…л №м–ҙ л“ұлЎқ к°Җмқҙл“ң в”Җв”Җ
            elif text in ("/м„Өм •", "/setup"):
                send(
                    "вҡҷпёҸ <b>BotFather лӘ…л №м–ҙ л“ұлЎқ л°©лІ•</b>\n"
                    "н…”л Ҳк·ёлһЁм—җм„ң / мһ…л Ҙ мӢң н•ңкёҖ м„ӨлӘ…мқҙ мһҗлҸҷмҷ„м„ұмңјлЎң лңЁкІҢ лҗ©лӢҲлӢӨ\n\n"
                    "<b>в‘  @BotFather м—җкІҢ м•„лһҳ лӘ…л №м–ҙ м „мҶЎ</b>\n"
                    "<code>/setcommands</code>\n\n"
                    "<b>в‘Ў лҙҮ м„ нғқ нӣ„ м•„лһҳ лӮҙмҡ© к·ёлҢҖлЎң ліөл¶ҷ</b>\n"
                    "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                    "<code>"
                    "status - рҹӨ– лҙҮ мғҒнғң л°Ҹ лІ„м „ нҷ•мқё\n"
                    "list - рҹ“Ӣ нҳ„мһ¬ к°җмӢң мӨ‘мқё мў…лӘ© лӘ©лЎқ\n"
                    "top - рҹҸҶ мҳӨлҠҳмқҳ мөңмҡ°м„  мў…лӘ© TOP 5\n"
                    "daily - рҹ“Ҡ мҳӨлҠҳ мқјмқј м„ұкіј мҰүмӢң мЎ°нҡҢ\n"
                    "nxt - рҹҹЎ NXT л„ҘмҠӨнҠёл Ҳмқҙл“ң мӢӨмӢңк°„ лҸҷн–Ҙ\n"
                    "week - рҹ“… мқҙлІҲ мЈј мһ м • м„ұкіј мЎ°нҡҢ\n"
                    "stats - рҹ“Ҳ мӢ нҳё мң нҳ•лі„ мҠ№лҘ  нҶөкі„\n"
                    "compact - рҹ—ң м»ҙнҢ©нҠёВ·мғҒм„ё м•ҢлҰј лӘЁл“ң м „нҷҳ\n"
                    "stop - вҸё м•ҢлҰј мқјмӢң м •м§Җ\n"
                    "resume - в–¶пёҸ м•ҢлҰј мһ¬к°ң\n"
                    "menu - рҹ“Ң лІ„нҠј л©”лүҙ м—ҙкё°\n"
                    "result - вңҚпёҸ мҲҳмқөлҘ  мҲҳлҸҷ кё°лЎқ (мҳҲ: result лҢҖмЈјмӮ°м—… +12.5)"
                    "</code>\n"
                    "в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                    "в‘ў л“ұлЎқ мҷ„лЈҢ нӣ„ мұ„нҢ…м°Ҫм—җм„ң / мһ…л Ҙн•ҳл©ҙ\n"
                    "   н•ңкёҖ м„ӨлӘ…кіј н•Ёк»ҳ мһҗлҸҷмҷ„м„ұмқҙ лӮҳнғҖлӮ©лӢҲлӢӨ"
                )

            # в”Җв”Җ м•Ң мҲҳ м—ҶлҠ” лӘ…л №м–ҙ вҶ’ л©”лүҙ н‘ңмӢң в”Җв”Җ

            # в”Җв”Җ /geo вҖ” м§Җм •н•ҷ л¶„м„қ мҲҳлҸҷ мӢӨн–ү в”Җв”Җ
            elif text == "/geo":
                send("рҹҢҚ м§Җм •н•ҷ лүҙмҠӨ л¶„м„қ мӨ‘... (10~20мҙҲ мҶҢмҡ”)")
                def _run_geo():
                    try:
                        headlines_by_src = _fetch_multi_source_headlines()
                        if not headlines_by_src:
                            send("вҡ пёҸ лүҙмҠӨ мҶҢмҠӨ мҲҳм§‘ мӢӨнҢЁ вҖ” лӘЁл“  RSS м ‘к·ј л¶Ҳк°Җ")
                            return
                        src_summary = "  ".join(f"{k}:{len(v)}кұҙ" for k,v in headlines_by_src.items())
                        send(f"рҹ“Ў мҲҳм§‘ мҷ„лЈҢ ({len(headlines_by_src)}к°ң мҶҢмҠӨ)\n{src_summary}")
                        geo = analyze_geopolitical_event(headlines_by_src)
                        if not geo.get("detected"):
                            send("вң… м§Җм •н•ҷ мқҙлІӨнҠё м—ҶмқҢ вҖ” нҳ„мһ¬ м•Ҳм „ мғҒнғң")
                            return
                        unc_emoji = {"high":"рҹ”ө","mid":"рҹҹЎ","low":"рҹ”ҙ"}.get(geo.get("uncertainty","mid"),"рҹҹЎ")
                        msg = (f"рҹҢҚ <b>м§Җм •н•ҷ л¶„м„қ кІ°кіј</b>\n"
                               f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                               f"{unc_emoji} л¶Ҳнҷ•мӢӨм„ұ: <b>{geo.get('uncertainty','?').upper()}</b>\n\n")
                        if geo.get("entities"):
                            msg += "<b>мЈјмІҙлі„ мһ…мһҘ</b>\n"
                            for e in geo["entities"][:6]:
                                s_emoji = {"кёҚм •":"рҹ”ҙ","л¶Җм •":"рҹ”ө","мӨ‘лҰҪ":"рҹҹЎ"}.get(e.get("stance","мӨ‘лҰҪ"),"рҹҹЎ")
                                msg += f"  {s_emoji} {e.get('name','')} вҖ” {e.get('stance','')} ({e.get('reason','')})\n"
                            msg += "\n"
                        # /geo н•ёл“Өлҹ¬ вҖ” sector_directions м—Ҷмңјл©ҙ fallback мғқм„ұ
                        sec_dirs = geo.get("sector_directions", [])
                        if not sec_dirs and geo.get("sectors"):
                            _kws_fb = geo.get("kws", [])
                            sec_dirs = _build_fallback_sector_directions(_kws_fb, geo["sectors"])
                        if sec_dirs:
                            msg += "<b>рҹ“Ҡ м„№н„°лі„ мҳҒн–Ҙ</b>\n"
                            for sd in sec_dirs:
                                _dir2   = sd.get("direction", "мӨ‘лҰҪ")
                                _icon2  = _DIR_DISPLAY.get(_dir2, "в–¶")
                                _adj2   = int(sd.get("score_adj", 0) or 0)
                                _adj2_str = f"  <b>{_adj2:+d}м җ</b>" if _adj2 != 0 else ""
                                _sec2   = sd.get("sector", "")
                                _stocks2 = _get_geo_sector_stocks(_sec2, max_n=3)
                                _stk2_str = "  ".join(f"<code>{n}</code>" for c,n in _stocks2) if _stocks2 else ""
                                # v37.0: кіјкұ° мң мӮ¬ мқҙлІӨнҠё мқҙл Ҙ
                                _hist2_str = _get_geo_sector_history(_sec2, _stocks2) if _stocks2 else ""
                                msg += (f"в”Ң {_icon2} <b>{_sec2}</b>{_adj2_str}\n"
                                        f"в”Ӯ  {sd.get('reason','')}\n"
                                        + (f"в”Ӯ  рҹ“Ң {_stk2_str}\n" if _stk2_str else "")
                                        + (f"{_hist2_str}\n" if _hist2_str else "")
                                        + "в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ\n")
                            msg += "\n"
                        elif geo.get("sectors"):
                            msg += f"рҹ“Ҡ кҙҖл Ё м„№н„°: {', '.join(geo['sectors'])}\n"
                        if geo.get("summary"):
                            msg += f"\nрҹ’Ў {geo['summary']}"
                        _gadj = int(geo.get("score_adj", 0) or 0)
                        msg += f"\n\nм „мІҙ м җмҲҳ ліҙм •: {_gadj:+d}м җ"
                        send(msg)
                    except Exception as e:
                        send(f"вқҢ мҳӨлҘҳ: {e}")
                threading.Thread(target=_run_geo, daemon=True).start()

            # в”Җв”Җ /us вҖ” лҜёкөӯ мӢңмһҘ нҳ„нҷ© мҲҳлҸҷ мЎ°нҡҢ в”Җв”Җ
            elif text == "/us":
                try:
                    _us_cache.clear()  # мәҗмӢң л¬ҙнҡЁнҷ” вҶ’ к°•м ң к°ұмӢ 
                    us = get_us_market_signals()
                    gap_emoji = {"gap_up":"в¬ҶпёҸ к°ӯмғҒмҠ№ кё°лҢҖ","flat":"вһЎпёҸ к°ӯ м—ҶмқҢ","gap_down":"в¬ҮпёҸ к°ӯн•ҳлқҪ мЈјмқҳ"}
                    regime_kor = {"panic":"рҹ”ө кёүлқҪмһҘ","risk_off":"рҹ”ө м•Ҫм„ёмһҘ","neutral":"рҹ”ҙ ліҙнҶөмһҘ","risk_on":"рҹ”ҙ к°•м„ёмһҘ","crash":"рҹ”ө кёүлқҪмһҘ","bear":"рҹ”ө м•Ҫм„ёмһҘ","bull":"рҹ”ҙ к°•м„ёмһҘ"}
                    msg = (f"рҹҢҗ <b>лҜёкөӯ мӢңмһҘ нҳ„нҷ©</b>\n"
                           f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                           f"лӮҳмҠӨлӢҘм„ л¬ј: {us.get('nasdaq_chg',0):+.2f}%\n"
                           f"VIX кіөнҸ¬м§ҖмҲҳ: {us.get('vix',0):.1f}\n"
                           f"лӢ¬лҹ¬мқёлҚұмҠӨ: {us.get('dxy',0):.2f}\n"
                           f"мӢңмһҘ көӯл©ҙ: {regime_kor.get(us.get('us_regime','neutral'),'рҹҹЎ мӨ‘лҰҪ')}\n"
                           f"к°ӯ мҳҲмёЎ: {gap_emoji.get(us.get('gap_signal','flat'),'вһЎпёҸ')}\n"
                           f"м җмҲҳ ліҙм •: {int(us.get('score_adj',0) or 0):+d}м җ")
                    send(msg)
                except Exception as e:
                    send(f"вқҢ лҜёкөӯ мӢңмһҘ мЎ°нҡҢ мҳӨлҘҳ: {e}")

            # в”Җв”Җ /overnight вҖ” мҳӨлІ„лӮҳмқҙнҠё лӘЁлӢҲн„° мҲҳлҸҷ мӢӨн–ү в”Җв”Җ
            elif text == "/overnight":
                send("рҹҢҷ мҳӨлІ„лӮҳмқҙнҠё лӘЁлӢҲн„° мҲҳлҸҷ мӢӨн–ү мӨ‘...")
                def _run_overnight():
                    try:
                        run_overnight_monitor()
                        # м¶”м Ғ мӨ‘ мў…лӘ© мң„н—ҳлҸ„лҸ„ мІҙнҒ¬
                        send_overnight_risk_alerts()
                    except Exception as e:
                        send(f"вқҢ мҳӨлҘҳ: {e}")
                threading.Thread(target=_run_overnight, daemon=True).start()

            elif text.startswith("/test"):
                # /test вҖ” лҙҮ м „мІҙ кё°лҠҘ л№ лҘё м җкІҖ
                send(
                    f"рҹ§Ә <b>кё°лҠҘ м җкІҖ</b>  {BOT_VERSION}\n"
                    f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                    f"/us вҖ” лҜёкөӯ мӢңмһҘ нҳ„нҷ©\n"
                    f"/geo вҖ” м§Җм •н•ҷ лүҙмҠӨ л¶„м„қ\n"
                    f"/overnight вҖ” мҳӨлІ„лӮҳмқҙнҠё мң„н—ҳлҸ„\n"
                    f"/stats вҖ” мӢ нҳё нҶөкі„\n"
                    f"/top вҖ” мҳӨлҠҳ TOP 5\n"
                    f"/nxt вҖ” NXT лҸҷн–Ҙ"
                )

            else:
                _send_menu(f"вқ“ <b>'{raw}'</b> лҠ” м•Ң мҲҳ м—ҶлҠ” лӘ…л №м–ҙмҳҲмҡ”\nм•„лһҳ лІ„нҠјмңјлЎң мӢӨн–үн•ҙліҙм„ёмҡ”")
    except Exception as e:
        print(f"вҡ пёҸ TG лӘ…л №м–ҙ мҳӨлҘҳ: {e}")

def _telegram_poll_loop():
    """мҠӨмә”кіј л¶„лҰ¬лҗң н…”л Ҳк·ёлһЁ лӘ…л №/лІ„нҠј м „мҡ© лЈЁн”„ (м§ҖмҲҳ л°ұмҳӨн”„ м Ғмҡ©)."""
    _consecutive_fails = 0
    _TG_POLL_BACKOFF_MAX = 60  # мөңлҢҖ л°ұмҳӨн”„ 60мҙҲ
    while True:
        try:
            poll_telegram_commands()
            _consecutive_fails = 0  # м„ұкіө мӢң мҰүмӢң м •мғҒ к°„кІ© ліөк·Җ
        except Exception as e:
            _consecutive_fails += 1
            if _consecutive_fails <= 3 or _consecutive_fails == 5:
                print(f"вҡ пёҸ н…”л Ҳк·ёлһЁ нҸҙл§Ғ лЈЁн”„ мҳӨлҘҳ ({_consecutive_fails}нҡҢ м—°мҶҚ): {e}")
            elif _consecutive_fails == 10:
                print(f"вҡ пёҸ н…”л Ҳк·ёлһЁ нҸҙл§Ғ м—°мҶҚ мӢӨнҢЁ {_consecutive_fails}нҡҢ вҖ” л°ұмҳӨн”„ {min(TELEGRAM_POLL_INTERVAL * (2 ** min(_consecutive_fails, 5)), _TG_POLL_BACKOFF_MAX)}мҙҲ")
            backoff = min(TELEGRAM_POLL_INTERVAL * (2 ** min(_consecutive_fails, 5)), _TG_POLL_BACKOFF_MAX)
            time.sleep(max(1, backoff))
            continue
        time.sleep(max(1, TELEGRAM_POLL_INTERVAL))




def _request_actual_entry_confirm(rec: dict):
    """
    мқҙлЎ  м¶”м Ғ мҷ„лЈҢ мӢң вҶ’ мӢӨм ң м§„мһ… м—¬л¶Җ нҷ•мқё мҡ”мІӯ м•ҢлҰј.
    мӮ¬мҡ©мһҗк°Җ /result лҳҗлҠ” /skipмңјлЎң мқ‘лӢө.
    """
    name    = rec.get("name", "")
    code    = rec.get("code", "")
    pnl     = rec.get("pnl_pct", 0)
    sig     = rec.get("signal_type", "")
    pnl_str = f"+{pnl:.1f}%" if pnl >= 0 else f"{pnl:.1f}%"
    emoji   = "вң…" if pnl > 0 else "рҹ”ө"
    msg = (
        f"вқ“ <b>[м§„мһ… м—¬л¶Җ нҷ•мқё]</b>\n"
        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
        f"{emoji} <b>{name}</b>  <code>{code}</code>\n"
        f"мқҙлЎ  кІ°кіј: <b>{pnl_str}</b>  [{sig}]\n"
        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
        f"мӢӨм ң м§„мһ…н•ҳм…ЁлӢӨл©ҙ:\n"
        f"<code>/result {name} мӢӨм ңмҲҳмқөлҘ </code>\n"
        f"мҳҲ) /result {name} +8.5\n\n"
        f"рҹ’Ў лҜёмқ‘лӢө мӢң лҜём§„мһ…мңјлЎң мһҗлҸҷ мІҳлҰ¬лҗ©лӢҲлӢӨ"
    )
    send(msg)


def _handle_entry_confirm_command(raw: str):
    """
    /м§„мһ… мў…лӘ©лӘ… [мӢӨм ңм§„мһ…к°Җ]  мІҳлҰ¬
    мҳҲ) /м§„мһ… лҢҖмЈјмӮ°м—…          вҶҗ лҙҮмқҙ кі„мӮ°н•ң м§„мһ…к°ҖлЎң нҷ•м •
    мҳҲ) /м§„мһ… лҢҖмЈјмӮ°м—… 15300    вҶҗ мӢӨм ң м§„мһ…к°Җ м§Ғм ‘ мһ…л Ҙ

    лӘ©м Ғ: лӮҙк°Җ мӢӨм ң м§„мһ…н•ң мў…лӘ©мқ„ кё°лЎқн•ҙм„ң /statsмқҳ "лӮҙ мӢӨм ң мҲҳмқө" м—җ л°ҳмҳҒ.
    лҙҮмқҳ мқҙлЎ  м¶”м Ғ(signal_log)мқҖ кі„мҶҚ лі‘н–ү вҶ’ лҙҮ мЎ°кұҙ н•ҷмҠөм—җ нҷңмҡ©лҗЁ.
    мҰү, м§„мһ… м—¬л¶ҖмҷҖ л¬ҙкҙҖн•ҳкІҢ мқҙлЎ  лҚ°мқҙн„°лҠ” н•ӯмғҒ мҢ“мһ„.
    """
    try:
        parts      = raw.strip().split(maxsplit=2)
        name_input = parts[1] if len(parts) > 1 else ""
        price_input = parts[2] if len(parts) > 2 else ""

        if not name_input:
            send("вҡ пёҸ нҳ•мӢқ: /м§„мһ… мў…лӘ©лӘ… [мӢӨм ңм§„мһ…к°Җ]\n"
                 "мҳҲ) /м§„мһ… лҢҖмЈјмӮ°м—…\n"
                 "мҳҲ) /м§„мһ… лҢҖмЈјмӮ°м—… 15300"); return

        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception: pass

        matched = []
        for log_key, rec in data.items():
            if name_input in rec.get("name", "") and rec.get("actual_entry") is None:
                matched.append((log_key, rec))

        if not matched:
            send(f"вқ“ '{name_input}' мў…лӘ©мқ„ м°ҫмқ„ мҲҳ м—Ҷм–ҙмҡ”.\n"
                 f"м¶”м Ғ мӨ‘мқё мў…лӘ©лӘ…мқ„ нҷ•мқён•ҙмЈјм„ёмҡ”."); return

        # к°ҖмһҘ мөңк·ј мӢ нҳё м„ нғқ
        matched.sort(key=lambda x: x[1].get("detect_date",""), reverse=True)
        log_key, rec = matched[0]

        # мӢӨм ң м§„мһ…к°Җ мІҳлҰ¬
        try:
            actual_price = int(price_input) if price_input else rec.get("entry_price", 0)
        except Exception:
            actual_price = rec.get("entry_price", 0)

        rec["actual_entry"]       = True
        rec["actual_entry_price"] = actual_price
        # мӢӨм ң м§„мһ…к°ҖлЎң мҶҗм Ҳ/лӘ©н‘ң мһ¬кі„мӮ°
        if actual_price and actual_price != rec.get("entry_price", 0):
            diff_ratio = actual_price / rec["entry_price"] if rec.get("entry_price") else 1
            rec["stop_price"]    = int(rec.get("stop_price",  0) * diff_ratio / 10) * 10
            rec["target_price"]  = int(rec.get("target_price", 0) * diff_ratio / 10) * 10

        _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)

        entry_p  = actual_price or rec.get("entry_price", 0)
        stop_p   = rec.get("stop_price", 0)
        target_p = rec.get("target_price", 0)
        stop_pct  = round((stop_p   - entry_p) / entry_p * 100, 1) if entry_p else 0
        tgt_pct   = round((target_p - entry_p) / entry_p * 100, 1) if entry_p else 0
        send(f"вң… <b>[м§„мһ… нҷ•м •]</b>\n"
             f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
             f"рҹ”ҙ <b>{rec['name']}</b>  <code>{rec['code']}</code>\n"
             f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
             f"рҹ“Қ мӢӨм ң м§„мһ…к°Җ: <b>{entry_p:,}мӣҗ</b>\n"
             f"рҹӣЎ мҶҗм Ҳк°Җ:  <b>{stop_p:,}мӣҗ</b>  ({stop_pct:+.1f}%)\n"
             f"рҹҸҶ лӘ©н‘ңк°Җ:  <b>{target_p:,}мӣҗ</b>  ({tgt_pct:+.1f}%)\n"
             f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
             f"мқҙ кё°мӨҖмңјлЎң мһҗлҸҷ м¶”м Ғмқ„ мӢңмһ‘н•©лӢҲлӢӨ.\n"
             f"кІ°кіјлҠ” /result лЎң м§Ғм ‘ мһ…л Ҙн•ҳкұ°лӮҳ\n"
             f"лӘ©н‘ңк°Җ/мҶҗм Ҳк°Җ лҸ„лӢ¬ мӢң мһҗлҸҷ нҷ•м •лҗ©лӢҲлӢӨ.")
        print(f"  вң… м§„мһ… нҷ•м •: {rec['name']} {entry_p:,}мӣҗ")
    except Exception as e:
        _log_error("_handle_entry_confirm_command", e)
        send(f"вҡ пёҸ /м§„мһ… мІҳлҰ¬ мҳӨлҘҳ: {e}")

def _handle_skip_command(raw: str):
    """
    /skip мў…лӘ©лӘ… мқҙмң   мІҳлҰ¬
    мҳҲ) /skip лҢҖмЈјмӮ°м—… мӢңк°„м—ҶмқҢ
    вҶ’ actual_entry=False, skip_reason кё°лЎқ
    вҶ’ лҙҮ н•ҷмҠө: м–ҙл–Ө мғҒнҷ©м—җм„ң м§„мһ… кё°нҡҢлҘј лҶ“м№ҳлҠ”м§Җ нҢЁн„ҙ л¶„м„қ
    """
    try:
        parts      = raw.strip().split(maxsplit=2)
        name_input = parts[1] if len(parts) > 1 else ""
        reason     = parts[2] if len(parts) > 2 else "лҜёмһ…л Ҙ"

        if not name_input:
            send("вҡ пёҸ нҳ•мӢқ: /skip мў…лӘ©лӘ… мқҙмң \nмҳҲ) /skip лҢҖмЈјмӮ°м—… мӢңк°„м—ҶмқҢ\n\n"
                 "мқҙмң  мҳҲмӢң: мӢңк°„м—ҶмқҢ / мЎ°кұҙл¶Ҳмқјм№ҳ / мқҙлҜёмғҒмҠ№ / л¶„мӮ°нҲ¬мһҗ / кё°нғҖ"); return

        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception: pass

        matched_key  = None
        matched_name = None
        # к°ҖмһҘ мөңк·ј н•ҙлӢ№ мў…лӘ© м°ҫкё°
        for key in sorted(data.keys(), reverse=True):
            rec = data[key]
            if name_input in rec.get("name", ""):
                matched_key  = key
                matched_name = rec["name"]
                break

        if not matched_key:
            send(f"вҡ пёҸ '{name_input}' мў…лӘ©мқ„ м°ҫмқ„ мҲҳ м—Ҷм–ҙмҡ”.\n/list лЎң к°җмӢң мӨ‘мқё мў…лӘ© нҷ•мқё"); return

        data[matched_key]["actual_entry"]  = False
        data[matched_key]["skip_reason"]   = reason
        data[matched_key]["actual_pnl"]    = None

        _write_json_atomic(SIGNAL_LOG_FILE, data, indent=2)

        theo_pnl = data[matched_key].get("pnl_pct", 0)
        theo_str = f"+{theo_pnl:.1f}%" if theo_pnl >= 0 else f"{theo_pnl:.1f}%"
        send(
            f"вҸӯ <b>м§„мһ… мҠӨнӮө кё°лЎқ мҷ„лЈҢ</b>\n"
            f"мў…лӘ©: <b>{matched_name}</b>\n"
            f"мқҙмң : {reason}\n"
            f"мқҙлЎ  мҲҳмқөлҘ : {theo_str} (лҙҮ н•ҷмҠөм—җ л°ҳмҳҒлҗ©лӢҲлӢӨ)\n\n"
            f"рҹ’Ў мҠӨнӮө нҢЁн„ҙлҸ„ мҢ“мқҙл©ҙ лҙҮмқҙ м§„мһ… нғҖмқҙл°Қмқ„ к°ңм„ н•ҙмҡ”."
        )
        print(f"  вҸӯ мҠӨнӮө кё°лЎқ: {matched_name} / {reason}")

    except Exception as e:
        send(f"вҡ пёҸ мҠӨнӮө кё°лЎқ мҳӨлҘҳ: {e}")

def _handle_result_command(raw: str):
    """
    /result мў…лӘ©лӘ… мҲҳмқөлҘ   мІҳлҰ¬
    мҳҲ) /result лҢҖмЈјмӮ°м—… +12.5
    вҶ’ signal_log.json (л©”мқё) + early_detect_log.json (н•ҳмң„нҳёнҷҳ) лҸҷмӢң м—…лҚ°мқҙнҠё
    вҶ’ мһҗлҸҷ нҠңлӢқ мҰүмӢң л°ҳмҳҒ
    """
    try:
        parts = raw.strip().split()
        if len(parts) < 3:
            send("вҡ пёҸ нҳ•мӢқ: /result мў…лӘ©лӘ… мҲҳмқөлҘ \nмҳҲ) /result лҢҖмЈјмӮ°м—… +12.5"); return
        name_input = parts[1]
        pnl_str    = parts[2].replace("%","")
        pnl        = float(pnl_str)

        result_emoji = "вң…" if pnl > 0 else ("рҹ”ө" if pnl < 0 else "вһ–")
        status       = "мҲҳмқө" if pnl > 0 else ("мҶҗмӢӨ" if pnl < 0 else "ліём „")
        today        = datetime.now().strftime("%Y%m%d")
        matched_name = None
        signal_type  = "MANUAL"

        # в”Җв”Җ в‘  signal_log.json м—җм„ң м¶”м Ғ мӨ‘мқё мў…лӘ© м°ҫкё° (л©”мқё) в”Җв”Җ
        sig_data = {}
        sig_matched_key = None
        try:
            sig_data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception: pass

        # мў…лӘ©лӘ… нҸ¬н•Ё + м¶”м ҒмӨ‘ мғҒнғңмқё кІғ мҡ°м„  л§Өм№ӯ
        for key, rec in sig_data.items():
            if name_input in rec.get("name", "") and rec.get("status") == "м¶”м ҒмӨ‘":
                sig_matched_key = key
                matched_name    = rec["name"]
                signal_type     = rec.get("signal_type", "MANUAL")
                # нҳ„мһ¬к°Җ мЎ°нҡҢн•ҙм„ң мҲҳмқөлҘ  кІҖмҰқ
                try:
                    cur_p = get_stock_price(rec["code"]).get("price", 0)
                    entry = rec.get("entry_price", 0)
                    if cur_p and entry:
                        auto_pnl = round((cur_p - entry) / entry * 100, 1)
                        # мһ…л Ҙк°’кіј мһҗлҸҷкі„мӮ°к°’мқҙ 5%p мқҙмғҒ м°ЁмқҙлӮҳл©ҙ кІҪкі 
                        if abs(pnl - auto_pnl) > 5:
                            send(f"вҡ пёҸ мһ…л Ҙ мҲҳмқөлҘ ({pnl:+.1f}%)кіј нҳ„мһ¬к°Җ кё°мӨҖ({auto_pnl:+.1f}%) м°Ёмқҙк°Җ нҒҪлӢҲлӢӨ.\n"
                                 f"нҳ„мһ¬к°Җ: {cur_p:,}мӣҗ  |  мһ…л Ҙк°’ к·ёлҢҖлЎң кё°лЎқн•©лӢҲлӢӨ.")
                except Exception: pass
                break

        if sig_matched_key:
            rec = sig_data[sig_matched_key]
            # мқҙлЎ  мҲҳмқөлҘ мқҙ м•„м§Ғ м—Ҷмңјл©ҙ н•Ёк»ҳ кё°лЎқ
            if not rec.get("pnl_pct"):
                rec["gross_pnl_pct"] = pnl
                rec["net_pnl_pct"]   = pnl
                rec["round_trip_cost_pct"] = 0.0
                rec["pnl_pct"]     = pnl
                rec["status"]      = status
                rec["exit_date"]   = today
                rec["exit_time"]   = datetime.now().strftime("%H:%M:%S")
                rec["exit_reason"] = "мҲҳлҸҷмһ…л Ҙ"
            # мӢӨм ң м§„мһ… кІ°кіј кё°лЎқ (лі„лҸ„ ліҙмЎҙ)
            rec["actual_entry"]     = True
            rec["actual_pnl"]       = pnl
            rec["actual_exit_date"] = today
            rec["skip_reason"]      = ""
            _write_json_atomic(SIGNAL_LOG_FILE, sig_data, indent=2)

        # в”Җв”Җ в‘Ў early_detect_log.json лҸ„ лҸҷмӢң м—…лҚ°мқҙнҠё (н•ҳмң„ нҳёнҷҳ) в”Җв”Җ
        early_data = {}
        try:
            with open(EARLY_LOG_FILE, "r") as f: early_data = json.load(f)
        except Exception: pass

        early_matched = None
        for code, info in early_data.items():
            if name_input in info.get("name", ""):
                early_matched = code; break

        if early_matched:
            early_data[early_matched].update({
                "status": status, "gross_pnl_pct": pnl, "net_pnl_pct": pnl, "round_trip_cost_pct": 0.0, "pnl_pct": pnl,
                "exit_date": today,
            })
        else:
            # л‘ҳ лӢӨ м—Ҷмңјл©ҙ мҲҳлҸҷ кё°лЎқмңјлЎң signal_logм—җ мғҲлЎң м¶”к°Җ
            new_key = f"manual_{datetime.now().strftime('%m%d%H%M')}"
            sig_data[new_key] = {
                "log_key": new_key, "code": new_key,
                "name": name_input, "signal_type": "MANUAL",
                "detect_date": today, "detect_time": datetime.now().strftime("%H:%M:%S"),
                "detect_price": 0, "entry_price": 0,
                "stop_price": 0, "target_price": 0,
                "status": status, "gross_pnl_pct": pnl, "net_pnl_pct": pnl, "round_trip_cost_pct": 0.0, "pnl_pct": pnl,
                "exit_date": today, "exit_time": datetime.now().strftime("%H:%M:%S"),
                "exit_reason": "мҲҳлҸҷмһ…л Ҙ",
                "score": 0, "sector_bonus": 0, "sector_theme": "",
            }
            _write_json_atomic(SIGNAL_LOG_FILE, sig_data, indent=2)
            matched_name = name_input

        if early_matched:
            _write_json_atomic(EARLY_LOG_FILE, early_data, indent=2)

        display_name = matched_name or name_input
        send(f"{result_emoji} <b>кІ°кіј кё°лЎқ мҷ„лЈҢ</b>\n"
             f"мў…лӘ©: <b>{display_name}</b>\n"
             f"мҲҳмқөлҘ : <b>{pnl:+.1f}%</b>  ({status})\n"
             f"мӢ нҳё: {signal_type}\n\n"
             f"/stats лЎң м „мІҙ нҶөкі„ нҷ•мқё")

        # мҰүмӢң мһҗлҸҷ нҠңлӢқ л°ҳмҳҒ
        load_tracker_feedback()

    except ValueError:
        send("вҡ пёҸ мҲҳмқөлҘ  нҳ•мӢқ мҳӨлҘҳ. мҳҲ) /result лҢҖмЈјмӮ°м—… +12.5")
    except Exception as e:
        send(f"вҡ пёҸ кІ°кіј кё°лЎқ мҳӨлҘҳ: {e}")



