# рҹҢҷ мҳӨлІ„лӮҳмқҙнҠё мң„н—ҳлҸ„ кі„мӮ°
# ============================================================
def calc_overnight_risk(code: str, name: str, entry: int, current_pnl: float) -> dict:
    """
    мһҘ л§Ҳк°җ нӣ„ ліҙмң  мң„н—ҳлҸ„ кі„мӮ°.
    v40.0-#5: лҰ¬мҠӨнҒ¬ мӣҗмқёлі„ л¶„лҘҳ (мң лҸҷм„ұ/м—җл„Ҳм§ҖВ·м§Җм •н•ҷ/көӯлӮҙм¶”м„ё)
    л°ҳнҷҳ: {level: "high"/"mid"/"low", score: int, reason: str, causes: list}
    """
    try:
        us         = get_us_market_signals()
        short_r    = get_short_sell_ratio(code)
        vix        = us.get("vix", 20)
        us_regime  = us.get("us_regime", "neutral")
        gap_signal = us.get("gap_signal", "flat")

        risk_score = 0
        reasons    = []

        # NXT мӢңк°„лҢҖ вҶ’ кұ°лһҳлҹү м–Үм•„м„ң ліҖлҸҷм„ұ м¶”к°Җ
        nxt_only = is_nxt_open() and not is_market_open()
        if nxt_only:
            risk_score += 10; reasons.append("рҹ“Ў NXT лӢЁлҸ… мӢңк°„лҢҖ (мң лҸҷм„ұ лӮ®мқҢ)")

        if us_regime == "panic":
            risk_score += 40; reasons.append("рҹ”ө лҜёкөӯ кёүлқҪмһҘ")
        elif us_regime == "risk_off":
            risk_score += 20; reasons.append("рҹ”ө лҜёкөӯ м•Ҫм„ёмһҘ")

        if vix >= 30:
            risk_score += 20; reasons.append(f"рҹ”ө VIX {vix:.0f} (кіөнҸ¬)")
        elif vix >= 25:
            risk_score += 10; reasons.append(f"рҹҹЎ VIX {vix:.0f} (л¶Ҳм•Ҳ)")

        if short_r >= 10:
            risk_score += 15; reasons.append(f"рҹ“ү кіөл§ӨлҸ„ {short_r:.1f}%")
        elif short_r >= 5:
            risk_score += 7; reasons.append(f"вҡ пёҸ кіөл§ӨлҸ„ {short_r:.1f}%")

        if gap_signal == "gap_down":
            risk_score += 15; reasons.append("в¬ҮпёҸ к°ӯн•ҳлқҪ к°ҖлҠҘм„ұ")

        if current_pnl > 5:
            risk_score -= 10; reasons.append(f"вң… нҳ„мһ¬ +{current_pnl:.1f}% мҲҳмқө мӨ‘")

        # v40.0-#6: кёҲмҡ”мқј л§Ҳк°җ мӢң мЈјл§җ лҰ¬мҠӨнҒ¬ к°ҖмӨ‘
        if datetime.now().weekday() == 4 and _get_time_risk_profile() == "friday_close":
            risk_score += 10; reasons.append("рҹ“… кёҲмҡ”мқј мҳӨлІ„лӮҳмқҙнҠё (мЈјл§җ лҰ¬мҠӨнҒ¬)")

        # v41.61 #6: н•ңкөӯ мӢңмһҘ л Ҳм§җ кё°л°ҳ мҳӨлІ„лӮҳмқҙнҠё мң„н—ҳ к°ҖмӨ‘
        _on_regime_add = get_regime_overnight_add()
        if _on_regime_add > 0:
            risk_score += _on_regime_add
            _on_regime_mode = _dynamic.get("regime_mode", "normal")
            _on_labels = {"bear": "рҹ”ө н•ҳлқҪмһҘ", "crash": "рҹ”ө кёүлқҪмһҘ"}
            reasons.append(f"{_on_labels.get(_on_regime_mode, '')} л Ҳм§җ к°ҖмӨ‘ +{_on_regime_add}м җ")

        if   risk_score >= 50: level = "high"
        elif risk_score >= 25: level = "mid"
        else:                  level = "low"

        # v40.0-#5: мӣҗмқёлі„ л¶„лҘҳ
        kospi_5d = 0.0
        try:
            items = get_daily_data("0001", 10)
            closes = [i["close"] for i in items if i.get("close")]
            if len(closes) >= 5:
                kospi_5d = (closes[-1] - closes[-5]) / closes[-5] * 100
        except Exception:
            pass
        geo_state = _get_effective_geo_state(now)
        overnight_lines = _get_effective_overnight_lines(now)
        causes = _classify_risk_causes(us, geo_state, kospi_5d)

        level_emoji = {"high": "рҹ”ө мң„н—ҳ", "mid": "рҹҹЎ кІҪкі„", "low": "рҹ”ҙ м•Ҳм „"}
        return {
            "level":  level,
            "score":  risk_score,
            "reason": f"{level_emoji[level]}  {'  '.join(reasons)}",
            "causes": causes,
        }
    except Exception:
        return {"level": "low", "score": 0, "reason": "", "causes": []}

# ============================================================
# рҹ”„ н…Ңл§Ҳ лЎңн…Ңмқҙм…ҳ к°җм§Җ
# ============================================================
_theme_rotation_cache: dict = {"ts": 0, "themes": {}}

def detect_theme_rotation() -> dict:
    """
    THEME_MAP кё°л°ҳ н…Ңл§Ҳлі„ нҸүк·  л“ұлқҪлҘ  кі„мӮ° вҶ’ к°•м„ё/м•Ҫм„ё н…Ңл§Ҳ к°җм§Җ.
    1мӢңк°„ мәҗмӢң. л°ҳнҷҳ: {к°•н•ңн…Ңл§Ҳ: [], м•Ҫн•ңн…Ңл§Ҳ: [], ts}
    """
    if time.time() - _theme_rotation_cache["ts"] < 3600:
        return _theme_rotation_cache

    theme_scores = {}
    try:
        for theme_key, theme_info in list(THEME_MAP.items())[:10]:  # мғҒмң„ 10к°ң н…Ңл§Ҳ
            stocks   = theme_info.get("stocks", [])[:5]  # н…Ңл§ҲлӢ№ 5к°ңл§Ң
            chg_list = []
            for code, name in stocks:
                try:
                    cur = get_stock_price(code)
                    if cur and cur.get("change_rate") is not None:
                        chg_list.append(cur["change_rate"])
                    time.sleep(0.1)
                except Exception: continue
            if chg_list:
                theme_scores[theme_key] = round(sum(chg_list) / len(chg_list), 2)

        sorted_themes = sorted(theme_scores.items(), key=lambda x: -x[1])
        strong = [(k, v) for k, v in sorted_themes if v >= 2.0][:3]
        weak   = [(k, v) for k, v in sorted_themes if v <= -1.5][:3]

        _theme_rotation_cache.update({
            "ts":      time.time(),
            "themes":  theme_scores,
            "strong":  strong,
            "weak":    weak,
        })
    except Exception as e:
        _log_error("detect_theme_rotation", e)

    return _theme_rotation_cache

