# рҹ’ё лҶ“м№ң мҲҳмқө м¶”м Ғ
# ============================================================
def get_missed_profit_summary() -> dict:
    """
    signal_logм—җм„ң лҜём§„мһ…(actual_entry=False лҳҗлҠ” None) кұҙмқҳ
    мқҙлЎ  мҲҳмқөлҘ  м§‘кі„ вҶ’ "лҶ“м№ң мҲҳмқө" нҶөкі„.
    л°ҳнҷҳ: {count, avg_pnl, total_pnl, best: dict}
    """
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception: pass

        missed = [v for v in data.values()
                  if v.get("actual_entry") in (False, None)
                  and v.get("status") in ("мҲҳмқө", "мҶҗмӢӨ", "ліём „")
                  and v.get("pnl_pct") is not None]

        if not missed:
            return {"count": 0, "avg_pnl": 0.0, "total_pnl": 0.0, "best": None}

        pnls     = [v["pnl_pct"] for v in missed]
        avg_pnl  = round(sum(pnls) / len(pnls), 1)
        best_rec = max(missed, key=lambda x: x.get("pnl_pct", 0))

        return {
            "count":     len(missed),
            "avg_pnl":   avg_pnl,
            "total_pnl": round(sum(pnls), 1),
            "best":      best_rec,
        }
    except Exception:
        return {"count": 0, "avg_pnl": 0.0, "total_pnl": 0.0, "best": None}

def _send_stats():
    """мӢ нҳё мң нҳ•лі„ мҠ№лҘ В·нҸүк·  мҲҳмқөлҘ  нҶөкі„ м „мҶЎ (signal_log.json кё°л°ҳ)"""
    try:
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception: pass

        # в”Җв”Җ мқҙлЎ  мҷ„лЈҢ (м „мІҙ вҖ” лҙҮ н•ҷмҠө + мӢ нҳё н’Ҳм§Ҳ нҸүк°Җмҡ©) в”Җв”Җ
        completed      = [v for v in data.values() if v.get("status") in ["мҲҳмқө","мҶҗмӢӨ","ліём „"]]
        tracking       = _get_valid_tracking(data)
        # в”Җв”Җ мӢӨм ң м§„мһ… (лӮҙ мҲҳмқө нҶөкі„мҡ© вҖ” /result лҳҗлҠ” /м§„мһ… нҷ•мқёл¶„л§Ң) в”Җв”Җ
        actual_entered = [v for v in data.values()
                          if v.get("actual_entry") is True and v.get("actual_pnl") is not None]
        skipped        = [v for v in data.values() if v.get("actual_entry") is False]
        unconfirmed    = [v for v in completed     if v.get("actual_entry") is None]

        if len(completed) < 3:
            send(f"рҹ“Ҡ м•„м§Ғ мқҙлЎ  кІ°кіјк°Җ {len(completed)}кұҙлҝҗмқҙм—җмҡ”. (м¶”м Ғ мӨ‘: {len(tracking)}кұҙ)\n"
                 f"кІ°кіјк°Җ мҢ“мқҙл©ҙ мһҗлҸҷмңјлЎң нҶөкі„к°Җ к°ұмӢ лҸјмҡ”."); return


        type_labels = {
            "UPPER_LIMIT":  "рҹҡЁ мғҒн•ңк°Җ",
            "NEAR_UPPER":   "рҹ”Ҙ мғҒн•ңк°Җк·јм ‘",
            "STRONG_BUY":   "рҹ’Һ к°•л Ҙл§ӨмҲҳ",
            "SURGE":        "рҹ“Ҳ кёүл“ұ",
            "EARLY_DETECT": "рҹ”Қ мЎ°кё°нҸ¬м°©",
            "ENTRY_POINT":  "рҹҺҜ лҲҢлҰјлӘ©",
            "MID_PULLBACK": "рҹҸҶ лҲҢлҰјлӘ©",
            "MANUAL":       "вңҸпёҸ мҲҳлҸҷ",
        }

        # в”Җв”Җ мқҙлЎ  нҶөкі„ в”Җв”Җ
        total_pnl  = [v["pnl_pct"] for v in completed]
        total_win  = sum(1 for p in total_pnl if p > 0)
        avg_pnl    = sum(total_pnl) / len(total_pnl)
        total_rate = total_win / len(total_pnl) * 100

        # в”Җв”Җ мӢӨм ң м§„мһ… нҶөкі„ в”Җв”Җ
        actual_msg = ""
        if actual_entered:
            a_pnls = [v["actual_pnl"] for v in actual_entered]
            a_win  = sum(1 for p in a_pnls if p > 0)
            a_avg  = sum(a_pnls) / len(a_pnls)
            a_rate = a_win / len(a_pnls) * 100
            actual_msg = (f"рҹ’° <b>лӮҙ мӢӨм ң мҲҳмқө</b>  {len(actual_entered)}кұҙ\n"
                          f"  мҠ№лҘ  <b>{a_rate:.0f}%</b>  нҸүк·  <b>{a_avg:+.1f}%</b>\n")
        elif unconfirmed:
            actual_msg = f"вқ“ нҷ•мқё лҢҖкё° {len(unconfirmed)}кұҙ  (/result лҳҗлҠ” /skip лЎң кё°лЎқ)\n"

        # в”Җв”Җ мҠӨнӮө нҢЁн„ҙ л¶„м„қ в”Җв”Җ
        skip_msg = ""
        if skipped:
            skip_reasons = {}
            for v in skipped:
                r = v.get("skip_reason", "лҜёмһ…л Ҙ")
                skip_reasons[r] = skip_reasons.get(r, 0) + 1
            skip_top = sorted(skip_reasons.items(), key=lambda x: -x[1])[:3]
            skip_str = "  /  ".join([f"{r}:{n}кұҙ" for r, n in skip_top])
            # мҠӨнӮөн•ң мӢ нҳёл“Өмқҳ мқҙлЎ  мҲҳмқөлҘ  нҸүк·  (кё°нҡҢл№„мҡ©)
            skip_pnls = [v.get("pnl_pct", 0) for v in skipped if v.get("pnl_pct")]
            opp_cost  = sum(skip_pnls) / len(skip_pnls) if skip_pnls else 0
            skip_msg  = (f"вҸӯ <b>мҠӨнӮө</b>  {len(skipped)}кұҙ  (мқҙлЎ  нҸүк·  {opp_cost:+.1f}%)\n"
                         f"  мқҙмң : {skip_str}\n")

        # в”Җв”Җ м§„мһ…лҜёлӢ¬ нҶөкі„ в”Җв”Җ
        miss_all      = [v for v in data.values() if v.get("status") in ["м§„мһ…лҜёлӢ¬", "м§„мһ…к°ҖліҖкІҪ"]]
        miss_surge    = sum(1 for v in miss_all if "мғҒмҠ№мқҙнғҲ"   in str(v.get("exit_reason","")))
        miss_expire   = sum(1 for v in miss_all if "кё°к°„л§ҢлЈҢ"   in str(v.get("exit_reason","")))
        miss_reentry  = sum(1 for v in miss_all if "м§„мһ…к°ҖліҖкІҪ" in str(v.get("exit_reason","")))
        cur_ratio     = _dynamic.get("entry_pullback_ratio", ENTRY_PULLBACK_RATIO)

        miss_msg = ""
        if miss_all:
            miss_msg = (f"вҡ пёҸ <b>м§„мһ… лҜёлӢ¬</b>  {len(miss_all)}кұҙ\n"
                        f"  мғҒмҠ№мқҙнғҲ {miss_surge}кұҙ  кё°к°„л§ҢлЈҢ {miss_expire}кұҙ  мһ¬нҸ¬м°© {miss_reentry}кұҙ\n"
                        f"  нҳ„мһ¬ м§„мһ…к°Җ л№„мңЁ: <b>{cur_ratio:.2f}</b>  (0.2=ліҙмҲҳм Ғ вҶ” 0.7=кіөкІ©м Ғ)\n")

        msg = (f"рҹ“Ҡ <b>мӢ нҳё м„ұкіј нҶөкі„</b>\n"
               f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
               f"рҹӨ– <b>мқҙлЎ  мҲҳмқөлҘ </b> (лҙҮ н•ҷмҠө кё°мӨҖ)  {len(completed)}кұҙ\n"
               f"  мҠ№лҘ  <b>{total_rate:.0f}%</b>  нҸүк·  <b>{avg_pnl:+.1f}%</b>  м¶”м ҒмӨ‘ {len(tracking)}кұҙ\n"
               f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
               + actual_msg
               + skip_msg
               + miss_msg
               + f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n")

        # в”Җв”Җ лҶ“м№ң мҲҳмқө в”Җв”Җ
        try:
            missed = get_missed_profit_summary()
            if missed["count"] >= 3:
                best  = missed.get("best") or {}
                b_str = f"  мөңкі : {best.get('name','')} {best.get('pnl_pct',0):+.1f}%" if best else ""
                msg  += (f"рҹ’ё <b>лҶ“м№ң мҲҳмқө</b>  {missed['count']}кұҙ  "
                         f"нҸүк·  {missed['avg_pnl']:+.1f}%  н•©кі„ {missed['total_pnl']:+.1f}%\n"
                         f"{b_str}\n"
                         f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n")
        except Exception: pass

        # мӢ нҳё мң нҳ•лі„
        by_type = {}
        for v in completed:
            t = v.get("signal_type", "кё°нғҖ")
            by_type.setdefault(t, []).append(v)

        for t, recs in sorted(by_type.items(), key=lambda x: -len(x[1])):
            pnls = [r["pnl_pct"] for r in recs]
            win  = sum(1 for p in pnls if p > 0)
            rate = win / len(pnls) * 100
            avg  = sum(pnls) / len(pnls)
            best = max(pnls); worst = min(pnls)
            label = type_labels.get(t, t)
            bar   = "рҹ”ҙ" * int(rate/20)
            # мІӯмӮ° мқҙмң  л¶„нҸ¬
            reasons = {}
            for r in recs:
                ex = r.get("exit_reason", "?")
                reasons[ex] = reasons.get(ex, 0) + 1
            reason_str = "  ".join([f"{k}:{v}кұҙ" for k, v in reasons.items()])
            msg += (f"\n{label}  ({len(recs)}кұҙ)\n"
                    f"  {bar}  мҠ№лҘ  {rate:.0f}%  нҸүк·  {avg:+.1f}%\n"
                    f"  мөңкі  {best:+.1f}%  мөңм Җ {worst:+.1f}%\n"
                    f"  {reason_str}\n")

        # лӢЁлҸ… vs н…Ңл§Ҳ лҸҷл°ҳ л№„көҗ
        solo   = [v for v in completed if not v.get("sector_bonus", 0)]
        themed = [v for v in completed if v.get("sector_bonus", 0)]
        if solo and themed:
            solo_avg   = sum(v["pnl_pct"] for v in solo)   / len(solo)
            themed_avg = sum(v["pnl_pct"] for v in themed) / len(themed)
            solo_win   = sum(1 for v in solo   if v["pnl_pct"] > 0) / len(solo)   * 100
            themed_win = sum(1 for v in themed if v["pnl_pct"] > 0) / len(themed) * 100
            msg += (f"\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                    f"рҹ”Қ лӢЁлҸ… мғҒмҠ№:  мҠ№лҘ  {solo_win:.0f}%  нҸүк·  {solo_avg:+.1f}% ({len(solo)}кұҙ)\n"
                    f"рҹҸӯ н…Ңл§Ҳ лҸҷл°ҳ:  мҠ№лҘ  {themed_win:.0f}%  нҸүк·  {themed_avg:+.1f}% ({len(themed)}кұҙ)\n")

        # в”Җв”Җ мӢңк°„лҢҖлі„ мҠ№лҘ  л¶„м„қ в”Җв”Җ
        slot_stats = analyze_timeslot_winrate(completed)
        if slot_stats:
            slot_order = ["мһҘмҙҲл°ҳ", "мҳӨм „", "мҳӨнӣ„", "мһҘнӣ„л°ҳ", "кё°нғҖ"]
            msg += "\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ•җ <b>мӢңк°„лҢҖлі„ мҠ№лҘ </b>\n"
            for slot in slot_order:
                if slot not in slot_stats: continue
                st  = slot_stats[slot]
                adj = _dynamic["timeslot_score_adj"].get(slot, 0)
                adj_str = f"  [+{adj}м җ ліҙм • мӨ‘]" if adj > 0 else ""
                bar = "рҹ”ҙ" * int(st["rate"] / 20)
                msg += (f"  {slot}: {bar}  мҠ№лҘ  {st['rate']:.0f}%  "
                        f"нҸүк·  {st['avg']:+.1f}%  ({st['total']}кұҙ){adj_str}\n")

        # в”Җв”Җ мҶҗмӢӨ нҢЁн„ҙ л¶„м„қ в”Җв”Җ
        loss_pattern = analyze_loss_pattern(completed)
        if loss_pattern:
            msg += f"\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n{loss_pattern}\n"


        # в”Җв”Җ v41.63 #4: KPI мҡ”м•Ҫ (мҠ№лҘ /мҶҗмқөл№„/кё°лҢҖмҲҳмқө) в”Җв”Җ
        try:
            kpi = compute_signal_kpi(completed)
            ov = kpi.get("overall", {})
            if ov.get("n", 0) >= KPI_MIN_SAMPLES:
                exp_emoji = "рҹ”ҙ" if ov["expectancy"] > 0.5 else "рҹҹЎ" if ov["expectancy"] >= 0 else "рҹ”ө"
                pf_emoji = "рҹ”ҙ" if ov["profit_factor"] > 1.5 else "рҹҹЎ" if ov["profit_factor"] >= 1.0 else "рҹ”ө"
                msg += (f"\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                        f"рҹ“җ <b>KPI мҡ”м•Ҫ</b> ({ov['n']}кұҙ кё°мӨҖ)\n"
                        f"  мҠ№лҘ : <b>{ov['win_rate']:.0f}%</b>  "
                        f"мҶҗмқөл№„: {pf_emoji} <b>{ov['payoff_ratio']:.2f}</b>  "
                        f"кё°лҢҖмҲҳмқө: {exp_emoji} <b>{ov['expectancy']:+.2f}%</b>\n"
                        f"  Profit Factor: {ov['profit_factor']:.2f}\n")
                by_t = kpi.get("by_type", {})
                type_labels_kpi = {
                    "UPPER_LIMIT": "мғҒн•ңк°Җ", "NEAR_UPPER": "мғҒн•ңк°Җк·јм ‘",
                    "STRONG_BUY": "к°•л Ҙл§ӨмҲҳ", "SURGE": "кёүл“ұ",
                    "EARLY_DETECT": "мЎ°кё°нҸ¬м°©", "ENTRY_POINT": "лҲҢлҰјлӘ©",
                    "MID_PULLBACK": "лҲҢлҰјлӘ©", "MANUAL": "мҲҳлҸҷ",
                }
                good = [(t, k) for t, k in by_t.items()
                        if k.get("n", 0) >= 5 and k["win_rate"] >= 60 and k.get("payoff_ratio", 0) >= 1.2]
                bad = [(t, k) for t, k in by_t.items()
                       if k.get("n", 0) >= 5 and (k["win_rate"] < 35 or k.get("payoff_ratio", 0) < 0.8)]
                if good:
                    g_str = ", ".join(f"{type_labels_kpi.get(t,t)}({k['win_rate']:.0f}%)" for t, k in good[:3])
                    msg += f"  рҹҢҹ кі м„ұкіј: {g_str}\n"
                if bad:
                    b_str = ", ".join(f"{type_labels_kpi.get(t,t)}({k['win_rate']:.0f}%)" for t, k in bad[:3])
                    msg += f"  вҡ пёҸ м Җм„ұкіј: {b_str}\n"
                if kpi.get("consecutive_loss", 0) >= 3:
                    msg += f"  рҹҡЁ м—°мҶҚ мҶҗм Ҳ: {kpi['consecutive_loss']}нҡҢ\n"
            else:
                msg += (f"\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                        f"рҹ“җ <b>KPI</b>: лҚ°мқҙн„° л¶ҖмЎұ ({ov.get('n', 0)}/{KPI_MIN_SAMPLES}кұҙ)\n")

            bucket_kpi = kpi.get("by_mid_pullback_bucket", {})
            if bucket_kpi:
                msg += "\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ§Ә <b>лҲҢлҰјлӘ© bucket м§„лӢЁ</b>\n"
                high_buckets = []
                low_buckets = []
                for bucket in ["weekly_monthly_trend", "daily_trend", "gap_first_pullback", "intraday_reclaim"]:
                    bk = bucket_kpi.get(bucket)
                    if not bk:
                        continue
                    label = MID_PULLBACK_BUCKET_LABELS.get(bucket, bucket)
                    n = bk.get("n", 0)
                    if n < 2:
                        msg += f"  {label}: н‘ңліё л¶ҖмЎұ ({n}кұҙ)\n"
                        continue
                    grade_dist = bk.get("execution_grade_dist", {}) or {}
                    grade_str = " ".join(f"{g}{grade_dist.get(g,0)}" for g in ("A", "B", "C") if grade_dist.get(g, 0)) or "-"
                    emoji = "рҹ”ҙ" if bk.get("expectancy", 0) > 0.5 else "рҹҹЎ" if bk.get("expectancy", 0) >= 0 else "рҹ”ө"
                    msg += (f"  {emoji} {label}: мҠ№лҘ  {bk['win_rate']:.0f}%  нҸүк·  {bk['avg_pnl']:+.1f}%  "
                            f"мҶҗмқөл№„ {bk['payoff_ratio']:.2f}  кё°лҢҖ {bk['expectancy']:+.2f}%  ({n}кұҙ) [{grade_str}]\n")
                    if n >= 3 and bk.get("win_rate", 0) >= 60 and bk.get("expectancy", 0) > 0:
                        high_buckets.append(label)
                    if n >= 3 and (bk.get("win_rate", 0) < 35 or bk.get("expectancy", 0) < 0):
                        low_buckets.append(label)
                if high_buckets:
                    msg += f"  рҹҢҹ кі м„ұкіј bucket: {', '.join(high_buckets[:3])}\n"
                if low_buckets:
                    msg += f"  вҡ пёҸ м Җм„ұкіј bucket: {', '.join(low_buckets[:3])}\n"

            actual_bucket_recs = [v for v in actual_entered if v.get("mid_pullback_bucket")]
            if actual_bucket_recs:
                actual_kpi = compute_signal_kpi(actual_bucket_recs, pnl_field="actual_pnl")
                actual_bucket_kpi = actual_kpi.get("by_mid_pullback_bucket", {})
                if actual_bucket_kpi:
                    msg += "\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹӘҷ <b>мӢӨм§„мһ… лҲҢлҰјлӘ© bucket</b>\n"
                    high_actual = []
                    low_actual = []
                    for bucket in ["weekly_monthly_trend", "daily_trend", "gap_first_pullback", "intraday_reclaim"]:
                        bk = actual_bucket_kpi.get(bucket)
                        if not bk:
                            continue
                        label = MID_PULLBACK_BUCKET_LABELS.get(bucket, bucket)
                        n = bk.get("n", 0)
                        if n < 2:
                            msg += f"  {label}: н‘ңліё л¶ҖмЎұ ({n}кұҙ)\n"
                            continue
                        grade_dist = bk.get("execution_grade_dist", {}) or {}
                        grade_str = " ".join(f"{g}{grade_dist.get(g,0)}" for g in ("A", "B", "C") if grade_dist.get(g, 0)) or "-"
                        emoji = "рҹ”ҙ" if bk.get("expectancy", 0) > 0.5 else "рҹҹЎ" if bk.get("expectancy", 0) >= 0 else "рҹ”ө"
                        msg += (f"  {emoji} {label}: мҠ№лҘ  {bk['win_rate']:.0f}%  нҸүк·  {bk['avg_pnl']:+.1f}%  "
                                f"мҶҗмқөл№„ {bk['payoff_ratio']:.2f}  кё°лҢҖ {bk['expectancy']:+.2f}%  ({n}кұҙ) [{grade_str}]\n")
                        if n >= 3 and bk.get("win_rate", 0) >= 60 and bk.get("expectancy", 0) > 0:
                            high_actual.append(label)
                        if n >= 3 and (bk.get("win_rate", 0) < 35 or bk.get("expectancy", 0) < 0):
                            low_actual.append(label)
                    if high_actual:
                        msg += f"  рҹҢҹ мӢӨм§„мһ… кі м„ұкіј: {', '.join(high_actual[:3])}\n"
                    if low_actual:
                        msg += f"  вҡ пёҸ мӢӨм§„мһ… м Җм„ұкіј: {', '.join(low_actual[:3])}\n"
        except Exception:
            pass

        # в”Җв”Җ мӢңмһҘ көӯл©ҙ нҳ„нҷ© в”Җв”Җ
        regime = get_market_regime()
        rmode  = regime.get("mode", "normal")
        rlabels = {"bull":"рҹ”ҙ мғҒмҠ№мһҘ","normal":"рҹҹЎ ліҙнҶөмһҘ","bear":"рҹ”ө н•ҳлқҪмһҘ","crash":"рҹ”ө кёүлқҪмһҘ"}
        mult_map = {"bull":"кё°мӨҖ мҷ„нҷ” (Г—1.15)","normal":"н‘ңмӨҖ","bear":"кё°мӨҖ к°•нҷ” (Г—0.75)","crash":"кёүлқҪмһҘ вҖ” мғҒн•ңк°Җл§Ң н—Ҳмҡ©"}
        msg += (f"\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                f"рҹҢҗ <b>нҳ„мһ¬ мӢңмһҘ көӯл©ҙ</b>: {rlabels.get(rmode,'ліҙнҶөмһҘ')}\n"
                f"  мҪ”мҠӨн”ј лӢ№мқј {regime.get('chg_1d',0):+.1f}%  |  5мқј {regime.get('chg_5d',0):+.1f}%\n"
                f"  мӢ нҳё кё°мӨҖ: {mult_map.get(rmode,'н‘ңмӨҖ')}\n")

        # в”Җв”Җ нҸ¬м§Җм…ҳ мӮ¬мқҙм§• мҡ”м•Ҫ в”Җв”Җ
        if completed:
            a_recs = [v for v in completed if v.get("grade","B") == "A"]
            b_recs = [v for v in completed if v.get("grade","B") == "B"]
            if a_recs:
                a_avg = sum(v["pnl_pct"] for v in a_recs) / len(a_recs)
                a_win = sum(1 for v in a_recs if v["pnl_pct"] > 0) / len(a_recs) * 100
                msg += (f"\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                        f"рҹ’° <b>л“ұкёүлі„ м„ұкіј</b>\n"
                        f"  Aл“ұкёү: {len(a_recs)}кұҙ  мҠ№лҘ  {a_win:.0f}%  нҸүк·  {a_avg:+.1f}%\n")
            if b_recs:
                b_avg = sum(v["pnl_pct"] for v in b_recs) / len(b_recs)
                b_win = sum(1 for v in b_recs if v["pnl_pct"] > 0) / len(b_recs) * 100
                msg += f"  Bл“ұкёү: {len(b_recs)}кұҙ  мҠ№лҘ  {b_win:.0f}%  нҸүк·  {b_avg:+.1f}%\n"

        # в”Җв”Җ нҳ„мһ¬ _dynamic нҢҢлқјлҜён„° мҡ”м•Ҫ в”Җв”Җ
        msg += (f"\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                f"вҡҷпёҸ <b>нҳ„мһ¬ мһҗлҸҷ мЎ°м • нҢҢлқјлҜён„°</b>\n"
                f"  мөңмҶҢм җмҲҳ: {_dynamic['min_score_normal']}м җ (м—„кІ©: {_dynamic['min_score_strict']}м җ)\n"
                f"  RSI кіјл§ӨмҲҳ кё°мӨҖ: {_dynamic['rsi_overbuy']:.0f}\n"
                f"  ATR мҶҗм Ҳ:{_dynamic['atr_stop_mult']} / лӘ©н‘ң:{_dynamic.get('atr_target_mult', ATR_TARGET_MULT)}\n"
                f"  нҸ¬м§Җм…ҳ кё°ліёл№„мӨ‘: {_dynamic.get('position_base_pct',8.0)}%\n")

        # в”Җв”Җ кё°лҠҘлі„ кё°м—¬лҸ„ нҳ„нҷ© в”Җв”Җ
        feat_labels = {
            "feat_w_rsi":    "RSI н•„н„°",
            "feat_w_ma":     "мқҙлҸҷнҸүк· ",
            "feat_w_bb":     "ліјлҰ°м Җл°ҙл“ң",
            "feat_w_sector": "м„№н„°лӘЁл©ҳн…Җ",
            "feat_w_nxt":    "NXT ліҙм •",
            "feat_w_geo":    "м§Җм •н•ҷ ліҙм •",
        }
        msg += f"\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nрҹ”§ <b>кё°лҠҘлі„ к°ҖмӨ‘м№ҳ</b> (auto_tune мһҗлҸҷ мЎ°м •)\n"
        for fk, flabel in feat_labels.items():
            w = _dynamic.get(fk, 1.0)
            if w >= 1.2:   status = "рҹ”ә к°•нҷ”"
            elif w >= 0.8: status = "вң… м •мғҒ"
            elif w >= 0.4: status = "рҹ”» м•Ҫнҷ”"
            else:           status = "вӣ” кұ°мқҳ л№„нҷңм„ұ"
            bar = "в–Ҳ" * int(w * 5) + "в–‘" * max(0, 5 - int(w * 5))
            msg += f"  {flabel}: {bar} {w:.1f}  {status}\n"

        send(msg)
    except Exception as e:
        send(f"вҡ пёҸ нҶөкі„ мҳӨлҘҳ: {e}")

