# мһҘ л§Ҳк°җ
# ============================================================
def on_market_close():
    # [v37.10-all5] м„ұкіј кё°л°ҳ мң лӢҲлІ„мҠӨ мһҗлҸҷ к°ұмӢ (мһҘ л§Ҳк°җ)
    update_universe_from_performance(days=int(os.getenv('UNIVERSE_PERF_DAYS','30') or '30'), max_codes=int(os.getenv('UNIVERSE_PERF_MAX','300') or '300'))
    # мһ¬м§„мһ… к°җмӢң вҖ” KRX only мў…лӘ©л§Ң мҙҲкё°нҷ”, NXT мғҒмһҘ мў…лӘ©мқҖ 20:00к№Ңм§Җ мң м§Җ
    nxt_remain = {c: w for c, w in _reentry_watch.items() if is_nxt_listed(c)}
    krx_only   = {c: w for c, w in _reentry_watch.items() if not is_nxt_listed(c)}
    if krx_only:
        for c in krx_only: _reentry_watch.pop(c, None)
        print(f"  рҹ”„ KRX мһ¬м§„мһ… к°җмӢң {len(krx_only)}кұҙ л§ҢлЈҢ (15:30)")
    if nxt_remain:
        print(f"  рҹҹЎ NXT мһ¬м§„мһ… к°җмӢң {len(nxt_remain)}кұҙ мң м§Җ (вҶ’20:00)")

    carry_list = []
    for code, info in list(_detected_stocks.items()):
        carry_day = info.get("carry_day",0)
        if carry_day >= MAX_CARRY_DAYS: del _detected_stocks[code]; continue
        _detected_stocks[code]["carry_day"]   = carry_day+1
        _detected_stocks[code]["detected_at"] = datetime.now()
        carry_list.append(f"вҖў {info['name']} ({code}) - {carry_day+1}мқјм°Ё")
    save_carry_stocks()
    auto_tune(notify=True)
    _send_pending_result_reminder()   # вҳ… мҳӨлҠҳ лҜёмһ…л Ҙ мў…лӘ© м•ҢлҰј

    today = datetime.now().strftime("%Y%m%d")
    today_str = datetime.now().strftime("%Y-%m-%d")
    try:
        data = {}
        data = _read_json_locked(SIGNAL_LOG_FILE)

        today_recs   = [v for v in data.values() if v.get("detect_date") == today]
        done_today   = [v for v in today_recs if v.get("status") != "м¶”м ҒмӨ‘"]
        # м „мІҙ м¶”м Ғ мӨ‘ (лӮ м§ң л¬ҙкҙҖ)
        all_tracking = _get_valid_tracking(data)

        sig_labels = {
            "UPPER_LIMIT":"мғҒн•ңк°Җ","NEAR_UPPER":"мғҒн•ңк°Җк·јм ‘","SURGE":"кёүл“ұ",
            "EARLY_DETECT":"мЎ°кё°нҸ¬м°©","MID_PULLBACK":"лҲҢлҰјлӘ©",
            "ENTRY_POINT":"лҲҢлҰјлӘ©","STRONG_BUY":"к°•л Ҙл§ӨмҲҳ",
        }

        msg = f"рҹ”” <b>мһҘ л§Ҳк°җ лҰ¬нҸ¬нҠё</b>  {today_str}\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"

        # в”Җв”Җ мҳӨлҠҳ нҷ•м • кІ°кіј в”Җв”Җ
        if done_today:
            wins   = sum(1 for v in done_today if v.get("pnl_pct",0) > 0)
            losses = sum(1 for v in done_today if v.get("pnl_pct",0) < 0)
            win_rate = round(wins / len(done_today) * 100) if done_today else 0
            avg_pnl  = sum(v.get("pnl_pct",0) for v in done_today) / len(done_today)
            msg += (f"\nрҹ“Ҡ <b>мҳӨлҠҳ нҷ•м • кІ°кіј</b>  ({len(done_today)}кұҙ)\n"
                    f"  мҠ№лҘ  <b>{win_rate}%</b>  нҸүк·  <b>{avg_pnl:+.1f}%</b>"
                    f"  |  мҲҳмқө {wins}кұҙ  мҶҗмӢӨ {losses}кұҙ\n")
            for v in sorted(done_today, key=lambda x: x.get("pnl_pct",0), reverse=True):
                pnl   = v.get("pnl_pct", 0)
                dot   = "вң…" if pnl > 0 else ("рҹ”ө" if pnl < 0 else "вһ–")
                label = sig_labels.get(v.get("signal_type",""), "")
                theme = f"[{v['sector_theme']}]" if v.get("sector_bonus",0) > 0 else "[лӢЁлҸ…]"
                msg  += f"  {dot} {v['name']} <b>{pnl:+.1f}%</b>  {label} {theme}\n"
        else:
            msg += "\nрҹ“Ҡ мҳӨлҠҳ нҷ•м •лҗң мӢ нҳё м—ҶмқҢ\n"

        # в”Җв”Җ м „мІҙ м¶”м Ғ мӨ‘ (мҳӨлҠҳ + мқҙмӣ”) мһ м • мҲҳмқөлҘ  в”Җв”Җ
        if all_tracking:
            msg += f"\nвҸі <b>м¶”м Ғ мӨ‘</b>  ({len(all_tracking)}кұҙ)\n"
            tracking_results = []
            for v in all_tracking:
                try:
                    # мһҘ л§Ҳк°җ нӣ„л©ҙ NXT к°ҖкІ© мҡ°м„  мӮ¬мҡ©
                    price = 0
                    if is_nxt_open():
                        nxt_p = get_nxt_stock_price(v["code"])
                        price = nxt_p.get("price", 0)
                    if not price:
                        cur   = get_stock_price(v["code"])
                        price = cur.get("price", 0)
                    entry = v.get("entry_price", 0)
                    if price and entry:
                        pnl      = round((price - entry) / entry * 100, 1)
                        days_ago = (datetime.strptime(today, "%Y%m%d") -
                                    datetime.strptime(v.get("detect_date", today), "%Y%m%d")).days
                        day_tag  = f" {days_ago}мқјм§ё" if days_ago > 0 else " мҳӨлҠҳ"
                        dot      = "рҹ”ҙ" if pnl >= 0 else "рҹҹЎ"
                        label    = sig_labels.get(v.get("signal_type",""), "")
                        nxt_tag  = " рҹҹЎNXT" if is_nxt_open() else ""
                        tracking_results.append((pnl, f"  {dot} {v['name']} <b>{pnl:+.1f}%</b>  {label}{day_tag}{nxt_tag}\n"))
                    time.sleep(0.1)
                except Exception: continue
            # мҲҳмқөлҘ  лҶ’мқҖ мҲң м •л ¬
            for _, line in sorted(tracking_results, key=lambda x: x[0], reverse=True):
                msg += line

        if carry_list:
            msg += f"\nрҹ“Ӯ <b>мқҙмӣ” мў…лӘ©</b>  ({len(carry_list)}к°ң)\n" + "\n".join(carry_list) + "\n"

        # в”Җв”Җ лҲ„м Ғ м„ұкіј мҡ”м•Ҫ (м „мІҙ мҷ„лЈҢ кұҙ) в”Җв”Җ
        all_done = [v for v in data.values() if v.get("status") in ["мҲҳмқө","мҶҗмӢӨ","ліём „"]]
        if len(all_done) >= 5:
            total_win  = sum(1 for v in all_done if v.get("pnl_pct",0) > 0)
            total_avg  = sum(v.get("pnl_pct",0) for v in all_done) / len(all_done)
            total_rate = round(total_win / len(all_done) * 100)
            msg += (f"\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
                    f"рҹ“Ҳ <b>лҲ„м Ғ м„ұкіј</b>  {len(all_done)}кұҙ\n"
                    f"  мҠ№лҘ  <b>{total_rate}%</b>  нҸүк·  <b>{total_avg:+.1f}%</b>\n")

    except Exception as e:
        msg = (f"рҹ”” <b>мһҘ л§Ҳк°җ</b>  {today_str}\n"
               f"к°җмӢң мў…лӘ©: <b>{len(_detected_stocks)}к°ң</b>\n"
               f"вҡ пёҸ лҰ¬нҸ¬нҠё мҳӨлҘҳ: {e}\n")
        if carry_list:
            msg += f"\nрҹ“Ӯ <b>мқҙмӣ”</b> ({len(carry_list)}к°ң)\n" + "\n".join(carry_list)

    send(msg)
    analyze_dart_disclosures()
    run_daily_self_audit(stage="krx")

    # кёҲмҡ”мқј мһҘ л§Ҳк°җ = мЈјк°„ лҰ¬нҸ¬нҠё (кёҲмҡ”мқјмқҙ кіөнңҙмқјмқҙлқј лӘ©мҡ”мқјм—җ л§Ҳк°җн•ҳлҠ” кІҪмҡ°лҸ„ мІҳлҰ¬)
    now = datetime.now()
    is_friday = now.weekday() == 4
    next_day_holiday = is_holiday((now + timedelta(days=1)).strftime("%Y%m%d"))
    is_last_trading_day = is_friday or (now.weekday() == 3 and next_day_holiday)
    if is_last_trading_day:
        send_weekly_report()

    # v38.3-D2: м—җлҹ¬ мқјмқј мҡ”м•Ҫ
    _send_error_daily_summary()


def _send_error_daily_summary():
    """v38.3-D2: лӢ№мқј м—җлҹ¬лҘј м№ҙн…Ңкі лҰ¬лі„ м§‘кі„н•ҙ н…”л Ҳк·ёлһЁ л°ңмҶЎ."""
    global _error_daily_counts, _error_daily_samples
    try:
        if not _error_daily_counts:
            print("вң… мҳӨлҠҳ м—җлҹ¬ 0кұҙ"); return
        total = sum(_error_daily_counts.values())
        sorted_errs = sorted(_error_daily_counts.items(), key=lambda x: -x[1])[:10]
        lines = [f"вҖў <code>{fn}</code>: {cnt}нҡҢ\n  в”” {_error_daily_samples.get(fn,'')[:60]}"
                 for fn, cnt in sorted_errs]
        send(f"рҹ“Ҡ <b>мқјмқј м—җлҹ¬ мҡ”м•Ҫ</b>  {datetime.now().strftime('%Y-%m-%d')}\n"
             f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nмҙқ м—җлҹ¬: <b>{total}кұҙ</b> / {len(_error_daily_counts)}к°ң н•ЁмҲҳ\n"
             f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n" + "\n".join(lines))
        _error_daily_counts = {}; _error_daily_samples = {}
    except Exception as e:
        print(f"вҡ пёҸ м—җлҹ¬ мҡ”м•Ҫ л°ңмҶЎ мӢӨнҢЁ: {e}")


# ============================================================
# v40.0-#3: мһҘ мӢңмһ‘ м „ лҰ¬мҠӨнҒ¬ нҸүк°Җ м•ҢлҰј (08:30)
# v40.0-#5: лҰ¬мҠӨнҒ¬ мӣҗмқёлі„ м—”м§„ (мң лҸҷм„ұ/м—җл„Ҳм§ҖВ·м§Җм •н•ҷ/көӯлӮҙм¶”м„ё)
# v40.0-#6: мӢңк°„лҢҖлі„ лҰ¬мҠӨнҒ¬ н”„лЎңнҢҢмқј
# ============================================================
def _classify_risk_causes(us: dict, geo_state: dict, kospi_5d: float = 0.0) -> list:
    """v40.0-#5: лҰ¬мҠӨнҒ¬лҘј мӣҗмқёлі„лЎң л¶„лҘҳ.
    л°ҳнҷҳ: [{"type": str, "label": str, "score": int, "detail": str}, ...]
    """
    causes = []
    try:
        # в‘  мң лҸҷм„ұ мҮјнҒ¬ (VIX/DXY/нҷҳмңЁ)
        vix = float(us.get("vix", 20) or 20)
        dxy = float(us.get("dxy", 104) or 104)
        krw = float(us.get("krw_usd", 0) or 0)
        krw_chg = float(us.get("krw_usd_chg", 0) or 0)
        liq_score = 0
        liq_parts = []
        if vix >= 30:
            liq_score += 40; liq_parts.append(f"VIX {vix:.0f} кіөнҸ¬")
        elif vix >= 25:
            liq_score += 20; liq_parts.append(f"VIX {vix:.0f} л¶Ҳм•Ҳ")
        if dxy >= 107:
            liq_score += 15; liq_parts.append(f"лӢ¬лҹ¬ {dxy:.1f} к°•м„ё")
        if krw >= 1400:
            liq_score += 25; liq_parts.append(f"мӣҗнҷ” {krw:.0f}мӣҗ мң„кё°")
        elif krw_chg >= 0.8:
            liq_score += 10; liq_parts.append(f"мӣҗнҷ” кёүлқҪ {krw_chg:+.1f}%")
        if liq_score > 0:
            causes.append({
                "type": "liquidity", "label": "мң лҸҷм„ұ мҮјнҒ¬",
                "score": liq_score, "detail": " / ".join(liq_parts)
            })

        # в‘Ў м—җл„Ҳм§ҖВ·м§Җм •н•ҷ мҮјнҒ¬
        oil_chg = float(us.get("oil_chg", 0) or 0)
        gold_chg = float(us.get("gold_chg", 0) or 0)
        geo_active = bool(geo_state.get("active") and time.time() - float(geo_state.get("ts", 0) or 0) < 14400)
        geo_unc = str(geo_state.get("uncertainty", "low") or "low")
        eg_score = 0
        eg_parts = []
        if abs(oil_chg) >= 4.0:
            eg_score += 20; eg_parts.append(f"мң к°Җ {oil_chg:+.1f}%")
        elif abs(oil_chg) >= 2.0:
            eg_score += 8; eg_parts.append(f"мң к°Җ {oil_chg:+.1f}%")
        if gold_chg >= 2.0:
            eg_score += 10; eg_parts.append(f"кёҲ {gold_chg:+.1f}% (м•Ҳм „мһҗмӮ°)")
        if geo_active:
            geo_add = {"high": 30, "mid": 15, "low": 5}.get(geo_unc, 5)
            eg_score += geo_add
            eg_parts.append(f"м§Җм •н•ҷ {geo_unc.upper()}")
        if eg_score > 0:
            causes.append({
                "type": "energy_geo", "label": "м—җл„Ҳм§ҖВ·м§Җм •н•ҷ мҮјнҒ¬",
                "score": eg_score, "detail": " / ".join(eg_parts)
            })

        # в‘ў көӯлӮҙ м¶”м„ё л¶•кҙҙ
        nasdaq_chg = float(us.get("nasdaq_chg", 0) or 0)
        dom_score = 0
        dom_parts = []
        if kospi_5d <= -7.0:
            dom_score += 40; dom_parts.append(f"мҪ”мҠӨн”ј 5мқј {kospi_5d:+.1f}% кёүлқҪ")
        elif kospi_5d <= -3.0:
            dom_score += 20; dom_parts.append(f"мҪ”мҠӨн”ј 5мқј {kospi_5d:+.1f}% н•ҳлқҪ")
        if nasdaq_chg <= -3.0:
            dom_score += 25; dom_parts.append(f"лӮҳмҠӨлӢҘ {nasdaq_chg:+.1f}% кёүлқҪ")
        elif nasdaq_chg <= -1.5:
            dom_score += 10; dom_parts.append(f"лӮҳмҠӨлӢҘ {nasdaq_chg:+.1f}%")
        if dom_score > 0:
            causes.append({
                "type": "domestic_trend", "label": "көӯлӮҙ м¶”м„ё л¶•кҙҙ",
                "score": dom_score, "detail": " / ".join(dom_parts)
            })
    except Exception:
        pass
    return sorted(causes, key=lambda x: -x["score"])



def _run_holiday_standby_until_trading_day():
    """мЈјл§җ/кіөнңҙмқј лҢҖкё° лӘЁл“ң мң м§Җ. нҸүмқј м „нҷҳ мӢң мҠӨмјҖмӨ„мқ„ л№„мҡ°кі  м •мғҒ лӘЁл“ңлЎң ліөк·Җ."""
    print("вң… лҢҖкё° лӘЁл“ң мҠӨмјҖмӨ„ л“ұлЎқ мҷ„лЈҢ")
    while True:
        try:
            schedule.run_pending()
            if not is_holiday():
                print("рҹҢ… кіөнңҙмқј/мЈјл§җ лҢҖкё° лӘЁл“ң мў…лЈҢ вҖ” нҸүмқј мҠӨмјҖмӨ„лЎң м „нҷҳ")
                try:
                    schedule.clear()
                except Exception as clear_err:
                    print(f"вҡ пёҸ лҢҖкё° лӘЁл“ң мҠӨмјҖмӨ„ мҙҲкё°нҷ” мӢӨнҢЁ: {clear_err}")
                break
            time.sleep(1)
        except Exception as e:
            print(f"вҡ пёҸ лҢҖкё° лӘЁл“ң лЈЁн”„ мҳӨлҘҳ: {e}")
            time.sleep(5)

def _build_premarket_risk_payload() -> dict:
    us = get_us_market_signals()
    total_score = 0
    parts = []

    nasdaq_chg = float(us.get("nasdaq_chg", 0) or 0)
    vix = float(us.get("vix", 20) or 20)
    gap_signal = us.get("gap_signal", "flat")

    kospi_5d = 0.0
    now = _now_kst()
    geo_state = _get_effective_geo_state(now) or {}
    overnight_lines = _get_effective_overnight_lines(now)
    try:
        items = get_daily_data("0001", 10)
        closes = [i["close"] for i in items if i.get("close")]
        if len(closes) >= 5:
            kospi_5d = (closes[-1] - closes[-5]) / closes[-5] * 100
    except Exception:
        pass

    causes = _classify_risk_causes(us, geo_state, kospi_5d)
    total_score = sum(c["score"] for c in causes)

    if now.weekday() == 4:
        total_score += 10
        parts.append("рҹ“… кёҲмҡ”мқј (мЈјл§җ мҳӨлІ„лӮҳмқҙнҠё лҰ¬мҠӨнҒ¬)")

    if total_score >= 50:
        level = "мң„н—ҳ"; level_emoji = "рҹ”ө"; action = "мӢ к·ң м§„мһ… м¶•мҶҢ / кё°мЎҙ нҸ¬м§Җм…ҳ м •лҰ¬ кІҖнҶ "
    elif total_score >= 25:
        level = "кІҪкі„"; level_emoji = "рҹҹЎ"; action = "мӢ к·ң м§„мһ… ліҙмҲҳм Ғ / мҶҗм Ҳ нғҖмқҙнҠён•ҳкІҢ"
    else:
        level = "м•Ҳм „"; level_emoji = "рҹ”ҙ"; action = "м •мғҒ мҡҙмҳҒ"

    msg = (
        f"рҹӣЎ <b>мһҘм „ лҰ¬мҠӨнҒ¬ нҸүк°Җ</b>  {now.strftime('%Y-%m-%d %H:%M')}\n"
        f"в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\n"
        f"рҹ“Ҡ мҳӨлҠҳ лҰ¬мҠӨнҒ¬ л“ұкёү: {level_emoji} <b>{level}</b> ({total_score}м җ)\n"
        f"рҹ’Ў к¶ҢмһҘ: <b>{action}</b>\n"
    )

    if causes:
        msg += f"\nрҹ”Қ <b>лҰ¬мҠӨнҒ¬ мӣҗмқё л¶„м„қ</b>\n"
        for c in causes[:3]:
            c_emoji = {"liquidity": "рҹ’§", "energy_geo": "рҹҢҚ", "domestic_trend": "рҹ“ү"}.get(c["type"], "вҡ пёҸ")
            msg += f"  {c_emoji} {c['label']}: {c['detail']} ({c['score']}м җ)\n"

    try:
        geo_summary = str(geo_state.get("summary", "") or "")
        geo_unc = str(geo_state.get("uncertainty", "low") or "low")
        geo_sectors = list(geo_state.get("sectors") or [])
        geo_history = list(geo_state.get("history_lines") or [])
        if overnight_lines or geo_summary or geo_history:
            msg += f"\nрҹҢҷ <b>м•јк°„ мқҙмҠҲ мҡ”м•Ҫ</b>\n"
            for line in list(overnight_lines or [])[-5:]:
                msg += f"  {line}\n"
            if geo_summary:
                sec_txt = f"  |  кҙҖл Ё м„№н„°: {', '.join(geo_sectors[:4])}" if geo_sectors else ""
                msg += f"  рҹҢҚ м§Җм •н•ҷ {geo_unc.upper()}: {geo_summary}{sec_txt}\n"
            elif geo_history:
                for line in geo_history[-3:]:
                    msg += f"  рҹҢҚ {line}\n"
    except Exception:
        pass

    msg += (
        f"\nрҹҢҗ <b>лҜёкөӯ мӢңмһҘ</b>\n"
        f"  лӮҳмҠӨлӢҘ {nasdaq_chg:+.1f}%  VIX {vix:.0f}  к°ӯмҳҲмёЎ {gap_signal}\n"
    )
    if kospi_5d != 0:
        msg += f"  мҪ”мҠӨн”ј 5мқј: {kospi_5d:+.1f}%\n"

    try:
        data = _read_json_locked(os.path.join(DATA_DIR, "signal_log.json"))
        tracking = _get_valid_tracking(data)
        if tracking and level in ("кІҪкі„", "мң„н—ҳ"):
            msg += f"\nвҡ пёҸ <b>м¶”м Ғ мӨ‘ {len(tracking)}кұҙ вҖ” м§„мһ…к°Җ лҸ„лӢ¬ мў…лӘ© мЈјмқҳ</b>\n"
            for rec in tracking[:5]:
                entry_p = rec.get("entry_price", 0)
                _name = rec.get("name", rec.get("code", ""))
                sig = get_signal_label(rec.get("signal_type", ""), "")
                msg += f"  вҖў {_name} (м§„мһ… {entry_p:,}мӣҗ) [{sig}]\n"
    except Exception:
        pass

    try:
        sig_stats = get_signal_type_stats()
        stats_line = _format_signal_type_stats_line(sig_stats)
        if stats_line:
            msg += f"\nрҹ“Ҳ <b>мң нҳ•лі„ мҠ№лҘ </b>\n  {stats_line}\n"
    except Exception:
        pass

    # v41.78 #3: м•јк°„ мқҙлІӨнҠё мӣҢм№ҳлҰ¬мҠӨнҠё лё”лЎқ
    try:
        wl_block = _format_overnight_watchlist_block()
        if wl_block:
            msg += f"\n{wl_block}\n"
    except Exception:
        pass

    msg += f"\nв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ\nвҸ° 09:00 мһҘ мӢңмһ‘"
    digest = hashlib.sha256(msg.encode("utf-8")).hexdigest()
    return {"msg": msg, "digest": digest, "score": total_score, "level": level, "ts": now.strftime('%Y-%m-%d %H:%M')}

def _save_premarket_risk_payload(payload: dict):
    try:
        _write_json_atomic(PREMARKET_RISK_LAST_FILE, payload, indent=2)
    except Exception:
        pass

def _try_mark_preopen_dispatch(kind: str, now_dt: datetime | None = None) -> bool:
    now_dt = now_dt or _now_kst()
    day_key = now_dt.strftime("%Y-%m-%d")
    key = f"{day_key}:{kind}"
    try:
        with _file_lock:
            state = {}
            if os.path.isfile(PREOPEN_DISPATCH_STATE_FILE):
                try:
                    with open(PREOPEN_DISPATCH_STATE_FILE, "r", encoding="utf-8") as f:
                        state = json.load(f) or {}
                except Exception:
                    state = {}
            if key in state:
                return False
            # prune old entries (keep recent 14 days)
            cutoff = (now_dt - timedelta(days=14)).strftime("%Y-%m-%d")
            pruned = {}
            for k, v in state.items():
                day = str(k).split(":", 1)[0]
                if day >= cutoff:
                    pruned[k] = v
            pruned[key] = {
                "ts": now_dt.strftime("%Y-%m-%d %H:%M:%S"),
                "instance": _INSTANCE_ID,
            }
            _atomic_write_bytes(PREOPEN_DISPATCH_STATE_FILE, json.dumps(pruned, ensure_ascii=False, indent=2).encode("utf-8"))
            return True
    except Exception as e:
        print(f"вҡ пёҸ мһҘм „ л””мҠӨнҢЁм№ҳ мғҒнғң кё°лЎқ мӢӨнҢЁ({kind}): {e}")
        return True

