# ============================================================
# рҹ“ў кіөмӢң м „ мқҙмғҒ кұ°лһҳлҹү к°җм§Җ (м„ л§ӨмҲҳ м„ёл Ҙ нҸ¬м°©)
# ============================================================
_pre_dart_cache: dict = {}  # code вҶ’ {ts, detected}

def detect_pre_dart_volume(code: str, name: str) -> dict:
    """
    DART кіөмӢң м§Ғм „ мқҙмғҒ кұ°лһҳлҹү к°җм§Җ.
    мөңк·ј 1мӢңк°„ лӮҙ кұ°лһҳлҹүмқҙ 5мқј нҸүк· мқҳ 3л°° мқҙмғҒмқҙкі ,
    м•„м§Ғ кіөмӢңк°Җ м—ҶлҠ” мғҒнғң вҶ’ м„ л§ӨмҲҳ м„ёл Ҙ к°җм§Җ.
    л°ҳнҷҳ: {detected: bool, vol_ratio: float, score_adj: int, reason: str}
    """
    cached = _pre_dart_cache.get(code)
    if cached and time.time() - cached.get("ts", 0) < 1800:
        return cached

    result = {"detected": False, "vol_ratio": 0.0, "score_adj": 0, "reason": "", "ts": time.time()}
    try:
        # нҳ„мһ¬ кұ°лһҳлҹү л№„мңЁ (Z-score кі„мӮ°мҡ©)
        cur  = get_stock_price(code)
        if not cur:
            return result
        vol_ratio = cur.get("volume_ratio", 0)

        # кұ°лһҳлҹү кёүмҰқ (5мқј нҸүк·  лҢҖл№„ 5л°° мқҙмғҒ) мқҙл©ҙм„ң кіөмӢң м—Ҷмңјл©ҙ мқҳмӢ¬
        if vol_ratio >= 5.0:
            # мөңк·ј DART кіөмӢң нҷ•мқё (2мӢңк°„ мқҙлӮҙ)
            today_str   = datetime.now().strftime("%Y%m%d")
            dart_list   = _fetch_dart_list(today_str) if DART_API_KEY else []
            recent_dart = [d for d in dart_list if d.get("stock_code") == code]

            if not recent_dart:
                # кіөмӢң м—ҶлҠ”лҚ° кұ°лһҳлҹү нҸӯл°ң вҶ’ м„ л§ӨмҲҳ мқҳмӢ¬
                score_adj = 10 if vol_ratio >= 10 else 6
                reason    = f"рҹҡЁ кіөмӢң м „ мқҙмғҒ кұ°лһҳлҹү {vol_ratio:.1f}л°° вҖ” м„ л§ӨмҲҳ к°җм§Җ (+{score_adj}м җ)"
                result.update({"detected": True, "vol_ratio": vol_ratio,
                                "score_adj": score_adj, "reason": reason})
            else:
                # кіөмӢң лӮҳмҳЁ нӣ„ кұ°лһҳлҹү вҶ’ мқјл°ҳ л°ҳмқ‘
                result.update({"detected": False, "vol_ratio": vol_ratio,
                                "score_adj": 3, "reason": f"рҹ“ў кіөмӢң нӣ„ кұ°лһҳлҹү л°ҳмқ‘ {vol_ratio:.1f}л°°"})

        _pre_dart_cache[code] = result
    except Exception as e:
        _log_error(f"detect_pre_dart_volume({code})", e)

    return result

def get_short_sell_ratio(code: str) -> float:
    """
    кіөл§ӨлҸ„ мһ”кі  л№„мңЁ мЎ°нҡҢ (KIS API кё°л°ҳ).
    л°ҳнҷҳ: 0~100 (%) вҖ” 5% мқҙмғҒмқҙл©ҙ кіөл§ӨлҸ„ м••л Ҙ лҶ’мқҢ
    """
    cached = _short_cache.get(code)
    if cached and time.time() - cached["ts"] < 3600:
        return cached["ratio"]
    try:
        token  = get_token()
        url    = "https://openapi.koreainvestment.com:9443/uapi/domestic-stock/v1/quotations/inquire-short-balance"
        headers = {
            "Authorization": f"Bearer {token}",
            "appkey":    KIS_APP_KEY,
            "appsecret": KIS_APP_SECRET,
            "tr_id":     "SHSHORT030R",
            "Content-Type": "application/json; charset=utf-8",
        }
        params = {"FID_COND_MRKT_DIV_CODE": "J", "FID_INPUT_ISCD": code}
        resp  = requests.get(url, headers=headers, params=params, timeout=5)
        data  = resp.json()
        ratio = float(data.get("output", {}).get("ssts_rsqn_rate", 0) or 0)
        _short_cache[code] = {"ratio": ratio, "ts": time.time()}
        return ratio
    except Exception:
        return 0.0

def _get_daily_investor_data(code: str) -> list:
    """
    KIS API: мқјлі„ мҷёкөӯмқё/кё°кҙҖ мҲңл§ӨмҲҳ лҚ°мқҙн„° (мөңк·ј 20мқј).
    л°ҳнҷҳ: [{date, foreign_net, institution_net}, ...]
    """
    try:
        end   = datetime.now().strftime("%Y%m%d")
        start = (datetime.now() - timedelta(days=30)).strftime("%Y%m%d")
        if _daily_trade_api_disabled_today():
            return _daily_trade_api_fallback(_get_daily_trade_api_disable_reason() or "disabled_today", code=code)
        url   = f"{KIS_BASE_URL}/uapi/domestic-stock/v1/quotations/inquire-daily-trade"
        params = {
            "FID_COND_MRKT_DIV_CODE": "J",
            "FID_INPUT_ISCD":  code,
            "FID_INPUT_DATE_1": start,
            "FID_INPUT_DATE_2": end,
            "FID_PERIOD_DIV_CODE": "D",
        }
        data, status, ct, body = _safe_get_meta(url, "FHKST03010400", params)
        if status == 404:
            return _daily_trade_api_fallback("404", code=code, status=status, ct=ct, body=body)
        if status not in (None, 200):
            return _daily_trade_api_fallback(f"status_{status}", code=code, status=status, ct=ct, body=body)
        if not isinstance(data, dict):
            return _daily_trade_api_fallback("invalid_response", code=code, status=status, ct=ct, body=body)
        items = data.get("output2", []) if data else []
        if not isinstance(items, list):
            return _daily_trade_api_fallback("invalid_output2", code=code, status=status, ct=ct, body=body)
        result = sorted([{
            "date":            i.get("stck_bsop_date", ""),
            "foreign_net":     int(i.get("frgn_ntby_qty", 0) or 0),
            "institution_net": int(i.get("orgn_ntby_qty",  0) or 0),
        } for i in items if i.get("stck_bsop_date")], key=lambda x: x["date"])
        return result[-20:]
    except Exception:
        return []

def get_foreign_consecutive_days(code: str) -> int:
    """
    мҷёкөӯмқё м—°мҶҚ мҲңл§ӨмҲҳ/мҲңл§ӨлҸ„мқј.
    м–‘мҲҳ: м—°мҶҚ мҲңл§ӨмҲҳмқј, мқҢмҲҳ: м—°мҶҚ мҲңл§ӨлҸ„мқј
    KIS мқјлі„ нҲ¬мһҗмһҗ лҚ°мқҙн„° мӮ¬мҡ© (1мӢңк°„ мәҗмӢң)
    """
    cached = _foreign_cache.get(code)
    if cached and time.time() - cached.get("ts", 0) < 3600:
        return cached.get("days", 0)
    try:
        items = _get_daily_investor_data(code)
        days = 0; sign = None
        for item in reversed(items):
            f_net    = item.get("foreign_net", 0)
            cur_sign = 1 if f_net > 0 else (-1 if f_net < 0 else 0)
            if cur_sign == 0: break
            if sign is None: sign = cur_sign
            if cur_sign != sign: break
            days += 1
        result = days * (sign or 1)
        _foreign_cache[code] = {"days": result, "inst_days": 0, "ts": time.time()}
        # кё°кҙҖлҸ„ к°ҷмқҙ кі„мӮ°н•ҙм„ң мәҗмӢң
        inst_days = 0; inst_sign = None
        for item in reversed(items):
            i_net    = item.get("institution_net", 0)
            cur_sign = 1 if i_net > 0 else (-1 if i_net < 0 else 0)
            if cur_sign == 0: break
            if inst_sign is None: inst_sign = cur_sign
            if cur_sign != inst_sign: break
            inst_days += 1
        _foreign_cache[code]["inst_days"] = inst_days * (inst_sign or 1)
        return result
    except Exception:
        return 0

def get_institution_consecutive_days(code: str) -> int:
    """кё°кҙҖ м—°мҶҚ мҲңл§ӨмҲҳ/мҲңл§ӨлҸ„мқј (мҷёкөӯмқё мәҗмӢң кіөмң )"""
    cached = _foreign_cache.get(code)
    if cached and time.time() - cached.get("ts", 0) < 3600:
        return cached.get("inst_days", 0)
    get_foreign_consecutive_days(code)  # мәҗмӢң к°ұмӢ 
    return _foreign_cache.get(code, {}).get("inst_days", 0)


def _korea_etf_time_weight(now: datetime | None = None) -> float:
    now = now or _now_kst()
    t = now.time()
    if dtime(8, 0) <= t < dtime(9, 0):
        return 1.00
    if dtime(9, 0) <= t < dtime(10, 0):
        return 0.70
    if dtime(10, 0) <= t < dtime(11, 0):
        return 0.40
    if dtime(11, 0) <= t < dtime(15, 30):
        return 0.20
    return 0.0


def _get_korea_etf_bucket_weights() -> dict:
    """лҸҷм Ғ нҢҢлқјлҜён„°м—җ м ҖмһҘлҗң EWY/FLKR м„№н„° к°ҖмӨ‘м№ҳлҘј мҡ°м„  мӮ¬мҡ©."""
    try:
        saved = _dynamic.get("korea_etf_bucket_weights", {})
        if isinstance(saved, dict) and saved:
            merged = dict(KOREA_ETF_BUCKET_WEIGHTS_DEFAULT)
            for k, v in saved.items():
                if k in merged:
                    merged[k] = float(v)
            return merged
    except Exception:
        pass
    return dict(KOREA_ETF_BUCKET_WEIGHTS_DEFAULT)


def _get_korea_etf_snapshot(code: str, name: str, signal_type: str = "", theme_name: str = "") -> dict:
    """мӢ нҳё мӢңм җмқҳ н•ҙмҷё н•ңкөӯ ETF мғҒнғңлҘј м ҖмһҘмҡ©мңјлЎң мҠӨлғ…мғ·."""
    try:
        weight = _korea_etf_time_weight()
        bucket, _bw, bucket_label = _classify_korea_etf_bucket(name, theme_name, signal_type)
        etf = get_korea_etf_signals() if USE_GLOBAL_KOREA_ETF_SCORE else {}
        return {
            "enabled": bool(USE_GLOBAL_KOREA_ETF_SCORE),
            "time_weight": round(weight, 2),
            "bucket": bucket,
            "bucket_label": bucket_label,
            "bucket_weight": round(float(_get_korea_etf_bucket_weights().get(bucket, KOREA_ETF_SMALLCAP_DAMPING)), 3),
            "avg_chg": round(float(etf.get("avg_chg", 0.0) or 0.0), 2),
            "market_adj": int(etf.get("market_adj", 0) or 0),
            "tone": str(etf.get("tone", "neutral") or "neutral"),
            "summary": str(etf.get("summary", "") or ""),
        }
    except Exception as e:
        _log_error(f"_get_korea_etf_snapshot({code})", e)
        return {"enabled": False, "time_weight": 0.0, "bucket": "smallcap", "bucket_label": "мҶҢнҳ•/н…Ңл§Ҳ"}


def _auto_tune_korea_etf_weights(completed: list) -> list:
    """signal_log м„ұкіјлҘј л°”нғ•мңјлЎң EWY/FLKR м„№н„° к°ҖмӨ‘м№ҳлҘј мһҗлҸҷ мһ¬мЎ°м •."""
    changes = []
    try:
        if not USE_GLOBAL_KOREA_ETF_SCORE:
            return changes

        cutoff = datetime.now() - timedelta(days=TUNE_LOOKBACK_DAYS)
        rows = []
        for rec in completed:
            snap = rec.get("korea_etf_snapshot") or {}
            if not isinstance(snap, dict) or not snap.get("enabled"):
                continue
            try:
                d = datetime.strptime(str(rec.get("detect_date", "")), "%Y%m%d")
                if d < cutoff:
                    continue
            except Exception:
                continue

            bucket = str(snap.get("bucket", "") or "")
            if not bucket:
                continue
            pnl = float(rec.get("pnl_pct", 0.0) or 0.0)
            avg_chg = float(snap.get("avg_chg", 0.0) or 0.0)
            tw = float(snap.get("time_weight", 0.0) or 0.0)
            if tw <= 0:
                continue
            rows.append({
                "bucket": bucket,
                "pnl": pnl,
                "avg_chg": avg_chg,
                "time_weight": tw,
            })

        if len(rows) < 8:
            return changes

        cur = _get_korea_etf_bucket_weights()
        new_weights = dict(cur)

        for bucket, base_w in KOREA_ETF_BUCKET_WEIGHTS_DEFAULT.items():
            subset = [r for r in rows if r["bucket"] == bucket]
            if len(subset) < 4:
                continue

            aligned = [r for r in subset if (r["avg_chg"] >= 0 and r["pnl"] >= 0) or (r["avg_chg"] < 0 and r["pnl"] < 0)]
            anti    = [r for r in subset if (r["avg_chg"] >= 0 and r["pnl"] < 0) or (r["avg_chg"] < 0 and r["pnl"] >= 0)]
            if not aligned and not anti:
                continue

            def _wavg(items):
                denom = sum(max(r["time_weight"], 0.2) for r in items) or 1.0
                return sum(r["pnl"] * max(r["time_weight"], 0.2) for r in items) / denom

            aligned_avg = _wavg(aligned) if aligned else 0.0
            anti_avg = _wavg(anti) if anti else 0.0
            edge = aligned_avg - anti_avg
            sample_mult = min(len(subset) / 12.0, 1.0)

            target = base_w
            if edge >= 4.0:
                target = base_w + 0.18 * sample_mult
            elif edge >= 2.0:
                target = base_w + 0.10 * sample_mult
            elif edge <= -4.0:
                target = base_w - 0.18 * sample_mult
            elif edge <= -2.0:
                target = base_w - 0.10 * sample_mult

            target = max(0.15, min(1.20, target))
            cur_w = float(cur.get(bucket, base_w) or base_w)
            smoothed = round(cur_w * (1 - TUNE_ALPHA) + target * TUNE_ALPHA, 3)
            smoothed = max(0.15, min(1.20, smoothed))
            if abs(smoothed - cur_w) >= 0.03:
                new_weights[bucket] = smoothed
                changes.append(
                    f"рҹҮ°рҹҮ· <b>н•ҙмҷё н•ңкөӯETF н•ҷмҠө</b> {bucket}: {cur_w:.2f} вҶ’ {smoothed:.2f} "
                    f"(edge {edge:+.1f}, n={len(subset)})"
                )

        if new_weights != cur:
            _dynamic["korea_etf_bucket_weights"] = new_weights
            _save_dynamic_params()
    except Exception as e:
        _log_error("auto_tune.korea_etf_weights", e)
    return changes


def _classify_korea_etf_bucket(name: str = "", theme_name: str = "", signal_type: str = "") -> tuple[str, float, str]:
    txt = f"{name or ''} {theme_name or ''} {signal_type or ''}"

    bucket_rules = [
        ("semiconductor", "л°ҳлҸ„мІҙ/IT", ["л°ҳлҸ„мІҙ", "л©”лӘЁлҰ¬", "hbm", "нҢЁнӮӨм§•", "кё°нҢҗ", "ai", "м№©", "fab", "нҢҢмҡҙл“ңлҰ¬", "н•ҳмқҙлӢүмҠӨ", "мӮјм„ұм „мһҗ", "мқҙмҲҳнҺҳнғҖ", "н•ңлҜёл°ҳлҸ„мІҙ"]),
        ("financial", "кёҲмңө", ["мҰқк¶Ң", "кёҲмңө", "мқҖн–ү", "м§ҖмЈј", "ліҙн—ҳ", "лҜёлһҳм—җм…Ӣ", "kb", "мӢ н•ң", "н•ҳлӮҳкёҲмңө", "мҡ°лҰ¬кёҲмңө"]),
        ("industrial", "мӮ°м—…мһ¬", ["мӨ‘кіөм—…", "мЎ°м„ ", "кё°кі„", "мқён”„лқј", "м „л Ҙкё°кё°", "м „м„ ", "кұҙм„Ө", "н”ҢлһңнҠё", "л‘җмӮ°м—җл„Ҳл№ҢлҰ¬нӢ°"]),
        ("defense", "л°©мӮ°", ["л°©мӮ°", "мҡ°мЈјн•ӯкіө", "н•ңнҷ”м—җм–ҙлЎң", "нҳ„лҢҖлЎңн…ң", "l igл„ҘмҠӨ", "ligл„ҘмҠӨ", "л№…н…Қ"]),
        ("nuclear", "мӣҗм „", ["мӣҗм „", "мӣҗмһҗл Ҙ", "л‘җмӮ°м—җл„Ҳл№ҢлҰ¬нӢ°", "л№„м—җмқҙм№ҳм•„мқҙ", "н•ңм „кё°мҲ "]),
        ("auto", "мһҗлҸҷм°Ё", ["мһҗлҸҷм°Ё", "нҳ„лҢҖм°Ё", "кё°м•„", "лӘЁл№„мҠӨ", "мһҗмңЁмЈјн–ү", "м°Ёл¶Җн’Ҳ"]),
        ("internet", "мқён„°л„·/н”Ңлһ«нҸј", ["мқён„°л„·", "н”Ңлһ«нҸј", "мҶҢн”„нҠёмӣЁм–ҙ", "кІҢмһ„", "naver", "м№ҙм№ҙмҳӨ", "м—”н„°"]),
        ("bio", "л°”мқҙмҳӨ", ["л°”мқҙмҳӨ", "м ңм•Ҫ", "н—¬мҠӨ", "мқҳлЈҢ", "м…ҖнҠёлҰ¬мҳЁ", "мӮјм„ұл°”мқҙмҳӨ"]),
        ("battery", "2м°Ём „м§Җ", ["2м°Ём „м§Җ", "л°°н„°лҰ¬", "м–‘к·№мһ¬", "мқҢк·№мһ¬", "лҰ¬нҠ¬", "м „н•ҙм§Ҳ", "м—җмҪ”н”„лЎң", "lgм—җл„Ҳм§ҖмҶ”лЈЁм…ҳ", "нҸ¬мҠӨмҪ”н“ЁмІҳм— "]),
    ]

    lower = txt.lower()
    for bucket, label, keywords in bucket_rules:
        if any(k.lower() in lower for k in keywords):
            return bucket, float(_get_korea_etf_bucket_weights().get(bucket, 0.35) or 0.35), label

    return "smallcap", float(KOREA_ETF_SMALLCAP_DAMPING), "мҶҢнҳ•/н…Ңл§Ҳ"


def get_korea_etf_signals() -> dict:
    if time.time() - _korea_etf_cache.get("ts", 0) < 5400:
        return _korea_etf_cache

    result = {
        "ts": time.time(),
        "ewy_chg": 0.0,
        "flkr_chg": 0.0,
        "avg_chg": 0.0,
        "market_adj": 0,
        "tone": "neutral",
        "summary": "",
    }
    try:
        values = {}
        for sym, key in KOREA_ETF_TICKERS.items():
            try:
                url = f"https://query1.finance.yahoo.com/v8/finance/chart/{sym}?interval=1d&range=5d"
                resp = requests.get(url, timeout=8, headers=_random_ua())
                data = resp.json()
                meta = data["chart"]["result"][0]["meta"]
                prev = data["chart"]["result"][0]["indicators"]["quote"][0]["close"]
                prev_close = [c for c in prev if c is not None]
                cur_price = float(meta.get("regularMarketPrice", 0) or 0)
                if cur_price and prev_close:
                    values[f"{key}_chg"] = round((cur_price - prev_close[-1]) / prev_close[-1] * 100, 2)
                time.sleep(0.2)
            except Exception:
                pass

        ewy = float(values.get("ewy_chg", 0.0) or 0.0)
        flkr = float(values.get("flkr_chg", 0.0) or 0.0)
        avg = round((ewy + flkr) / 2.0, 2)

        if ewy >= 1.5 and flkr >= 1.5:
            tone, market_adj = "strong_up", 8
        elif ewy >= 0.8 and flkr >= 0.8:
            tone, market_adj = "up", 5
        elif avg >= 0.3 and min(ewy, flkr) >= 0:
            tone, market_adj = "slight_up", 2
        elif ewy <= -1.5 and flkr <= -1.5:
            tone, market_adj = "strong_down", -8
        elif ewy <= -0.8 and flkr <= -0.8:
            tone, market_adj = "down", -5
        elif avg <= -0.3 and max(ewy, flkr) <= 0:
            tone, market_adj = "slight_down", -2
        else:
            tone, market_adj = "neutral", 0

        tone_map = {"strong_up":"рҹ”ҙ к°•м„ё", "up":"рҹ”ҙ мҡ°нҳё", "slight_up":"рҹҹ© мҶҢнҸӯ мҡ°нҳё",
                    "neutral":"мӨ‘лҰҪ", "slight_down":"рҹҹ§ мҶҢнҸӯ кІҪкі„", "down":"рҹҹЎ кІҪкі„", "strong_down":"рҹ”ө м•Ҫм„ё"}
        summary = f"{tone_map.get(tone, 'мӨ‘лҰҪ')} EWY {ewy:+.1f}% / FLKR {flkr:+.1f}%"
        result.update({
            "ts": time.time(),
            "ewy_chg": ewy,
            "flkr_chg": flkr,
            "avg_chg": avg,
            "market_adj": market_adj,
            "tone": tone,
            "summary": summary,
        })
        _korea_etf_cache.update(result)
        print(f"  рҹҮ°рҹҮ· н•ҙмҷё н•ңкөӯ ETF: {summary}")
    except Exception as e:
        _log_error("get_korea_etf_signals", e)

    return result


def calc_korea_etf_score_adj(code: str, name: str, signal_type: str = "", theme_name: str = "") -> tuple[int, str]:
    if not USE_GLOBAL_KOREA_ETF_SCORE:
        return 0, ""

    weight = _korea_etf_time_weight()
    if weight <= 0:
        return 0, ""

    try:
        etf = get_korea_etf_signals()
        market_adj = int(round(float(etf.get("market_adj", 0) or 0) * KOREA_ETF_MARKET_WEIGHT * weight))
        bucket, bucket_weight, bucket_label = _classify_korea_etf_bucket(name, theme_name, signal_type)

        avg_chg = float(etf.get("avg_chg", 0.0) or 0.0)
        sector_unit = 0
        if avg_chg >= 1.0:
            sector_unit = 4
        elif avg_chg >= 0.5:
            sector_unit = 2
        elif avg_chg <= -1.0:
            sector_unit = -4
        elif avg_chg <= -0.5:
            sector_unit = -2

        sector_adj = 0
        if USE_HOLDINGS_WEIGHTED_SECTOR_BONUS and sector_unit != 0:
            sector_adj = int(round(sector_unit * bucket_weight * weight))

        total = max(-KOREA_ETF_MAX_ABS_ADJ, min(KOREA_ETF_MAX_ABS_ADJ, market_adj + sector_adj))
        if total == 0:
            return 0, ""

        reason = (f"рҹҮ°рҹҮ· н•ҙмҷё н•ңкөӯ ETF {etf.get('summary','')} / "
                  f"{bucket_label} м—°лҸҷ {total:+d}м җ")
        return total, reason
    except Exception as e:
        _log_error(f"calc_korea_etf_score_adj({code})", e)
        return 0, ""


def get_us_market_signals() -> dict:
    """
    лӮҳмҠӨлӢҘ м„ л¬ј(NQ=F), VIX(^VIX), лӢ¬лҹ¬мқёлҚұмҠӨ(DX-Y.NYB) мЎ°нҡҢ.
    Yahoo Finance JSON API мӮ¬мҡ© (л¬ҙлЈҢ, pip м„Өм№ҳ л¶Ҳн•„мҡ”).
    л°ҳнҷҳ:
      nasdaq_chg  : лӮҳмҠӨлӢҘ м„ л¬ј л“ұлқҪлҘ  (%)
      vix         : VIX кіөнҸ¬м§ҖмҲҳ
      dxy         : лӢ¬лҹ¬мқёлҚұмҠӨ
      us_regime   : "risk_on" / "neutral" / "risk_off" / "panic"
      gap_signal  : "gap_up" / "flat" / "gap_down"  (лӢӨмқҢлӮ  к°ӯ мҳҲмёЎ)
      score_adj   : мӢ нҳё м җмҲҳ ліҙм •к°’ (-15 ~ +10)
      summary     : н…”л Ҳк·ёлһЁ н‘ңмӢңмҡ© мҡ”м•Ҫ л¬ёмһҗм—ҙ
    """
    if time.time() - _us_cache.get("ts", 0) < 3600:
        return _us_cache

    result = {
        "ts": time.time(), "nasdaq_chg": 0.0, "vix": 20.0,
        "dxy": 104.0, "us_regime": "neutral",
        "gap_signal": "flat", "score_adj": 0, "summary": "",
        # v38.5: м¶”к°Җ м„ л¬јВ·м§Җн‘ң
        "sp500_chg": 0.0, "gold_chg": 0.0, "oil_chg": 0.0, "tnx": 0.0,
        "krw_usd": 0.0, "krw_usd_chg": 0.0,  # v39.4: мӣҗ/лӢ¬лҹ¬ нҷҳмңЁ
    }
    try:
        # v39.4: кё°мЎҙ 7к°ң + KRW/USD = 8к°ң м§Җн‘ң
        symbols = {
            "NQ=F": "nasdaq", "^VIX": "vix", "DX-Y.NYB": "dxy",
            "ES=F": "sp500",   # S&P 500 м„ л¬ј
            "GC=F": "gold",    # кёҲ м„ л¬ј (м•Ҳм „мһҗмӮ° м§Җн‘ң)
            "CL=F": "oil",     # WTI мӣҗмң  м„ л¬ј (м—җл„Ҳм§ҖВ·мқён”Ңл Ҳ м§Җн‘ң)
            "^TNX": "tnx",     # лҜёкөӯ 10л…„ көӯмұ„ мҲҳмқөлҘ  (кёҲлҰ¬В·мұ„к¶Ң м§Җн‘ң)
            "KRW=X": "krw",    # v39.4: мӣҗ/лӢ¬лҹ¬ нҷҳмңЁ (мҷёкөӯмқё мһҗкёҲнқҗлҰ„ н•өмӢ¬)
        }
        values  = {}
        for sym, key in symbols.items():
            try:
                url  = f"https://query1.finance.yahoo.com/v8/finance/chart/{sym}?interval=1d&range=2d"
                resp = requests.get(url, timeout=8, headers=_random_ua())
                data = resp.json()
                meta = data["chart"]["result"][0]["meta"]
                prev = data["chart"]["result"][0]["indicators"]["quote"][0]["close"]
                prev_close = [c for c in prev if c is not None]
                cur_price  = meta.get("regularMarketPrice", 0)
                if key == "vix":
                    values["vix"] = round(float(cur_price), 1)
                elif key == "dxy":
                    values["dxy"] = round(float(cur_price), 2)
                elif key == "tnx":
                    values["tnx"] = round(float(cur_price), 3)  # мҲҳмқөлҘ  %
                elif key == "krw":
                    values["krw_usd"] = round(float(cur_price), 1)  # v39.4: мӣҗ/лӢ¬лҹ¬
                    if prev_close and cur_price:
                        values["krw_usd_chg"] = round((float(cur_price) - prev_close[-1]) / prev_close[-1] * 100, 2)
                elif prev_close and cur_price:
                    chg = round((float(cur_price) - prev_close[-1]) / prev_close[-1] * 100, 2)
                    values[f"{key}_chg"] = chg
                time.sleep(0.2)
            except Exception: pass

        nasdaq_chg = values.get("nasdaq_chg", 0.0)
        vix        = values.get("vix", 20.0)
        dxy        = values.get("dxy", 104.0)
        sp500_chg  = values.get("sp500_chg", 0.0)
        gold_chg   = values.get("gold_chg", 0.0)
        oil_chg    = values.get("oil_chg", 0.0)
        tnx        = values.get("tnx", 0.0)
        krw_usd    = values.get("krw_usd", 0.0)
        krw_usd_chg = values.get("krw_usd_chg", 0.0)

        # в”Җв”Җ лҜёкөӯ мӢңмһҘ көӯл©ҙ нҢҗлӢЁ в”Җв”Җ
        if vix >= 35 or nasdaq_chg <= -3.0:
            us_regime  = "panic"
            score_adj  = -15
            gap_signal = "gap_down"
        elif vix >= 25 or nasdaq_chg <= -1.5:
            us_regime  = "risk_off"
            score_adj  = -8
            gap_signal = "gap_down" if nasdaq_chg <= -2.0 else "flat"
        elif vix <= 15 and nasdaq_chg >= 1.0:
            us_regime  = "risk_on"
            score_adj  = +8
            gap_signal = "gap_up"
        elif nasdaq_chg >= 0.5:
            us_regime  = "risk_on"
            score_adj  = +4
            gap_signal = "flat"
        else:
            us_regime  = "neutral"
            score_adj  = 0
            gap_signal = "flat"

        # в”Җв”Җ лӢ¬лҹ¬ к°•м„ё вҶ’ мҷёкөӯмқё л§ӨлҸ„ м••л Ҙ в”Җв”Җ
        if dxy >= 107:
            score_adj -= 5

        # в”Җв”Җ v39.4: мӣҗ/лӢ¬лҹ¬ нҷҳмңЁ ліҙм • (мҷёкөӯмқё мһҗкёҲнқҗлҰ„ н•өмӢ¬) в”Җв”Җ
        if krw_usd >= 1400:
            score_adj -= 5  # мӣҗнҷ” мң„кё° мҲҳмӨҖ вҶ’ мҷёкөӯмқё лҢҖлҹү мқҙнғҲ мң„н—ҳ
        elif krw_usd_chg >= 0.8:
            score_adj -= 3  # мӣҗнҷ” кёүлқҪ(лӢ¬лҹ¬ лҢҖл№„) вҶ’ мҷёкөӯмқё л§ӨлҸ„ мң мқё
        elif krw_usd_chg <= -0.8:
            score_adj += 2  # мӣҗнҷ” к°•м„ё вҶ’ мҷёкөӯмқё л§ӨмҲҳ мң мқё

        # в”Җв”Җ v38.5: мӣҗмһҗмһ¬В·кёҲлҰ¬ ліҙм • в”Җв”Җ
        # кёҲ кёүл“ұ = м•Ҳм „мһҗмӮ° м„ нҳё(risk-off к°•нҷ”)
        if gold_chg >= 2.0:
            score_adj -= 3
        # мң к°Җ кёүл“ұ = м—җл„Ҳм§Җ м„№н„° нҳёмһ¬, but мқён”Ңл Ҳ мҡ°л Ө
        if oil_chg >= 4.0:
            score_adj -= 2  # мқён”Ңл Ҳ мҡ°л Өк°Җ лҚ” нҒј
        elif oil_chg <= -4.0:
            score_adj += 1  # мң к°Җ н•ҳлқҪ = мқён”Ңл Ҳ мҷ„нҷ”
        # көӯмұ„ мҲҳмқөлҘ  кёүл“ұ = кёҲлҰ¬ мғҒмҠ№ л¶ҖлӢҙ
        if tnx >= 5.0:
            score_adj -= 3  # кі кёҲлҰ¬ л¶ҖлӢҙ
        elif tnx >= 4.5:
            score_adj -= 1

        # в”Җв”Җ мҡ”м•Ҫ л¬ёмһҗм—ҙ в”Җв”Җ
        regime_emoji = {"panic":"рҹ”ө","risk_off":"рҹҹЎ","neutral":"рҹҹЎ","risk_on":"рҹ”ҙ"}
        gap_emoji    = {"gap_up":"в¬ҶпёҸ","flat":"вһЎпёҸ","gap_down":"в¬ҮпёҸ"}
        # н•өмӢ¬ 3к°ң + м¶”к°Җ м§Җн‘ң м••м¶•
        extra_parts = []
        if krw_usd: extra_parts.append(f"мӣҗ/лӢ¬лҹ¬{krw_usd:.0f}мӣҗ({krw_usd_chg:+.1f}%)")
        if gold_chg: extra_parts.append(f"кёҲ{gold_chg:+.1f}%")
        if oil_chg: extra_parts.append(f"мң к°Җ{oil_chg:+.1f}%")
        if tnx: extra_parts.append(f"10Y{tnx:.2f}%")
        if sp500_chg: extra_parts.append(f"S&P{sp500_chg:+.1f}%")
        extra_str = "  ".join(extra_parts)
        summary = (f"{regime_emoji.get(us_regime,'рҹҹЎ')} лӮҳмҠӨлӢҘм„ л¬ј {nasdaq_chg:+.1f}%  "
                   f"VIX {vix:.0f}  DXY {dxy:.1f}  "
                   f"к°ӯмҳҲмёЎ {gap_emoji.get(gap_signal,'вһЎпёҸ')} {gap_signal}")
        if extra_str:
            summary += f"\n  рҹ“Ҡ {extra_str}"

        result.update({
            "ts": time.time(), "nasdaq_chg": nasdaq_chg, "vix": vix,
            "dxy": dxy, "us_regime": us_regime, "gap_signal": gap_signal,
            "score_adj": score_adj, "summary": summary,
            # v38.5: м¶”к°Җ м§Җн‘ң
            "sp500_chg": sp500_chg, "gold_chg": gold_chg,
            "oil_chg": oil_chg, "tnx": tnx,
            # v39.4: мӣҗ/лӢ¬лҹ¬
            "krw_usd": krw_usd, "krw_usd_chg": krw_usd_chg,
        })
        MARKET_REGIME.update(compute_market_regime(nasdaq_chg, vix, dxy))
        _us_cache.update(result)
        print(f"  рҹҢҗ лҜёкөӯ мӢңмһҘ: {summary}")

    except Exception as e:
        _log_error("get_us_market_signals", e)

    return result

# ============================================================
# рҹ’° в‘Ў нҸ¬м§Җм…ҳ мӮ¬мқҙм§• к°Җмқҙл“ң (Kelly кё°л°ҳ)
# ============================================================
def calc_position_size(signal_type: str, score: int, grade: str) -> dict:
    """
    v41.66: 1мў…лӘ© м§‘мӨ‘ + л¶„н• м§„мһ… л№„мӨ‘ кі„мӮ°.
    нҲ¬мһҗкёҲ 10л§Ңмӣҗ кё°мӨҖ, 1мў…лӘ© м§‘мӨ‘ м „лһө.
    мјҲлҰ¬ кіөмӢқ: f = (p*b - q) / b  (p=мҠ№лҘ , q=1-p, b=мҶҗмқөл№„)
    л°ҳнҷҳ: {"pct": float, "phase1_pct": int, "phase2_pct": int, "strength": str,
           "kelly": float, "guide": str, "win_rate": float|None, "samples": int}
    """
    try:
        # кіјкұ° мӢ нҳё мң нҳ•лі„ мҠ№лҘ  мЎ°нҡҢ
        data = {}
        try:
            data = _read_json_locked(SIGNAL_LOG_FILE)
        except Exception: pass

        same_type = [v for v in data.values()
                     if v.get("signal_type") == signal_type
                     and v.get("status") in ["мҲҳмқө","мҶҗмӢӨ","ліём „"]]

        if len(same_type) >= 5:
            wins  = sum(1 for v in same_type if v["pnl_pct"] > 0)
            p     = wins / len(same_type)
            avg_w = sum(v["pnl_pct"] for v in same_type if v["pnl_pct"] > 0) / max(wins, 1)
            avg_l = abs(sum(v["pnl_pct"] for v in same_type if v["pnl_pct"] < 0) / max(len(same_type)-wins, 1))
            b     = avg_w / avg_l if avg_l else 2.0
            kelly = max(0, (p * b - (1-p)) / b)
            kelly = min(kelly * 0.5, 0.25)  # н•ҳн”„ мјҲлҰ¬, 1мў…лӘ© м§‘мӨ‘мқҙлҜҖлЎң мөңлҢҖ 25%
        else:
            p     = 0.55  # кё°ліёк°’
            kelly = 0.10

        # л“ұкёүлі„ ліҙм • вҶ’ мӢ нҳё к°•лҸ„ кІ°м •
        grade_upper = str(grade or "B").upper()
        if grade_upper == "A" and score >= 75:
            strength = "к°•н•ң"
        elif grade_upper == "C" or score < 50:
            strength = "м•Ҫн•ң"
        else:
            strength = "ліҙнҶө"

        # л¶„н• м§„мһ… л№„мӨ‘ к·ңм№ҷ
        split_rule = _get_entry_split_rule(strength)

        # мӢңмһҘ көӯл©ҙ ліҙм • (к°җм¶• м „мҡ©, 1мў…лӘ©мқҙлҜҖлЎң нҷ•лҢҖлҠ” м ңн•ңм Ғ)
        regime_info  = get_market_regime()
        regime       = regime_info.get("mode", "normal")
        nxt_only     = regime_info.get("nxt_only", False)
        regime_mult  = {"bull": 1.0, "normal": 1.0, "bear": 0.7, "crash": 0.4}.get(regime, 1.0)
        # v41.64: NXT мӢңк°„лҢҖлі„ нҸ¬м§Җм…ҳ л№„мӨ‘ м„ёл¶„нҷ”
        if nxt_only:
            _nxt_p = get_nxt_params()
            if _nxt_p:
                regime_mult = max(regime_mult * _nxt_p.get("position_mult", 0.8), 0.3)
            else:
                regime_mult = max(regime_mult * 0.8, 0.3)

        # 1мў…лӘ© м§‘мӨ‘ кё°ліё: мҙқ л№„мӨ‘ = phase1 + phase2 (л№„мғҒм—¬мң  м ңмҷё)
        total_base = split_rule["phase1_pct"] + split_rule["phase2_pct"]
        final_pct = round(min(total_base * regime_mult, 100.0), 1)
        phase1_pct = int(split_rule["phase1_pct"] * regime_mult)
        phase2_pct = int(split_rule["phase2_pct"] * regime_mult) if split_rule["phase2_allowed"] else 0

        if regime in ("bear", "crash"):
            guide = f"вҡ пёҸ {regime_label()} вҖ” л№„мӨ‘ м¶•мҶҢ, 1мў…лӘ© м§‘мӨ‘"
        elif strength == "к°•н•ң" and p >= 0.6:
            guide = f"рҹ’Ә кі нҷ•лҘ  мӢ нҳё вҖ” 1мў…лӘ© м Ғк·№ м§„мһ…"
        elif strength == "м•Ҫн•ң":
            guide = f"вҡ пёҸ м•Ҫн•ң мӢ нҳё вҖ” кҙҖм°° м „мҡ©, мӢӨм§„мһ… м ңмҷё"
        else:
            guide = f"рҹ“Ҡ н‘ңмӨҖ л№„мӨ‘ вҖ” 1мў…лӘ© л¶„н•  м§„мһ…"

        return {
            "pct":       final_pct,
            "phase1_pct": phase1_pct,
            "phase2_pct": phase2_pct,
            "strength":  strength,
            "kelly":     round(kelly * 100, 1),
            "guide":     guide,
            "win_rate":  round(p * 100, 1) if len(same_type) >= 5 else None,
            "samples":   len(same_type),
        }
    except Exception:
        return {"pct": 35.0, "phase1_pct": 35, "phase2_pct": 0, "strength": "ліҙнҶө",
                "kelly": 10.0, "guide": "рҹ“Ҡ н‘ңмӨҖ л№„мӨ‘", "win_rate": None, "samples": 0}

# ============================================================
# рҹ“җ в‘ў мҶҗмқөл№„ лҸҷм Ғ мөңм Ғнҷ”
# ============================================================
def calc_dynamic_stop_target(code: str, entry: int, signal_type: str | None = None) -> tuple:
    """
    мӢңмһҘ ліҖлҸҷм„ұ + көӯл©ҙ + мӢ нҳёмң нҳ•м—җ л”°лқј мҶҗм Ҳ/лӘ©н‘ңк°Җ л°°мҲҳ лҸҷм Ғ мЎ°м •.
    v41.61: мӢ нҳёмң нҳ•лі„ SIGNAL_STOP_PARAMS м Ғмҡ© + мў…лӘ© ATR ліҖлҸҷм„ұ кө¬к°„ ліҙм •.
    л°ҳнҷҳ: (stop, target, stop_pct, target_pct, atr_used)
    """
    atr = get_atr(code)
    if not atr:
        _rm   = get_atr_regime_mult()
        _stop_pct   = max(0.05, 0.07 * _rm)
        _target_pct = max(0.08, 0.15 / _rm)
        stop   = int(entry * (1 - _stop_pct)   / 10) * 10
        target = int(entry * (1 + _target_pct) / 10) * 10
        return stop, target, round(_stop_pct*100,1), round(_target_pct*100,1), False

    regime_info = get_market_regime()
    regime  = regime_info.get("mode", "normal")
    nxt_only = regime_info.get("nxt_only", False)

    # в”Җв”Җ v41.61 #8: мӢ нҳёмң нҳ•лі„ кё°ліё л°°мҲҳ м„ нғқ в”Җв”Җ
    sig_params = SIGNAL_STOP_PARAMS.get(signal_type or "", {})
    stop_m  = _dynamic.get("atr_stop_mult",   sig_params.get("stop_mult", ATR_STOP_MULT))
    tgt_m   = _dynamic.get("atr_target_mult", sig_params.get("target_mult", ATR_TARGET_MULT))
    # signal_typeмқҙ лӘ…мӢңлҗң кІҪмҡ° н•ҙлӢ№ мң нҳ• л°°мҲҳлҘј мҡ°м„  м Ғмҡ©
    if signal_type and signal_type in SIGNAL_STOP_PARAMS:
        stop_m = sig_params["stop_mult"]
        tgt_m  = sig_params["target_mult"]

    # в”Җв”Җ v41.61 #8: мў…лӘ©лі„ ATR ліҖлҸҷм„ұ кө¬к°„ ліҙм • в”Җв”Җ
    # м ҖліҖлҸҷ(ATR<1.5%) вҶ’ мҶҗм Ҳ нғҖмқҙнҠё, лӘ©н‘ң ліҙмҲҳм Ғ
    # кі ліҖлҸҷ(ATR>4.0%) вҶ’ мҶҗм Ҳ м—¬мң , лӘ©н‘ң нҷ•лҢҖ
    atr_pct = atr / entry * 100 if entry > 0 else 2.0
    if atr_pct < 1.5:
        stop_m  = max(stop_m * 0.85, 0.8)    # м ҖліҖлҸҷ: нғҖмқҙнҠё
        tgt_m   = max(tgt_m * 0.85, 1.5)
    elif atr_pct > 4.0:
        stop_m  = min(stop_m * 1.25, 3.5)    # кі ліҖлҸҷ: м—¬мң 
        tgt_m   = min(tgt_m * 1.20, 6.0)

    # мӢңмһҘ көӯл©ҙ ліҙм •
    if regime == "crash":
        stop_m  = max(stop_m  * 0.8, 1.0)
        tgt_m   = max(tgt_m   * 0.7, 2.0)
    elif regime == "bear":
        stop_m  = max(stop_m  * 0.9, 1.0)
        tgt_m   = max(tgt_m   * 0.8, 2.0)
    elif regime == "bull":
        tgt_m   = min(tgt_m   * 1.2, 5.0)

    # NXT лӢЁлҸ… мӢңк°„лҢҖ ліҙм •: v41.64 мӢңк°„лҢҖлі„ м„ёл¶„нҷ”
    if nxt_only:
        _nxt_p = get_nxt_params()
        if _nxt_p:
            stop_m  = max(stop_m  * _nxt_p.get("stop_mult", 1.0),   1.0)
            tgt_m   = max(tgt_m   * _nxt_p.get("target_mult", 1.0), 1.5)
        else:
            stop_m  = max(stop_m  * 0.85, 1.0)
            tgt_m   = max(tgt_m   * 0.80, 1.5)

    stop      = int((entry - atr * stop_m)  / 10) * 10
    target    = int((entry + atr * tgt_m)   / 10) * 10
    stop_pct  = round((entry - stop)   / entry * 100, 1)
    tgt_pct   = round((target - entry) / entry * 100, 1)
    return stop, target, stop_pct, tgt_pct, True

# ============================================================
# рҹ“… в‘Ј мӢӨм Ғ л°ңн‘ң м „нӣ„ н•„н„°
# ============================================================
_earnings_cache: dict = {}   # {code: {"date": "YYYYMMDD", "ts": float}}

def check_earnings_risk(code: str, name: str) -> dict:
    """
    DARTм—җм„ң мөңк·ј мӢӨм Ғ л°ңн‘ң мқјм • нҷ•мқё.
    л°ңн‘ң 3мқј м „мқҙл©ҙ кІҪкі , лӢ№мқј/лӢӨмқҢлӮ мқҙл©ҙ к°•кІҪкі .
    л°ҳнҷҳ: {"risk": "none"/"warn"/"high", "desc": str}
    """
    if not DART_API_KEY:
        return {"risk": "none", "desc": ""}

    cached = _earnings_cache.get(code)
    if cached and time.time() - cached["ts"] < 3600:
        return cached["result"]

    try:
        today   = datetime.now()
        bgn_de  = today.strftime("%Y%m%d")
        end_de  = (today + timedelta(days=7)).strftime("%Y%m%d")

        url    = "https://opendart.fss.or.kr/api/list.json"
        params = {
            "crtfc_key": DART_API_KEY,
            "bgn_de":    bgn_de,
            "end_de":    end_de,
            "pblntf_ty": "A",           # м •кё°кіөмӢң (мӢӨм Ғ)
            "corp_name": name[:4],      # мў…лӘ©лӘ… м•һ 4кёҖмһҗлЎң кІҖмғү
            "page_count": 10,
        }
        resp = _session.get(url, params=params, timeout=10)
        items = resp.json().get("list", []) if resp.status_code == 200 else []

        result = {"risk": "none", "desc": ""}
        for item in items:
            rpt_nm = item.get("report_nm", "")
            rcept_dt = item.get("rcept_dt", "")
            if any(kw in rpt_nm for kw in ["мӮ¬м—…ліҙкі м„ң","л¶„кё°ліҙкі м„ң","л°ҳкё°ліҙкі м„ң"]):
                try:
                    rpt_date = datetime.strptime(rcept_dt, "%Y%m%d")
                    diff = (rpt_date - today).days
                    if diff <= 1:
                        result = {"risk": "high",
                                  "desc": f"вҡ пёҸ мӢӨм Ғл°ңн‘ң мһ„л°•! ({rcept_dt}) вҖ” ліҖлҸҷм„ұ мЈјмқҳ"}
                    elif diff <= 3:
                        result = {"risk": "warn",
                                  "desc": f"рҹ“… мӢӨм Ғл°ңн‘ң {diff}мқј м „ ({rcept_dt}) вҖ” кҙҖл§қ кі л Ө"}
                    break
                except Exception: pass

        _earnings_cache[code] = {"result": result, "ts": time.time()}
        return result

    except Exception:
        return {"risk": "none", "desc": ""}

# ============================================================
# рҹ—ӮпёҸ в‘Ө лҸҷмӢң мӢ нҳё нҸ¬нҠёнҸҙлҰ¬мҳӨ кҙҖлҰ¬
# ============================================================
def _get_carry_position_context() -> tuple[int, set[str]]:
    try:
        siglog_data = _read_json_safe(SIGNAL_LOG_FILE, {})
    except Exception:
        siglog_data = {}
    today = datetime.now().strftime("%Y%m%d")

    actionable_codes = _collect_actionable_position_limit_codes(siglog_data=siglog_data, today=today)
    if actionable_codes:
        return len(actionable_codes), actionable_codes

    latest_by_code = _build_latest_tracking_by_code(siglog_data)
    carry_codes = set()
    try:
        with _state_lock:
            detected_snapshot = dict(_detected_stocks)
    except Exception:
        detected_snapshot = dict(_detected_stocks)

    for raw_code, info in detected_snapshot.items():
        if not isinstance(info, dict):
            continue
        code = normalize_stock_code(raw_code or info.get("code"))
        if not code:
            continue
        latest_rec = latest_by_code.get(code)
        if _is_active_carry_snapshot(info, latest_rec=latest_rec, today=today):
            carry_codes.add(code)

    if carry_codes:
        return len(carry_codes), carry_codes

    try:
        raw_carry = _read_json_safe(CARRY_FILE, {})
        sanitized_carry, _ = _sanitize_carry_snapshot_map(raw_carry, siglog_data=siglog_data)
        carry_codes = set(sanitized_carry.keys())
        return len(carry_codes), carry_codes
    except Exception:
        return 0, set()


def _apply_position_limit_after_priority(sorted_alerts: list, carry_codes: set[str], carry_count: int, max_positions: int, stage: str = "") -> list:
    if not sorted_alerts:
        return []
    if carry_count < max_positions:
        return sorted_alerts

    allowed = []
    blocked = []
    for rank, alert in enumerate(sorted_alerts, start=1):
        if alert.get("code") in carry_codes:
            allowed.append(alert)
            continue
        blocked.append((rank, alert))

    if blocked:
        for rank, alert in blocked:
            _record_shadow_capture(
                alert.get("code", ""), alert.get("name", alert.get("code", "")),
                "position_limit", alert.get("signal_type", ""), stage=stage or "filter_portfolio_signals",
                extra={
                    "score": alert.get("score", 0),
                    "grade": alert.get("grade", ""),
                    "change_rate": alert.get("change_rate", 0),
                    "market": alert.get("market", ""),
                    "priority_rank": rank,
                    "leader_priority_hit": bool(alert.get("leader_priority_hit")),
                    "stale_pullback_hit": bool(alert.get("stale_pullback_hit")),
                    "stale_replay_penalty_hit": bool(alert.get("stale_replay_penalty_hit")),
                },
            )
        print(f"  рҹӣЎ лҸҷмӢңліҙмң  м ңн•ң: {carry_count}/{max_positions}мў…лӘ© ліҙмң  мӨ‘ вҶ’ нҸүк°Җ нӣ„ мӢ к·ң {len(blocked)}к°ң м–өм ң")

    return allowed


def filter_portfolio_signals(alerts: list) -> list:
    """
    лҸҷмӢң лӢӨл°ң мӢ нҳём—җм„ң мӢӨм§Ҳ м„№н„° мҠӨмҪ”м–ҙ кё°л°ҳ мӨ‘ліө м ңкұ°.
    - л‘җ мӢ нҳё к°„ real_sector_score >= 50 мқҙл©ҙ к°ҷмқҖ мӢӨм§Ҳм„№н„°лЎң нҢҗлӢЁ
    - м җмҲҳ лҶ’мқҖ кІғ 1к°ңл§Ң нҶөкіј (лӮҳлЁём§Җ м ңмҷё)
    - көӯл©ҙлі„ мҙқ мӢ нҳё мҲҳ м ңн•ң
    - v53: мӢ к·ң/кё°мЎҙ мӢ нҳёлҘј лЁјм Җ нҸүк°Җн•ң л’Ө лҸҷмӢң ліҙмң  м ңн•ңмқ„ л§Ҳм§Җл§ү н–үлҸҷ лӢЁкі„м—җ м Ғмҡ©
    """
    if not alerts:
        return alerts

    regime_info = get_market_regime()
    regime    = regime_info.get("mode", "normal")
    rp        = REGIME_PARAMS.get(regime, REGIME_PARAMS["normal"])
    max_positions = rp.get("max_positions", 1)
    max_total = {"bull": 8, "normal": 6, "bear": 3, "crash": 1}.get(regime, 6)

    carry_count, carry_codes = _get_carry_position_context()

    alerts = _apply_stale_pullback_quota(alerts, stage="filter_portfolio_signals")

    # мӢ к·ң лҰ¬лҚ” мҡ°м„  + stale лҲҢлҰјлӘ© нӣ„мҲңмң„ м •л ¬
    sorted_alerts = sorted(
        alerts,
        key=lambda x: (
            1 if x.get("leader_priority_hit") else 0,
            0 if x.get("stale_pullback_hit") else 1,
            0 if x.get("stale_replay_penalty_hit") else 1,
            int(x.get("score", 0) or 0),
            float(x.get("change_rate", 0) or 0),
            float(x.get("volume_ratio", 0) or 0),
        ),
        reverse=True,
    )

    sorted_alerts = _apply_position_limit_after_priority(
        sorted_alerts,
        carry_codes=carry_codes,
        carry_count=carry_count,
        max_positions=max_positions,
        stage="filter_portfolio_signals",
    )
    if not sorted_alerts:
        return []

    passed   = []
    excluded = set()

    for i, s in enumerate(sorted_alerts):
        if len(passed) >= max_total:
            break
        if s["code"] in excluded:
            continue
        passed.append(s)
        # м•„м§Ғ нҶөкіј м•Ҳ лҗң л’Ө мӢ нҳёл“Өкіј мӢӨм§Ҳ м„№н„° л№„көҗ
        for j in range(i + 1, len(sorted_alerts)):
            peer = sorted_alerts[j]
            if peer["code"] in excluded:
                continue
            try:
                rs = calc_real_sector_score(s["code"], peer["code"],
                                            s["name"], peer["name"])
                if rs["score"] >= 50:
                    # к°ҷмқҖ м„№н„° лӮҙ max_same_sector к°ңмҲҳк№Ңм§ҖлҠ” н—Ҳмҡ©
                    same_sector_passed = sum(
                        1 for p in passed
                        if calc_real_sector_score(s["code"], p["code"], s["name"], p["name"]).get("score", 0) >= 50
                    )
                    _max_same = _dynamic.get("max_same_sector", 2)
                    if same_sector_passed >= _max_same:
                        excluded.add(peer["code"])
                        print(f"  рҹ—ӮпёҸ мӢӨм§Ҳм„№н„° мӨ‘ліө м ңмҷё: {_resolve_stock_name(peer['code'], peer.get('name',''))} ({rs['label']}, {rs['score']}м җ, м„№н„°лӮҙ {same_sector_passed}/{_max_same})")
            except Exception:
                pass

    if len(passed) < len(sorted_alerts):
        skipped = len(sorted_alerts) - len(passed)
        print(f"  рҹ—ӮпёҸ нҸ¬нҠёнҸҙлҰ¬мҳӨ н•„н„°: {skipped}к°ң м ңмҷё ({regime}мһҘ, мөңлҢҖ {max_total}к°ң)")

    return passed

# v37.0: schedule lambda вҶ’ лӘ…лӘ… н•ЁмҲҳ (м—җлҹ¬ м¶”м Ғ к°ҖлҠҘ)
def _on_market_open():
    """мһҘ мӢңмһ‘ мӢң мҙҲкё°нҷ” вҖ” scheduleм—җм„ң нҳём¶ң"""
    if is_holiday(): return
    _clear_all_cache()
    _overnight_state.update({"last_us_regime":"neutral","last_vix":20.0,
                              "alerted_regime":"","summary_lines":[]})
    try:
        _save_overnight_active_state(_default_overnight_active_state())
        _save_geo_active_state(_default_geo_active_state())
    except Exception:
        pass
    _upper_limit_day_alerted.clear()  # v40.0-#10: мғҒн•ңк°Җ лӢ№мқј м¶”м Ғ мҙҲкё°нҷ”
    reset_top_signals_daily()
    refresh_dynamic_candidates()
    send(f"рҹҢ… <b>мһҘ мӢңмһ‘!</b>  {datetime.now().strftime('%Y-%m-%d')}\n"
         f"рҹ“Ӯ мқҙмӣ”: {len(_detected_stocks)}к°ң  |  рҹ“Ў м „мІҙ мҠӨмә” мӢңмһ‘")

def run_scan():
    code = ""  # HOTFIX: prevent NameError in exception paths
    # KRX л§Ҳк°җ нӣ„м—җлҸ„ NXT мҡҙмҳҒ мӨ‘мқҙл©ҙ NXT мҠӨмә” + м¶”м Ғ мІҙнҒ¬ кі„мҶҚ
    krx_open = is_market_open()
    nxt_open = is_nxt_open()
    if not krx_open and not nxt_open: return   # лӘЁл“  мӢңмһҘ л§Ҳк°җ
    if _bot_paused: return

    strict_tag = " [м—„кІ©]" if is_strict_time() else ""
    mkt_tag    = "KRX+NXT" if krx_open and nxt_open else ("NXTм „мҡ©" if nxt_open else "KRX")
    print(f"\n[{datetime.now().strftime('%H:%M:%S')}] мҠӨмә”{strict_tag} [{mkt_tag}]...", flush=True)
    try:
        _ensure_dynamic_candidates_fresh()
        alerts, seen = [], set()

        # v41.78 #4: м•јк°„ мӣҢм№ҳлҰ¬мҠӨнҠё мў…лӘ© вҶ’ лҸҷм Ғ нӣ„ліҙкө° мҡ°м„  нҺёмһ…
        try:
            if _overnight_watchlist and krx_open:
                for wl_code, wl_info in list(_overnight_watchlist.items())[:10]:
                    if wl_code in seen:
                        continue
                    try:
                        cur = get_stock_price(wl_code)
                        if cur and cur.get("price", 0) > 0:
                            wl_stock = {
                                "code": wl_code,
                                "name": wl_info.get("name", ""),
                                "price": cur["price"],
                                "change_rate": cur.get("change_rate", 0),
                                "volume_ratio": cur.get("volume_ratio", 0),
                                "today_vol": cur.get("today_vol", 0),
                                "_overnight_event": wl_info.get("event", ""),
                            }
                            r = analyze(wl_stock)
                            if r and time.time() - _alert_history.get(r["code"], 0) > get_regime_cooldown():
                                alerts.append(r)
                                seen.add(wl_code)
                        time.sleep(0.1)
                    except Exception:
                        continue
        except Exception as _e:
            print(f"  вҡ пёҸ м•јк°„ мӣҢм№ҳлҰ¬мҠӨнҠё мҡ°м„  мҠӨмә” мҳӨлҘҳ: {_e}")

        # KRX мҠӨмә” (мһҘ мӨ‘м—җл§Ң)
        if krx_open:
            today_date = datetime.now().strftime("%Y%m%d")
            for stock in get_upper_limit_stocks():
                if stock["code"] in seen: continue
                # v40.0-#10: мғҒн•ңк°Җ мң м§Җ мў…лӘ© лӢ№мқј мһ¬м•ҢлҰј м°ЁлӢЁ
                _ul_rec = _upper_limit_day_alerted.get(stock["code"])
                if _ul_rec and _ul_rec.get("date") == today_date:
                    cr = stock.get("change_rate", 0)
                    if cr >= 29.0:
                        # м•„м§Ғ мғҒн•ңк°Җ мң м§Җ мӨ‘ вҶ’ м°ЁлӢЁ
                        continue
                    else:
                        # мғҒн•ңк°Җ н’ҖлҰј вҶ’ мҙҲкё°нҷ” (мһ¬м°Ё мғҒн•ңк°Җ лҸ„лӢ¬ мӢң лӢӨмӢң м•ҢлҰј к°ҖлҠҘ)
                        _upper_limit_day_alerted.pop(stock["code"], None)
                r = analyze(stock)
                if r and time.time()-_alert_history.get(r["code"],0)>get_regime_cooldown():
                    # v40.0-#10: мғҒн•ңк°Җ к°җм§Җл©ҙ лӢ№мқј кё°лЎқ
                    if r.get("signal_type") in ("UPPER_LIMIT", "NEAR_UPPER"):
                        _upper_limit_day_alerted[r["code"]] = {"date": today_date, "alerted": True}
                    alerts.append(r); seen.add(r["code"])
            for stock in get_volume_surge_stocks():
                if stock["code"] in seen: continue
                r = analyze(stock)
                if r and time.time()-_alert_history.get(r["code"],0)>get_regime_cooldown():
                    alerts.append(r); seen.add(r["code"])

        # в”Җв”Җ NXT мҠӨмә” (NXT мҡҙмҳҒ мӢңк°„м—җл§Ң) в”Җв”Җ
        if nxt_open:
            for stock in get_nxt_surge_stocks():
                if stock["code"] in seen: continue
                r = analyze(stock)
                if r and time.time()-_alert_history.get(f"NXT_{r['code']}",0)>get_regime_cooldown():
                    r["market"] = "NXT"
                    alerts.append(r); seen.add(stock["code"])

        # мӢӨмӢңк°„ лһӯнӮ№ нӣ„ліҙкө° м§Ғм ‘ мҠӨмә” вҖ” мһҘмҙҲл°ҳмқҖ к°•н•ҳкІҢ, мқҙнӣ„ мһҘмӨ‘мқҖ ліҙмҲҳм ҒмңјлЎң
        _rank_scan_limit = NXT_POSTMARKET_EXTRA_RANK_LIMIT if _is_nxt_postmarket_only_window() else None
        for stock in get_market_rank_focus_stocks(scan_limit_per_market=_rank_scan_limit):
            code = stock.get("code")
            if not code or code in seen:
                continue
            r = analyze(stock)
            if r and time.time()-_alert_history.get((f"NXT_{r['code']}" if r.get("market") == "NXT" else r["code"]),0)>get_regime_cooldown():
                alerts.append(r); seen.add(code)

        # в”Җв”Җ н…Ңл§Ҳ лҸҷмЎ°мЈј нӣ„ліҙ нҷ•мһҘ: к°•н•ң seed мў…лӘ©мқҳ лҸҷмқј н…Ңл§Ҳ peerлҘј м ңн•ңм ҒмңјлЎң м¶”к°Җ мҠӨмә” в”Җв”Җ
        for stock in _collect_theme_peer_follow_candidates(existing_codes=seen):
            code = stock.get("code")
            if not code or code in seen:
                continue
            r = analyze(stock)
            if r and time.time()-_alert_history.get((f"NXT_{r['code']}" if r.get("market") == "NXT" else r["code"]),0)>get_regime_cooldown():
                alerts.append(r); seen.add(code)

        # мЎ°кё°нҸ¬м°©мқҖ KRX мһҘмӨ‘ + мҳӨм „ NXT мһҘм „ м„ нҸ¬м°©мқ„ лӘЁл‘җ л°ҳмҳҒ
        if krx_open:
            for s in check_early_detection():
                hist_key = f"NXT_{s['code']}" if s.get("market") == "NXT" else s["code"]
                if s["code"] not in seen and time.time()-_alert_history.get(hist_key,0)>get_regime_cooldown():
                    alerts.append(s); seen.add(s["code"])
            for s in check_pullback_signals():
                # v39.3-#9-2: MID_PULLBACKвҶ”ENTRY_POINT лҸҷмқјмў…лӘ© мӨ‘ліө м–өм ң
                if s["code"] not in seen and s["code"] not in _mid_pullback_alert_history:
                    alerts.append(s); seen.add(s["code"])
        elif nxt_open:
            for s in check_nxt_preopen_detection(existing_codes=seen):
                if s["code"] not in seen and time.time()-_alert_history.get(f"NXT_{s['code']}",0)>get_regime_cooldown():
                    alerts.append(s); seen.add(s["code"])
            for s in check_nxt_postmarket_detection(existing_codes=seen):
                if s["code"] not in seen and time.time()-_alert_history.get(f"NXT_{s['code']}",0)>get_regime_cooldown():
                    alerts.append(s); seen.add(s["code"])

        # в”Җв”Җ v39.3-#9-5: м„№н„°лӢ№ мөңлҢҖ мӢ нҳё мҲҳ м ңн•ң (м§‘мӨ‘лҸ„ н–ҘмғҒ) в”Җв”Җ
        alerts = sorted(alerts, key=_sector_gate_sort_key, reverse=True)
        MAX_SIGNALS_PER_SECTOR = 3
        MAX_SIGNALS_MISC = 4
        sector_counts = {}
        filtered_alerts = []
        for s in alerts:
            sec = _extract_alert_sector_theme(s)
            sec_limit = MAX_SIGNALS_MISC if sec == "кё°нғҖ" else MAX_SIGNALS_PER_SECTOR
            sector_counts[sec] = sector_counts.get(sec, 0) + 1
            if sector_counts[sec] <= sec_limit:
                if not s.get("sector_theme") and sec != "кё°нғҖ":
                    s["sector_theme"] = sec
                filtered_alerts.append(s)
            else:
                _record_shadow_capture(s.get("code", ""), s.get("name", s.get("code", "")), "sector_limit", s.get("signal_type", ""), stage="sector_gate", extra={"sector": sec, "score": s.get("score", 0), "change_rate": s.get("change_rate", 0)})
                print(f"  вҸӯ м„№н„° м ңн•ң({sec} {sector_counts[sec]}лІҲм§ё): {s.get('name','')} мғқлһө")
        alerts = filtered_alerts

        # в”Җв”Җ в‘Ө нҸ¬нҠёнҸҙлҰ¬мҳӨ н•„н„° в”Җв”Җ
        alerts = filter_portfolio_signals(alerts)

        if not alerts: print("  вҶ’ мЎ°кұҙ м¶©мЎұ м—ҶмқҢ")
        else:
            print(f"  вҶ’ {len(alerts)}к°ң к°җм§Җ! [{regime_label()}]")
            for s in alerts:
                if is_scoring_only_instrument(s.get("code", ""), s.get("name", "")):
                    print(f"  вҸӯ м җмҲҳм „мҡ© мў…лӘ© м ңмҷё: {s.get('name', s.get('code',''))}")
                    continue
                is_nxt = s.get("market") == "NXT"
                hist_key = f"NXT_{s['code']}" if is_nxt else s["code"]
                if not _dispatch_general_alert_signal(s, hist_key=hist_key, source_label="мқјл°ҳ нҸ¬м°©"):
                    continue
                # sleep м ңкұ°: 20мҙҲ мҠӨмә” мЈјкё°м—җм„ң мӢ нҳёлӢ№ 1мҙҲ лё”лЎқ л¶Ҳн•„мҡ”

        check_execution_setup_watch()  # вҳ… мІҙкІ°мҶҚлҸ„ нҷ•мқё нӣ„ м§„мһ… нҷ•м • мІҙнҒ¬
        _tick_exec_speed_prewarm()     # вҳ… мІҙкІ°мҶҚлҸ„ мӮ¬м „ мӣҢл°Қ вҖ” м§„мһ…к°Җ лҸ„лӢ¬ м „ мғҳн”Ң мөңмӢ нҷ”
        check_entry_watch()     # вҳ… м§„мһ…к°Җ лҸ„лӢ¬ мІҙнҒ¬
        check_preclose_gap_entry_watch()  # вҳ… мһҘл§Ҳк°җ м „ м„ м§„мһ…к°Җ лҸ„лӢ¬ мІҙнҒ¬
        run_entry_defense_monitor()  # рҹӣЎ мһҘл§Ҳк°җ мҶҗмқө л°©м–ҙ к°Җмқҙл“ң
        check_reentry_watch()   # вҳ… мҶҗм Ҳ нӣ„ мһ¬м§„мһ… к°җмӢң
        track_signal_results()  # вҳ… м¶”м Ғ мӨ‘ мӢ нҳё кІ°кіј мІҙнҒ¬
    except Exception as e: _log_error("run_scan", e, critical=True)

